INSERT INTO public.ai_jobs VALUES ('0eb30948-97dc-4af8-8832-a84016647cfb', '089843ca-0b3f-4d4c-a065-ccebc95842b1', 'f25d83e6-0885-4844-8603-490c00d54be4', NULL, 'synthesize_speech', 'local', 'mock_tts', 'succeeded', '{"persona_id": "f25d83e6-0885-4844-8603-490c00d54be4", "persona_name": "Grandma", "text": "<think>The user wants me to generate a warm first-person memory story from Grandma''s perspective, using only the provided reviewed memory. The theme is birthday and the nickname for the user is \"Child\". The retrieved memory is: - ID: 245e37d5-a7a3-48df-b6fa-9c53eb5b4134 - Title: Birthday wontons - Content: \"Grandma liked making wontons on birthdays.\" - Quote: \"making wontons on birthdays\" - Source: smoke:manual#1 I need to create a warm, first-person memory story from Grandma''s perspective about making wontons on birthdays. I should expand on this memory in a heartfelt way, while keeping it based only on this single memory. I''ll craft a cozy, loving story about the tradition of making wontons together on birthdays. Let me write a warm story that captures the love, tradition, and special moments of making birthday wontons together.</think> ```json { \"title\": \"Birthday Wontons with Grandma\", \"content\": \"Oh, Child, do you remember when it was your birthday? Every single year, I would wake up before the sun even thought about rising, and I would head straight to the kitchen to make wontons for you. It was our special little tradition, just you and me.\\n\\nI would lay out the wrappers so carefully on the wooden board, and I would mix the filling just the way you liked it. My hands moved slowly, folding each little wonton into its perfect shape, thinking about how lucky I was to have you in my life. The kitchen would fill up with that lovely smell, and I would hum little songs while I worked, happy as could be.\\n\\nWhen you came padding into the kitchen in your pajamas, still sleepy-eyed and looking for me, I would smile and pat the chair next to me. \\\"Come sit, my darling,\\\" I would say. \\\"Grandma is making your birthday wontons today.\\\" And your face would light up like the candles on your cake, even though the cake hadn''t come out yet!\\n\\nWe would boil them up nice and gentle, and I would watch you slurp them down, and my heart would feel so full it might just burst. Making wontons on birthdays, Child, that was my way of wrapping you up in love, one little dumpling at a time. Every fold was a wish for your happiness, every pinch was a prayer for your good health. And every birthday, I loved you more than the year before.\", \"source_memory_ids\": [\"245e37d5-a7a3-48df-b6fa-9c53eb5b4134\"], \"source_memories\": [\"Grandma liked making wontons on birthdays.\"] } ```", "voice_status": "default_tts", "default_tts_notice": "\u5f53\u524d\u4f7f\u7528\u7cfb\u7edf\u9ed8\u8ba4\u58f0\u97f3\uff0c\u4e0d\u662f TA \u7684\u771f\u5b9e\u58f0\u97f3\u3002\u4e0a\u4f20 TA \u7684\u6e05\u6670\u8bed\u97f3\u540e\uff0c\u53ef\u4ee5\u5c1d\u8bd5\u751f\u6210\u6a21\u62df\u97f3\u8272\u3002"}', '{"provider_type": "third_party", "provider_name": "minimax", "capability": "tts", "status": "succeeded", "input": {"persona_id": "f25d83e6-0885-4844-8603-490c00d54be4", "persona_name": "Grandma", "text": "<think>The user wants me to generate a warm first-person memory story from Grandma''s perspective, using only the provided reviewed memory. The theme is birthday and the nickname for the user is \"Child\". The retrieved memory is: - ID: 245e37d5-a7a3-48df-b6fa-9c53eb5b4134 - Title: Birthday wontons - Content: \"Grandma liked making wontons on birthdays.\" - Quote: \"making wontons on birthdays\" - Source: smoke:manual#1 I need to create a warm, first-person memory story from Grandma''s perspective about making wontons on birthdays. I should expand on this memory in a heartfelt way, while keeping it based only on this single memory. I''ll craft a cozy, loving story about the tradition of making wontons together on birthdays. Let me write a warm story that captures the love, tradition, and special moments of making birthday wontons together.</think> ```json { \"title\": \"Birthday Wontons with Grandma\", \"content\": \"Oh, Child, do you remember when it was your birthday? Every single year, I would wake up before the sun even thought about rising, and I would head straight to the kitchen to make wontons for you. It was our special little tradition, just you and me.\\n\\nI would lay out the wrappers so carefully on the wooden board, and I would mix the filling just the way you liked it. My hands moved slowly, folding each little wonton into its perfect shape, thinking about how lucky I was to have you in my life. The kitchen would fill up with that lovely smell, and I would hum little songs while I worked, happy as could be.\\n\\nWhen you came padding into the kitchen in your pajamas, still sleepy-eyed and looking for me, I would smile and pat the chair next to me. \\\"Come sit, my darling,\\\" I would say. \\\"Grandma is making your birthday wontons today.\\\" And your face would light up like the candles on your cake, even though the cake hadn''t come out yet!\\n\\nWe would boil them up nice and gentle, and I would watch you slurp them down, and my heart would feel so full it might just burst. Making wontons on birthdays, Child, that was my way of wrapping you up in love, one little dumpling at a time. Every fold was a wish for your happiness, every pinch was a prayer for your good health. And every birthday, I loved you more than the year before.\", \"source_memory_ids\": [\"245e37d5-a7a3-48df-b6fa-9c53eb5b4134\"], \"source_memories\": [\"Grandma liked making wontons on birthdays.\"] } ```", "voice_status": "default_tts", "default_tts_notice": "\u5f53\u524d\u4f7f\u7528\u7cfb\u7edf\u9ed8\u8ba4\u58f0\u97f3\uff0c\u4e0d\u662f TA \u7684\u771f\u5b9e\u58f0\u97f3\u3002\u4e0a\u4f20 TA \u7684\u6e05\u6670\u8bed\u97f3\u540e\uff0c\u53ef\u4ee5\u5c1d\u8bd5\u751f\u6210\u6a21\u62df\u97f3\u8272\u3002", "job_id": "0eb30