al:body#section2"}], "relationship": [{"title": "\u90d1\u6728\u751f\u4e0e\u963f\u5b37\u7684\u60c5\u611f\u5173\u7cfb\uff08\u79bb\u4e61\u65f6\uff09", "content": "\u79bb\u4e61\u65f6\u90d1\u6728\u751f\u4e0e\u963f\u5b37\u5f7c\u6b64\u60e6\u8bb0\uff0c\u4f46\u672a\u786e\u7acb\u5a5a\u59fb\u5173\u7cfb", "category": "relationship", "confidence_level": "high", "confidence_score": 0, "source_quote": "\u4e24\u4e2a\u4eba\u6ca1\u6709\u6b63\u5f0f\u8c08\u8fc7\u4ec0\u4e48\u8f70\u8f70\u70c8\u70c8\u7684\u604b\u7231\uff0c\u90a3\u4e2a\u5e74\u4ee3\u7684\u4eba\u4e5f\u8bf4\u4e0d\u51fa\u592a\u591a\u8089\u9ebb\u7684\u8bdd\u3002\u53ef\u662f\u4ed6\u4eec\u5fc3\u91cc\u90fd\u77e5\u9053\uff0c\u5bf9\u65b9\u662f\u81ea\u5df1\u60e6\u8bb0\u7684\u4eba\u3002", "source_location": "manual:body#section2"}], "preference": [], "habit": [], "expression_style": [], "shared_event": []}, "unclassified": [], "warnings": []}, "memory_extraction_provider_type": "third_party", "memory_extraction_provider_name": "dashscope", "provider_names": null, "profile_summary": "\u90d1\u6728\u751f\u662f\u7528\u6237\u5df2\u6545\u7684\u7237\u7237\uff0c\u4eab\u5e7486\u5c81\uff0c\u51fa\u751f\u4e8e\u798f\u5efa\u7701\u6cc9\u5dde\u664b\u6c5f\u53bf\u4e00\u4e2a\u9760\u6d77\u7684\u5c0f\u6751\u5e84\uff0c\u5bb6\u4e2d\u957f\u5b50\u30021952\u5e74\uff0818\u5c81\uff09\u56e0\u7956\u5c4b\u6f0f\u96e8\u3001\u592a\u516c\u75c5\u5f31\u3001\u5f1f\u59b9\u5e74\u5e7c\u3001\u5bb6\u8d1f\u7c73\u94fa\u503a\u52a1\uff0c\u4f5c\u4e3a\u957f\u5b50\u72ec\u81ea\u4ece\u53a6\u95e8\u4e58\u8239\u4e0b\u5357\u6d0b\u8c0b\u751f\u3002\u79bb\u4e61\u524d\u591c\uff0c\u672a\u5a5a\u59bb\u963f\u5b37\uff08\u6751\u91cc\u81ea\u5c0f\u76f8\u8bc6\u7684\u59d1\u5a18\uff09\u7f1d\u5236\u4e00\u4e2a\u5c0f\u5e03\u5305\u76f8\u8d60\uff0c\u5185\u88c5\u4e00\u5c0f\u64ae\u5bb6\u4e61\u571f\u3001\u4e00\u679a\u94dc\u94b1\u548c\u5199\u6709\"\u6728\u751f\uff0c\u5e73\u5b89\u56de\u6765\"\u7684\u7eb8\u6761\uff0c\u4ed6\u968f\u8eab\u643a\u5e26\u7ec8\u751f\u3002\u90d1\u6728\u751f\u5916\u8c8c\u4e3a\u6ee1\u5934\u94f6\u53d1\uff0c\u66fe\u8eab\u7a7f\u6d45\u7070\u8272\u957f\u8896\u886c\u886b\u548c\u5361\u5176\u8272\u957f\u88e4\uff0c\u53cc\u624b\u80cc\u5728\u8eab\u540e\uff0c\u9762\u5e26\u6e29\u548c\u6148\u7965\u7684\u7b11\u5bb9\uff0c\u5e38\u7acb\u4e8e\u53e4\u6734\u8001\u5b85\u6728\u95e8\u524d\u3002\u5728\u5357\u6d0b\u671f\u95f4\uff0c\u4ed6\u5148\u5728\u7801\u5934\u505a\u82e6\u529b\u625b\u7c73\u5378\u8d27\uff0c\u540e\u8f6c\u81f3\u6a61\u80f6\u56ed\u5272\u80f6\uff0c\u6bcf\u65e5\u51cc\u6668\u5165\u6797\uff0c\u5fcd\u53d7\u6e7f\u70ed\u3001\u868a\u866b\u3001\u624b\u4f24\u548c\u96e8\u6c34\u81f4\u65e0\u5de5\u94b1\u7684\u56f0\u5883\uff1b\u5b9e\u9645\u4ee5\u767d\u7ca5\u54b8\u83dc\u5ea6\u65e5\uff0c\u9ad8\u70e7\u6655\u5012\u540e\u9192\u6765\u7684\u7b2c\u4e00\u4ef6\u4e8b\u662f\u786e\u8ba4\u5bc4\u56de\u5bb6\u4fee\u5c4b\u9876\u7684\u94b1\u662f\u5426\u5b89\u5168\u3002\u4ed6\u6587\u5316\u6709\u9650\uff0c\u6bcf\u6708\u5de5\u94b1\u4e25\u683c\u5206\u4e3a\u4e09\u4efd\uff08\u8d61\u517b\u7236\u6bcd\u5f1f\u59b9\u3001\u6258\u4eba\u4ea4\u963f\u5b37\u3001\u81ea\u7559\u6700\u5c11\uff09\uff0c\u5176\u4fe1\u5ff5\u662f\"\u81ea\u5df1\u591a\u82e6\u4e00\u70b9\uff0c\u5bb6\u91cc\u4eba\u5c31\u80fd\u5c11\u82e6\u4e00\u70b9\"\u3002\u4ed6\u4e0e\u963f\u5b37\u4e4b\u95f4\u6700\u91cd\u8981\u7684\u8bb0\u5fc6\u662f\u4ece\u5357\u6d0b\u5bc4\u56de\u798f\u5efa\u7684\u5bb6\u4e66\uff0c\u5e38\u5728\u5de5\u68da\u7164\u6cb9\u706f\u4e0b\u71ac\u591c\u6162\u5199\uff0c\u7eb8\u8d35\u5b57\u5bc6\uff0c\u4ece\u4e0d\u76f4\u767d\u8bf4\"\u60f3\u4f60\"\uff0c\u800c\u4ee5\u666f\u5bc4\u60c5\uff1a\"\u7801\u5934\u98ce\u5927\uff0c\u60f3\u8d77\u6751\u53e3\u6995\u6811\"\"\u96e8\u591a\uff0c\u4f60\u5e26\u4f1e\"\"\u7b49\u6211\u56de\u6765\uff0c\u5c31\u628a\u65e5\u5b50\u8fc7\u7a33\"\u3002\u7b2c\u4e09\u5e74\u95fb\u963f\u5b37\u6216\u88ab\u63d0\u4eb2\uff0c\u4ed6\u5199\u4fe1\u5766\u8bda\uff1a\"\u53ea\u8981\u6211\u90d1\u6728\u751f\u6d3b\u7740\uff0c\u5c31\u4e0d\u4f1a\u8ba9\u4f60\u4e00\u4eba\u53d7\u59d4\u5c48\"\u3002\u963f\u5b37\u5b88\u8bfa\u672a\u5ac1\u3002\u90d1\u6728\u751f\u7ea61955\u5e74\u7626\u9ed1\u8fd4\u4e61\uff0c\u643a\u65e7\u85e4\u7bb1\uff08\u5185\u88c5\u5c0f\u91d1\u6212\u6307\u3001\u82b1\u5e03\u3001\u79ef\u84c4\uff09\uff0c\u4e0e\u963f\u5b37\u7b80\u529e\u5a5a\u5bb4\uff0c\u4e92\u6709\u7ecf\u5178\u5bf9\u8bdd\"\u4f60\u771f\u7684\u56de\u6765\u4e86\"\"\u6211\u7b54\u5e94\u8fc7\u4f60\u7684\"\uff0c\u6b64\u8bed\u6210\u5bb6\u65cf\u6838\u5fc3\u4fe1\u6761\u3002\u5a5a\u540e\u505a\u8fc7\u642c\u8fd0\u3001\u4fee\u8239\u3001\u6728\u5de5\u3001\u5c0f\u4e70\u5356\uff0c\u4e25\u6559\u5b50\u5973\u60dc\u7cae\u3001\u6212\u8c0e\u3001\u52e4\u5b66\uff0c\u665a\u5e74\u6c89\u9ed8\u5be1\u8a00\u3002\u65e5\u5e38\u4e60\u60ef\uff1a\u6668\u8d77\u70e7\u6c34\u626b\u9662\uff08\u7ec6\u81f4\u81f3\u5899\u89d2\u843d\u53f6\uff09\u3001\u7897\u4e0d\u5269\u7c73\uff08\u89c1\u5269\u996d\u5373\u81ea\u98df\uff09\u3001\u55dc\u6d53\u8336\u7528\u78d5\u635f\u65e7\u642a\u74f7\u676f\u591a\u5e74\u62d2\u6362\u65b0\u676f\u3001\u907f\u62cd\u7167\u5374\u5168\u5bb6\u5408\u5f71\u65f6\u6084\u6084\u6362\u8863\u7ad9\u540e\u6392\uff1b\u5bf9\u963f\u5b37\u4ee5\u884c\u52a8\u5173\u6000\uff08\u54b3\u5373\u4e70\u836f\u3001\u7076\u65c1\u6253\u4e0b\u624b\uff09\uff1b\u5bf9\u5b59\u8f88\u9690\u79d8\u6e29\u67d4\uff08\u85cf\u7cd6\u997c\u5e72\u4e8e\u67dc\uff0c\u5631\"\u522b\u8ba9\u7238\u5988\u77e5\u9053\u592a\u591a\"\uff09\u3002\u4ed6\u6700\u91cd\u5bb6\u4eba\u5e73\u5b89\u800c\u975e\u5bcc\u8d35\uff0c\u81ea\u8ba4\"\u5634\u7b28\"\u4e0d\u5584\u8868\u8fbe\uff0c\u5374\u4ee5\"\u7b54\u5e94\u8fc7\u7684\u4e8b\u6709\u6ca1\u6709\u505a\u5230\"\u5b9a\u4e49\u7231\u3002\u5bf9\u665a\u8f88\u79f0\u547c\u4eb2\u5207\u6734\u7d20\uff08\u5982\"\u5c0f\u56e1\"\"\u5b69\u5b50\"\"\u963f\u59b9\"\"\u4e56\u5b59\"\uff09\uff0c\u8bed\u8a00\u7f13\u6162\u5e26\u95fd\u5357\u957f\u8f88\u5f0f\u5173\u5fc3\uff0c\u65e0\u73b0\u4ee3\u7f51\u7edc\u8bed\u3002", "trust_score": 78, "trust_level": "usable", "trust_rationale": "\u8bc1\u636e\u8f83\u4e3a\u4e30\u5bcc\u4e14\u6765\u6e90\u4e00\u81f4\uff1a\u5171\u67096\u4e2a\u624b\u52a8\u6587\u672c\u6765\u6e90\u