53a6\u95e8\u4e58\u8239\u4e0b\u5357\u6d0b\uff1b\u79bb\u4e61\u524d\u591c\uff0c\u672a\u5a5a\u59bb\u963f\u5b37\u8d60\u4e88\u5185\u542b\u5bb6\u4e61\u571f\u3001\u94dc\u94b1\u4e0e\"\u6728\u751f\uff0c\u5e73\u5b89\u56de\u6765\"\u7eb8\u6761\u7684\u5c0f\u5e03\u5305\uff0c\u4ed6\u968f\u8eab\u643a\u5e26\u7ec8\u751f\u3002\u5728\u5357\u6d0b\u671f\u95f4\u5148\u505a\u7801\u5934\u82e6\u529b\u625b\u7c73\u5378\u8d27\uff0c\u540e\u8f6c\u6a61\u80f6\u56ed\u5272\u80f6\uff0c\u767d\u7ca5\u54b8\u83dc\u5ea6\u65e5\uff0c\u9ad8\u70e7\u6655\u5012\u540e\u4ecd\u5148\u786e\u8ba4\u5bc4\u5bb6\u4fee\u5c4b\u9876\u94b1\u6b3e\u5b89\u5168\uff1b\u6bcf\u6708\u5de5\u94b1\u4e25\u5206\u4e09\u4efd\u2014\u2014\u8d61\u517b\u7236\u6bcd\u5f1f\u59b9\u3001\u6258\u4eba\u4ea4\u963f\u5b37\u3001\u81ea\u7559\u6700\u5c11\uff0c\u79c9\u6301\"\u81ea\u5df1\u591a\u82e6\u4e00\u70b9\uff0c\u5bb6\u91cc\u4eba\u5c31\u80fd\u5c11\u82e6\u4e00\u70b9\"\u4e4b\u4fe1\u5ff5\u3002\u4e0e\u963f\u5b37\u4e4b\u95f4\u6700\u91cd\u8981\u7684\u7ebd\u5e26\u662f\u7164\u6cb9\u706f\u4e0b\u71ac\u591c\u6162\u5199\u7684\u5bb6\u4e66\uff1a\u7eb8\u8d35\u5b57\u5bc6\uff0c\u4ece\u4e0d\u76f4\u8bf4\"\u60f3\u4f60\"\uff0c\u800c\u4ee5\u666f\u5bc4\u60c5\u2014\u2014\"\u7801\u5934\u98ce\u5927\uff0c\u60f3\u8d77\u6751\u53e3\u6995\u6811\"\"\u96e8\u591a\uff0c\u4f60\u5e26\u4f1e\"\"\u7b49\u6211\u56de\u6765\"\uff1b\u7b2c\u4e09\u5e74\u95fb\u963f\u5b37\u6216\u88ab\u63d0\u4eb2\u65f6\u5766\u8bda\u5199\u4e0b\"\u53ea\u8981\u4f60\u613f\u7b49\uff0c\u6211\u5fc5\u4e0d\u8d1f\u2026\u2026\u53ea\u8981\u6211\u90d1\u6728\u751f\u6d3b\u7740\uff0c\u5c31\u4e0d\u4f1a\u8ba9\u4f60\u4e00\u4eba\u53d7\u59d4\u5c48\"\uff0c\u963f\u5b37\u5b88\u8bfa\u672a\u5ac1\u3002\u7ea61955\u5e74\u7626\u9ed1\u8fd4\u4e61\uff0c\u643a\u65e7\u85e4\u7bb1\uff08\u5185\u542b\u5c0f\u91d1\u6212\u6307\u3001\u82b1\u5e03\u3001\u79ef\u84c4\uff09\u4e0e\u963f\u5b37\u7b80\u529e\u5a5a\u5bb4\uff0c\u7559\u4e0b\"\u4f60\u771f\u7684\u56de\u6765\u4e86\"\"\u6211\u7b54\u5e94\u8fc7\u4f60\u7684\"\u2014\u2014\u6b64\u8bed\u6210\u4e3a\u5bb6\u65cf\u6838\u5fc3