u6210\u7684\u5fc3\u613f\n\u5982\u679c\u6211\u8fd8\u80fd\u548c\u7237\u7237\u8bf4\u8bdd\uff0c\u6211\u5e0c\u671b\u4e0d\u53ea\u662f\u542c\u4ed6\u8bf4\u201c\u5b69\u5b50\uff0c\u8981\u597d\u597d\u7684\u201d\u3002\u6211\u66f4\u5e0c\u671b\u80fd\u628a\u90a3\u4e9b\u6765\u4e0d\u53ca\u95ee\u7684\u95ee\u9898\uff0c\u4e00\u53e5\u4e00\u53e5\u95ee\u5b8c\u3002\n\u6211\u60f3\u95ee\u4ed6\uff1a\n\u201c\u7237...\n- manual: \u516b\u3001\u6211\u5bf9\u5df2\u6545\u7237\u7237\u7684\u9057\u61be\n\u6211\u5bf9\u7237\u7237\u6700\u5927\u7684\u9057\u61be\uff0c\u662f\u6211\u61c2\u5f97\u592a\u665a\u3002\n\u5c0f\u65f6\u5019\uff0c\u6211\u4e00\u76f4\u4ee5\u4e3a\u7237\u7237\u53ea\u662f\u4e00\u4e2a\u666e\u901a\u7684\u3001\u6c89\u9ed8\u7684\u3001\u8282\u4fed\u7684\u8001\u4eba\u3002\u6211\u4e0d\u61c2\u4ed6\u4e3a\u4ec0\u4e48\u603b\u662f\u820d\u4e0d\u5f97\u5f00\u706f\uff0c\u4e0d\u61c2\u4ed6\u4e3a\u4ec0\u4e48...\n- manual: \u4e03\u3001\u5173\u4e8e\u7237\u7237\u5177\u4f53\u7684\u8bb0\u5fc6\n\u7b2c\u4e00\uff0c\u4ed6\u8bb0\u5f97\u81ea\u5df1\u5e74\u8f7b\u65f6\u4e0b\u5357\u6d0b\u7684\u7ecf\u5386\u3002\u4ed6\u8bb0\u5f97\u53a6\u95e8\u7801\u5934\u7684\u8239\uff0c\u8bb0\u5f97\u79bb\u5f00\u5bb6\u4e61\u90a3\u5929\u7684\u6d77\u98ce\uff0c\u8bb0\u5f97\u963f\u5b37\u7ed9\u4ed6\u7684\u5e03\u5305\uff0c\u8bb0\u5f97\u6a61\u80f6\u6797\u91cc\u7684\u96e8\uff0c\u8bb0\u5f97\u5de5\u68da\u91cc\u7684\u7164\u6cb9\u706f...\n- manual: \u516d\u3001\u7237\u7237\u7684\u5177\u4f53\u751f\u6d3b\u4e60\u60ef\u548c\u8bb0\u5fc6\u7ec6\u8282\n\u7237\u7237\u8d77\u5e8a\u5f88\u65e9\u3002\u54ea\u6015\u665a\u5e74\u4e0d\u7528\u518d\u505a\u5de5\uff0c\u4ed6\u4e5f\u4e60\u60ef\u5929\u521a\u4eae\u5c31\u9192\u3002\u4ed6\u4f1a\u5148\u70e7\u6c34\uff0c\u7136\u540e\u628a\u9662\u5b50\u626b\u4e00\u904d\u3002\u626b\u5730\u7684\u65f6\u5019\u52a8\u4f5c\u5f88\u6162\uff0c\u4f46\u626b\u5f97\u5f88\u5e72\u51c0\uff0c\u8fde\u5899\u89d2\u7684...\n- manual: \u4e94\u3001\u56de\u4e61\u4e4b\u540e\uff1a\u7237\u7237\u5982\u4f55\u6491\u8d77\u4e00\u4e2a\u5bb6\n\u7237\u7237\u56de\u4e61\u540e\uff0c\u548c\u963f\u5b37\u7ed3\u4e86\u5a5a\u3002\u4ed6\u4eec\u6ca1\u6709\u76db\u5927\u7684\u5a5a\u793c\uff0c\u4e5f\u6ca1\u6709\u6f02\u4eae\u7684\u5a5a\u7eb1\u7167\u3002\u90a3\u65f6\u5bb6\u91cc\u8fd8\u662f\u7a77\uff0c\u5a5a\u5bb4\u53ea\u662f\u6446\u4e86\u51e0\u684c\u7b80\u5355\u7684\u996d\u83dc\u3002\u7237\u7237\u7ed9\u963f\u5b37\u6234\u4e0a\u90a3...\n- manual: \u4e8c\u3001\u7237\u7237\u4e0b\u5357\u6d0b\u7684\u80cc\u666f\n\u7237\u7237 18 \u5c81\u90a3\u5e74\uff0c\u4e5f\u5c31\u662f 1952 \u5e74\uff0c\u51b3\u5b9a\u8ddf\u7740\u540c\u4e61\u4e0b\u5357\u6d0b\u3002\u90a3\u4e00\u5e74\u5bb6\u91cc\u7684\u7956\u5c4b\u6f0f\u96e8\uff0c\u592a\u516c\u8eab\u4f53\u4e0d\u597d\uff0c\u5f1f\u59b9\u8fd8\u5c0f\uff0c\u5bb6\u91cc\u6b20\u7740\u7c73\u94fa\u7684\u94b1\u3002\u7237\u7237\u4f5c\u4e3a\u5bb6\u91cc...\n- manual: \u56db\u3001\u7237\u7237\u548c\u963f\u5b37\u7684\u5bb6\u4e66\u6545\u4e8b\n\u7237\u7237\u548c\u963f\u5b37\u4e4b\u95f4\u6700\u91cd\u8981\u7684\u8bb0\u5fc6\uff0c\u662f\u90a3\u4e9b\u4ece\u5357\u6d0b\u5bc4\u56de\u798f\u5efa\u7684\u4fe1\u3002\n\u7237\u7237\u6587\u5316\u4e0d\u9ad8\uff0c\u5c0f\u65f6\u5019\u6ca1\u8bfb\u8fc7\u51e0\u5e74\u4e66\uff0c\u5f88\u591a\u5b57\u4e0d\u4f1a\u5199\u3002\u4ed6\u5199\u4fe1\u5f88\u6162\uff0c\u6709\u65f6\u4e00\u5c01\u4fe1\u8981\u5199\u4e09\u56db...\n- manual: \u4e09\u3001\u5357\u6d0b\u5c81\u6708\uff1a\u4ed6\u5982\u4f55\u628a\u82e6\u65e5\u5b50\u71ac\u6210\u5bb6\u4eba\u7684\u751f\u8def\n\u7237\u7237\u521a\u5230\u5357\u6d0b\u65f6\uff0c\u5148\u5728\u7801\u5934\u505a\u82e6\u529b\u3002\u7801\u5934\u7684\u6d3b\u5f88\u91cd\uff0c\u8981\u625b\u7c73\u888b\u3001\u642c\u6728\u7bb1\u3001\u5378\u8d27\u3002\u4e00\u888b\u7c73\u538b\u5728\u80a9\u4e0a\uff0c\u8d70\u51e0\u6b65\u80a9\u8180\u5c31\u50cf\u88ab\u5200\u5272\u4e00\u6837\u75bc\u3002\u90a3...\n- manual: \u4e09\u3001\u5357\u6d0b\u5c81\u6708\uff1a\u4ed6\u5982\u4f55\u628a\u82e6\u65e5\u5b50\u71ac\u6210\u5bb6\u4eba\u7684\u751f\u8def\n\u7237\u7237\u521a\u5230\u5357\u6d0b\u65f6\uff0c\u5148\u5728\u7801\u5934\u505a\u82e6\u529