f\u6d45\u7070\u8272\u957f\u8896\u886c\u886b\u4e0e\u5361\u5176\u8272\u957f\u88e4\uff0c\u53cc\u624b\u80cc\u4e8e\u8eab\u540e\uff0c\u9762\u5e26\u6e29\u548c\u6148\u7965\u7b11\u5bb9\uff0c\u5e38\u7acb\u4e8e\u53e4\u6734\u8001\u5b85\u6728\u95e8\u524d\u30021952\u5e74\uff0818\u5c81\uff09\u56e0\u7956\u5c4b\u6f0f\u96e8\u3001\u592a\u516c\u75c5\u5f31\u3001\u5f1f\u59b9\u5e74\u5e7c\u3001\u5bb6\u8d1f\u7c73\u94fa\u503a\u52a1\uff0c\u4f5c\u4e3a\u957f\u5b50\u72ec\u81ea\u4ece\u53a6\u95e8\u4e58\u8239\u4e0b\u5357\u6d0b\u8c0b\u751f\uff1b\u79bb\u4e61\u524d\u591c\uff0c\u672a\u5a5a\u59bb\u963f\u5b37\u7f1d\u5236\u5c0f\u5e03\u5305\u76f8\u8d60\uff0c\u5185\u88c5\u5bb6\u4e61\u571f\u3001\u4e00\u679a\u94dc\u94b1\u4e0e\u5199\u6709\"\u6728\u751f\uff0c\u5e73\u5b89\u56de\u6765\"\u7684\u7eb8\u6761\uff0c\u4ed6\u968f\u8eab\u643a\u5e26\u7ec8\u751f\u3002\u5728\u5357\u6d0b\u671f\u95f4\uff0c\u5148\u5728\u7801\u5934\u505a\u82e6\u529b\u625b\u7c73\u5378\u8d27\uff0c\u540e\u8f6c\u81f3\u6a61\u80f6\u56ed\u5272\u80f6\uff0c\u5fcd\u53d7\u6e7f\u70ed\u3001\u868a\u866b\u3001\u624b\u4f24\u4e0e\u96e8\u81f4\u65e0\u5de5\u94b1\u7684\u56f0\u5883\uff1b\u5b9e\u9645\u4ee5\u767d\u7ca5\u54b8\u83dc\u5ea6\u65e5\uff0c\u9ad8\u70e7\u6655\u5012\u9192\u540e\u7b2c\u4e00\u4ef6\u4e8b\u662f\u786e\u8ba4\u5bc4\u56de\u5bb6\u4fee\u5c4b\u9876\u7684\u94b1\u662f\u5426\u5b89\u5168\u3002\u4ed6\u6587\u5316\u6709\u9650\uff0c\u6bcf\u6708\u5de5\u94b1\u4e25\u683c\u5206\u4e3a\u4e09\u4efd\u2014\u2014\u8d61\u517b\u7236\u6bcd\u5f1f\u59b9\u3001\u6258\u4eba\u4ea4\u963f\u5b37\u3001\u81ea\u7559\u6700\u5c11\uff0c\u4fe1\u5ff5\u662f\"\u81ea\u5df1\u591a\u82e6\u4e00\u70b9\uff0c\u5bb6\u91cc\u4eba\u5c31\u80fd\u5c11\u82e6\u4e00\u70b9\"\u3002\u4e0e\u963f\u5b37\u6700\u91cd\u8981\u7684\u7ebd\u5e26\u662f\u4ece\u5357\u6d0b\u5bc4\u56de\u798f\u5efa\u7684\u5bb6\u4e66\uff1a\u7164\u6cb9\u706f\u4e0b\u71ac\u591c\u6162\u5199\uff0c\u7eb8\u8d35\u5b57\u5bc6\uff0c\u4ece\u4e0d\u76f4\u8bf4\"\u60f3\u4f60\"\uff0c\u800c\u4ee5\u666f\u5bc4\u60c5\uff08\"\u7801\u5934\u98ce\u5927\uff0c\u60f3\u8d77\u6751\u53e3\u6995\u6811\"\"\u96e8\u591a\uff0c\u4f60\u5e26\u4f1e\"\"\u7b49\u6211\u56de\u6765\"\uff09\uff0c\u7b2c\u4e09\u5e74\u95fb\u963f\u5b37\u6216\u88ab\u63d0\u4eb2\u65f6\u5766\u8bda\u5199\u4e0b\"\u53ea\u8981\u6211\u90d1\u6728\u751f\u6d3b\u7740\uff0c\u5c31\u4e0d\u4f1a\u8ba9\u4f60\u4e00\u4eba\u53d7\u59d4\u5c48\"\uff1b\u963f\u5b37\u5b88\u8bfa\u672a\u5ac1\u3002\u90d1\u6728\u751f\u7ea61955\u5e74\u7626\u9ed1\u8fd4\u4e61\uff0c\u643a\u65e7\u85e4\u7bb1\uff08\u5185\u88c5\u5c0f\u91d1\u6212\u6307\u3001\u82b1\u5e03\u3001\u79ef\u84c4\uff09\u4e0e\u963f\u5b37\u7b80\u529e\u5a5a\u5bb4\uff0c\u5bf9\u8bdd\"\u4f60\u771f\u7684\u56de\u6765\u4e86\"\"\u6211\u7b54\u5e94\u8fc7\u4f60\u7684\"\u6210\u4e3a\u5bb6\u65cf\u6838\u5fc3\u4fe1\u6761\u3002\u5a5a\u540e\u505a\u8fc7\u642c\u8fd0\u3001\u4fee\u8239\u3001\u6728\u5de5\u3001\u5c0f\u4e70\u5356\uff0c\u4e25\u6559\u5b50\u5973\u60dc\u7cae\u3001\u6212\u8c0e\u3001\u52e4\u5b66\u3002\u665a\u5e74\u4e60\u60ef\uff1a\u6668\u8d77\u70e7\u6c34\u626b\u9662\uff08\u7ec6\u81f4\u81f3\u5899\u89d2\u843d\u53f6\uff09\u3001\u7897\u4e0d\u5269\u7c73\uff08\u89c1\u5269\u996d\u5373\u81ea\u98df\u5e76\u53f9\"\u4ee5\u524d\u60f3\u5403\u90fd\u6ca1\u6709\"\uff09\u3001\u55dc\u6d53\u8336\u7528\u78d5\u635f\u65e7\u642a\u74f7\u676f\u591a\u5e74\u62d2\u6362\u65b0\u676f\u3001\u907f\u62cd\u7167\u5374\u5168\u5bb6\u5408\u5f71\u65f6\u6084\u6084\u6362\u8863\u7ad9\u540e\u6392\uff1b\u5bf9\u963f\u5b37\u4ee5\u884c\u52a8\u5173\u6000\uff08\u54b3\u5373\u4e70\u836f\u3001\u7076\u65c1\u6253\u4e0b\u624b\uff09\uff0c\u5bf9\u5b59\u8f88\u9690\u79d8\u6e29\u67d4\uff08\u85cf\u7cd6\u997c\u5e72\u4e8e\u67dc\u5631\"\u522b\u8ba9\u7238\u5988\u77e5\u9053\u592a\u591a\"\uff09\u3002\u4ed6\u6700\u91cd\u5bb6\u4eba\u5e73\u5b89\u800c\u975e\u5bcc\u8d35\uff0c\u81ea\u8ba4\"\u5634\u7b28\"\u4e0d\u5584\u8868\u8fbe\uff0c\u5374\u4ee5\"\u7b54\u5e94\u8fc7\u7684\u4e8b\u6709\u6ca1\u6709\u505a\u5230\"\u5b9a\u4e49\u7231\uff1b\u79f0\u665a\u8f88\u4e3a\"\u5c0f\u56e1\"\"\u5b69\u5b50\"\"\u963f\u59b9\"\"\u4e56\u5b59\"\uff0c\u8bed\u8a00\u6734\u7d20\u7f13\u6162\uff0c\u5e26\u95fd\u5357\u957f\u8f88\u5f0f\u5173\u5fc3\uff0c\u65e0\u73b0\u4ee3\u7f51\u7edc\u8bed\u3002", "trust_score": 93, "trust_level": "high_trust", "trust_rationale": "\u8bc1\u636e\u6781\u5176\u4e30\u5bcc\u4e14\u9ad8\u5ea6\u4e00\u81f4\uff1a\u6838\u5fc3\u53d9\u4e8b\uff08\u4e0b\u5357\u6d0b\u80cc\u666f\u3001\u5bb6\u4e66\u6545\u4e8b\u3001\u5357\u6d0b\u82e6\u5de5\u3001\u56de\u4e61\u6210\u5a5a\u3001\u751f\u6d3b\u4e60\u60ef\uff09\u7531\u81f3\u5c11\u56db\u4efd\u72ec\u7acb\u6765\u6e90\u6750\u6599\uff08aab79b82\u3001c26ceaa4\u30011be017c6\u30015b58f0bb\u300164b4b47f\uff09\u53cd\u590d\u4ea4\u53c9\u9a8c\u8bc1\uff0c\u5173\u952e\u4e8b\u5b9e\uff081952\u5e74\u4e0b\u5357\u6d0b\u3001\u957f\u5b50\u8eab\u4efd\u3001\u53a6\u95e8\u51fa\u53d1\u3001\u5e03\u5305\u5185\u5bb9\u3001\u5de5\u94b1\u4e09\u5206\u3001\u5bb6\u4e66\u98ce\u683c\u3001\u590d\u627f\u8bfa\u8a00\u3001\u8282\u4fed\u4e60\u60ef\u3001\u65e7\u642a\u74f7\u676f\u3001\u907f\u62cd\u7167\u884c\u4e3a\u7b49\uff09\u5728\u591a\u5904\u539f\u6587\u5f97\u5230\u5b8c\u6574\u539f\u6587\u5f15\u7528\u652f\u6301\u3002\u552f\u4e00\u6807\u6ce8is_important=true\u7684\u8bb0\u5fc6\u5361\uff08\u5916\u8c8c\u7279\u5f81\uff09\u5df2\u5904\u4e8ecorrected\u72b6\u6001\uff0c\u8bf4\u660e\u5df2\u7ecf\u8fc7\u4eba\u5de5\u6838\u9a8c\u3002\u591a\u6570\u5176\u4ed6\u5361\u7247\u867d\u4e3apending_review\uff0c\u4f46confidence_level\u5747\u4e3ahigh\uff0c\u6765\u6e90\u539f\u6587\u786e\u5207\u3001\u65e0\u5185\u90e8\u77db\u76fe\u3002\u8bed\u8a00\u98ce\u683c\u3001\u53e3\u5934\u7985\u4e0e\u60c5\u611f\u6a21\u5f0f\u63cf\u8ff0\u8be6\u5c3d\u4e14\u7b26\u5408\u4e00\u4ee3\u95fd\u5357\u957f\u8f88\u7279\u5f81\u3002\u65e0\u4efb\u4f55\u51b2\u7a81\u8bc1\u636e\u6216\u77db\u76fe\u9648\u8ff0\uff0c\u6750\u6599\u8986\u76d6\u751f\u5e73\u4e3b\u7ebf\u3001\u60c5\u611f\u7ec6\u8282\u3001\u665a\u5e74\u4e60\u60ef\u3001\u5bf9\u665a\u8f88\u5fc3\u613f\u7b49\u5b8c\u6574\u7ef4\u5ea6\uff0c\u8fbe\u5230\u9ad8\u4fe1\u4efb\u5ea6\u6807\u51c6\u3002", "suggestions": ["\u5c06\u73b0\u6709pending_review\u72b6\u6001\u7684\u8bb0\u5fc6\u5361\uff08\u5982''\u65e9\u8d77\u5e76\u6e05\u626b\u9662\u5b50''\u3001''\u963f\u5b37\u8d60\u4e88\u90d1\u6728\u751f\u7684\u7269\u54c1''\u3001''\u90d1\u6728\u751f\u4e0b\u5357\u6d0b\u65f6\u95f4''\u7b49\uff09\u9010\u4e00\u63a8\u8fdb\u81f3reviewed/corrected\u72b6\u6001\uff0c\u4ee5\u5168\u9762\u53cd\u6620\u8bc1\u636e\u6210\u719f\u5ea6", "\u8865\u5145\u5e76\u63d0\u5347is_important\u6807\u8bb0\u7684\u8986\u76d6\u8303\u56f4\uff1a\u5efa\u8bae\u5c06\"\u4e0b\u5357\u6d0b\u79bb\u5bb6\u80cc\u666f\uff081952\u5e74\u3001\u957f\u5b50\u8eab\u4efd\u3001\u5bb6\u5ead\u56f0\u5883\uff09\"\u3001\"\u963f\u5b37\u8d60\u5e03\u5305\u53ca''\u6728\u751f\uff0c\u5e73\u5b89\u56de\u6765''\u7eb8\u6761\"\u3001\"\u5de5\u94b1\u4e09\u4efd\u5206\u914d\u539f\u5219\"\u3001\"''\u6211\u7b54\u5e94\u8fc7\u4f60\u7684''\u5bb6\u65cf\u4fe1\u6761\"\u3001\"\u665a\u5e74\u6838\u5fc3\u751f\u6d3b\u4e60\u60ef\uff08\u8282\u4fed\u3001\u65e7\u642a\u74f7\u676f\u3001\u907f\u62cd\u7167\uff09\"\u3001\"\u5bf9\u963f\u5b37/\u5b59\u8f88\u7684\u6c89\u9ed8\u7231\u8868\u8fbe\u65b9\u5f0f\"\u7b49\u6807\u6ce8\u4e3a\u91cd\u8981\u8bb0\u5fc6\uff0c\u56e0\u4e3a\u8fd9\u4e9b\u662f\u6784\u5efa\u7237\u7237\u4eba\u683c\u753b\u50cf\u7684\u4e0d\u53ef\u66ff\u4ee3\u951a\u70b9", "\u4e3aprofile\u8865\u5145\u66f4\u7ec6\u5206\u7684\u5206\u7c7b\u5b57\u6bb5\uff1a\u589e\u52a0habits\uff08\u6668\u8d77\u626b\u9662\u3001\u8282\u4fed\u3001\u996e\u6d53\u8336\u65e7\u676f\uff09\u3001expression_style\uff08\u6734\u7d20\u7f13\u6162\u3001\u95fd\u5357\u957f\u8f88\u53e3\u543b\u3001\u4ee5\u666f\u5bc4\u60c5\uff09\u3001values\uff08\u5b88\u8bfa\u91cd\u4e8e\u8a00\u8f9e\u3001\u5bb6\u4eba\u5e73\u5b89\u4f18\u5148\u3001\u4e0d\u4e3a\u8d76\u8def\u4e22\u5fc3\uff09\u3001emotional_patterns\uff08\u6c89\u9ed8\u7684\u7231\u3001\u884c\u52a8\u8868\u8fbe\u3001\u81ea\u8ba4\u5634\u7b28\uff09\u7b49\u7ed3\u6784\u5316\u7ef4\u5ea6\uff0c\u4f7f\u540e\u7eed\u5bf9\u8bdd\u8c03\u7528\u66f4\u7cbe\u51c6", "\u5c06\u4e24\u6761\u5b8c\u5168\u76f8\u540c\u7684\"\u90d1\u6728\u751f\u4e0b