INSERT INTO public.audit_logs VALUES ('6b50cd28-3bdf-4826-a7e5-4f3cb451f7c9', 'fa52a51d-dc18-43df-aa63-df4d02d8dff2', 'e19a2da5-b6ba-40bb-a2fb-3631484a99a5', 'memory', '84c2929c-f1e6-4d1c-b4cb-e51f286e32e2', '资料解析生成记忆卡片', 'null', '{"id": "84c2929c-f1e6-4d1c-b4cb-e51f286e32e2", "persona_id": "e19a2da5-b6ba-40bb-a2fb-3631484a99a5", "title": "\u5218\u52e4\u94ed\u5b9e\u4e60\u7ecf\u5386\uff1a\u5fb7\u56fd\u5927\u9646", "content": "\u5fb7\u56fd\u5927\u9646\uff08Continental\uff09\u4fe1\u606f\u90e8\u4f9b\u5e94\u94fe\u4e0e\u6570\u636e\u5206\u6790\u7ec4\u5b9e\u4e60\u751f\uff0c\u5c97\u4f4d\u4e3a\u4ea7\u54c1&\u6570\u636e\u5206\u6790\uff0c\u5b9e\u4e60\u65f6\u95f4\u4e3a2023\u5e7410\u6708\u81f32024\u5e742\u6708\uff1b\u5de5\u4f5c\u5185\u5bb9\u5305\u62ec\u65b0\u5de5\u5382HR\u7cfb\u7edf\u9879\u76ee\u9700\u6c42\u5206\u6790\u4e0e\u89e3\u51b3\u65b9\u6848\u8bbe\u8ba1\uff08\u542bAxure\u539f\u578b\uff09\u3001LMS\u8d27\u8fd0\u6307\u6807\u4f53\u7cfb\u5b8c\u5584\u4e0eTableau\u770b\u677f\u642d\u5efa\u3001FineBI\u6d77\u8fd0\u8ba2\u5355\u8f68\u8ff9\u53ef\u89c6\u5316\u5e73\u53f0\u5f00\u53d1\u3001\u914d\u9001\u5546KPI\u8ddf\u8e2a\u53cd\u9988\u673a\u5236\u5efa\u8bbe\u4e0e\u53cc\u5468\u590d\u76d8\u4f1a\u4e3b\u6301\u3002", "category": "unknown", "confidence_level": "high", "confidence_score": 0, "source_material_id": "8c059e8d-cd10-4d84-b6aa-33330fefb259", "parsed_chunk_id": "2edbee1c-b144-4073-b4ae-9c75a6337c52", "source_type": "image", "source_quote": "\u5fb7\u56fd\u5927\u9646 (\u5916\u4f01) - \u4fe1\u606f\u90e8 \u4f9b\u5e94\u94fe\u4e0e\u6570\u636e\u5206\u6790\u7ec4 \u5b9e\u4e60\u751f-\u4ea7\u54c1&\u6570\u636e\u5206\u6790 2023\u5e7410\u6708-2024\u5e742\u6708 \u2022 \u4ea7\u54c1\u7ecf\u7406\uff1a\u534f\u52a9\u9879\u76ee\u7ecf\u7406\u8d1f\u8d23\u65b0\u5de5\u5382 HR \u7cfb\u7edf\u9879\u76ee\u2026\u2026\u72ec\u7acb\u5b8c\u6210\u7cfb\u7edf\u89e3\u51b3\u65b9\u6848\u8bbe\u8ba1\uff08\u542bAxure\u7ed8\u5236\u7b80\u5355\u539f\u578b\u56fe\uff09\u2026\u2026\u2022 \u6570\u636e\u5206\u6790\uff1a\u4e3a\u6539\u5584