INSERT INTO public.memory_cards VALUES ('648151ea-08ee-4ba2-b9d0-93c2136c04e3', 'c3648756-e231-4be5-b077-147ff87a0bde', 'Alice', 'A young girl who is sitting by her sister on a riverbank, feeling tired and bored; she is sleepy and mentally sluggish due to the hot day, and is contemplating whether to make a daisy-chain; she observes a White Rabbit with pink eyes who speaks aloud and checks a watch.', 'unknown', 'high', 0, 'e68da906-5312-46b7-aecd-ea887442c078', '13972bee-6be6-46e2-b510-da8847c4bd4d', 'text', 'Alice was beginning to get very tired of sitting by her sister on the bank, and of having nothing to do... So she was considering in her own mind (as well as she could, for the hot day made her feel very sleepy and stupid), whether the pleasure of making a daisy-chain would be worth the trouble of getting up and picking the daisies, when suddenly a White Rabbit with pink eyes ran close by her.', 'text:alice-derived.pdf, page 1', '{"provider_name": "dashscope", "provider_type": "third_party", "parsed_summary": "Introduction of Alice, her boredom by the riverbank, her sister''s unillustrated book, her idle thoughts about daisies, and the sudden appearance of a talking White Rabbit checking a watch.", "parsed_provider_name": "dashscope"}', 'pending_review', NULL, 'system', '2026-07-04 07:57:27.836904', '2026-07-04 07:57:27.836904', NULL, NULL, NULL, NULL, NULL, NULL, false);
INSERT INTO public.memory_cards VALUES ('cdca8891-8cfb-4cf7-8bdd-20099eab2364', 'c3648756-e231-4be5-b077-147ff87a0bde', 'White Rabbit', 'A white rabbit with pink eyes who runs close by Alice, speaks aloud saying ''Oh dear! Oh dear! I shall be late!'', and later is described as taking a watch.', 'unknown', 'high', 0, 'e68da906-5312-46b7-aecd-ea887442c078', '13972bee-6be6-46e2-b510-da8847c4bd4d', 'text', 'a White Rabbit with pink eyes ran close by her... it occurred to her that she ought to have wondered at this... but when the Rabbit actually _took a watch', 'text:alice-derived.pdf, page 1', '{"provider_name": "dashscope", "provider_type": "third_party", "parsed_summary": "Introduction of Alice, her boredom by the riverbank, her sister''s unillustrated book, her idle thoughts about daisies, and the sudden appearance of a talking White Rabbit checking a watch.", "parsed_provider_name": "dashscope"}', 'pending_review', NULL, 'system', '2026-07-04 07:57:27.836904', '2026-07-04 07:57:27.836904', NULL, NULL, NULL, NULL, NULL, NULL, false);
INSERT INTO public.memory_cards VALUES ('f6288ed9-6f24-4755-a693-fd17f2f65e23', 'c3648756-e231-4be5-b077-147ff87a0bde', 'Alice', 'A young girl who feels bored while sitting by her sister on the bank; she is sleepy and stupid due to the hot day; she notices a White Rabbit with pink eyes, becomes curious upon seeing it take a watch from its waistcoat-pocket, and impulsively follows it down a rabbit-hole.', 'unknown', 'high', 0, 'f9c1c4ea-451e-4c5b-8424-048d8fec87d8', 'a69416d0-e08c-426e-8cbf-391453d69ee8', 'text', 'Alice was beginning to get very tired of sitting by her sister on the bank, and of having nothing to do... So she was considering in her own mind (as well as she could, for the hot day made her feel very sleepy and stupid)... when suddenly a White Rabbit with pink eyes ran close by her... Alice started to her feet... she ran across the field after it... down went Alice after it, never once considering how in the world she was to get out again.', 'text:alice-memory-trimmed.txt', '{"provider_name": "dashscope", "provider_type": "third_party", "parsed_summary": "Alice, bored while sitting with her sister, notices a White Rabbit with pink eyes who speaks and checks a watch from its waistcoat-pocket; intrigued, she follows it down a rabbit-hole and begins falling down a deep well.", "parsed_provider_name": "dashscope"}', 'pending_review', NULL, 'system', '2026-07-04 07:56:36.03644', '2026-07-04 07:56:36.03644', NULL, NULL, NULL, NULL, NULL, NULL, false);
INSERT INTO public.memory_cards VALUES ('da1f60fc-2533-403f-8f5c-0f35161bc9e0', 'c3648756-e231-4be5-b077-147ff87a0bde', 'White Rabbit', 'A rabbit with pink eyes who wears a waistcoat with a pocket, carries a watch, speaks aloud saying ''Oh dear! Oh dear! I shall be late!'', and runs hurriedly before disappearing down a large rabbit-hole under the hedge.', 'unknown', 'high', 0, 'f9c1c4ea-451e-4c5b-8424-048d8fec87d8', 'a69416d0-e08c-426e-8cbf-391453d69ee8', 'text', 'a White Rabbit with pink eyes ran close by her... the Rabbit say to itself, ''Oh dear! Oh dear! I shall be late!''... the Rabbit actually _took a watch out of its waistcoat-pocket_, and looked at it, and then hurried on... it pop down a large rabbit-hole under the hedge.', 'text:alice-memory-trimmed.txt', '{"provider_name": "dashscope", "provider_type": "third_party", "parsed_summary": "Alice, bored while sitting with her sister, notices a White Rabbit with pink eyes who speaks and checks a watch from its waistcoat-pocket; intrigued, she follows it down a rabbit-hole and begins falling down a deep well.", "parsed_provider_name": "dashscope"}', 'pending_review', NULL, 'system', '2026-07-04 07:56:36.03644', '2026-07-04 07:56:36.03644', NULL, NULL, NULL, NULL, NULL, NULL, false);
INSERT INTO public.memory_cards VALUES ('614e441c-e218-4a7b-a1b9-8fba3049c208', 'c3648756-e231-4be5-b077-147ff87a0bde', 'Alice', 'A young girl who is sitting by her sister on the bank, feeling tired and sleepy on a hot day; she is contemplative, questioning the value of books without pictures or conversations, and considers making a daisy-chain; she observes a White Rabbit with pink eyes who speaks and carries a watch.', 'unknown', 'high', 0, '57998fba-7d83-47ff-b60d-1281af4ff4fe', '4f265604-36b7-47c5-a266-aa871a910915', 'text', 'Alice was beginning to get very tired of sitting by her sister on the bank, and of having nothing to do: once or twice she had peeped into the book her sister was reading, but it had no pictures or conversations in it, “and what is the use of a book,” thought Alice, “without pictures or conversations?” So she was considering in her own mind (as well as she could, for the hot day made her feel very sleepy and stupid), whether the pleasure of making a daisy-chain would be worth the trouble of getting up and picking the daisies, when suddenly a White Rabbit with pink eyes ran close by her.', 'text:alice-derived.docx', '{"provider_name": "dashscope", "provider_type": "third_party", "parsed_summary": "Alice, bored while sitting with her sister by a riverbank, notices a talking White Rabbit with pink eyes who checks a watch and worries about being late \u2014 an event that initially seems ordinary to her despite its strangeness.", "parsed_provider_name": "dashscope"}', 'pending_review', NULL, 'system', '2026-07-04 07:57:44.90988', '2026-07-04 07:57:44.90988', NULL, NULL, NULL, NULL, NULL, NULL, false);
INSERT INTO public.memory_cards VALUES ('6e07dd00-2cd2-4fcc-a5cf-3bc83d10a84c', 'c3648756-e231-4be5-b077-147ff87a0bde', 'White Rabbit', 'A rabbit with pink eyes who runs close by Alice, speaks aloud to itself saying ''Oh dear! Oh dear! I shall be late!'', and is described as actually taking a watch.', 'unknown', 'high', 0, '57998fba-7d83-47ff-b60d-1281af4ff4fe', '4f265604-36b7-47c5-a266-aa871a910915', 'text', 'when suddenly a White Rabbit with pink eyes ran close by her. There was nothing so very remarkable in that; nor did Alice think it so very much out of the way to hear the Rabbit say to itself, “Oh dear! Oh dear! I shall be late!” ... but when the Rabbit actually took a watch...', 'text:alice-derived.docx', '{"provider_name": "dashscope", "provider_type": "third_party", "parsed_summary": "Alice, bored while sitting with her sister by a riverbank, notices a talking White Rabbit with pink eyes who checks a watch and worries about being late \u2014 an event that initially seems ordinary to her despite its strangeness.", "parsed_provider_name": "dashscope"}', 'pending_review', NULL, 'system', '2026-07-04 07:57:44.90988', '2026-07-04 07:57:44.90988', NULL, NULL, NULL, NULL, NULL, NULL, false);
