INSERT INTO public.memory_cards VALUES ('44a76f51-fded-4df5-a6e6-dab43ecae46b', '85ef4852-f13c-4e86-a93f-2bd3adb4e8e4', 'Alice', 'A young girl who feels bored and sleepy while sitting by her sister on a riverbank; she is curious, imaginative, and impulsive enough to chase a talking White Rabbit with a waistcoat-pocket and watch, then follow it down a rabbit-hole without considering how to get out.', 'unknown', 'high', 0, '404e59bc-2db4-4909-927b-33677c1e69a5', 'bcc03a04-dc8d-4459-a749-9d7f29ea230e', 'text', 'Alice was beginning to get very tired of sitting by her sister on the bank, and of having nothing to do... when suddenly a White Rabbit with pink eyes ran close by her... Alice started to her feet... she ran across the field after it... down went Alice after it, never once considering how in the world she was to get out again.', 'text:alice-memory-trimmed.txt', '{"provider_name": "dashscope", "provider_type": "third_party", "parsed_summary": "Alice, bored while sitting with her sister, notices a talking White Rabbit with a waistcoat-pocket and a watch; intrigued, she follows it down a rabbit-hole and begins falling down a deep well.", "parsed_provider_name": "dashscope"}', 'pending_review', NULL, 'system', '2026-07-04 07:59:31.852655', '2026-07-04 07:59:31.852655', NULL, NULL, NULL, NULL, NULL, NULL, false);
INSERT INTO public.memory_cards VALUES ('1ae2899a-eaf4-4108-bbd7-ec3ecc61127a', '85ef4852-f13c-4e86-a93f-2bd3adb4e8e4', 'White Rabbit', 'A white rabbit with pink eyes who speaks aloud to itself, wears a waistcoat with a pocket, and carries a watch; its behavior—particularly checking the watch and exclaiming ''Oh dear! Oh dear! I shall be late!''—triggers Alice''s curiosity and prompts her to follow it.', 'unknown', 'high', 0, '404e59bc-2db4-4909-927b-33677c1e69a5', 'bcc03a04-dc8d-4459-a749-9d7f29ea230e', 'text', 'a White Rabbit with pink eyes ran close by her... the Rabbit say to itself, ''Oh dear! Oh dear! I shall be late!''... the Rabbit actually took a watch out of its waistcoat-pocket, and looked at it, and then hurried on', 'text:alice-memory-trimmed.txt', '{"provider_name": "dashscope", "provider_type": "third_party", "parsed_summary": "Alice, bored while sitting with her sister, notices a talking White Rabbit with a waistcoat-pocket and a watch; intrigued, she follows it down a rabbit-hole and begins falling down a deep well.", "parsed_provider_name": "dashscope"}', 'pending_review', NULL, 'system', '2026-07-04 07:59:31.852655', '2026-07-04 07:59:31.852655', NULL, NULL, NULL, NULL, NULL, NULL, false);
INSERT INTO public.memory_cards VALUES ('72946f2a-244c-49d5-9a8e-699ff32a01d7', '85ef4852-f13c-4e86-a93f-2bd3adb4e8e4', 'Abu Ben Adhem', 'A figure who awoke from a deep dream of peace and encountered an angel writing in a book of gold; he asked to be written as one who loves his fellow men, and the next night his name appeared first among those blessed by love of God.', 'unknown', 'high', 0, 'a494504d-37ac-4cee-ad3a-2ab93f11c329', 'ca061865-1747-48f3-8edb-42fa04c75885', 'audio', 'Abu Ben Adhem by Leigh Hunt. Abu Ben Adhem, may his tribe increase, awoke one night from a deep dream of peace, and saw within the moonlight in his room, making it rich and like a lily in bloom, an angel writing in a book of gold. Exceeding peace had made Ben Adhem bold, and to the presence in the room he said, "What writest thou?" The vision raised its head, and with a look made of all sweet accord answered, "The names of those who love the Lord." "And is mine one?" said Abu. "Nay, not so," replied the angel. Abu spoke more low, but cheerly still, and said, "I pray thee then, write me as one that loves his fellow men." The angel wrote and vanished. The next night it came again with a great wakening light, and showed the names whom love of God had blessed, and lo, Ben Adhem''s name led all the rest.', 'audio:abou-ben-adhem.mp3#00:00', '{"provider_name": "dashscope", "provider_type": "third_party", "parsed_summary": "This is a LibriVox recording. All LibriVox recordings are in the public domain. ", "parsed_provider_name": "dashscope"}', 'pending_review', NULL, 'system', '2026-07-04 08:00:16.934619', '2026-07-04 08:00:16.934619', NULL, NULL, NULL, NULL, NULL, NULL, false);
INSERT INTO public.memory_cards VALUES ('e65d4890-dc05-4945-ab8c-3c52ea5dfe69', '85ef4852-f13c-4e86-a93f-2bd3adb4e8e4', 'Leigh Hunt', 'The author of the poem ''Abu Ben Adhem''.', 'unknown', 'high', 0, 'a494504d-37ac-4cee-ad3a-2ab93f11c329', 'ca061865-1747-48f3-8edb-42fa04c75885', 'audio', 'Abu Ben Adhem by Leigh Hunt.', 'audio:abou-ben-adhem.mp3#00:00', '{"provider_name": "dashscope", "provider_type": "third_party", "parsed_summary": "This is a LibriVox recording. All LibriVox recordings are in the public domain. ", "parsed_provider_name": "dashscope"}', 'pending_review', NULL, 'system', '2026-07-04 08:00:16.934619', '2026-07-04 08:00:16.934619', NULL, NULL, NULL, NULL, NULL, NULL, false);
