INSERT INTO public.memory_cards VALUES ('4b941d5f-4265-4d10-932b-a5e32b50f685', '488853b6-8829-4261-a5db-fae4cc630c89', 'Alice', 'A young girl who feels bored while sitting by her sister on the bank; she is sleepy and stupid from the hot day, considers making a daisy-chain, and becomes curious upon seeing a White Rabbit with pink eyes that speaks and checks a watch taken from its waistcoat-pocket.', 'unknown', 'high', 0, '510255e7-2ba4-4ccd-87e0-49114903fbdf', '4746263b-15df-4007-8861-5867e656704a', 'text', 'Alice was beginning to get very tired of sitting by her sister on the bank, and of having nothing to do... So she was considering in her own mind (as well as she could, for the hot day made her feel very sleepy and stupid), whether the pleasure of making a daisy-chain would be worth the trouble of getting up and picking the daisies, when suddenly a White Rabbit with pink eyes ran close by her.', 'text:alice-memory-trimmed.txt', '{"provider_name": "dashscope", "provider_type": "third_party", "parsed_summary": "Alice, bored while sitting with her sister, notices a talking White Rabbit with a waistcoat-pocket and a watch; intrigued, she follows it down a rabbit-hole and begins falling down a deep well.", "parsed_provider_name": "dashscope"}', 'pending_review', NULL, 'system', '2026-07-04 08:02:44.374459', '2026-07-04 08:02:44.374459', NULL, NULL, NULL, NULL, NULL, NULL, false);
INSERT INTO public.memory_cards VALUES ('b0abaeda-8b9c-43e9-bc8d-f520c844fecd', '488853b6-8829-4261-a5db-fae4cc630c89', 'White Rabbit', 'A rabbit with pink eyes who speaks aloud (''Oh dear! Oh dear! I shall be late!'') and takes a watch out of its waistcoat-pocket before hurrying away.', 'unknown', 'high', 0, '510255e7-2ba4-4ccd-87e0-49114903fbdf', '4746263b-15df-4007-8861-5867e656704a', 'text', 'a White Rabbit with pink eyes ran close by her... it occurred to her that she ought to have wondered at this... but when the Rabbit actually _took a watch out of its waistcoat-pocket_, and looked at it, and then hurried on', 'text:alice-memory-trimmed.txt', '{"provider_name": "dashscope", "provider_type": "third_party", "parsed_summary": "Alice, bored while sitting with her sister, notices a talking White Rabbit with a waistcoat-pocket and a watch; intrigued, she follows it down a rabbit-hole and begins falling down a deep well.", "parsed_provider_name": "dashscope"}', 'pending_review', NULL, 'system', '2026-07-04 08:02:44.374459', '2026-07-04 08:02:44.374459', NULL, NULL, NULL, NULL, NULL, NULL, false);
INSERT INTO public.memory_cards VALUES ('6c41bb14-0e4d-4312-ba5b-6878791c754b', '488853b6-8829-4261-a5db-fae4cc630c89', 'Alice', 'A young girl who feels tired and bored while sitting by her sister on a riverbank; she finds books without pictures or conversations useless; she is drowsy and mentally sluggish due to the hot day; she contemplates making a daisy-chain; she observes a White Rabbit with pink eyes who speaks aloud about being late.', 'unknown', 'high', 0, 'b5c1ebd1-d351-4250-b17c-dfa2a7a424ed', '8da0e147-a3a2-49fe-b407-d9a6414b2eec', 'text', 'Alice was beginning to get very tired of sitting by her sister on the bank, and of having nothing to do: once or twice she had peeped into the book her sister was reading, but it had no pictures or conversations in it, “and what is the use of a book,” thought Alice “without pictures or conversations?” So she was considering in her own mind (as well as she could, for the hot day made her feel very sleepy and stupid), whether the pleasure of making a daisy-chain would be worth the trouble of getting up and picking the daisies, when suddenly a White Rabbit with pink eyes ran close by her.', 'text:alice-derived.doc', '{"provider_name": "dashscope", "provider_type": "third_party", "parsed_summary": "Alice, bored while sitting with her sister, notices a talking White Rabbit with pink eyes who checks a watch and worries about being late \u2014 prompting her curiosity and marking the start of her adventure.", "parsed_provider_name": "dashscope"}', 'pending_review', NULL, 'system', '2026-07-04 08:03:06.921671', '2026-07-04 08:03:06.921671', NULL, NULL, NULL, NULL, NULL, NULL, false);
INSERT INTO public.memory_cards VALUES ('ad85e885-753b-438a-8233-156db23fb9c5', '488853b6-8829-4261-a5db-fae4cc630c89', 'White Rabbit', 'A rabbit with pink eyes who runs close by Alice; speaks aloud to itself saying ''Oh dear! Oh dear! I shall be late!''; later takes a watch.', 'unknown', 'high', 0, 'b5c1ebd1-d351-4250-b17c-dfa2a7a424ed', '8da0e147-a3a2-49fe-b407-d9a6414b2eec', 'text', 'when suddenly a White Rabbit with pink eyes ran close by her. There was nothing so _very_ remarkable in that; nor did Alice think it so _very_ much out of the way to hear the Rabbit say to itself, “Oh dear! Oh dear! I shall be late!” ... but when the Rabbit actually _took a watch', 'text:alice-derived.doc', '{"provider_name": "dashscope", "provider_type": "third_party", "parsed_summary": "Alice, bored while sitting with her sister, notices a talking White Rabbit with pink eyes who checks a watch and worries about being late \u2014 prompting her curiosity and marking the start of her adventure.", "parsed_provider_name": "dashscope"}', 'pending_review', NULL, 'system', '2026-07-04 08:03:06.921671', '2026-07-04 08:03:06.921671', NULL, NULL, NULL, NULL, NULL, NULL, false);
