INSERT INTO public.memory_cards VALUES ('993b9d47-38bb-423e-b5bb-ae923478a473', 'c0fe8892-725a-4205-a7d1-bb1e63b0d258', '外婆的处世态度', '外婆主张做事不急躁，强调在情绪不适时先调整呼吸、稳定状态。', 'unknown', 'low', 0, '560af6fd-e2ce-415c-9c6c-0c1f31210b33', '102a5811-494e-4db8-bd44-3dc97d677d1e', 'manual', '外婆常说慢慢来，别急，心里难受的时候先把气喘匀。', 'manual:body', '{"provider_name": "dashscope", "provider_type": "third_party", "parsed_summary": "\u5916\u5a46\u6559\u5bfc\u9047\u60c5\u7eea\u6ce2\u52a8\u65f6\u5148\u5e73\u7a33\u547c\u5438\u3001\u653e\u6162\u8282\u594f\u3002", "parsed_provider_name": "dashscope"}', 'confirmed', NULL, 'system', '2026-07-04 08:50:38.920673', '2026-07-04 08:50:49.980576', NULL, NULL, NULL, NULL, NULL, NULL, false);
INSERT INTO public.memory_cards VALUES ('3e0e48a8-4df9-4492-b79c-494514039282', '7182da13-4f02-4aab-91ba-07b664d1d8f7', 'Alice', 'A young girl who feels bored while sitting by her sister on the bank; she is sleepy and stupid from the hot day, considers making a daisy-chain, and becomes curious upon seeing a White Rabbit with pink eyes that speaks and checks a watch taken from its waistcoat-pocket.', 'unknown', 'high', 0, '7a2e0ce2-c076-4d37-bbc0-b1c2d6e36bd9', '32d6b105-0e6b-4b17-84d3-4c649cfc5ba5', 'text', 'Alice was beginning to get very tired of sitting by her sister on the bank, and of having nothing to do... So she was considering in her own mind (as well as she could, for the hot day made her feel very sleepy and stupid), whether the pleasure of making a daisy-chain would be worth the trouble of getting up and picking the daisies, when suddenly a White Rabbit with pink eyes ran close by her.', 'text:alice-memory-trimmed.txt', '{"provider_name": "dashscope", "provider_type": "third_party", "parsed_summary": "Alice, bored while sitting with her sister, notices a talking White Rabbit with pink eyes who checks a pocket watch and rushes away; intrigued by its unusual appearance and behavior, she follows it into a rabbit-hole and begins falling down a deep well.", "parsed_provider_name": "dashscope"}', 'pending_review', NULL, 'system', '2026-07-04 09:07:21.434178', '2026-07-04 09:07:21.434178', NULL, NULL, NULL, NULL, NULL, NULL, false);
INSERT INTO public.memory_cards VALUES ('a059c975-c6e5-4293-9924-df89f6a9b89c', '7182da13-4f02-4aab-91ba-07b664d1d8f7', 'Alice''s sister', 'A person sitting with Alice on the bank; she is reading a book that has no pictures or conversations.', 'unknown', 'high', 0, '7a2e0ce2-c076-4d37-bbc0-b1c2d6e36bd9', '32d6b105-0e6b-4b17-84d3-4c649cfc5ba5', 'text', 'Alice was beginning to get very tired of sitting by her sister on the bank, and of having nothing to do: once or twice she had peeped into the book her sister was reading, but it had no pictures or conversations in it', 'text:alice-memory-trimmed.txt', '{"provider_name": "dashscope", "provider_type": "third_party", "parsed_summary": "Alice, bored while sitting with her sister, notices a talking White Rabbit with pink eyes who checks a pocket watch and rushes away; intrigued by its unusual appearance and behavior, she follows it into a rabbit-hole and begins falling down a deep well.", "parsed_provider_name": "dashscope"}', 'pending_review', NULL, 'system', '2026-07-04 09:07:21.434178', '2026-07-04 09:07:21.434178', NULL, NULL, NULL, NULL, NULL, NULL, false);
INSERT INTO public.memory_cards VALUES ('9aa02f95-bd2a-46db-b5fa-4af62313bc32', '7182da13-4f02-4aab-91ba-07b664d1d8f7', 'White Rabbit', 'A rabbit with pink eyes who runs close by Alice, speaks aloud saying ''Oh dear! Oh dear! I shall be late!'', and takes a watch out of its waistcoat-pocket.', 'unknown', 'high', 0, '7a2e0ce2-c076-4d37-bbc0-b1c2d6e36bd9', '32d6b105-0e6b-4b17-84d3-4c649cfc5ba5', 'text', 'a White Rabbit with pink eyes ran close by her... the Rabbit say to itself, ''Oh dear! Oh dear! I shall be late!''... when the Rabbit actually _took a watch out of its waistcoat-pocket_, and looked at it, and then hurried on', 'text:alice-memory-trimmed.txt', '{"provider_name": "dashscope", "provider_type": "third_party", "parsed_summary": "Alice, bored while sitting with her sister, notices a talking White Rabbit with pink eyes who checks a pocket watch and rushes away; intrigued by its unusual appearance and behavior, she follows it into a rabbit-hole and begins falling down a deep well.", "parsed_provider_name": "dashscope"}', 'pending_review', NULL, 'system', '2026-07-04 09:07:21.434178', '2026-07-04 09:07:21.434178', NULL, NULL, NULL, NULL, NULL, NULL, false);
INSERT INTO public.memory_cards VALUES ('14279f32-3fec-4731-99ab-2cf78eb0faf6', '7182da13-4f02-4aab-91ba-07b664d1d8f7', 'Use of stop sign for safety instruction', 'The persona used a public stop sign to teach the user to pause, stop, and look both ways for safety during a walk.', 'unknown', 'high', 0, '459b97bb-5581-445f-8f27-e77794b81df4', 'a36ff013-47b8-4498-8a6c-2213a9b1f522', 'image', 'During a walk, the persona used a public stop sign to teach the user to pause, stop, and look both ways for safety.', 'image:stop-sign.png', '{"provider_name": "dashscope", "provider_type": "third_party", "parsed_summary": "A standard red octagonal traffic sign with the word ''STOP'' written in large white capital letters.", "parsed_provider_name": "dashscope"}', 'pending_review', NULL, 'system', '2026-07-04 09:07:44.373853', '2026-07-04 09:07:44.373853', NULL, NULL, NULL, NULL, NULL, NULL, false);
INSERT INTO public.memory_cards VALUES ('9a7ec81c-0cd7-42a8-8b4e-19b138460295', '7182da13-4f02-4aab-91ba-07b664d1d8f7', 'White Rabbit', 'A white rabbit with pink eyes who runs close by Alice, speaks aloud to itself saying ''Oh dear! Oh dear! I shall be late!'', and carries a watch.', 'unknown', 'high', 0, 'f5da3082-1fa5-42b9-8e46-f7bdf8232ace', '987004a3-b403-43b3-8430-d86819c856f8', 'text', 'when suddenly a White Rabbit with pink eyes ran close by her... but when the Rabbit actually took a watch...', 'text:alice-derived.doc', '{"provider_name": "dashscope", "provider_type": "third_party", "parsed_summary": "Alice grows bored while sitting with her sister by the riverbank, finds her sister\u2019s book dull for lacking pictures and conversation, contemplates making a daisy-chain, and then sees a White Rabbit with pink eyes muttering about being late and checking a watch.", "parsed_provider_name": "dashscope"}', 'pending_review', NULL, 'system', '2026-07-04 09:09:27.580209', '2026-07-04 09:09:27.580209', NULL, NULL, NULL, NULL, NULL, NULL, false);
INSERT INTO public.memory_cards VALUES ('ea63fd30-cefc-4374-a1e4-6d738de9f899', '7182da13-4f02-4aab-91ba-07b664d1d8f7', 'Abu Ben Adhem', 'Abu Ben Adhem is a figure from Leigh Hunt''s poem who awakens one night to see an angel writing in a book of gold. He asks the angel what it is writing, learns it is ''the names of those who love the Lord'', and when told his name is not among them, requests to be written ''as one that loves his fellow men''. The next night, his name appears first among those blessed by love of God.', 'unknown', 'high', 0, 'e986ab43-6287-48d4-a970-23b17561d211', 'fe8f9135-057d-46e6-9ccd-8de58f578e5b', 'audio', 'Abu Ben Adhem by Leigh Hunt. Abu Ben Adhem, may his tribe increase, awoke one night from a deep dream of peace, and saw within the moonlight in his room, making it rich and like a lily in bloom, an angel writing in a book of gold. Exceeding peace had made Ben Adhem bold, and to the presence in the room he said, "What writest thou?" The vision raised its head, and with a look made of all sweet accord answered, "The names of those who love the Lord." And is mine one? said Abu. "Nay, not so," replied the angel. Abu spoke more low, but cheerily still, and said, "I pray thee then, write me as one that loves his fellow men." The angel wrote and vanished. The next night it came again with a great wakening light, and showed the names whom love of God had blessed. And lo, Ben Adhem''s name led all the rest.', 'audio:abou-ben-adhem.mp3#00:00', '{"provider_name": "dashscope", "provider_type": "third_party", "parsed_summary": "This is a LibriVox recording. All LibriVox recordings are in the public domain. ", "parsed_provider_name": "dashscope"}', 'pending_review', NULL, 'system', '2026-07-04 09:08:11.46207', '2026-07-04 09:08:11.46207', NULL, NULL, NULL, NULL, NULL, NULL, false);
INSERT INTO public.memory_cards VALUES ('3e7a566d-0722-4544-b1e1-d1f07865cc40', '7182da13-4f02-4aab-91ba-07b664d1d8f7', 'USGS科研人员', '视频中未出现具体人物，隐含的主体是进行科学观测和记录的美国地质调查局（USGS）科研人员。', 'unknown', 'medium', 0, 'd5e51dfd-171e-4ce4-87d4-4854651d9c9b', 'a2b75799-aa07-4d17-be8d-ffd9a9315afc', 'video', '视频中未出现具体人物。隐含的主体是进行科学观测和记录的 USGS（美国地质调查局）科研人员。', 'video:volcano-lava-smoke-clip.mp4#00:00', '{"provider_name": "dashscope", "provider_type": "third_party", "parsed_summary": "\u6839\u636e\u60a8\u63d0\u4f9b\u7684\u89c6\u9891\u5173\u952e\u5e27\u548c\u97f3\u9891\u8f6c\u5199\u5185\u5bb9\uff0c\u4ee5\u4e0b\u662f\u89c6\u9891\u573a\u666f\u6458\u8981\uff1a **\u89c6\u9891\u573a\u666f\u6458\u8981** \u8fd9\u6bb5\u89c6\u9891\u7531\u7f8e\u56fd\u5730\u8d28\u8c03\u67e5\u5c40\uff08USGS\uff09\u5236\u4f5c\uff0c\u4e3b\u8981\u5c55\u793a\u4e86\u706b\u5c71\u7194\u5ca9\u6d41\u52a8\u7684\u81ea\u7136\u5947\u89c2\u3002\u89c6\u9891\u4ee5 USGS \u7684\u6807\u5fd7\u5f00\u573a\uff0c\u968f\u540e\u5207\u5165\u706b\u5c71\u73b0\u573a\u753b\u9762\uff0c\u5c55\u793a\u4e86\u70bd\u70ed\u7684\u7194\u5ca9\u5728\u51b7\u5374\u7684\u9ed1\u8272\u5ca9\u77f3\u5730\u8868\u4e0a\u873f\u8712\u6d41\u6dcc\u7684\u58ee\u89c2\u666f\u8c61\uff0c\u5e76\u6807\u6ce8\u4e86\u201cVOLCANO Lava Sample\u201d\uff08\u706b\u5c71\u7194\u5ca9\u6837\u672c\uff09\uff0c\u8868\u660e\u8fd9\u662f\u4e00\u6bb5\u5173\u4e8e\u5730\u8d28\u79d1\u5b66\u8bb0\u5f55\u6216\u6837\u672c\u5c55\u793a\u7684\u5f71\u50cf\u3002 **\u8be6\u7ec6\u8bf4\u660e\uff1a** * **\u4eba\u7269\uff1a** \u89c6\u9891\u4e2d\u672a\u51fa\u73b0\u5177\u4f53\u4eba\u7269\u3002\u9690\u542b\u7684\u4e3b\u4f53\u662f\u8fdb\u884c\u79d1\u5b66\u89c2\u6d4b\u548c\u8bb0\u5f55\u7684 USGS\uff08\u7f8e\u56fd\u5730\u8d28\u8c03\u67e5\u5c40\uff09\u79d1\u7814\u4eba\u5458\u3002 * **\u5730\u70b9\uff1a** \u6d3b\u8dc3\u7684\u706b\u5c71\u533a\u57df\uff0c\u5177\u4f53\u4e3a\u7194\u5ca9\u6d41\u7ecf\u8fc7\u7684\u5730\u5e26\uff08\u5730\u9762\u8986\u76d6\u7740\u51b7\u5374\u7684\u9ed1\u8272\u7194\u5ca9\uff09\u3002 * **\u4e8b\u4ef6\uff1a** \u89c6\u9891\u8bb0\u5f55\u4e86\u706b\u5c71\u7194\u5ca9\u7684\u6d41\u52a8\u8fc7\u7a0b\uff0c\u5e76\u5c06\u5176\u5b9a\u4e49\u4e3a\u201c\u7194\u5ca9\u6837\u672c\u201d\uff0c\u65e8\u5728\u5c55\u793a\u5730\u8d28\u6d3b\u52a8\u6216\u4e3a\u79d1\u5b66\u7814\u7a76\u63d0\u4f9b\u89c6\u89c9\u8d44\u6599\u3002 * **\u60c5\u7eea\uff1a** \u9707\u64bc\u3001\u58ee\u89c2\u3001\u656c\u754f\u81ea\u7136\u3002\u7ea2\u8272\u7684\u7194\u5ca9\u4e0e\u9ed1\u8272\u7684\u73af\u5883\u5f62\u6210\u5f3a\u70c8\u5bf9\u6bd4\uff0c\u65e2\u5371\u9669\u53c8\u7f8e\u4e3d\uff0c\u540c\u65f6\u4e5f\u5e26\u6709\u79d1\u5b66\u8bb0\u5f55\u7684\u5ba2\u89c2\u4e0e\u4e25\u8c28\u3002 * **\u53ef\u4f5c\u4e3a\u8bb0\u5fc6\u7684\u7247\u6bb5\uff1a** 1. **\u5f00\u573a\u6807\u5fd7\uff1a** \u9ed1\u5e95\u767d\u5b57\u7684 USGS \u6807\u5fd7\u53ca\u5176\u6807\u8bed\u201cscience for a changing world\u201d\uff08\u4e3a\u53d8\u5316\u7684\u4e16\u754c\u63d0\u4f9b\u79d1\u5b66\uff09\u3002 2. **\u7194\u5ca9\u6d41\u6dcc\uff1a** \u70bd\u70ed\u7684\u6a59\u7ea2\u8272\u7194\u5ca9\u50cf\u6cb3\u6d41\u4e00\u6837\uff0c\u5728\u7070\u9ed1\u8272\u3001\u5d0e\u5c96\u4e0d\u5e73\u7684\u51b7\u5374\u7194\u5ca9\u5730\u8868\u4e0a\u873f\u8712\u6d41\u52a8\u7684\u7279\u5199\u955c\u5934\u3002 3. **\u6587\u5b57\u6807\u9898\uff1a** \u753b\u9762\u4e2d\u592e\u53e0\u52a0\u7684\u767d\u8272\u5927\u5b57\u201cVOLCANO Lava Sample\u201d\uff0c\u660e\u786e\u4e86\u89c6\u9891\u7684\u4e3b\u9898\u3002", "parsed_provider_name": "dashscope"}', 'pending_review', NULL, 'system', '2026-07-04 09:08:20.687867', '2026-07-04 09:08:20.687867', NULL, NULL, NULL, NULL, NULL, NULL, false);
INSERT INTO public.memory_cards VALUES ('e979463c-5b12-4617-bc43-eb6f51b0fa8e', '7182da13-4f02-4aab-91ba-07b664d1d8f7', 'Alice', 'A young girl who is sitting by her sister on the bank, feeling tired and sleepy on a hot day; she is contemplative, curious, and initially unimpressed by a book lacking pictures or conversations.', 'unknown', 'high', 0, '5bc8bdfa-a06e-407f-a51f-ae0ad329dd43', 'eff005c0-36a1-4f9b-afec-2fb7206fff66', 'text', 'Alice was beginning to get very tired of sitting by her sister on the bank, and of having nothing to do: once or twice she had peeped into the book her sister was reading, but it had no pictures or conversations in it, and what is the use of a book, thought Alice, without pictures or conversations? So she was considering in her own mind (as well as she could, for the hot day made her feel very sleepy and stupid), whether the pleasure of making a daisy-chain would be worth the trouble of getting up and picking the daisies', 'text:alice-derived.pdf, page 1', '{"provider_name": "dashscope", "provider_type": "third_party", "parsed_summary": "Introduction to Alice and the beginning of her adventure: she grows bored, observes her sister''s dull book, reflects on daisy-chaining, and is startled by a talking White Rabbit with a watch.", "parsed_provider_name": "dashscope"}', 'pending_review', NULL, 'system', '2026-07-04 09:08:53.46048', '2026-07-04 09:08:53.46048', NULL, NULL, NULL, NULL, NULL, NULL, false);
INSERT INTO public.memory_cards VALUES ('58c01eea-842c-4f74-95de-57403753486a', '7182da13-4f02-4aab-91ba-07b664d1d8f7', 'Alice', 'A young girl who is sitting by her sister on the bank, feeling tired and sleepy on a hot day; she is contemplative, questioning the value of books without pictures or conversations, and considers making a daisy-chain.', 'unknown', 'high', 0, '2fa35ab5-31c7-4ed3-8f21-a13d1bf8899d', '65a3f8eb-dd20-4f91-9efa-2e4048beaa24', 'text', 'Alice was beginning to get very tired of sitting by her sister on the bank, and of having nothing to do: once or twice she had peeped into the book her sister was reading, but it had no pictures or conversations in it, “and what is the use of a book,” thought Alice, “without pictures or conversations?” So she was considering in her own mind (as well as she could, for the hot day made her feel very sleepy and stupid), whether the pleasure of making a daisy-chain would be worth the trouble of getting up and picking the daisies...', 'text:alice-derived.docx', '{"provider_name": "dashscope", "provider_type": "third_party", "parsed_summary": "Alice, bored while sitting with her sister, notices a talking White Rabbit with pink eyes who checks a watch and worries about being late \u2014 an event that initially seems ordinary to her despite its strangeness.", "parsed_provider_name": "dashscope"}', 'pending_review', NULL, 'system', '2026-07-04 09:09:10.40179', '2026-07-04 09:09:10.40179', NULL, NULL, NULL, NULL, NULL, NULL, false);
INSERT INTO public.memory_cards VALUES ('ca176a0c-7ad2-43c3-a1ee-1f5e84317b3a', '7182da13-4f02-4aab-91ba-07b664d1d8f7', 'Alice', 'A young girl who is sitting by her sister on the bank, feeling tired and sleepy on a hot day; she is contemplative, observant, and initially unimpressed by a book lacking pictures or conversations.', 'unknown', 'high', 0, 'f5da3082-1fa5-42b9-8e46-f7bdf8232ace', '987004a3-b403-43b3-8430-d86819c856f8', 'text', 'Alice was beginning to get very tired of sitting by her sister on the bank, and of having nothing to do: once or twice she had peeped into the book her sister was reading, but it had no pictures or conversations in it, “and what is the use of a book,” thought Alice, “without pictures or conversations?” So she was considering in her own mind (as well as she could, for the hot day made her feel very sleepy and stupid), whether the pleasure of making a daisy-chain would be worth the trouble of getting up and picking the daisies...', 'text:alice-derived.doc', '{"provider_name": "dashscope", "provider_type": "third_party", "parsed_summary": "Alice grows bored while sitting with her sister by the riverbank, finds her sister\u2019s book dull for lacking pictures and conversation, contemplates making a daisy-chain, and then sees a White Rabbit with pink eyes muttering about being late and checking a watch.", "parsed_provider_name": "dashscope"}', 'pending_review', NULL, 'system', '2026-07-04 09:09:27.580209', '2026-07-04 09:09:27.580209', NULL, NULL, NULL, NULL, NULL, NULL, false);
