INSERT INTO public.memory_cards VALUES ('bcbbcdb3-141b-4d11-8166-3526a176529a', '6e71e1ce-8524-4466-8957-b9bd518531f4', 'Alice', 'A young girl who feels tired and bored while sitting by her sister on the bank; she is sleepy and feels stupid due to the hot day; she contemplates making a daisy-chain; she thinks books without pictures or conversations are useless.', 'unknown', 'high', 0, '5cb049b2-f5b8-4225-aaf2-704c8b2e13d5', 'e77764ec-c0ef-487a-9139-eb0682c61032', 'text', 'Alice was beginning to get very tired of sitting by her sister on the bank, and of having nothing to do: once or twice she had peeped into the book her sister was reading, but it had no pictures or conversations in it, “and what is the use of a book,” thought Alice “without pictures or conversations?” So she was considering in her own mind (as well as she could, for the hot day made her feel very sleepy and stupid), whether the pleasure of making a daisy-chain would be worth the trouble of getting up and picking the daisies', 'text:alice-memory-trimmed.txt', '{"provider_name": "dashscope", "provider_type": "third_party", "parsed_summary": "Alice grows bored beside her sister, dismisses a text-only book as dull, contemplates daisy-chaining, and notices a White Rabbit with pink eyes.", "parsed_provider_name": "dashscope"}', 'pending_review', NULL, 'system', '2026-07-04 10:06:23.35042', '2026-07-04 10:06:23.35042', NULL, NULL, NULL, NULL, NULL, NULL, false);
INSERT INTO public.memory_cards VALUES ('6ac76c46-b06e-4eb6-8d49-43b0cd93e57d', '6e71e1ce-8524-4466-8957-b9bd518531f4', 'Persona''s teaching about stop signs', 'The persona taught the user to pause, stop, and look both ways during a walk.', 'unknown', 'low', 0, '9324f115-9527-40d7-9744-125efb0ab4e0', '1d8ae69d-7bf9-4390-8d12-b7948d7656bb', 'image', 'the persona taught the user to pause, stop, and look both ways.', 'image:stop-sign.png', '{"provider_name": "dashscope", "provider_type": "third_party", "parsed_summary": "A standard red octagonal traffic sign with the word ''STOP'' in large white capital letters.", "parsed_provider_name": "dashscope"}', 'pending_review', NULL, 'system', '2026-07-04 10:06:50.001524', '2026-07-04 10:06:50.001524', NULL, NULL, NULL, NULL, NULL, NULL, false);
INSERT INTO public.memory_cards VALUES ('ad73a556-64dc-48e3-aea3-5ffba2620206', '6e71e1ce-8524-4466-8957-b9bd518531f4', 'Abu Ben Adhem', 'A figure who awoke from a deep dream of peace and encountered an angel writing names in a book of gold; he asked to be inscribed not among those who love the Lord, but among those who love their fellow men; his name subsequently appeared first among those blessed by love of God.', 'unknown', 'high', 0, '218b4a0c-1881-4121-a3c2-1b217eac317d', '73028df9-a285-45b6-acef-7b499240eb6f', 'audio', 'Abu Ben Adhem by Leigh Hunt. Abu Ben Adhem, may his tribe increase, awoke one night from a deep dream of peace, and saw within the moonlight in his room, making it rich and like a lily in bloom, an angel writing in a book of gold. Exceeding peace had made Ben Adhem bold, and to the presence in the room he said, "What writest thou?" The vision raised its head, and with a look made of all sweet accord, answered, "The names of those who love the Lord." "And is mine one?" said Abu. "Nay, not so," replied the angel. Abu spoke more low, but cheerly still, and said, "I pray thee then, write me as one that loves his fellow men." The angel wrote, and vanished. The next night it came again with a great wakening light, and showed the names whom love of God had blessed. And lo, Ben Adhem''s name led all the rest.', 'audio:abou-ben-adhem.mp3#00:00', '{"provider_name": "dashscope", "provider_type": "third_party", "parsed_summary": "This is a LibriVox recording. All LibriVox recordings are in the public domain. ", "parsed_provider_name": "dashscope"}', 'pending_review', NULL, 'system', '2026-07-04 10:07:10.862302', '2026-07-04 10:07:10.862302', NULL, NULL, NULL, NULL, NULL, NULL, false);
INSERT INTO public.memory_cards VALUES ('120699d7-2895-48dc-abda-c2b43c0010af', '6e71e1ce-8524-4466-8957-b9bd518531f4', 'Leigh Hunt', 'The author of the poem ''Abu Ben Adhem''.', 'unknown', 'high', 0, '218b4a0c-1881-4121-a3c2-1b217eac317d', '73028df9-a285-45b6-acef-7b499240eb6f', 'audio', 'Abu Ben Adhem by Leigh Hunt.', 'audio:abou-ben-adhem.mp3#00:00', '{"provider_name": "dashscope", "provider_type": "third_party", "parsed_summary": "This is a LibriVox recording. All LibriVox recordings are in the public domain. ", "parsed_provider_name": "dashscope"}', 'pending_review', NULL, 'system', '2026-07-04 10:07:10.862302', '2026-07-04 10:07:10.862302', NULL, NULL, NULL, NULL, NULL, NULL, false);
