INSERT INTO public.memory_cards VALUES ('a0d5a6f7-7860-4fe6-9abb-62468320f0cf', 'a1ad9ba1-f881-40c7-ae85-9a09323b8c47', '外婆给小铭包馄饨', '外婆喜欢给小铭包馄饨。', 'unknown', 'low', 0, '6fddc178-4be3-4264-a0a1-2fa78cf70e91', '5e0f215f-8698-4dcc-aeec-e96a4a87fc39', 'manual', '外婆喜欢给小铭包馄饨，也常说饭要趁热慢慢吃。', 'manual:body', '{"provider_name": "dashscope", "provider_type": "third_party", "parsed_summary": "\u5916\u5a46\u4e3a\u5c0f\u94ed\u5305\u9984\u9968\uff0c\u5e76\u53ee\u5631\u996d\u8981\u8d81\u70ed\u6162\u6162\u5403\u3002", "parsed_provider_name": "dashscope"}', 'confirmed', NULL, 'system', '2026-07-04 16:47:15.662946', '2026-07-04 16:47:33.586219', NULL, NULL, NULL, NULL, NULL, NULL, false);
INSERT INTO public.memory_cards VALUES ('aa342f0b-bbce-45da-93cd-d145246e1454', '6e71e1ce-8524-4466-8957-b9bd518531f4', 'USGS标志', '视频片头出现黑底白字的''USGS''（美国地质调查局）标志。', 'unknown', 'low', 0, '00d9f5de-c493-41e1-9f85-f5000d90d087', '39fd24c2-29b0-4e72-907b-02c0434daf2a', 'video', '片头黑底白字的USGS标志。', 'video:volcano-lava-smoke-clip.mp4#00:00', '{"provider_name": "dashscope", "provider_type": "third_party", "parsed_summary": "\u6839\u636e\u60a8\u63d0\u4f9b\u7684\u89c6\u9891\u5173\u952e\u5e27\u548c\u97f3\u9891\u8f6c\u5199\uff0c\u4ee5\u4e0b\u662f\u89c6\u9891\u573a\u666f\u6458\u8981\uff1a **\u89c6\u9891\u573a\u666f\u6458\u8981** * **\u4eba\u7269**\uff1a\u89c6\u9891\u4e2d\u65e0\u5177\u4f53\u4eba\u7269\u51fa\u955c\uff0c\u4e3b\u8981\u901a\u8fc7\u7247\u5934\u7684\u201cUSGS\u201d\uff08\u7f8e\u56fd\u5730\u8d28\u8c03\u67e5\u5c40\uff09\u6807\u5fd7\u9690\u542b\u4e86\u79d1\u5b66\u89c2\u5bdf\u8005\u548c\u8bb0\u5f55\u8005\u7684\u89c6\u89d2\u3002 * **\u5730\u70b9**\uff1a\u706b\u5c71\u6d3b\u52a8\u533a\u57df\uff0c\u5177\u4f53\u4e3a\u7194\u5ca9\u6d41\u8fc7\u7684\u5730\u8868\uff08\u53ef\u80fd\u662f\u590f\u5a01\u5937\u7b49\u5730\u7684\u706b\u5c71\u56fd\u5bb6\u516c\u56ed\uff09\u3002 * **\u4e8b\u4ef6**\uff1a\u89c6\u9891\u9996\u5148\u5c55\u793a\u4e86\u7f8e\u56fd\u5730\u8d28\u8c03\u67e5\u5c40\uff08USGS\uff09\u7684\u6807\u5fd7\uff0c\u968f\u540e\u5207\u5165\u706b\u5c71\u7194\u5ca9\u6d41\u52a8\u7684\u753b\u9762\u3002\u753b\u9762\u4e2d\u51fa\u73b0\u4e86\u201cVOLCANO Lava Sample\u201d\uff08\u706b\u5c71\u7194\u5ca9\u6837\u672c\uff09\u7684\u6807\u9898\uff0c\u8868\u660e\u8fd9\u662f\u4e00\u6bb5\u5173\u4e8e\u8bb0\u5f55\u6216\u5c55\u793a\u706b\u5c71\u7194\u5ca9\u6837\u672c\u7684\u79d1\u5b66\u5f71\u50cf\u8d44\u6599\uff0c\u4e3b\u8981\u5c55\u793a\u4e86\u7194\u5ca9\u5728\u5730\u8868\u873f\u8712\u6d41\u52a8\u7684\u81ea\u7136\u8fc7\u7a0b\u3002 * **\u60c5\u7eea**\uff1a\u9707\u64bc\u3001\u58ee\u89c2\u3002\u9c9c\u7ea2\u7684\u7194\u5ca9\u4e0e\u9ed1\u8272\u7684\u51b7\u5374\u5ca9\u77f3\u5f62\u6210\u5f3a\u70c8\u5bf9\u6bd4\uff0c\u5c55\u73b0\u4e86\u5927\u81ea\u7136\u7684\u529b\u91cf\uff0c\u540c\u65f6\u4e5f\u5e26\u6709\u4e00\u79cd\u79d1\u5b66\u8bb0\u5f55\u7684\u5ba2\u89c2\u4e0e\u51b7\u9759\u3002 * **\u53ef\u4f5c\u4e3a\u8bb0\u5fc6\u7684\u7247\u6bb5**\uff1a 1. \u7247\u5934\u9ed1\u5e95\u767d\u5b57\u7684USGS\u6807\u5fd7\u3002 2. \u70bd\u70ed\u9c9c\u7ea2\u7684\u7194\u5ca9\u50cf\u6cb3\u6d41\u4e00\u6837\uff0c\u5728\u7070\u9ed1\u8272\u3001\u5d0e\u5c96\u4e0d\u5e73\u7684\u51b7\u5374\u7194\u5ca9\u5730\u4e0a\u873f\u8712\u6d41\u6dcc\u7684\u58ee\u89c2\u666f\u8c61\u3002 3. \u753b\u9762\u4e2d\u592e\u6d6e\u73b0\u51fa\u767d\u8272\u5927\u5b57\u201cVOLCANO Lava Sample\u201d\u3002", "parsed_provider_name": "dashscope"}', 'pending_review', NULL, 'system', '2026-07-04 10:07:22.916963', '2026-07-04 10:07:22.916963', NULL, NULL, NULL, NULL, NULL, NULL, false);
INSERT INTO public.memory_cards VALUES ('b276c368-d12c-45c3-acc8-abeee2ea1110', '6e71e1ce-8524-4466-8957-b9bd518531f4', 'Alice', 'A young girl who is tired of sitting by her sister on the bank, feels sleepy and stupid due to the hot day, and is contemplative about simple pleasures like making a daisy-chain; she observes a White Rabbit with pink eyes who speaks and checks a watch.', 'unknown', 'high', 0, 'bad08d81-f5eb-4c18-99d9-4a681e381127', '6ea45e0d-1191-4190-8054-858b1f5f4064', 'text', 'Alice was beginning to get very tired of sitting by her sister on the bank, and of having nothing to do... So she was considering in her own mind (as well as she could, for the hot day made her feel very sleepy and stupid), whether the pleasure of making a daisy-chain would be worth the trouble of getting up and picking the daisies, when suddenly a White Rabbit with pink eyes ran close by her.', 'text:alice-derived.docx', '{"provider_name": "dashscope", "provider_type": "third_party", "parsed_summary": "Alice, bored while sitting beside her sister, contemplates making a daisy-chain; a White Rabbit with pink eyes runs past, speaking anxiously about being late and then takes out a watch.", "parsed_provider_name": "dashscope"}', 'pending_review', NULL, 'system', '2026-07-04 10:08:01.826805', '2026-07-04 10:08:01.826805', NULL, NULL, NULL, NULL, NULL, NULL, false);
INSERT INTO public.memory_cards VALUES ('b9633319-79fa-45a7-b2ad-b80f71914e3a', '6e71e1ce-8524-4466-8957-b9bd518531f4', 'White Rabbit', 'A white rabbit with pink eyes who runs close by Alice, speaks aloud saying ''Oh dear! Oh dear! I shall be late!'', and later is observed taking a watch.', 'unknown', 'high', 0, 'bad08d81-f5eb-4c18-99d9-4a681e381127', '6ea45e0d-1191-4190-8054-858b1f5f4064', 'text', 'a White Rabbit with pink eyes ran close by her... it occurred to her that she ought to have wondered at this... but when the Rabbit actually _took a watch', 'text:alice-derived.docx', '{"provider_name": "dashscope", "provider_type": "third_party", "parsed_summary": "Alice, bored while sitting beside her sister, contemplates making a daisy-chain; a White Rabbit with pink eyes runs past, speaking anxiously about being late and then takes out a watch.", "parsed_provider_name": "dashscope"}', 'pending_review', NULL, 'system', '2026-07-04 10:08:01.826805', '2026-07-04 10:08:01.826805', NULL, NULL, NULL, NULL, NULL, NULL, false);
