INSERT INTO public.memory_cards VALUES ('34476ba2-c856-48de-905a-657df51d8dcf', '6e71e1ce-8524-4466-8957-b9bd518531f4', 'Alice', 'A young girl named Alice, sitting by her sister on a riverbank, feeling tired and sleepy on a hot day; she is contemplative, curious, and initially unimpressed by a book lacking pictures or conversations.', 'unknown', 'high', 0, '0875b9d4-8981-4c41-8eb7-3298aa48ceea', 'd4f71332-5cd1-4ea2-8aaa-c5c37d1a6ea7', 'text', 'Alice was beginning to get very tired of sitting by her sister on the bank, and of having nothing to do: once or twice she had peeped into the book her sister was reading, but it had no pictures or conversations in it, and what is the use of a book, thought Alice without pictures or conversations? So she was considering in her own mind (as well as she could, for the hot day made her feel very sleepy and stupid), whether the pleasure of making a daisy-chain would be worth the trouble of getting up and picking the daisies', 'text:alice-derived.pdf, page 1', '{"provider_name": "dashscope", "provider_type": "third_party", "parsed_summary": "Alice, bored while sitting with her sister, notices a talking White Rabbit with pink eyes who checks a watch and worries about being late \u2014 an event that initially seems ordinary to her despite its strangeness.", "parsed_provider_name": "dashscope"}', 'pending_review', NULL, 'system', '2026-07-04 10:07:46.885141', '2026-07-04 10:07:46.885141', NULL, NULL, NULL, NULL, NULL, NULL, false);
INSERT INTO public.memory_cards VALUES ('2c881209-5d32-4bea-99ac-b756f8519444', '6e71e1ce-8524-4466-8957-b9bd518531f4', 'White Rabbit', 'A white rabbit with pink eyes who runs close by Alice and speaks aloud to itself, saying ''Oh dear! Oh dear! I shall be late!''', 'unknown', 'high', 0, '0875b9d4-8981-4c41-8eb7-3298aa48ceea', 'd4f71332-5cd1-4ea2-8aaa-c5c37d1a6ea7', 'text', 'a White Rabbit with pink eyes ran close by her... when the Rabbit actually _took a watch', 'text:alice-derived.pdf, page 1', '{"provider_name": "dashscope", "provider_type": "third_party", "parsed_summary": "Alice, bored while sitting with her sister, notices a talking White Rabbit with pink eyes who checks a watch and worries about being late \u2014 an event that initially seems ordinary to her despite its strangeness.", "parsed_provider_name": "dashscope"}', 'pending_review', NULL, 'system', '2026-07-04 10:07:46.885141', '2026-07-04 10:07:46.885141', NULL, NULL, NULL, NULL, NULL, NULL, false);
INSERT INTO public.memory_cards VALUES ('ea521963-95d7-419f-8bbf-4547c76c1112', '6e71e1ce-8524-4466-8957-b9bd518531f4', 'Alice', 'A young girl who feels bored and sleepy while sitting by her sister on a riverbank; she questions the value of books without pictures or conversations; she is contemplative and observant, noting the White Rabbit''s behavior but initially finds it natural rather than remarkable.', 'unknown', 'high', 0, 'e555ff94-1e15-459f-8c5e-142c11c7480e', '67db8a53-a3fb-42be-8d61-29c06e9b6227', 'text', 'Alice was beginning to get very tired of sitting by her sister on the bank, and of having nothing to do: once or twice she had peeped into the book her sister was reading, but it had no pictures or conversations in it, “and what is the use of a book,” thought Alice, “without pictures or conversations?” So she was considering in her own mind (as well as she could, for the hot day made her feel very sleepy and stupid), whether the pleasure of making a daisy-chain would be worth the trouble of getting up and picking the daisies, when suddenly a White Rabbit with pink eyes ran close by her.', 'text:alice-derived.doc', '{"provider_name": "dashscope", "provider_type": "third_party", "parsed_summary": "Alice, bored while sitting with her sister, notices a talking White Rabbit with pink eyes who checks a watch and exclaims about being late \u2014 an event she initially finds unremarkable despite its strangeness.", "parsed_provider_name": "dashscope"}', 'pending_review', NULL, 'system', '2026-07-04 10:08:18.885463', '2026-07-04 10:08:18.885463', NULL, NULL, NULL, NULL, NULL, NULL, false);
INSERT INTO public.memory_cards VALUES ('b67e7ce6-9456-4e4c-8a7b-230b709fe316', '6e71e1ce-8524-4466-8957-b9bd518531f4', 'White Rabbit', 'A white rabbit with pink eyes who runs close by Alice, speaks aloud to itself saying ''Oh dear! Oh dear! I shall be late!'', and later takes out a watch.', 'unknown', 'high', 0, 'e555ff94-1e15-459f-8c5e-142c11c7480e', '67db8a53-a3fb-42be-8d61-29c06e9b6227', 'text', 'when suddenly a White Rabbit with pink eyes ran close by her. There was nothing so _very_ remarkable in that; nor did Alice think it so _very_ much out of the way to hear the Rabbit say to itself, “Oh dear! Oh dear! I shall be late!” ... but when the Rabbit actually _took a watch', 'text:alice-derived.doc', '{"provider_name": "dashscope", "provider_type": "third_party", "parsed_summary": "Alice, bored while sitting with her sister, notices a talking White Rabbit with pink eyes who checks a watch and exclaims about being late \u2014 an event she initially finds unremarkable despite its strangeness.", "parsed_provider_name": "dashscope"}', 'pending_review', NULL, 'system', '2026-07-04 10:08:18.885463', '2026-07-04 10:08:18.885463', NULL, NULL, NULL, NULL, NULL, NULL, false);
