INSERT INTO public.memory_cards VALUES ('cd041faa-abdb-4e47-aa58-f922667982b6', 'e19a2da5-b6ba-40bb-a2fb-3631484a99a5', '画面中无具体人物出镜', '视频画面中没有出现任何具体人物，仅以高空俯瞰的‘上帝视角’或拍摄者第一人称视角呈现。', 'unknown', 'low', 0, '15e974dd-5e0b-480c-8d62-b103c40d5b90', '80436207-f39f-4837-86c9-7d8bb3a9541b', 'video', '画面中无具体人物出镜，以“上帝视角”或拍摄者的第一人称视角呈现，仿佛记忆中的眼睛在注视着这座城市。', 'video:4月8日 (1).mp4#00:00', '{"provider_name": "dashscope", "provider_type": "third_party", "parsed_summary": "\u6839\u636e\u60a8\u63d0\u4f9b\u7684\u89c6\u9891\u5173\u952e\u5e27\uff0c\u8fd9\u662f\u4e00\u6bb5\u5c55\u73b0\u4e0a\u6d77\u57ce\u5e02\u7edd\u7f8e\u5929\u9645\u7ebf\u7684\u73cd\u8d35\u5f71\u50cf\u3002\u4ee5\u4e0b\u662f\u4e3a\u60a8\u751f\u6210\u7684\u89c6\u9891\u573a\u666f\u6458\u8981\uff0c\u9002\u5408\u7528\u4e8e\u201c\u661f\u661f\u9875\u201d\u7684\u73cd\u8d35\u56de\u5fc6\u8bb0\u5f55\uff1a **\u89c6\u9891\u573a\u666f\u6458\u8981\uff1a** \u8fd9\u6bb5\u89c6\u9891\u4ee5\u9ad8\u7a7a\u4fef\u77b0\u7684\u89c6\u89d2\uff0c\u8bb0\u5f55\u4e86\u4e0a\u6d77\u9646\u5bb6\u5634\u53ca\u5916\u6ee9\u4ece\u9ec4\u660f\u65e5\u843d\u5230\u534e\u706f\u521d\u4e0a\u7684\u58ee\u4e3d\u8fc7\u7a0b\u3002\u753b\u9762\u6355\u6349\u4e86\u5929\u7a7a\u8272\u5f69\u4ece\u6e29\u6696\u7684\u6a59\u7ea2\u8272\u665a\u971e\u9010\u6e10\u8fc7\u6e21\u5230\u6df1\u9083\u7684\u591c\u5e55\uff0c\u57ce\u5e02\u706f\u5149\u968f\u4e4b\u70b9\u4eae\uff0c\u5c55\u73b0\u4e86\u9b54\u90fd\u7e41\u534e\u800c\u8ff7\u4eba\u7684\u4e00\u9762\u3002 * **\u4eba\u7269\uff1a** \u753b\u9762\u4e2d\u65e0\u5177\u4f53\u4eba\u7269\u51fa\u955c\uff0c\u4ee5\u201c\u4e0a\u5e1d\u89c6\u89d2\u201d\u6216\u62cd\u6444\u8005\u7684\u7b2c\u4e00\u4eba\u79f0\u89c6\u89d2\u5448\u73b0\uff0c\u4eff\u4f5b\u8bb0\u5fc6\u4e2d\u7684\u773c\u775b\u5728\u6ce8\u89c6\u7740\u8fd9\u5ea7\u57ce\u5e02\u3002 * **\u5730\u70b9\uff1a** \u4e2d\u56fd\u4e0a\u6d77\uff0c\u9646\u5bb6\u5634\u91d1\u878d\u4e2d\u5fc3\uff08\u53ef\u89c1\u4e0a\u6d77\u4e2d\u5fc3\u3001\u73af\u7403\u91d1\u878d\u4e2d\u5fc3\u7b49\u9ad8\u697c\uff09\u53ca\u5916\u6ee9\uff0c\u9ec4\u6d66\u6c5f\u873f\u8712\u5176\u4e2d\u3002 * **\u4e8b\u4ef6\uff1a** \u8bb0\u5f55\u57ce\u5e02\u663c\u591c\u4ea4\u66ff\u7684\u65f6\u523b\u3002\u4ece\u5915\u9633\u897f\u4e0b\u65f6\u7684\u6726\u80e7\u7f8e\u611f\uff0c\u5230\u591c\u665a\u9713\u8679\u95ea\u70c1\u7684\u7e41\u534e\u666f\u8c61\uff0c\u7279\u522b\u662f\u4e1c\u65b9\u660e\u73e0\u5854\u8272\u5f69\u7684\u53d8\u6362\u3002 * **\u60c5\u7eea\uff1a** \u9707\u64bc\u3001\u5b8f\u5927\u3001\u6d6a\u6f2b\u3001\u5b81\u9759\u3002\u4f5c\u4e3a\u73cd\u8d35\u56de\u5fc6\uff0c\u5b83\u5e26\u6709\u4e00\u79cd\u5bf9\u7f8e\u597d\u65f6\u5149\u6d41\u901d\u7684\u7737\u604b\u548c\u5bf9\u57ce\u5e02\u7e41\u534e\u7684\u8d5e\u53f9\u3002 * **\u53ef\u4f5c\u4e3a\u8bb0\u5fc6\u7684\u7247\u6bb5\uff1a** 1. **\u665a\u971e\u6f2b\u5929\uff1a** \u89c6\u9891\u5f00\u59cb\u65f6\uff0c\u5929\u7a7a\u5448\u73b0\u51fa\u6e29\u67d4\u7684\u6a59\u7ea2\u8272\uff0c\u8584\u96fe\u7b3c\u7f69\u7740\u57ce\u5e02\uff0c\u5915\u9633\u7684\u4f59\u6656\u6d12\u5728\u9ec4\u6d66\u6c5f\u9762\u4e0a\u3002 2. **\u534e\u706f\u521d\u4e0a\uff1a** \u968f\u7740\u5929\u8272\u53d8\u6697\uff0c\u4e24\u5cb8\u7684\u5efa\u7b51\u7fa4\u9010\u6e10\u4eae\u8d77\u91d1\u8272\u7684\u706f\u5149\uff0c\u5982\u540c\u661f\u6cb3\u843d\u5730\u3002 3. **\u4e1c\u65b9\u660e\u73e0\u7684\u591c\u8272\uff1a** \u4e1c\u65b9\u660e\u73e0\u5854\u5728\u591c\u8272\u4e2d\u4eae\u8d77\u7eda\u4e3d\u7684\u706f\u5149\uff08\u4ece\u84dd\u767d\u8272\u53d8\u4e3a\u7d2b\u8272\u3001\u7ea2\u8272\uff09\uff0c\u6210\u4e3a\u753b\u9762\u7684\u89c6\u89c9\u7126\u70b9\u3002 4. **\u6d41\u5149\u6ea2\u5f69\u7684\u6c5f\u9762\uff1a** \u9ec4\u6d66\u6c5f\u4e0a\u7684\u8239\u53ea\u7a7f\u68ad\uff0c\u6c5f\u6c34\u5012\u6620\u7740\u4e24\u5cb8\u7684\u706f\u706b\uff0c\u6ce2\u5149\u7cbc\u7cbc\u3002", "parsed_provider_name": "dashscope"}', 'confirmed', NULL, 'system', '2026-07-04 16:03:15.046816', '2026-07-04 17:21:13.563888', '2026-07-04 17:21:13.566034', NULL, NULL, NULL, NULL, NULL, false);
