INSERT INTO public.memory_cards VALUES ('84c2929c-f1e6-4d1c-b4cb-e51f286e32e2', 'e19a2da5-b6ba-40bb-a2fb-3631484a99a5', '刘勤铭实习经历：德国大陆', '德国大陆（Continental）信息部供应链与数据分析组实习生，岗位为产品&数据分析，实习时间为2023年10月至2024年2月；工作内容包括新工厂HR系统项目需求分析与解决方案设计（含Axure原型）、LMS货运指标体系完善与Tableau看板搭建、FineBI海运订单轨迹可视化平台开发、配送商KPI跟踪反馈机制建设与双周复盘会主持。', 'unknown', 'high', 0, '8c059e8d-cd10-4d84-b6aa-33330fefb259', '2edbee1c-b144-4073-b4ae-9c75a6337c52', 'image', '德国大陆 (外企) - 信息部 供应链与数据分析组 实习生-产品&数据分析 2023年10月-2024年2月 • 产品经理：协助项目经理负责新工厂 HR 系统项目……独立完成系统解决方案设计（含Axure绘制简单原型图）……• 数据分析：为改善物流部效率，完善LMS货运指标体系，Tableau搭建货运看板……FineBI开发海运订单轨迹可视化平台……• 协助优化：协助建立货运长期问题跟踪反馈机制，策划并主持双周配送商复盘会……', 'image:简历.png', '{"provider_name": "dashscope", "provider_type": "third_party", "parsed_summary": "\u4e00\u5f20\u8be6\u7ec6\u7684\u4e2d\u6587\u4e2a\u4eba\u7b80\u5386\u957f\u56fe\uff0c\u9876\u90e8\u663e\u793a\u59d3\u540d\u5218\u52e4\u94ed\u53ca\u8054\u7cfb\u65b9\u5f0f\uff0c\u53f3\u4e0a\u89d2\u9644\u6709\u4e00\u5f20\u8eab\u7a7f\u6df1\u8272\u4e0a\u8863\u7684\u7537\u58eb\u534a\u8eab\u7167\u3002\u6b63\u6587\u5185\u5bb9\u5bc6\u96c6\uff0c\u5206\u4e3a\u6559\u80b2\u80cc\u666f\u3001\u5b9e\u4e60\u7ecf\u5386\uff08\u5305\u62ec\u6ef4\u6ef4\u3001\u5b57\u8282\u8df3\u52a8\u3001\u730e\u8058\u7f51\u3001\u5fb7\u56fd\u5927\u9646\uff09\u3001\u9879\u76ee\u7ecf\u5386\u3001\u8363\u8a89\u8bc1\u4e66\u3001\u4e13\u4e1a\u6280\u80fd\u548c\u81ea\u6211\u8bc4\u4ef7\u7b49\u677f\u5757\uff0c\u6392\u7248\u6e05\u6670\u4e13\u4e1a\u3002", "parsed_provider_name": "dashscope"}', 'confirmed', NULL, 'system', '2026-07-04 16:01:15.277739', '2026-07-04 17:21:13.563888', '2026-07-04 17:21:13.566034', NULL, NULL, NULL, NULL, NULL, false);
