INSERT INTO public.memory_cards VALUES ('5301adef-143b-4e20-a2f0-93931dd718d2', '9183ebe2-437b-4d69-be7f-2dec45a29d55', '阿妈的身份（被提及）', '阿妈是老爷爷所提及的人物，其情书被托付保管；资料中未明确说明阿妈与小伟或老爷爷的具体亲属关系，仅指出她是‘情感的核心人物，老爷爷的伴侣或长辈’，但‘伴侣或长辈’属推测性描述，故仅保留‘被老爷爷提及、拥有情书’这一事实。', 'unknown', 'low', 0, '9251c854-6ad8-4468-a337-694a3e93c2d7', '1478a856-0fef-4175-ac45-d8985e3f0e8b', 'video', '小伟，记得保管好阿妈的情书。', 'video:爷爷视频.mp4#00:00', '{"provider_name": "dashscope", "provider_type": "third_party", "parsed_summary": "\u57fa\u4e8e\u60a8\u63d0\u4f9b\u7684\u89c6\u9891\u753b\u9762\uff08AI\u751f\u6210\u7684\u8001\u5b85\u8001\u4eba\u56fe\u50cf\uff09\u548c\u97f3\u9891\u8f6c\u5199\uff0c\u4ee5\u4e0b\u662f\u4e3a\u60a8\u521b\u5efa\u7684\u201c\u661f\u661f\u9875\u201d\u73cd\u8d35\u56de\u5fc6\u573a\u666f\u6458\u8981\uff1a **\u573a\u666f\u6458\u8981\uff1a\u8001\u5b85\u524d\u7684\u53ee\u5631** * **\u4eba\u7269**\uff1a * **\u753b\u9762\u4e3b\u89d2**\uff1a\u4e00\u4f4d\u6ee1\u5934\u94f6\u53d1\u3001\u7a7f\u7740\u6d45\u8272\u886c\u886b\u548c\u5361\u5176\u8272\u957f\u88e4\u7684\u8001\u7237\u7237\uff08\u53ef\u80fd\u662f\u7236\u4eb2\u6216\u7956\u7236\uff09\u3002\u4ed6\u53cc\u624b\u80cc\u5728\u8eab\u540e\uff0c\u795e\u6001\u5b89\u8be6\u3002 * **\u63d0\u53ca\u4eba\u7269**\uff1a\u201c\u5c0f\u4f1f\u201d\uff08\u88ab\u53ee\u5631\u7684\u665a\u8f88\uff09\u3001\u201c\u963f\u5988\u201d\uff08\u60c5\u611f\u7684\u6838\u5fc3\u4eba\u7269\uff0c\u8001\u7237\u7237\u7684\u4f34\u4fa3\u6216\u957f\u8f88\uff09\u3002 * **\u5730\u70b9**\uff1a * \u4e00\u5ea7\u5145\u6ee1\u5c81\u6708\u75d5\u8ff9\u7684\u4f20\u7edf\u8001\u5b85\u5ead\u9662\u95e8\u53e3\u3002\u6591\u9a73\u7684\u5899\u58c1\u3001\u8d34\u7740\u892a\u8272\u7ea2\u5bf9\u8054\u7684\u6728\u95e8\u3001\u4ee5\u53ca\u65c1\u8fb9\u7684\u76c6\u683d\u548c\u6728\u6905\uff0c\u8425\u9020\u51fa\u4e00\u79cd\u6000\u65e7\u3001\u5b81\u9759\u7684\u8001\u5bb6\u6c1b\u56f4\u3002 * **\u4e8b\u4ef6**\uff1a * \u8001\u4eba\u7ad9\u5728\u8001\u5c4b\u95e8\u524d\uff0c\u9762\u5e26\u5fae\u7b11\u5730\u6ce8\u89c6\u7740\u524d\u65b9\uff08\u4eff\u4f5b\u770b\u7740\u5c0f\u4f1f\uff09\u3002\u4ed6\u5728\u53ee\u5631\u5c0f\u4f1f\u8981\u59a5\u5584\u4fdd\u7ba1\u597d\u201c\u963f\u5988\u201d\u7684\u60c5\u4e66\uff0c\u8fd9\u662f\u4e00\u4e2a\u5173\u4e8e\u4f20\u627f\u5bb6\u65cf\u8bb0\u5fc6\u548c\u73cd\u89c6\u60c5\u611f\u7684\u77ac\u95f4\u3002 * **\u60c5\u7eea**\uff1a * **\u6148\u7965\u4e0e\u6e29\u6696**\uff1a\u8001\u4eba\u7684\u7b11\u5bb9\u975e\u5e38\u6e29\u548c\uff0c\u7ed9\u4eba\u4e00\u79cd\u5b89\u5168\u611f\u3002 * **\u6000\u65e7\u4e0e\u6df1\u60c5**\uff1a\u63d0\u5230\u201c\u963f\u5988\u7684\u60c5\u4e66\u201d\uff0c\u8ba9\u753b\u9762\u5145\u6ee1\u4e86\u6d6a\u6f2b\u4e0e\u5c81\u6708\u7684\u6c89\u6dc0\u611f\uff0c\u662f\u5bf9\u8fc7\u53bb\u7f8e\u597d\u65f6\u5149\u7684\u73cd\u89c6\u3002 * **\u53ef\u5f15\u7528\u8bb0\u5fc6**\uff1a * \u201c\u5c0f\u4f1f\uff0c\u8bb0\u5f97\u4fdd\u7ba1\u597d\u963f\u5988\u7684\u60c5\u4e66\u3002\u201d\uff08\u8fd9\u53e5\u8bdd\u662f\u8fd9\u6bb5\u56de\u5fc6\u7684\u6838\u5fc3\uff0c\u8c61\u5f81\u7740\u7231\u7684\u4f20\u627f\u548c\u73cd\u8d35\u7684\u5bb6\u65cf\u5386\u53f2\u3002\uff09", "parsed_provider_name": "dashscope"}', 'pending_review', NULL, 'system', '2026-07-04 17:10:37.701395', '2026-07-04 17:21:08.126502', '2026-07-04 17:21:08.129722', NULL, NULL, NULL, NULL, NULL, false);
INSERT INTO public.memory_cards VALUES ('705a63d3-d9b5-442a-a6c6-4c14c9a1e464', 'ff80949b-3232-47bd-9d64-1b14fb9b28f2', '爷爷所处环境', '传统中式老宅门口，背景为斑驳墙壁、贴有红色对联的木门、青砖地面，周围摆放盆栽和老式木家具，阳光洒落。', 'unknown', 'low', 0, '70b9dbe4-e27c-4d2c-b190-3b9695bb1809', 'c7e0c60a-9ed7-48be-868d-0de7c22188e8', 'image', '背景是斑驳的墙壁、贴着红色对联的木门以及青砖地面，周围摆放着盆栽和老式木家具，阳光洒在身上，充满岁月静好的氛围。', 'image:爷爷图片.png', '{"provider_name": "dashscope", "provider_type": "third_party", "parsed_summary": "\u4e00\u4f4d\u6ee1\u5934\u94f6\u53d1\u7684\u8001\u5e74\u7537\u6027\u7ad9\u5728\u4f20\u7edf\u4e2d\u5f0f\u8001\u5b85\u7684\u95e8\u53e3\uff0c\u8eab\u7a7f\u6d45\u7070\u8272\u957f\u8896\u886c\u886b\u548c\u5361\u5176\u8272\u957f\u88e4\uff0c\u811a\u8e29\u6df1\u7070\u8272\u4f11\u95f2\u978b\uff0c\u53cc\u624b\u80cc\u5728\u8eab\u540e\uff0c\u9762\u5e26\u6e29\u548c\u6148\u7965\u7684\u5fae\u7b11\u3002\u80cc\u666f\u662f\u6591\u9a73\u7684\u5899\u58c1\u3001\u8d34\u7740\u7ea2\u8272\u5bf9\u8054\u7684\u6728\u95e8\u4ee5\u53ca\u9752\u7816\u5730\u9762\uff0c\u5468\u56f4\u6446\u653e\u7740\u76c6\u683d\u548c\u8001\u5f0f\u6728\u5bb6\u5177\uff0c\u9633\u5149\u6d12\u5728\u8eab\u4e0a\uff0c\u5145\u6ee1\u5c81\u6708\u9759\u597d\u7684\u6c1b\u56f4\u3002", "parsed_provider_name": "dashscope"}', 'pending_review', NULL, 'system', '2026-07-04 17:08:05.762613', '2026-07-04 17:21:10.806079', '2026-07-04 17:21:10.808435', NULL, NULL, NULL, NULL, NULL, false);
INSERT INTO public.memory_cards VALUES ('4215f941-2089-4021-a4db-6023160374b0', 'b0cc3808-8bbe-4909-9efa-e3d2a7754b14', '处于诱导性言语引导情境', 'Bambi被置于一种引导性语言环境中，包括深度放松、呼吸指令、''Bambi sleep''重复暗示及服从准备提示。', 'unknown', 'low', 0, '853cff76-40d1-4e79-a13a-539cb591d9b6', '4d25cc08-bad4-43e7-95b2-8c1918ea51fe', 'audio', '让自己开始舒服起来，开始放松，开始深呼吸。吸气，停一下下。再深深的呼气。专心听我说的话，进入Bambi sleep。……让内心做好深深服从的准备，做好条件训练的准备。', 'audio:t00-rapid-induction-3th.mp3#00:00', '{"provider_name": "dashscope", "provider_type": "third_party", "parsed_summary": "\u4f60\u597d\u554a\uff0cBambi\uff0c\u53c8\u89c1\u9762\u4e86\u3002\u4f60\u80fd\u611f\u89c9\u5230\u5417\uff1f\u662f\u7684\uff0cBambi\uff0c\u4f60\u80fd\u611f\u89c9\u5230\u8fd9\u79cd\u611f\u89c9\u6709\u591a\u597d\u662f\u5427\uff1f\u6211\u662f\u6307\u6210\u4e3aBambi\u7684\u611f\u89c9\u3002\u56e0\u4e3a\u4f60\u77e5\u9053\u5c06\u4f1a\u53d1\u751f\u4ec0\u4e48\u3002\u4f60\u4f1a\u8d70\u8def\u7684\u5f88\u6df1\uff0c", "parsed_provider_name": "dashscope"}', 'pending_review', NULL, 'system', '2026-07-04 16:36:33.570284', '2026-07-04 17:21:12.745943', '2026-07-04 17:21:12.748279', NULL, NULL, NULL, NULL, NULL, false);
