INSERT INTO public.memory_cards VALUES ('ed5908e9-b095-46d5-a120-997fe2f06c88', 'ff80949b-3232-47bd-9d64-1b14fb9b28f2', '对联内容与寓意', '木门上贴有红色对联，内容为‘造福苍生福报接接’，资料中明确指出该对联寓意‘造福苍生福报接接’。', 'unknown', 'low', 0, '70b9dbe4-e27c-4d2c-b190-3b9695bb1809', 'c7e0c60a-9ed7-48be-868d-0de7c22188e8', 'image', '背景对联寓意造福苍生福报接接。', 'image:爷爷图片.png', '{"provider_name": "dashscope", "provider_type": "third_party", "parsed_summary": "\u4e00\u4f4d\u6ee1\u5934\u94f6\u53d1\u7684\u8001\u5e74\u7537\u6027\u7ad9\u5728\u4f20\u7edf\u4e2d\u5f0f\u8001\u5b85\u7684\u95e8\u53e3\uff0c\u8eab\u7a7f\u6d45\u7070\u8272\u957f\u8896\u886c\u886b\u548c\u5361\u5176\u8272\u957f\u88e4\uff0c\u811a\u8e29\u6df1\u7070\u8272\u4f11\u95f2\u978b\uff0c\u53cc\u624b\u80cc\u5728\u8eab\u540e\uff0c\u9762\u5e26\u6e29\u548c\u6148\u7965\u7684\u5fae\u7b11\u3002\u80cc\u666f\u662f\u6591\u9a73\u7684\u5899\u58c1\u3001\u8d34\u7740\u7ea2\u8272\u5bf9\u8054\u7684\u6728\u95e8\u4ee5\u53ca\u9752\u7816\u5730\u9762\uff0c\u5468\u56f4\u6446\u653e\u7740\u76c6\u683d\u548c\u8001\u5f0f\u6728\u5bb6\u5177\uff0c\u9633\u5149\u6d12\u5728\u8eab\u4e0a\uff0c\u5145\u6ee1\u5c81\u6708\u9759\u597d\u7684\u6c1b\u56f4\u3002", "parsed_provider_name": "dashscope"}', 'pending_review', NULL, 'system', '2026-07-04 17:08:05.762613', '2026-07-04 17:21:10.806079', '2026-07-04 17:21:10.808435', NULL, NULL, NULL, NULL, NULL, false);
INSERT INTO public.memory_cards VALUES ('4f21d80d-1131-4d64-ac40-52bcbb183053', 'b0cc3808-8bbe-4909-9efa-e3d2a7754b14', '图像内容描述', '图像包含粉蓝渐变风格设计，左侧为闭眼微笑、双手托腮的卡通女孩头像，周围环绕星星和纸飞机；外围环绕粉蓝渐变的海豹（或类似海洋生物）卡通头像；右侧有蓝色艺术字体；右下角含小红书水印及账号信息。', 'unknown', 'low', 0, 'a82de503-382d-4781-97bc-e6ed302ebb68', 'f8b3f60d-5f18-4fc6-b8ca-d94253d5bf45', 'image', '这张图片展示了一个粉蓝渐变风格的数字设计。左侧是一个巨大的圆形图案，中心是一个闭眼微笑、双手托腮的卡通女孩头像，周围环绕着星星和纸飞机。右侧有几行蓝色的艺术字体（看起来像装饰性文字）。图片的外围环绕着一圈从粉色渐变到蓝色的可爱海豹（或类似海洋生物）卡通头像。右下角有小红书的水印及账号信息。', 'image:IMG_4731..JPG', '{"provider_name": "dashscope", "provider_type": "third_party", "parsed_summary": "\u8fd9\u5f20\u56fe\u7247\u5c55\u793a\u4e86\u4e00\u4e2a\u7c89\u84dd\u6e10\u53d8\u98ce\u683c\u7684\u6570\u5b57\u8bbe\u8ba1\u3002\u5de6\u4fa7\u662f\u4e00\u4e2a\u5de8\u5927\u7684\u5706\u5f62\u56fe\u6848\uff0c\u4e2d\u5fc3\u662f\u4e00\u4e2a\u95ed\u773c\u5fae\u7b11\u3001\u53cc\u624b\u6258\u816e\u7684\u5361\u901a\u5973\u5b69\u5934\u50cf\uff0c\u5468\u56f4\u73af\u7ed5\u7740\u661f\u661f\u548c\u7eb8\u98de\u673a\u3002\u53f3\u4fa7\u6709\u51e0\u884c\u84dd\u8272\u7684\u827a\u672f\u5b57\u4f53\uff08\u770b\u8d77\u6765\u50cf\u88c5\u9970\u6027\u6587\u5b57\uff09\u3002\u56fe\u7247\u7684\u5916\u56f4\u73af\u7ed5\u7740\u4e00\u5708\u4ece\u7c89\u8272\u6e10\u53d8\u5230\u84dd\u8272\u7684\u53ef\u7231\u6d77\u8c79\uff08\u6216\u7c7b\u4f3c\u6d77\u6d0b\u751f\u7269\uff09\u5361\u901a\u5934\u50cf\u3002\u53f3\u4e0b\u89d2\u6709\u5c0f\u7ea2\u4e66\u7684\u6c34\u5370\u53ca\u8d26\u53f7\u4fe1\u606f\u3002", "parsed_provider_name": "dashscope"}', 'pending_review', NULL, 'system', '2026-07-04 16:35:43.005579', '2026-07-04 17:21:12.745943', '2026-07-04 17:21:12.748279', NULL, NULL, NULL, NULL, NULL, false);
