INSERT INTO public.memory_cards VALUES ('7b5243da-55c5-4213-afdc-0092e3adab1e', 'e19a2da5-b6ba-40bb-a2fb-3631484a99a5', '刘勤铭实习经历：字节跳动', '字节跳动国际电商TTS用户增长UG商业化广告组实习生，岗位为数据分析，实习时间为2025年5月至2025年9月；工作内容包括ToB/ToC广告效果数据集维护与看板开发、SparkSQL优化、ROI2新指标开发与AB测试验证、高LTV精准人群指标体系完善及AB测试验证。', 'unknown', 'high', 0, '8c059e8d-cd10-4d84-b6aa-33330fefb259', '2edbee1c-b144-4073-b4ae-9c75a6337c52', 'image', '字节跳动 - 国际电商TTS - 用户增长 UG 商业化广告组 实习生 - 数据分析 2025年5月-2025年9月 • ToB/ToC 广告数据分析：维护国际电商商业化广告场景 ToB/ToC 效果数据集……• ROI2 新指标开发：主导新开国ToB广告看板 ROI2 升级口径开发……高LTV精准人群：完善高LTV人群指标体系……进行AB测试验证新LTV人群组vs原LTV人群组……', 'image:简历.png', '{"provider_name": "dashscope", "provider_type": "third_party", "parsed_summary": "\u4e00\u5f20\u8be6\u7ec6\u7684\u4e2d\u6587\u4e2a\u4eba\u7b80\u5386\u957f\u56fe\uff0c\u9876\u90e8\u663e\u793a\u59d3\u540d\u5218\u52e4\u94ed\u53ca\u8054\u7cfb\u65b9\u5f0f\uff0c\u53f3\u4e0a\u89d2\u9644\u6709\u4e00\u5f20\u8eab\u7a7f\u6df1\u8272\u4e0a\u8863\u7684\u7537\u58eb\u534a\u8eab\u7167\u3002\u6b63\u6587\u5185\u5bb9\u5bc6\u96c6\uff0c\u5206\u4e3a\u6559\u80b2\u80cc\u666f\u3001\u5b9e\u4e60\u7ecf\u5386\uff08\u5305\u62ec\u6ef4\u6ef4\u3001\u5b57\u8282\u8df3\u52a8\u3001\u730e\u8058\u7f51\u3001\u5fb7\u56fd\u5927\u9646\uff09\u3001\u9879\u76ee\u7ecf\u5386\u3001\u8363\u8a89\u8bc1\u4e66\u3001\u4e13\u4e1a\u6280\u80fd\u548c\u81ea\u6211\u8bc4\u4ef7\u7b49\u677f\u5757\uff0c\u6392\u7248\u6e05\u6670\u4e13\u4e1a\u3002", "parsed_provider_name": "dashscope"}', 'confirmed', NULL, 'system', '2026-07-04 16:01:15.277739', '2026-07-04 17:21:13.563888', '2026-07-04 17:21:13.566034', NULL, NULL, NULL, NULL, NULL, false);
INSERT INTO public.memory_cards VALUES ('84b480ab-c019-4ece-80ed-2fda46996d6b', 'e19a2da5-b6ba-40bb-a2fb-3631484a99a5', '刘勤铭实习经历：滴滴', '滴滴国际金融Fintech支付风险组实习生，岗位为风控算法，实习时间为2025年10月至2026年6月；工作内容包括支付风险指标异常根因分析系统开发、巴西钱包XGBoost风险模型建设与策略评估、支付风险策略规则自动调优与效果追踪系统开发、国际金融头寸LSTM时间序列预测建模。', 'unknown', 'high', 0, '8c059e8d-cd10-4d84-b6aa-33330fefb259', '2edbee1c-b144-4073-b4ae-9c75a6337c52', 'image', '滴滴 - 国际金融Fintech - 支付风险组Payment Risk 实习生 - 风控算法 2025年10月-2026年6月 • 阻挡指标动标根因分析：开发支付风险指标异常因动根异常系统……• 巴西钱包风险模型：参与巴西钱包 XGBoost 风险模型建设与策略评估……• 支付风险策略规则自动调优与效果追踪系统……• 头寸时间序列预测：参与国际金融头寸预测建模，基于历史入金、出金交易额构建 LSTM 时间序列预测模型……', 'image:简历.png', '{"provider_name": "dashscope", "provider_type": "third_party", "parsed_summary": "\u4e00\u5f20\u8be6\u7ec6\u7684\u4e2d\u6587\u4e2a\u4eba\u7b80\u5386\u957f\u56fe\uff0c\u9876\u90e8\u663e\u793a\u59d3\u540d\u5218\u52e4\u94ed\u53ca\u8054\u7cfb\u65b9\u5f0f\uff0c\u53f3\u4e0a\u89d2\u9644\u6709\u4e00\u5f20\u8eab\u7a7f\u6df1\u8272\u4e0a\u8863\u7684\u7537\u58eb\u534a\u8eab\u7167\u3002\u6b63\u6587\u5185\u5bb9\u5bc6\u96c6\uff0c\u5206\u4e3a\u6559\u80b2\u80cc\u666f\u3001\u5b9e\u4e60\u7ecf\u5386\uff08\u5305\u62ec\u6ef4\u6ef4\u3001\u5b57\u8282\u8df3\u52a8\u3001\u730e\u8058\u7f51\u3001\u5fb7\u56fd\u5927\u9646\uff09\u3001\u9879\u76ee\u7ecf\u5386\u3001\u8363\u8a89\u8bc1\u4e66\u3001\u4e13\u4e1a\u6280\u80fd\u548c\u81ea\u6211\u8bc4\u4ef7\u7b49\u677f\u5757\uff0c\u6392\u7248\u6e05\u6670\u4e13\u4e1a\u3002", "parsed_provider_name": "dashscope"}', 'confirmed', NULL, 'system', '2026-07-04 16:01:15.277739', '2026-07-04 17:21:13.563888', '2026-07-04 17:21:13.566034', NULL, NULL, NULL, NULL, NULL, false);
INSERT INTO public.memory_cards VALUES ('866378e4-dbf6-443d-bca4-42daef84f6e5', 'e19a2da5-b6ba-40bb-a2fb-3631484a99a5', '刘勤铭教育背景', '北京师范大学系统科学专业硕士研究生，就读时间为2024年9月至2027年7月；中国地质大学（北京）软件工程专业本科，就读时间为2019年9月至2023年7月；本科GPA为3.86/4（93.74/100），专业排名3/63。', 'unknown', 'high', 0, '8c059e8d-cd10-4d84-b6aa-33330fefb259', '2edbee1c-b144-4073-b4ae-9c75a6337c52', 'image', '北京师范大学 - 硕士 2024年9月-2027年7月 系统科学专业 中国地质大学(北京) - 本科 2019年9月-2023年7月 软件工程专业 GPA 3.86/4 93.74/100 专业排名 3/63', 'image:简历.png', '{"provider_name": "dashscope", "provider_type": "third_party", "parsed_summary": "\u4e00\u5f20\u8be6\u7ec6\u7684\u4e2d\u6587\u4e2a\u4eba\u7b80\u5386\u957f\u56fe\uff0c\u9876\u90e8\u663e\u793a\u59d3\u540d\u5218\u52e4\u94ed\u53ca\u8054\u7cfb\u65b9\u5f0f\uff0c\u53f3\u4e0a\u89d2\u9644\u6709\u4e00\u5f20\u8eab\u7a7f\u6df1\u8272\u4e0a\u8863\u7684\u7537\u58eb\u534a\u8eab\u7167\u3002\u6b63\u6587\u5185\u5bb9\u5bc6\u96c6\uff0c\u5206\u4e3a\u6559\u80b2\u80cc\u666f\u3001\u5b9e\u4e60\u7ecf\u5386\uff08\u5305\u62ec\u6ef4\u6ef4\u3001\u5b57\u8282\u8df3\u52a8\u3001\u730e\u8058\u7f51\u3001\u5fb7\u56fd\u5927\u9646\uff09\u3001\u9879\u76ee\u7ecf\u5386\u3001\u8363\u8a89\u8bc1\u4e66\u3001\u4e13\u4e1a\u6280\u80fd\u548c\u81ea\u6211\u8bc4\u4ef7\u7b49\u677f\u5757\uff0c\u6392\u7248\u6e05\u6670\u4e13\u4e1a\u3002", "parsed_provider_name": "dashscope"}', 'confirmed', NULL, 'system', '2026-07-04 16:01:15.277739', '2026-07-04 17:21:13.563888', '2026-07-04 17:21:13.566034', NULL, NULL, NULL, NULL, NULL, false);
INSERT INTO public.memory_cards VALUES ('8d3e0dc3-07ad-4ff3-9863-b6650fd657d6', '18b88e96-5633-4d75-b77a-0ad1988a846a', '郑木生曾下南洋', '郑木生年轻时下南洋，曾在橡胶林工作，住工棚，使用煤油灯。', 'basic_fact', 'high', 0, '478ea404-8b05-4ba0-b440-ca4b846c92a1', 'ae464e94-48be-42cd-aaf5-c203fb72c35e', 'manual', '他记得自己年轻时下南洋的经历。他记得厦门码头的船，记得离开家乡那天的海风，记得阿嬷给他的布包，记得橡胶林里的雨，记得工棚里的煤油灯，也记得每个月把工钱寄回家的心情。', 'manual:body', '{"provider_name": "dashscope", "provider_type": "third_party", "parsed_summary": "\u7237\u7237\u5e74\u8f7b\u65f6\u4e0b\u5357\u6d0b\u7684\u8bb0\u5fc6\uff0c\u5305\u62ec\u53a6\u95e8\u7801\u5934\u3001\u79bb\u4e61\u6d77\u98ce\u3001\u963f\u5b37\u6240\u8d60\u5e03\u5305\u3001\u6a61\u80f6\u6797\u964d\u96e8\u3001\u5de5\u68da\u7164\u6cb9\u706f\u53ca\u5bc4\u94b1\u56de\u5bb6\u7684\u5fc3\u60c5\u3002", "parsed_provider_name": "dashscope", "structured_memory_source": "memory_extraction", "memory_module": "basic_fact", "structured_memory_warnings": []}', 'pending_review', NULL, 'system', '2026-07-04 23:30:07.450752', '2026-07-04 23:30:07.450752', NULL, NULL, NULL, NULL, NULL, NULL, false);
INSERT INTO public.memory_cards VALUES ('9594d706-e933-4828-8033-7d0ae1617558', 'e19a2da5-b6ba-40bb-a2fb-3631484a99a5', '刘勤铭实习经历：猎聘网', '猎聘网技术部AI中心算法组实习生，岗位为大模型算法，实习时间为2025年1月至2025年5月；工作内容包括招聘JD与CV匹配项目的模型蒸馏（采用SFT和DPO方法）、240万原始数据全流程处理（含Spark取数、Prompt构造、分层清洗、embedding聚类去重、质量打分等）、数据分布分析与质量问题解决。', 'unknown', 'high', 0, '8c059e8d-cd10-4d84-b6aa-33330fefb259', '2edbee1c-b144-4073-b4ae-9c75a6337c52', 'image', '猎聘网 - 技术部AI中心 算法组 实习生-大模型算法 2025年1月-2025年5月 • 模型训练：负责招聘岗位说明 JD 与候选人简历 CV 整体匹配项目的模型蒸馏……• 数据清洗：快速对接新产品方，接手模型数据全流程，包括Spark取240w原始数据-正负样本合并-写Promptt模型总结字段-数据分层次清洗-embedding聚类去重数据-数据打质量分准度分-合并9w训练数据集等……• 质量质量：分析数据分布形态……发现并解决10余次多层次数据质量问题……', 'image:简历.png', '{"provider_name": "dashscope", "provider_type": "third_party", "parsed_summary": "\u4e00\u5f20\u8be6\u7ec6\u7684\u4e2d\u6587\u4e2a\u4eba\u7b80\u5386\u957f\u56fe\uff0c\u9876\u90e8\u663e\u793a\u59d3\u540d\u5218\u52e4\u94ed\u53ca\u8054\u7cfb\u65b9\u5f0f\uff0c\u53f3\u4e0a\u89d2\u9644\u6709\u4e00\u5f20\u8eab\u7a7f\u6df1\u8272\u4e0a\u8863\u7684\u7537\u58eb\u534a\u8eab\u7167\u3002\u6b63\u6587\u5185\u5bb9\u5bc6\u96c6\uff0c\u5206\u4e3a\u6559\u80b2\u80cc\u666f\u3001\u5b9e\u4e60\u7ecf\u5386\uff08\u5305\u62ec\u6ef4\u6ef4\u3001\u5b57\u8282\u8df3\u52a8\u3001\u730e\u8058\u7f51\u3001\u5fb7\u56fd\u5927\u9646\uff09\u3001\u9879\u76ee\u7ecf\u5386\u3001\u8363\u8a89\u8bc1\u4e66\u3001\u4e13\u4e1a\u6280\u80fd\u548c\u81ea\u6211\u8bc4\u4ef7\u7b49\u677f\u5757\uff0c\u6392\u7248\u6e05\u6670\u4e13\u4e1a\u3002", "parsed_provider_name": "dashscope"}', 'confirmed', NULL, 'system', '2026-07-04 16:01:15.277739', '2026-07-04 17:21:13.563888', '2026-07-04 17:21:13.566034', NULL, NULL, NULL, NULL, NULL, false);
INSERT INTO public.memory_cards VALUES ('fae18427-0229-443c-9d5d-302e43d7fadd', 'e19a2da5-b6ba-40bb-a2fb-3631484a99a5', '可信人格记忆Agent产品', '该产品将用户对亲友的记忆融合为可交互的数字人；依托语音、视频、文字、图片等多模态资料，构建具备记忆溯源、人格边界和授权机制的数字人格体；服务于亲友纪念、虚拟角色、专家经验复刻、个人助手、私人家教、企业知识沉淀等场景；核心目标是支持对话、回顾与情感陪伴，帮助用户弥补遗憾、产生新的记忆。', 'unknown', 'low', 0, 'fd41e9e1-9006-417d-bddf-6f38c6aaa8b7', '8697ceb1-0c7e-404c-bf19-e3a6e887f948', 'text', '武汉市鲲鹏灵境科技有限公司研发的可信人格记忆Agent产品，将用户对亲友的记忆融合为可交互的数字人；依托语音、视频、文字、图片等多模态资料，构建具备记忆溯源、人格边界和授权机制的数字人格体；服务于亲友纪念、虚拟角色、专家经验复刻、个人助手、私人家教、企业知识沉淀等场景；核心目标是支持对话、回顾与情感陪伴，帮助用户弥补遗憾、产生新的记忆。', '一、产品介绍', '{"provider_name": "dashscope", "provider_type": "third_party", "parsed_summary": "\u5b9a\u4e49\u4ea7\u54c1\u672c\u8d28\u3001\u8f93\u5165\u65b9\u5f0f\u3001\u5173\u952e\u7279\u6027\uff08\u8bb0\u5fc6\u6eaf\u6e90/\u4eba\u683c\u8fb9\u754c/\u6388\u6743\uff09\u53ca\u6838\u5fc3\u5e94\u7528\u573a\u666f\u4e0e\u60c5\u611f\u4ef7\u503c\u3002", "parsed_provider_name": "dashscope"}', 'confirmed', NULL, 'system', '2026-07-04 16:04:01.463902', '2026-07-04 17:21:13.563888', '2026-07-04 17:21:13.566034', NULL, NULL, NULL, NULL, NULL, false);
