INSERT INTO public.memory_cards VALUES ('2187f3ca-2889-48c9-ac15-0aec8506e9dd', '18b88e96-5633-4d75-b77a-0ad1988a846a', '郑木生外貌特征', '满头银发，身穿浅灰色长袖衬衫和卡其色长裤，双手背在身后，面带温和慈祥的笑容', 'basic_fact', 'high', 0, 'b393bc2c-b467-4cd0-8655-0a8ad5d861f7', '6972462e-03bc-4d03-8f23-330de1fa9013', 'image', '一位满头银发的老人站在古朴的老宅木门前，身穿浅灰色长袖衬衫和卡其色长裤，双手背在身后，面带温和慈祥的笑容。', 'image:爷爷图片.png', '{"provider_name": "dashscope", "provider_type": "third_party", "parsed_summary": "\u4e00\u4f4d\u6ee1\u5934\u94f6\u53d1\u7684\u8001\u4eba\u7ad9\u5728\u53e4\u6734\u7684\u8001\u5b85\u6728\u95e8\u524d\uff0c\u8eab\u7a7f\u6d45\u7070\u8272\u957f\u8896\u886c\u886b\u548c\u5361\u5176\u8272\u957f\u88e4\uff0c\u53cc\u624b\u80cc\u5728\u8eab\u540e\uff0c\u9762\u5e26\u6e29\u548c\u6148\u7965\u7684\u7b11\u5bb9\u3002\u95e8\u6846\u4e24\u4fa7\u8d34\u7740\u7ea2\u8272\u7684\u5bf9\u8054\uff0c\u5468\u56f4\u6446\u653e\u7740\u76c6\u683d\u3001\u6728\u6905\u548c\u9676\u7f50\uff0c\u5730\u9762\u94fa\u7740\u77f3\u677f\uff0c\u9633\u5149\u6d12\u5728\u8eab\u4e0a\uff0c\u753b\u9762\u5145\u6ee1\u5c81\u6708\u9759\u597d\u7684\u751f\u6d3b\u6c14\u606f\u3002", "parsed_provider_name": "dashscope", "structured_memory_source": "memory_extraction", "memory_module": "basic_fact", "structured_memory_warnings": []}', 'corrected', '满头银发，身穿浅灰色长袖衬衫和卡其色长裤，双手背在身后，面带温和慈祥的笑容', 'system', '2026-07-04 19:42:01.533242', '2026-07-04 20:40:44.987488', NULL, NULL, NULL, NULL, NULL, NULL, true);
