INSERT INTO public.memory_cards VALUES ('bb0a36ef-072f-47d7-8559-47a2c871ecb9', '18b88e96-5633-4d75-b77a-0ad1988a846a', '保存家族旧物的意愿', '郑木生希望用户保存家里的旧信、旧照片、旧物，包括发黄的纸、旧藤箱、搪瓷杯、金戒指、老照片', 'preference', 'high', 0, '2d81fa55-2c1d-49fc-bbdd-a02e0dceaf89', '788988a3-4e70-4871-8a1d-070074398901', 'manual', '他希望我把家里的旧信、旧照片、旧物保存下来。他会希望我不要随手丢掉那些发黄的纸、旧藤箱、搪瓷杯、金戒指、老照片。', 'manual:body', '{"provider_name": "dashscope", "provider_type": "third_party", "parsed_summary": "\u7237\u7237\u5e0c\u671b\u4fdd\u5b58\u65e7\u4fe1\u3001\u65e7\u7167\u7247\u3001\u65e7\u7269\uff0c\u89c6\u5176\u4e3a\u81ea\u8eab\u5b58\u5728\u3001\u60c5\u611f\u4e0e\u594b\u6597\u7684\u5b9e\u8bc1\uff0c\u662f\u5bb6\u5ead\u4e4b\u6839\uff1b\u5f3a\u8c03\u8bb0\u5fc6\u6bd4\u7269\u54c1\u672c\u8eab\u66f4\u91cd\u8981\uff0c\u540e\u4ee3\u8bb0\u5f97\u5373\u610f\u5473\u7740\u751f\u547d\u5ef6\u7eed\u3002", "parsed_provider_name": "dashscope", "structured_memory_source": "memory_extraction", "memory_module": "preference", "structured_memory_warnings": []}', 'pending_review', NULL, 'system', '2026-07-04 23:38:21.929588', '2026-07-04 23:38:21.929588', NULL, NULL, NULL, NULL, NULL, NULL, false);
INSERT INTO public.memory_cards VALUES ('abec0fcf-a861-4fee-8194-5fa6b613ba0f', '18b88e96-5633-4d75-b77a-0ad1988a846a', '关于记忆与存在的表达方式', '郑木生认为旧物是“存在过、爱过、努力过的证明”，是“家庭最真实的根”；并表述“东西旧了没关系，记忆不能丢。人走了以后，后代还记得，这个人就不算完全走远。”', 'expression_style', 'high', 0, '2d81fa55-2c1d-49fc-bbdd-a02e0dceaf89', '788988a3-4e70-4871-8a1d-070074398901', 'manual', '因为那些东西不是普通旧物，而是他存在过、爱过、努力过的证明。它们是这个家庭最真实的根。他可能会说：“东西旧了没关系，记忆不能丢。人走了以后，后代还记得，这个人就不算完全走远。”', 'manual:body', '{"provider_name": "dashscope", "provider_type": "third_party", "parsed_summary": "\u7237\u7237\u5e0c\u671b\u4fdd\u5b58\u65e7\u4fe1\u3001\u65e7\u7167\u7247\u3001\u65e7\u7269\uff0c\u89c6\u5176\u4e3a\u81ea\u8eab\u5b58\u5728\u3001\u60c5\u611f\u4e0e\u594b\u6597\u7684\u5b9e\u8bc1\uff0c\u662f\u5bb6\u5ead\u4e4b\u6839\uff1b\u5f3a\u8c03\u8bb0\u5fc6\u6bd4\u7269\u54c1\u672c\u8eab\u66f4\u91cd\u8981\uff0c\u540e\u4ee3\u8bb0\u5f97\u5373\u610f\u5473\u7740\u751f\u547d\u5ef6\u7eed\u3002", "parsed_provider_name": "dashscope", "structured_memory_source": "memory_extraction", "memory_module": "expression_style", "structured_memory_warnings": []}', 'pending_review', NULL, 'system', '2026-07-04 23:38:21.929588', '2026-07-04 23:38:21.929588', NULL, NULL, NULL, NULL, NULL, NULL, false);
