INSERT INTO public.memory_cards VALUES ('f5c70fcd-119f-4d30-8101-2562cc89ef8a', '18b88e96-5633-4d75-b77a-0ad1988a846a', '阿嬷赠予郑木生的物品', '阿嬷缝制小布包，内含家乡土、一枚铜钱、一张写有“木生，平安回来”的纸条', 'basic_fact', 'high', 0, 'aab79b82-c415-4cbc-8b5d-021a5b656e66', 'fed2c8a4-d60f-48fc-9ee8-db109ed130fc', 'manual', '阿嬷给爷爷缝了一个小布包，里面装了一小撮家乡的土、一枚铜钱，还有一张她写的小纸条。纸条上的字很简单： “木生，平安回来。”', 'manual:body#section2', '{"provider_name": "dashscope", "provider_type": "third_party", "parsed_summary": "1952\u5e74\uff0c18\u5c81\u7684\u7237\u7237\u90d1\u6728\u751f\u56e0\u5bb6\u5ead\u56f0\u987f\uff08\u7956\u5c4b\u6f0f\u96e8\u3001\u592a\u516c\u75c5\u5f31\u3001\u5f1f\u59b9\u5e74\u5e7c\u3001\u6b20\u7c73\u94fa\u503a\uff09\u4f5c\u4e3a\u957f\u5b50\u79bb\u4e61\u4e0b\u5357\u6d0b\u3002\u51fa\u53d1\u524d\u591c\uff0c\u672a\u5a5a\u59bb\u963f\u5b37\u8d60\u542b\u5bb6\u4e61\u571f\u3001\u94dc\u94b1\u53ca\u201c\u6728\u751f\uff0c\u5e73\u5b89\u56de\u6765\u201d\u7eb8\u6761\u7684\u5e03\u5305\u3002\u4ed6\u4ece\u53a6\u95e8\u4e58\u8239\u8d74\u5357\u6d0b\uff0c\u8239\u4e0a\u62e5\u6324\uff0c\u4ec5\u643a\u85e4\u7bb1\uff08\u4e24\u4ef6\u8863\u3001\u5e03\u978b\u3001\u5e72\u7cae\u3001\u5e03\u5305\uff09\uff0c\u6d77\u4e0a\u98ce\u6d6a\u98a0\u7c38\uff0c\u9760\u5bb6\u4e61\u571f\u652f\u6491\u4fe1\u5ff5\u3002", "parsed_provider_name": "dashscope", "structured_memory_source": "memory_extraction", "memory_module": "basic_fact", "structured_memory_warnings": []}', 'pending_review', NULL, 'system', '2026-07-04 23:24:35.574076', '2026-07-04 23:24:35.574076', NULL, NULL, NULL, NULL, NULL, NULL, false);
