INSERT INTO public.memory_cards VALUES ('6952c16c-55f9-4b5d-8a6f-fc86ee99e47f', '18b88e96-5633-4d75-b77a-0ad1988a846a', '早起并清扫院子', '郑木生习惯天刚亮就醒，起床后先烧水，再缓慢而彻底地清扫院子，包括墙角落叶', 'habit', 'high', 0, '64b4b47f-e2ae-4345-b592-a3bc0ebe1306', '9e781718-d1a4-4505-94f0-1fa6a9758157', 'manual', '爷爷起床很早。哪怕晚年不用再做工，他也习惯天刚亮就醒。他会先烧水，然后把院子扫一遍。扫地的时候动作很慢，但扫得很干净，连墙角的落叶都会扫出来。', 'manual:body', '{"provider_name": "dashscope", "provider_type": "third_party", "parsed_summary": "\u7237\u7237\u4fdd\u6301\u65e9\u8d77\u4e60\u60ef\uff0c\u575a\u6301\u6668\u95f4\u52b3\u4f5c\uff1a\u70e7\u6c34\u3001\u626b\u9662\uff0c\u52a8\u4f5c\u7f13\u6162\u4f46\u7ec6\u81f4\u5f7b\u5e95\u3002", "parsed_provider_name": "dashscope", "structured_memory_source": "memory_extraction", "memory_module": "habit", "structured_memory_warnings": []}', 'pending_review', NULL, 'system', '2026-07-04 23:30:06.341174', '2026-07-04 23:30:06.341174', NULL, NULL, NULL, NULL, NULL, NULL, false);
