INSERT INTO public.memory_cards VALUES ('ff9a6fae-4179-491c-b19c-45942f51e0af', '18b88e96-5633-4d75-b77a-0ad1988a846a', '郑木生婚宴简朴', '郑木生与阿嬷的婚礼没有盛大的仪式和婚纱照，婚宴仅摆了几桌简单的饭菜。', 'basic_fact', 'high', 0, '17761b2c-f5b6-42cd-9919-0348964c0c53', '4d99568f-2b11-4c82-8478-2ccbc50abf1c', 'manual', '他们没有盛大的婚礼，也没有漂亮的婚纱照。那时家里还是穷，婚宴只是摆了几桌简单的饭菜。', 'manual:body', '{"provider_name": "dashscope", "provider_type": "third_party", "parsed_summary": "\u7237\u7237\u56de\u4e61\u540e\u4e0e\u963f\u5b37\u7b80\u6734\u7ed3\u5a5a\uff0c\u8d60\u4e88\u5176\u4e00\u679a\u5357\u6d0b\u7701\u4e0b\u7684\u5c0f\u91d1\u6212\u6307\u3002", "parsed_provider_name": "dashscope", "structured_memory_source": "memory_extraction", "memory_module": "basic_fact", "structured_memory_warnings": []}', 'pending_review', NULL, 'system', '2026-07-04 23:30:05.287085', '2026-07-04 23:30:05.287085', NULL, NULL, NULL, NULL, NULL, NULL, false);
INSERT INTO public.memory_cards VALUES ('6ef6c509-72ed-4bad-a6e2-c75ad6aea90c', '18b88e96-5633-4d75-b77a-0ad1988a846a', '郑木生赠予阿嬷小金戒指', '郑木生将一枚从南洋带回来的小金戒指赠予阿嬷，该戒指由其在异乡省吃俭用攒钱购买。', 'basic_fact', 'high', 0, '17761b2c-f5b6-42cd-9919-0348964c0c53', '4d99568f-2b11-4c82-8478-2ccbc50abf1c', 'manual', '爷爷给阿嬷戴上那枚从南洋带回来的小金戒指。戒指不大，样式也普通，却是他在异乡省吃俭用攒下来的。', 'manual:body', '{"provider_name": "dashscope", "provider_type": "third_party", "parsed_summary": "\u7237\u7237\u56de\u4e61\u540e\u4e0e\u963f\u5b37\u7b80\u6734\u7ed3\u5a5a\uff0c\u8d60\u4e88\u5176\u4e00\u679a\u5357\u6d0b\u7701\u4e0b\u7684\u5c0f\u91d1\u6212\u6307\u3002", "parsed_provider_name": "dashscope", "structured_memory_source": "memory_extraction", "memory_module": "basic_fact", "structured_memory_warnings": []}', 'pending_review', NULL, 'system', '2026-07-04 23:30:05.287085', '2026-07-04 23:30:05.287085', NULL, NULL, NULL, NULL, NULL, NULL, false);
INSERT INTO public.memory_cards VALUES ('d9ed50b0-d528-487c-873d-d584bb679ce8', '18b88e96-5633-4d75-b77a-0ad1988a846a', '郑木生与阿嬷为夫妻关系', '郑木生与阿嬷系配偶关系，婚后共同生活。', 'relationship', 'high', 0, '17761b2c-f5b6-42cd-9919-0348964c0c53', '4d99568f-2b11-4c82-8478-2ccbc50abf1c', 'manual', '爷爷回乡后，和阿嬷结了婚。', 'manual:body', '{"provider_name": "dashscope", "provider_type": "third_party", "parsed_summary": "\u7237\u7237\u56de\u4e61\u540e\u4e0e\u963f\u5b37\u7b80\u6734\u7ed3\u5a5a\uff0c\u8d60\u4e88\u5176\u4e00\u679a\u5357\u6d0b\u7701\u4e0b\u7684\u5c0f\u91d1\u6212\u6307\u3002", "parsed_provider_name": "dashscope", "structured_memory_source": "memory_extraction", "memory_module": "relationship", "structured_memory_warnings": []}', 'pending_review', NULL, 'system', '2026-07-04 23:30:05.287085', '2026-07-04 23:30:05.287085', NULL, NULL, NULL, NULL, NULL, NULL, false);
