INSERT INTO public.memory_stories VALUES ('91d965cf-125f-45ca-847f-30c2a4e6a150', '1aee8903-eba4-48f5-a5ee-1c37af11a524', '家常', '家常里的回忆', '小铭，我想给你讲一段关于家常的回忆。我记得小铭生日那天，外婆准备了蛋糕和一碗热汤，笑着说只要小铭平安就好；外婆喜欢给小铭包馄饨，也常说饭要趁热慢慢吃；外婆常说慢慢来，别急，心里难受的时候先把气喘匀。这些我只能按已经确认的记忆慢慢说给你听。', 'mock://tts/1aee8903-eba4-48f5-a5ee-1c37af11a524/b83b9a16-1ffd-4b80-b8d1-12db07dff9bc.wav', '["f556d42a-2f3f-4d26-a003-e49ae9ab8f76", "bf4b210a-8007-44b4-bdfd-95907c58e77e", "2bcc8624-f259-4837-a1fd-dbc4b163d670"]', '[{"memory_card_id": "f556d42a-2f3f-4d26-a003-e49ae9ab8f76", "title": "\u8d44\u6599\u4e2d\u7684\u8868\u8fbe\u4e60\u60ef", "quote": "\u5c0f\u94ed\u751f\u65e5\u90a3\u5929\uff0c\u5916\u5a46\u51c6\u5907\u4e86\u86cb\u7cd5\u548c\u4e00\u7897\u70ed\u6c64\uff0c\u7b11\u7740\u8bf4\u53ea\u8981\u5c0f\u94ed\u5e73\u5b89\u5c31\u597d", "source_location": "manual:body#1"}, {"memory_card_id": "bf4b210a-8007-44b4-bdfd-95907c58e77e", "title": "\u8d44\u6599\u4e2d\u7684\u504f\u597d\u8bb0\u5fc6", "quote": "\u5916\u5a46\u559c\u6b22\u7ed9\u5c0f\u94ed\u5305\u9984\u9968\uff0c\u4e5f\u5e38\u8bf4\u996d\u8981\u8d81\u70ed\u6162\u6162\u5403", "source_location": "manual:body#1"}, {"memory_card_id": "2bcc8624-f259-4837-a1fd-dbc4b163d670", "title": "\u8d44\u6599\u4e2d\u7684\u8868\u8fbe\u4e60\u60ef", "quote": "\u5916\u5a46\u5e38\u8bf4\u6162\u6162\u6765\uff0c\u522b\u6025\uff0c\u5fc3\u91cc\u96be\u53d7\u7684\u65f6\u5019\u5148\u628a\u6c14\u5598\u5300", "source_location": "manual:body#1"}]', false, '{"provider": {"provider_name": "mock", "capability": "story_generation", "status": "succeeded"}, "generate_story_job_id": "4f7f89fb-b2d5-4449-b5bd-49aa66413dee", "synthesize_speech_job_id": "b83b9a16-1ffd-4b80-b8d1-12db07dff9bc", "voice": {"voice_status": "default_tts", "default_tts_notice": "\u5f53\u524d\u4f7f\u7528\u7cfb\u7edf\u9ed8\u8ba4\u58f0\u97f3\uff0c\u4e0d\u662f TA \u7684\u771f\u5b9e\u58f0\u97f3\u3002\u4e0a\u4f20 TA \u7684\u6e05\u6670\u8bed\u97f3\u540e\uff0c\u53ef\u4ee5\u5c1d\u8bd5\u751f\u6210\u6a21\u62df\u97f3\u8272\u3002"}}', '2026-07-