INSERT INTO public.memory_stories VALUES ('1822c283-350d-474b-ba02-72f00f7ed0f9', 'f25d83e6-0885-4844-8603-490c00d54be4', 'birthday', 'birthday', '<think>The user wants me to generate a warm first-person memory story from Grandma''s perspective, using only the provided reviewed memory. The theme is birthday and the nickname for the user is "Child". The retrieved memory is: - ID: 245e37d5-a7a3-48df-b6fa-9c53eb5b4134 - Title: Birthday wontons - Content: "Grandma liked making wontons on birthdays." - Quote: "making wontons on birthdays" - Source: smoke:manual#1 I need to create a warm, first-person memory story from Grandma''s perspective about making wontons on birthdays. I should expand on this memory in a heartfelt way, while keeping it based only on this single memory. I''ll craft a cozy, loving story about the tradition of making wontons together on birthdays. Let me write a warm story that captures the love, tradition, and special moments of making birthday wontons together.</think> ```json { "title": "Birthday Wontons with Grandma", "content": "Oh, Child, do you remember when it was your birthday? Every single year, I would wake up before the sun even thought about rising, and I would head straight to the kitchen to make wontons for you. It was our special little tradition, just you and me.\n\nI would lay out the wrappers so carefully on the wooden board, and I would mix the filling just the way you liked it. My hands moved slowly, folding each little wonton into its perfect shape, thinking about how lucky I was to have you in my life. The kitchen would fill up with that lovely smell, and I would hum little songs while I worked, happy as could be.\n\nWhen you came padding into the kitchen in your pajamas, still sleepy-eyed and looking for me, I would smile and pat the chair next to me. \"Come sit, my darling,\" I would say. \"Grandma is making your birthday wontons today.\" And your face would light up like the candles on your cake, even though the cake hadn''t come out yet!\n\nWe would boil them up nice and gentle, and I would watch you slurp them down, and my heart would feel so full it might just burst. Making wontons on birthdays, Child, that was my way of wrapping you up in love, one little dumpling at a time. Every fold was a wish for your happiness, every pinch was a prayer for your good health. And every birthday, I loved you more than the year before.", "source_memory_ids": ["245e37d5-a7a3-48df-b6fa-9c53eb5b4134"], "source_memories": ["Grandma liked making wontons on birthdays."] } ```', 'https://minimax-algeng-chat-tts.oss-cn-wulanchabu.aliyuncs.com/audio%2Feffect%2F0698093b52c28b95d40b5f298b3178dc_1783158334952_2818.mp3?Expires=1783244735&OSSAccessKeyId=LTAI5tGLnRTkBjLuYPjNcKQ8&Signature=OCItuA5g5Ll3aJes26sjlmjB3lc%3D', '["245e37d5-a7a3-48df-b6fa-9c53eb5b4134"]', '[{"memory_card_id": "245e37d5-a7a3-48df-b6fa-9c53eb5b4134", "title": "Birthday wontons", "quote": "making wontons on birthdays", "source_location": "smoke:manual#1"}]', false, '{"provider": {"provider_name": "minimax", "capability": "story_generation", "status": "succeeded"}, "generate_story_job_id": "a0b14bfe-ac3f-4621-bc34-21dad8ea3562", "synthesize_speech_job_id": "0eb30948-97dc-4af8-8832-a84016647cfb", "voice": {"voice_status": "default_tts", "default_tts_notice": "\u5f53\u524d\u4f7f\u7528\u7cfb\u7edf\u9ed8\u8ba4\u58f0\u97f3\uff0c\u4e0d\u662f TA \u7684\u771f\u5b9e\u58f0\u97f3\u3002\u4e0a\u4f20 TA \u7684\u6e05\u6670\u8bed\u97f3\u540e\uff0c\u53ef\u4ee5\u5c1d\u8bd5\u751f\u6210\u6a21\u62df\u97f3\u8272\u3002"}}', '2026-07-04 09:45:20.51321', '2026-07-04 09:45:20.51321', NULL);
INSERT INTO public.memory_stories VALUES ('146840ef-3b81-4bab-8f74-6325d7c1d347', '961b0a22-d2be-4646-853e-92be0f5708b1', '?????', '?????', '<think>The user has provided a prompt template for generating a memory story. Let me analyze what''s being asked: 1. The story_theme, user_nickname_by_persona, and the retrieved memories all contain question marks (??????) which suggests the actual values are missing or obfuscated. 2. The retrieved memory has: - id: "63af0004-f6d5-4621-9116-d1e25b2b590e" - title: "????" (question marks) - content: "???????????????" (question marks) - quote: "???????????????" (question marks) - source_location: "manual:minimax-api-smoke" 3. The developer policy says to generate a warm first-person memory story using only the provided reviewed memories. 4. The system policy establishes the model identity as MiniMax-M3. 5. The instruction says to return strict JSON with: title, content, source_memory_ids, and source_memories. The problem is that the actual memory content is all question marks - there''s no real content to work with. I cannot generate a meaningful story from question marks. I should be honest about this limitation rather than fabricating content. Wait, but looking at the developer policy more carefully - it says "Use only the provided reviewed memories." The memories provided are essentially blank (all question marks). I cannot create a story from no content. However, I also need to follow the format requirement. Let me think about what the right approach is: 1. I could generate a story but it would be entirely fabricated since there''s no real memory content 2. I should be honest that the memories are empty/unreadable Actually, re-reading the prompt - the question marks might be placeholder text that was meant to be filled in but wasn''t, or they might indicate redacted/missing data. The instruction says "Use only the provided reviewed memories" - and the provided memories have no real content. I think the best approach is to acknowledge that the memory content is unreadable/empty and return a JSON response indicating this, or generate something minimal based on what little metadata is available (the source_location says "manual:minimax-api-smoke" which might indicate this is a test/smoke test). Let me create a response that acknowledges the empty memories while still following the JSON format. I''ll make the response honest about the situation - that there are no usable memories to base a story on. Actually, looking at this again - this seems like it might be a test case (source_location: "manual:minimax-api-smoke"). The question marks might be intentional placeholders to test how the model handles empty/unreadable memory content. I should respond with valid JSON that: 1. Follows the required format (title, content, source_memory_ids, source_memories) 2. Is honest about the empty memories 3. Doesn''t fabricate content from non-existent memories Let me craft a response that''s warm but honest about the lack of usable memory data.</think> ```json { "title": "An Empty Page", "content": "Dear friend, I sat down today hoping to weave a story from the memories shared with me, but the threads I was given turned out to be blank — their words obscured, their moments hidden behind silence. Rather than invent details that were never truly offered, I want to be honest with you: the memories I have to work with right now carry no readable content, only echoes. So instead of a tale built on someone else''s recollections, I offer you this small truth — sometimes the kindest thing we can do is pause, admit what we don''t yet know, and wait for the real stories to arrive. When your memories come through clearly, I will be here, ready to turn them into something warm and worth keeping.", "source_memory_ids": ["63af0004-f6d5-4621-9116-d1e25b2b590e"], "source_memories": [ { "id": "63af0004-f6d5-4621-9116-d1e25b2b590e", "title": "Unavailable", "content": "The content of this memory was not provided in a readable form.", "quote": "The quoted portion was not provided in a readable form.", "source_location": "manual:minimax-api-smoke", "note": "Memory text appears to be missing or redacted; no usable details available for storytelling." } ] } ``` A small note on my choice: the memory you passed along came through with its title, body, and quote blanked out, so I deliberately avoided inventing scenes, people, or moments that weren''t actually there. If you can share the memory again — even just a sentence or two — I''ll happily spin it into the warm, first-person story the format calls for.', 'https://minimax-algeng-chat-tts.oss-cn-wulanchabu.aliyuncs.com/audio%2Feffect%2F06980e9f0119ae4566e0d8f674796e7e_1783159715147_6228.mp3?Expires=1783246115&OSSAccessKeyId=LTAI5tGLnRTkBjLuYPjNcKQ8&Signature=vkuHh1%2BVen9YW1vffh%2BPnZNvEVM%3D', '["63af0004-f6d5-4621-9116-d1e25b2b590e"]', '[{"memory_card_id": "63af0004-f6d5-4621-9116-d1e25b2b590e", "title": "????", "quote": "???????????????", "source_location": "manual:minimax-api-smoke"}]', false, '{"provider": {"provider_name": "minimax", "capability": "story_generation", "status": "succeeded"}, "generate_story_job_id": "72453d4e-a946-449b-abae-9e42c47ce55f", "synthesize_speech_job_id": "f3bb43e8-afe3-414d-abc3-9728266536ae", "voice": {"voice_status": "default_tts", "default_tts_notice": "\u5f53\u524d\u4f7f\u7528\u7cfb\u7edf\u9ed8\u8ba4\u58f0\u97f3\uff0c\u4e0d\u662f TA \u7684\u771f\u5b9e\u58f0\u97f3\u3002\u4e0a\u4f20 TA \u7684\u6e05\u6670\u8bed\u97f3\u540e\uff0c\u53ef\u4ee5\u5c1d\u8bd5\u751f\u6210\u6a21\u62df\u97f3\u8272\u3002"}}', '2026-07-04 10:08:18.847094', '2026-07-04 10:08:18.847094', NULL);
INSERT INTO public.memory_stories VALUES ('ec151ece-c597-46a9-bea1-f1e73f282d22', 'cdd2245c-f866-4951-9b8e-a0726d193f3a', '家常', '家常', '<think>The user wants me to generate a warm first-person memory story from the perspective of 外婆 (Grandma), addressed to 小铭. The theme is "家常" (homely/everyday life). I need to use only the three provided reviewed memories: 1. 外婆提醒饭要趁热慢慢吃 (Grandma reminds to eat rice while it''s hot, slowly) 2. 外婆的劝慰方式 (Grandma''s way of comforting - "take it slow, don''t rush, breathe evenly when feeling upset") 3. 外婆给小铭包馄饨 (Grandma likes to make wontons for 小铭) I need to create a warm, homely story that weaves these memories together naturally. The story should be in first person as 外婆, and output as strict JSON with: title, content, source_memory_ids, and source_memories.</think> ```json { "title": "外婆的馄饨和那句慢慢来", "content": "小铭，外婆今天又包了馄饨。你小时候最爱吃我包的馄饨，皮薄馅大，汤里撒上一把葱花，你每次都能吃上一大碗。外婆还记得那时候你急急忙忙就想往嘴里塞，我总拦着你，说饭要趁热慢慢吃，烫着了嘴可不好受。你那时候嘟着嘴嫌我啰嗦，可还是乖乖放慢了速度，一边吹一边吃，那副小大人的模样，外婆到现在都记得。\n\n其实外婆这辈人啊，什么风浪都见过，心里难受的时候也不是没有过。但外婆慢慢悟出来一个道理——慢慢来，别急，心里难受的时候先把气喘匀。什么事儿啊，只要不急，一口一口地来，总能过去的。包馄饨是这样，吃饭是这样，过日子也是这样。\n\n今天外婆一个人坐在灶台前，一边捏着馄饨一边想着你，也不知道你现在吃得好不好，有没有好好照顾自己。外婆包的馄饨馅儿调得咸淡刚好，汤也是老样子，你要是回来，外婆现在就给你下锅，趁热慢慢吃。", "source_memory_ids": [ "c7828786-877d-488d-9d17-ad5ad7d39a3e", "e6475793-1366-48cc-9cae-92b9242becb1", "d131f2b6-b244-4901-867b-dca9089ae6d7" ], "source_memories": [ "外婆喜欢给小铭包馄饨。", "外婆常说饭要趁热慢慢吃。", "外婆常说慢慢来，别急，心里难受的时候先把气喘匀。" ] } ```', 'https://minimax-algeng-chat-tts.oss-cn-wulanchabu.aliyuncs.com/audio%2Feffect%2F0698306a2ecf864dc98d96d08c8c2f31_1783168366375_9580.mp3?Expires=1783254766&OSSAccessKeyId=LTAI5tGLnRTkBjLuYPjNcKQ8&Signature=PZ66Pz4sdW5NJjxdpTwsyT97L70%3D', '["e6475793-1366-48cc-9cae-92b9242becb1", "d131f2b6-b244-4901-867b-dca9089ae6d7", "c7828786-877d-488d-9d17-ad5ad7d39a3e"]', '[{"memory_card_id": "e6475793-1366-48cc-9cae-92b9242becb1", "title": "\u5916\u5a46\u63d0\u9192\u996d\u8981\u8d81\u70ed\u6162\u6162\u5403", "quote": "\u5916\u5a46\u559c\u6b22\u7ed9\u5c0f\u94ed\u5305\u9984\u9968\uff0c\u4e5f\u5e38\u8bf4\u996d\u8981\u8d81\u70ed\u6162\u6162\u5403\u3002", "source_location": "manual:body"}, {"memory_card_id": "d131f2b6-b244-4901-867b-dca9089ae6d7", "title": "\u5916\u5a46\u7684\u529d\u6170\u65b9\u5f0f", "quote": "\u5916\u5a46\u5e38\u8bf4\u6162\u6162\u6765\uff0c\u522b\u6025\uff0c\u5fc3\u91cc\u96be\u53d7\u7684\u65f6\u5019\u5148\u628a\u6c14\u5598\u5300\u3002", "source_location": "manual:body"}, {"memory_card_id": "c7828786-877d-488d-9d17-ad5ad7d39a3e", "title": "\u5916\u5a46\u7ed9\u5c0f\u94ed\u5305\u9984\u9968", "quote": "\u5916\u5a46\u559c\u6b22\u7ed9\u5c0f\u94ed\u5305\u9984\u9968\uff0c\u4e5f\u5e38\u8bf4\u996d\u8981\u8d81\u70ed\u6162\u6162\u5403\u3002", "source_location": "manual:body"}]', false, '{"provider": {"provider_name": "minimax", "capability": "story_generation", "status": "succeeded"}, "generate_story_job_id": "b5318151-7af2-4691-8e75-9995c4ba57d5", "synthesize_speech_job_id": "02c64bbc-517f-4f36-a0dd-5ff9a3e3da8d", "voice": {"voice_status": "default_tts", "default_tts_notice": "\u5f53\u524d\u4f7f\u7528\u7cfb\u7edf\u9ed8\u8ba4\u58f0\u97f3\uff0c\u4e0d\u662f TA \u7684\u771f\u5b9e\u58f0\u97f3\u3002\u4e0a\u4f20 TA \u7684\u6e05\u6670\u8bed\u97f3\u540e\uff0c\u53ef\u4ee5\u5c1d\u8bd5\u751f\u6210\u6a21\u62df\u97f3\u8272\u3002"}}', '2026-07-04 12:32:34.420856', '2026-07-04 12:32:34.420856', NULL);
INSERT INTO public.memory_stories VALUES ('2164b687-6fdb-4161-8f42-3811667a8613', 'c32cdab4-7ed4-4a02-84b6-2f2753318419', '童年', '童年', '<think>The user wants me to generate a warm first-person memory story from the perspective of 外婆 (Grandma), addressing the user as 小铭. The theme is "童年" (childhood). I need to use only the three provided reviewed memories and return strict JSON with title, content, source_memory_ids, and source_memories. Let me craft a warm story incorporating all three memories: 1. Memory about 小铭''s birthday - cake and hot soup, wishing for his safety 2. Memory about 外婆''s comforting method - telling him to breathe evenly, "慢慢来，别急" (take it slow, don''t rush) 3. Memory about 外婆 reminding to eat hot meals slowly, and wrapping wontons for 小铭 I''ll weave these into a cohesive childhood memory story told from 外婆''s perspective. Let me write the story in first person as 外婆, addressing 小铭 warmly, and incorporating all three memories naturally.</think> ```json { "title": "外婆的小铭，童年里最暖的光", "content": "我的小铭啊，外婆常常想起你小时候的模样。那一年你生日，外婆一早就系上围裙，在小厨房里忙活了好一阵。烤好的蛋糕摆在桌中央，旁边还盛着一碗热汤，汤面上飘着细碎的葱花，像极了外婆说不出口的疼爱。你坐在桌前，眼睛亮亮的，外婆摸着你的头，笑着说：\"只要我们小铭平平安安的，比什么都好。\"\n\n你小时候呀，总爱急。外婆记得有一回你受了委屈，憋着小嘴跑来找外婆，眼眶红红的。外婆没有急着说什么大道理，只是把你轻轻搂进怀里，拍了拍你的背，告诉你：\"心里难受的时候，先把气喘匀。慢慢来，别急，外婆在呢。\"你吸了吸鼻子，学着外婆的样子深深呼了一口气，慢慢地，那张小脸上的褶皱就舒展开了。\n\n外婆还爱给你包馄饨。薄薄的面皮裹进调好的肉馅，捏出一个个像小元宝似的馄饨，下锅一滚就浮起来，热气腾腾地端到你面前。外婆总念叨：\"饭要趁热慢慢吃，烫着舌头可不行。\"你就乖乖地一边吹一边吃，吃得满嘴油亮亮的，外婆坐在对面看着，心里暖得什么似的。\n\n童年短得很，可那些蛋糕、热汤、馄饨，还有外婆那句\"慢慢来，别急\"，全都揉进了你长大的日子里。外婆老了，记忆也渐渐模糊，但你小时候坐在桌前吹馄饨的样子，外婆怎么也忘不掉。小铭啊，不管你走多远，外婆都希望你记得——慢慢来，别急，外婆永远盼你平安。", "source_memory_ids": [ "de18ef14-6d49-4f02-9612-d1c71af9a0c5", "c5754db3-1261-4de8-aca5-de9a1f8b096c", "335fa6bf-3c79-4ea9-a60d-e3273cfde074" ], "source_memories": [ { "id": "de18ef14-6d49-4f02-9612-d1c71af9a0c5", "title": "小铭的生日", "quote": "小铭生日那天，外婆准备了蛋糕和一碗热汤，笑着说只要小铭平安就好。" }, { "id": "c5754db3-1261-4de8-aca5-de9a1f8b096c", "title": "外婆的安抚方式", "quote": "外婆常说慢慢来，别急，心里难受的时候先把气喘匀。" }, { "id": "335fa6bf-3c79-4ea9-a60d-e3273cfde074", "title": "外婆叮嘱饭要趁热慢慢吃", "quote": "外婆喜欢给小铭包馄饨，也常说饭要趁热慢慢吃。" } ] } ```', 'https://minimax-algeng-chat-tts.oss-cn-wulanchabu.aliyuncs.com/audio%2Feffect%2F06983083a1d241ffe05fe5f6e7e9e68e_1783168392084_9773.mp3?Expires=1783254792&OSSAccessKeyId=LTAI5tGLnRTkBjLuYPjNcKQ8&Signature=ReO3Q76EMjdqajnVlxA7TO6BQg8%3D', '["de18ef14-6d49-4f02-9612-d1c71af9a0c5", "c5754db3-1261-4de8-aca5-de9a1f8b096c", "335fa6bf-3c79-4ea9-a60d-e3273cfde074"]', '[{"memory_card_id": "de18ef14-6d49-4f02-9612-d1c71af9a0c5", "title": "\u5c0f\u94ed\u7684\u751f\u65e5", "quote": "\u5c0f\u94ed\u751f\u65e5\u90a3\u5929\uff0c\u5916\u5a46\u51c6\u5907\u4e86\u86cb\u7cd5\u548c\u4e00\u7897\u70ed\u6c64\uff0c\u7b11\u7740\u8bf4\u53ea\u8981\u5c0f\u94ed\u5e73\u5b89\u5c31\u597d\u3002", "source_location": "manual:body"}, {"memory_card_id": "c5754db3-1261-4de8-aca5-de9a1f8b096c", "title": "\u5916\u5a46\u7684\u5b89\u629a\u65b9\u5f0f", "quote": "\u5916\u5a46\u5e38\u8bf4\u6162\u6162\u6765\uff0c\u522b\u6025\uff0c\u5fc3\u91cc\u96be\u53d7\u7684\u65f6\u5019\u5148\u628a\u6c14\u5598\u5300\u3002", "source_location": "manual:body"}, {"memory_card_id": "335fa6bf-3c79-4ea9-a60d-e3273cfde074", "title": "\u5916\u5a46\u53ee\u5631\u996d\u8981\u8d81\u70ed\u6162\u6162\u5403", "quote": "\u5916\u5a46\u559c\u6b22\u7ed9\u5c0f\u94ed\u5305\u9984\u9968\uff0c\u4e5f\u5e38\u8bf4\u996d\u8981\u8d81\u70ed\u6162\u6162\u5403\u3002", "source_location": "manual:body"}]', false, '{"provider": {"provider_name": "minimax", "capability": "story_generation", "status": "succeeded"}, "generate_story_job_id": "ac7f773f-8d1c-49c2-ab83-f044e72d19f4", "synthesize_speech_job_id": "84279646-7bca-48c9-a889-bba542421430", "voice": {"voice_status": "default_tts", "default_tts_notice": "\u5f53\u524d\u4f7f\u7528\u7cfb\u7edf\u9ed8\u8ba4\u58f0\u97f3\uff0c\u4e0d\u662f TA \u7684\u771f\u5b9e\u58f0\u97f3\u3002\u4e0a\u4f20 TA \u7684\u6e05\u6670\u8bed\u97f3\u540e\uff0c\u53ef\u4ee5\u5c1d\u8bd5\u751f\u6210\u6a21\u62df\u97f3\u8272\u3002"}}', '2026-07-04 12:32:54.957423', '2026-07-04 12:32:54.957423', NULL);
INSERT INTO public.memory_stories VALUES ('93419bcf-e78e-4b25-80f0-2a1cb64a5d12', '27e4e946-6b92-42a2-982c-fde85b36c284', '共同回忆', '共同回忆', '<think>The user wants me to generate a warm first-person memory story from the perspective of 外婆 (Grandma), addressed to 小铭, with the theme of "共同回忆" (shared memories). I need to use only the provided reviewed memories: 1. f3d478e0 - 小铭的生日: Grandma prepared cake and hot soup for 小铭''s birthday 2. c6f70db1 - 外婆给小铭包馄饨: Grandma likes making wontons for 小铭 3. 98a63224 - 外婆的处世态度: Grandma''s approach to life - take things slow, breathe when upset I need to weave these memories into a warm first-person narrative as Grandma speaking to 小铭. The story should be warm and reminiscent, focusing on shared memories. Let me craft a story that naturally incorporates all three memories, returning strict JSON with: title, content, source_memory_ids, and source_memories. Let me write this in first-person as 外婆: Title could be something like "外婆的小铭" or "那些年和外孙一起的日子" Content - I''ll weave the memories together naturally: - Birthday memory with cake and hot soup - Wonton-making memory - The philosophy of taking things slow Let me draft: "记得你生日那天，外婆在厨房里忙了一整个上午。蛋糕是你小时候最爱的那种，上面撒着细碎的水果糖针。旁边还有一碗热汤，咕嘟咕嘟冒着热气。外婆端到你面前的时候，笑着说：''只要小铭平安就好。''你那时候还小，眼睛亮亮的，一口蛋糕一口汤，吃得满嘴都是。外婆看着，心里比蜜还甜。 外婆也喜欢给你包馄饨。皮薄馅大，一碗一碗端上桌，外婆总在旁边叮嘱：''饭要趁热慢慢吃。''那时候厨房里蒸汽缭绕，窗户上蒙着一层薄雾，你坐在桌边等着的样子，外婆到现在还记得。 外婆这一辈子，没什么大道理，就信一句话——慢慢来，别急。心里难受的时候啊，先把气喘匀，外婆是这么过日子的，也想这么告诉你。 小铭，不管你走多远，外婆的厨房里，永远有你爱吃的蛋糕、热汤，还有那一碗碗包好的馄饨。" Let me count the memories I''m using: - f3d478e0 (birthday cake and soup) ✓ - c6f70db1 (wontons and eating slowly) ✓ - 98a63224 (take things slow, breathe) ✓ Good, I''m using all three memories. Let me finalize. source_memory_ids: all three IDs source_memories: corresponding quotes or summaries Let me format the JSON properly.</think> ```json { "title": "外婆的厨房里，藏着小铭的整个童年", "content": "小铭，外婆坐在老藤椅上翻照片的时候，又想起你了。\n\n记得你生日那天，外婆在厨房里忙了一整个上午。蛋糕是你小时候最爱的那种，上面还撒着细碎的水果糖针，旁边的灶台上炖着一碗热汤，咕嘟咕嘟冒着白气。外婆端着碗和蛋糕走到你面前，笑着说，只要小铭平安就好。你那年还小，眼睛亮亮的，一口蛋糕一口汤，吃得满嘴都是。外婆看着你，心里头比那碗汤还热。\n\n外婆也总喜欢给你包馄饨。皮薄馅大，一碗一碗端上桌，外婆就站在旁边念叨：饭要趁热慢慢吃。厨房里蒸汽缭绕，窗户上蒙着一层薄薄的水雾，你坐在小桌边眼巴巴等着的样子，外婆到现在都还记得，连你伸出小手接碗的动作都记得清清楚楚。\n\n外婆这一辈子没什么大道理，就信一句话——慢慢来，别急。心里难受的时候啊，先把气喘匀，外婆是这么过过来的日子，也想这么告诉你。\n\n小铭，不管你走得多远，外婆的厨房里，永远都有你爱吃的那口蛋糕、有那碗热汤，还有那一碗碗刚包好的馄饨等着你回来。", "source_memory_ids": [ "f3d478e0-d46a-41d7-8d99-2e07050a6c4c", "c6f70db1-b385-4815-b9b2-623d4dcf3dcb", "98a63224-15c7-4f4d-96a8-5bfc6e52c295" ], "source_memories": [ "小铭生日那天，外婆准备了蛋糕和一碗热汤，笑着说只要小铭平安就好。", "外婆喜欢给小铭包馄饨，也常说饭要趁热慢慢吃。", "外婆常说慢慢来，别急，心里难受的时候先把气喘匀。" ] } ```', 'https://minimax-algeng-chat-tts.oss-cn-wulanchabu.aliyuncs.com/audio%2Feffect%2F06989c676aecf53563497b3e6147086d_1783196010717_5169.mp3?Expires=1783282411&OSSAccessKeyId=LTAI5tGLnRTkBjLuYPjNcKQ8&Signature=9Kpk42sP%2BR9NnZELZ7VILzCWyI8%3D', '["f3d478e0-d46a-41d7-8d99-2e07050a6c4c", "c6f70db1-b385-4815-b9b2-623d4dcf3dcb", "98a63224-15c7-4f4d-96a8-5bfc6e52c295"]', '[{"memory_card_id": "f3d478e0-d46a-41d7-8d99-2e07050a6c4c", "title": "\u5c0f\u94ed\u7684\u751f\u65e5", "quote": "\u5c0f\u94ed\u751f\u65e5\u90a3\u5929\uff0c\u5916\u5a46\u51c6\u5907\u4e86\u86cb\u7cd5\u548c\u4e00\u7897\u70ed\u6c64\uff0c\u7b11\u7740\u8bf4\u53ea\u8981\u5c0f\u94ed\u5e73\u5b89\u5c31\u597d\u3002", "source_location": "manual:body"}, {"memory_card_id": "c6f70db1-b385-4815-b9b2-623d4dcf3dcb", "title": "\u5916\u5a46\u7ed9\u5c0f\u94ed\u5305\u9984\u9968", "quote": "\u5916\u5a46\u559c\u6b22\u7ed9\u5c0f\u94ed\u5305\u9984\u9968\uff0c\u4e5f\u5e38\u8bf4\u996d\u8981\u8d81\u70ed\u6162\u6162\u5403\u3002", "source_location": "manual:body"}, {"memory_card_id": "98a63224-15c7-4f4d-96a8-5bfc6e52c295", "title": "\u5916\u5a46\u7684\u5904\u4e16\u6001\u5ea6", "quote": "\u5916\u5a46\u5e38\u8bf4\u6162\u6162\u6765\uff0c\u522b\u6025\uff0c\u5fc3\u91cc\u96be\u53d7\u7684\u65f6\u5019\u5148\u628a\u6c14\u5598\u5300\u3002", "source_location": "manual:body"}]', false, '{"provider": {"provider_name": "minimax", "capability": "story_generation", "status": "succeeded"}, "generate_story_job_id": "f8dac276-7d72-4108-a000-5a622ae94c50", "synthesize_speech_job_id": "31381963-a8ab-47ae-9a87-ceb222bb6fad", "voice": {"voice_status": "default_tts", "default_tts_notice": "\u5f53\u524d\u4f7f\u7528\u7cfb\u7edf\u9ed8\u8ba4\u58f0\u97f3\uff0c\u4e0d\u662f TA \u7684\u771f\u5b9e\u58f0\u97f3\u3002\u4e0a\u4f20 TA \u7684\u6e05\u6670\u8bed\u97f3\u540e\uff0c\u53ef\u4ee5\u5c1d\u8bd5\u751f\u6210\u6a21\u62df\u97f3\u8272\u3002"}}', '2026-07-04 20:13:17.851634', '2026-07-04 20:13:17.851634', NULL);
INSERT INTO public.memory_stories VALUES ('9152a8df-f03a-4fae-b2d9-a1ec6ede033d', '12264fff-cbf4-4fd1-aa03-6c1dc0c9bb73', '共同回忆', '外婆和小铭的温暖小日子', '小铭啊，外婆刚才坐在灶台边包馄饨，擀面杖一下一下地敲着，心里头就想起咱俩在一起的那些日子，越想越暖。 你还记得不，外婆最喜欢给你包馄饨了。面皮是自己擀的，馅儿调得咸淡刚好，一个一个捏得整整齐齐。下锅的时候外婆总守在灶边看着，怕火太大把皮煮破。每次端上桌，外婆都叮嘱你——饭要趁热慢慢吃，别着急，烫着嘴就不好了。你那时候小，嘴巴鼓鼓的，一口一个，外婆看着你吃得香，心里头比啥都甜。 还有你生日那天，外婆早早地就忙活开了。蒸了一碗热汤，又摆了个小蛋糕。蜡烛点上的时候，外婆没许啥大愿望，就笑着跟你说，只要小铭平安就好。你吹蜡烛那一下，外婆看着你，心里头悄悄念了好几遍，盼着你健健康康的，往后的日子也顺顺当当。 外婆这辈子没啥大道理，就会跟你说——慢慢来，别急，心里难受的时候先把气喘匀。不管外面的事儿多忙多累，外婆这儿永远有热汤，有馄饨，有一个等你慢慢吃饭的家。小铭啊，啥时候想外婆了，就回来，外婆给你包馄饨，咱们一起慢慢吃。', 'https://minimax-algeng-chat-tts.oss-cn-wulanchabu.aliyuncs.com/audio%2Feffect%2F0698b34a8aff1d0614cfad3c59165bcb_1783201869389_204.mp3?Expires=1783288269&OSSAccessKeyId=LTAI5tGLnRTkBjLuYPjNcKQ8&Signature=gol4b5Uq5Jwb%2F5oSocW3TVJ%2BeFw%3D', '["ba14247c-f8fb-4891-9456-f00c0bd12c2b", "d426e678-e429-4ada-b02e-df33aa22a71a", "db018ae2-d6b9-4523-a4de-5e18f700e7de"]', '[{"memory_card_id": "ba14247c-f8fb-4891-9456-f00c0bd12c2b", "title": "\u5916\u5a46\u7ed9\u5c0f\u94ed\u5305\u9984\u9968", "quote": "\u5916\u5a46\u559c\u6b22\u7ed9\u5c0f\u94ed\u5305\u9984\u9968\uff0c\u4e5f\u5e38\u8bf4\u996d\u8981\u8d81\u70ed\u6162\u6162\u5403\u3002", "source_location": "manual:body"}, {"memory_card_id": "d426e678-e429-4ada-b02e-df33aa22a71a", "title": "\u5916\u5a46\u5bf9\u5c0f\u94ed\u7684\u795d\u798f", "quote": "\u5c0f\u94ed\u751f\u65e5\u90a3\u5929\uff0c\u5916\u5a46\u51c6\u5907\u4e86\u86cb\u7cd5\u548c\u4e00\u7897\u70ed\u6c64\uff0c\u7b11\u7740\u8bf4\u53ea\u8981\u5c0f\u94ed\u5e73\u5b89\u5c31\u597d\u3002", "source_location": "manual:body"}, {"memory_card_id": "db018ae2-d6b9-4523-a4de-5e18f700e7de", "title": "\u5916\u5a46\u7684\u529d\u6170\u65b9\u5f0f", "quote": "\u5916\u5a46\u5e38\u8bf4\u6162\u6162\u6765\uff0c\u522b\u6025\uff0c\u5fc3\u91cc\u96be\u53d7\u7684\u65f6\u5019\u5148\u628a\u6c14\u5598\u5300\u3002", "source_location": "manual:body"}]', false, '{"provider": {"provider_name": "minimax", "capability": "story_generation", "status": "succeeded"}, "memory_context": {"source": "memory_markdown", "long_term_path": "/app/storage/memory_context/12264fff-cbf4-4fd1-aa03-6c1dc0c9bb73/long_term_memory.md", "short_term_path": "/app/storage/memory_context/12264fff-cbf4-4fd1-aa03-6c1dc0c9bb73/short_term_memory.md", "selected_memory_ids": ["db018ae2-d6b9-4523-a4de-5e18f700e7de", "d426e678-e429-4ada-b02e-df33aa22a71a", "ba14247c-f8fb-4891-9456-f00c0bd12c2b"]}, "generate_story_job_id": "3a6bc120-b158-4537-8f17-134fe55db196", "synthesize_speech_job_id": "eb716f81-d706-469f-8256-8e93e2d107a4", "voice": {"voice_status": "default_tts", "default_tts_notice": "\u5f53\u524d\u4f7f\u7528\u7cfb\u7edf\u9ed8\u8ba4\u58f0\u97f3\uff0c\u4e0d\u662f TA \u7684\u771f\u5b9e\u58f0\u97f3\u3002\u4e0a\u4f20 TA \u7684\u6e05\u6670\u8bed\u97f3\u540e\uff0c\u53ef\u4ee5\u5c1d\u8bd5\u751f\u6210\u6a21\u62df\u97f3\u8272\u3002"}}', '2026-07-04 21:50:53.09954', '2026-07-04 21:50:53.09954', NULL);
INSERT INTO public.memory_stories VALUES ('b6d5a85e-f7ac-4452-b8ef-6247e4c38f56', '18b88e96-5633-4d75-b77a-0ad1988a846a', '共同回忆', '码头上的回忆', '孙子，爷爷站在老宅的门前，双手背在身后，看着这扇熟悉的木门，心里头暖暖的。你小时候最爱拉着我的手问东问西，爷爷总是笑呵呵地给你讲故事。今天，爷爷也想跟你说说那些藏在心底的记忆。 你瞧爷爷这满头银发，还有身上这件浅灰色的长袖衬衫和卡其色长裤——这身打扮，是爷爷年轻时就养成的习惯，朴素、干净、利索。爷爷笑了一辈子，到老了还是这副温和慈祥的模样，大概就是想着你们这些后辈，心里头就踏实。 孙子啊，爷爷这辈子吃过不少苦。刚到南洋的时候，人生地不熟，什么都没有，只能先在码头上做苦力。那些日子，爷爷扛过沉甸甸的米袋，搬过笨重的木箱，一趟趟地卸货。码头上的太阳毒得很，汗水顺着脊背往下淌，手掌磨出的老茧一层又一层。可爷爷从来没抱怨过，因为心里头一直有一个念想——只要肯吃苦，日子总会慢慢好起来的。 后来啊，日子真的慢慢好起来了。爷爷有了自己的家，有了这座老宅，有了你。每当爷爷站在门前，想起码头上的那些时光，再回头看看你，就觉得这辈子再苦再累都值得。那些扛米袋、搬木箱的日子，教会了爷爷什么是坚韧，也教会了爷爷，什么才是真正值得守护的东西。 孙子，爷爷不求别的，就盼着你平平安安、踏踏实实。累了就回来歇歇，爷爷还在这扇木门前，等你回家。', 'https://minimax-algeng-chat-tts.oss-cn-wulanchabu.aliyuncs.com/audio%2Feffect%2F0698a4dd01d86386ddf0eeb4326e8b5e_1783198176566_4959.mp3?Expires=1783284576&OSSAccessKeyId=LTAI5tGLnRTkBjLuYPjNcKQ8&Signature=bnrx0uNbgmLXCEo6x5u5Q6hNiA4%3D', '["2187f3ca-2889-48c9-ac15-0aec8506e9dd", "cca0d1a1-3b6f-4def-bea1-8b19c1622b47"]', '[{"memory_card_id": "2187f3ca-2889-48c9-ac15-0aec8506e9dd", "title": "\u90d1\u6728\u751f\u5916\u8c8c\u7279\u5f81", "quote": "\u4e00\u4f4d\u6ee1\u5934\u94f6\u53d1\u7684\u8001\u4eba\u7ad9\u5728\u53e4\u6734\u7684\u8001\u5b85\u6728\u95e8\u524d\uff0c\u8eab\u7a7f\u6d45\u7070\u8272\u957f\u8896\u886c\u886b\u548c\u5361\u5176\u8272\u957f\u88e4\uff0c\u53cc\u624b\u80cc\u5728\u8eab\u540e\uff0c\u9762\u5e26\u6e29\u548c\u6148\u7965\u7684\u7b11\u5bb9\u3002", "source_location": "image:\u7237\u7237\u56fe\u7247.png"}, {"memory_card_id": "cca0d1a1-3b6f-4def-bea1-8b19c1622b47", "title": "\u90d1\u6728\u751f\u5e74\u8f7b\u65f6\u5728\u5357\u6d0b\u7801\u5934\u505a\u82e6\u529b", "quote": "\u7237\u7237\u521a\u5230\u5357\u6d0b\u65f6\uff0c\u5148\u5728\u7801\u5934\u505a\u82e6\u529b\u3002\u7801\u5934\u7684\u6d3b\u5f88\u91cd\uff0c\u8981\u625b\u7c73\u888b\u3001\u642c\u6728\u7bb1\u3001\u5378\u8d27\u3002", "source_location": "manual:body"}]', false, '{"provider": {"provider_name": "minimax", "capability": "story_generation", "status": "succeeded"}, "memory_context": {"source": "memory_markdown", "long_term_path": "/app/storage/memory_context/18b88e96-5633-4d75-b77a-0ad1988a846a/long_term_memory.md", "short_term_path": "/app/storage/memory_context/18b88e96-5633-4d75-b77a-0ad1988a846a/short_term_memory.md", "selected_memory_ids": ["2187f3ca-2889-48c9-ac15-0aec8506e9dd", "cca0d1a1-3b6f-4def-bea1-8b19c1622b47"]}, "generate_story_job_id": "b9d25858-f8a0-4e99-9ffd-d12d80b93faf", "synthesize_speech_job_id": "5d84b709-ef92-4673-8101-15799e72e31d", "voice": {"voice_status": "default_tts", "default_tts_notice": "\u5f53\u524d\u4f7f\u7528\u7cfb\u7edf\u9ed8\u8ba4\u58f0\u97f3\uff0c\u4e0d\u662f TA \u7684\u771f\u5b9e\u58f0\u97f3\u3002\u4e0a\u4f20 TA \u7684\u6e05\u6670\u8bed\u97f3\u540e\uff0c\u53ef\u4ee5\u5c1d\u8bd5\u751f\u6210\u6a21\u62df\u97f3\u8272\u3002"}}', '2026-07-04 20:49:19.011891', '2026-07-04 22:10:50.8962', NULL);
INSERT INTO public.memory_stories VALUES ('99654e27-609f-4844-ad14-e2534b4f1e53', '12264fff-cbf4-4fd1-aa03-6c1dc0c9bb73', '共同回忆', '外婆心里那些暖烘烘的小事', '小铭，外婆跟你说说心里头那些暖烘烘的小事吧。 那年生日，外婆早早地就在厨房忙开了。蛋糕是外婆托隔壁王婶帮着订的，可那碗热汤，外婆是一勺一勺亲手熬的，就怕外面买的味道不对。汤端上桌的时候还冒着热气儿，你吹蜡烛的时候脸蛋红扑扑的，外婆在旁边看着，心里头那个美呀，就盼着你平平安安的，只要你好好的，外婆就比啥都踏实。 要说外婆最拿手的，还得是包馄饨。皮儿是外婆自己擀的，馅儿调得刚刚好，咬一口满嘴都是香味儿。小时候你每次来，外婆都给你包上一大碗，你就坐在小桌边，呼噜呼噜地吃着，外婆在旁边看着你，心里头高兴着呢。 外婆总跟你念叨，饭要趁热慢慢吃，别着急。那时候你小，嘴巴烫了一下还直皱眉，外婆就笑着说，慢点儿慢点儿，没人跟你抢。这话啊，外婆说了好多年，其实不光是说吃饭，做啥事儿都是这个理儿。 外婆还常跟你说，心里难受的时候，先把气喘匀，慢慢来，别急。外婆这辈子啥风浪都见过，可每次心里不舒坦的时候，就想起这句话，深深吸一口气，啥事儿都能过去。小铭啊，外婆希望你也记着，啥事儿都有外婆陪着呢，慢慢来，别怕。 这些个零零碎碎的小事，串在一起，就是外婆跟你在一起的日子。外婆都记着呢，一个字都没忘。', 'https://minimax-algeng-chat-tts.oss-cn-wulanchabu.aliyuncs.com/audio%2Feffect%2F0698ccb76f0f7f45ee12c832bd991e03_1783208378159_98.mp3?Expires=1783294778&OSSAccessKeyId=LTAI5tGLnRTkBjLuYPjNcKQ8&Signature=ZBAWded6Pq9l3Vu5A8OKdqbUF%2BY%3D', '["ba14247c-f8fb-4891-9456-f00c0bd12c2b", "d426e678-e429-4ada-b02e-df33aa22a71a", "db018ae2-d6b9-4523-a4de-5e18f700e7de"]', '[{"memory_card_id": "ba14247c-f8fb-4891-9456-f00c0bd12c2b", "title": "\u5916\u5a46\u7ed9\u5c0f\u94ed\u5305\u9984\u9968", "quote": "\u5916\u5a46\u559c\u6b22\u7ed9\u5c0f\u94ed\u5305\u9984\u9968\uff0c\u4e5f\u5e38\u8bf4\u996d\u8981\u8d81\u70ed\u6162\u6162\u5403\u3002", "source_location": "manual:body"}, {"memory_card_id": "d426e678-e429-4ada-b02e-df33aa22a71a", "title": "\u5916\u5a46\u5bf9\u5c0f\u94ed\u7684\u795d\u798f", "quote": "\u5c0f\u94ed\u751f\u65e5\u90a3\u5929\uff0c\u5916\u5a46\u51c6\u5907\u4e86\u86cb\u7cd5\u548c\u4e00\u7897\u70ed\u6c64\uff0c\u7b11\u7740\u8bf4\u53ea\u8981\u5c0f\u94ed\u5e73\u5b89\u5c31\u597d\u3002", "source_location": "manual:body"}, {"memory_card_id": "db018ae2-d6b9-4523-a4de-5e18f700e7de", "title": "\u5916\u5a46\u7684\u529d\u6170\u65b9\u5f0f", "quote": "\u5916\u5a46\u5e38\u8bf4\u6162\u6162\u6765\uff0c\u522b\u6025\uff0c\u5fc3\u91cc\u96be\u53d7\u7684\u65f6\u5019\u5148\u628a\u6c14\u5598\u5300\u3002", "source_location": "manual:body"}]', false, '{"provider": {"provider_name": "minimax", "capability": "story_generation", "status": "succeeded"}, "memory_context": {"source": "memory_markdown", "long_term_path": "/app/storage/memory_context/12264fff-cbf4-4fd1-aa03-6c1dc0c9bb73/long_term_memory.md", "short_term_path": "/app/storage/memory_context/12264fff-cbf4-4fd1-aa03-6c1dc0c9bb73/short_term_memory.md", "selected_memory_ids": ["db018ae2-d6b9-4523-a4de-5e18f700e7de", "d426e678-e429-4ada-b02e-df33aa22a71a", "ba14247c-f8fb-4891-9456-f00c0bd12c2b"]}, "generate_story_job_id": "0176355a-8a79-4bdd-b0ad-ba86381bb629", "synthesize_speech_job_id": "e19eeed6-f4c9-4c6a-aa2b-2f71af78a239", "voice": {"voice_status": "default_tts", "default_tts_notice": "\u5f53\u524d\u4f7f\u7528\u7cfb\u7edf\u9ed8\u8ba4\u58f0\u97f3\uff0c\u4e0d\u662f TA \u7684\u771f\u5b9e\u58f0\u97f3\u3002\u4e0a\u4f20 TA \u7684\u6e05\u6670\u8bed\u97f3\u540e\uff0c\u53ef\u4ee5\u5c1d\u8bd5\u751f\u6210\u6a21\u62df\u97f3\u8272\u3002"}}', '2026-07-04 23:39:25.111121', '2026-07-04 23:39:25.111121', NULL);
