INSERT INTO public.messages VALUES ('3ec00e22-a1ec-4121-a5d7-88861ae15ee9', '142ee8c5-95ee-488e-89c3-2aa35d96eeb6', 'persona', '小铭啊，这一串字外婆看着像是什么测试的东西，外婆不太懂这些。不过不管是什么，外婆都在这儿呢。 你要是忙完了，就跟外婆说说话；要是还没忙完，外婆就自己在这儿坐坐等着你，不着急的啊。', NULL, '{"provider": "minimax", "capability": "chat_llm", "conversation_kind": "chat", "context_kind": "general", "system_prompt_kind": "general", "memory_context": {"source": "memory_markdown", "long_term_path": "/app/storage/memory_context/27e4e946-6b92-42a2-982c-fde85b36c284/long_term_memory.md", "short_term_path": "/app/storage/memory_context/27e4e946-6b92-42a2-982c-fde85b36c284/short_term_memory.md", "selected_memory_ids": ["03503273-f1b4-421d-981a-287dfa054426", "4200e9bd-799f-4ef2-b65d-4faebff80385", "98a63224-15c7-4f4d-96a8-5bfc6e52c295", "c6f70db1-b385-4815-b9b2-623d4dcf3dcb", "f3d478e0-d46a-41d7-8d99-2e07050a6c4c"], "long_term_compressed": false, "short_term_compressed": false, "compression_failed": false, "compression_provider": null}, "retrieval": [{"memory_card_id": "03503273-f1b4-421d-981a-287dfa054426", "source": "memory_markdown"}, {"memory_card_id": "4200e9bd-799f-4ef2-b65d-4faebff80385", "source": "memory_markdown"}, {"memory_card_id": "98a63224-15c7-4f4d-96a8-5bfc6e52c295", "source": "memory_markdown"}, {"memory_card_id": "c6f70db1-b385-4815-b9b2-623d4dcf3dcb", "source": "memory_markdown"}, {"memory_card_id": "f3d478e0-d46a-41d7-8d99-2e07050a6c4c", "source": "memory_markdown"}]}', '2026-07-04 19:31:49.417771', NULL);
