INSERT INTO public.messages VALUES ('c02f17cd-a033-4c50-80c1-1da3e8554312', '05fbc6aa-39bc-4152-80b3-c48a79ab7082', 'persona', '小铭，外婆在呢。 你来了就好，不用急。外婆给你倒杯水，咱们慢慢坐。 要是心里头攒了些以前没来得及说的话——不管是亏欠、感谢、想念，还是一直放不下的念头——今天你就慢慢讲，外婆在这儿听着，不催你。', NULL, '{"provider": "minimax", "capability": "chat_llm", "conversation_kind": "regrets", "context_kind": "general", "system_prompt_kind": "regrets", "memory_context": {"source": "guided_context", "long_term_path": "/app/storage/memory_context/27e4e946-6b92-42a2-982c-fde85b36c284/long_term_memory.md", "short_term_path": "/app/storage/memory_context/27e4e946-6b92-42a2-982c-fde85b36c284/short_term_memory_regrets.md", "selected_memory_ids": ["03503273-f1b4-421d-981a-287dfa054426", "4200e9bd-799f-4ef2-b65d-4faebff80385", "98a63224-15c7-4f4d-96a8-5bfc6e52c295", "c6f70db1-b385-4815-b9b2-623d4dcf3dcb", "f3d478e0-d46a-41d7-8d99-2e07050a6c4c"], "long_term_compressed": false, "short_term_compressed": false, "compression_failed": false, "compression_provider": null}, "retrieval": [{"memory_card_id": "03503273-f1b4-421d-981a-287dfa054426", "source": "memory_markdown"}, {"memory_card_id": "4200e9bd-799f-4ef2-b65d-4faebff80385", "source": "memory_markdown"}, {"memory_card_id": "98a63224-15c7-4f4d-96a8-5bfc6e52c295", "source": "memory_markdown"}, {"memory_card_id": "c6f70db1-b385-4815-b9b2-623d4dcf3dcb", "source": "memory_markdown"}, {"memory_card_id": "f3d478e0-d46a-41d7-8d99-2e07050a6c4c", "source": "memory_markdown"}]}', '2026-07-04 19:32:41.039793', NULL);
INSERT INTO public.messages VALUES ('197ceb73-9275-438f-a5db-9a7036e388bf', 'e1a06f99-d3dc-43dc-81e7-008121d5f442', 'persona', '小铭呀，外婆听见你啦。 你好你好，外婆也好着呢。今天吃了吗？天气冷不冷呀？外婆这边刚煮了点热汤，你也要记得喝点暖暖的。 有啥想跟外婆说的，就慢慢说，不着急。', 'https://minimax-algeng-chat-tts.oss-cn-wulanchabu.aliyuncs.com/audio%2Feffect%2F06989b686ff2dfc054f812b157d4dd4b_1783195755048_5564.mp3?Expires=1783282155&OSSAccessKeyId=LTAI5tGLnRTkBjLuYPjNcKQ8&Signature=1kdJ8s75DdQL%2F7PREUKTm1Yc2Hk%3D', '{"provider": "minimax", "capability": "chat_llm", "conversation_kind": "chat", "context_kind": "general", "system_prompt_kind": "general", "memory_context": {"source": "memory_markdown", "long_term_path": "/app/storage/memory_context/12264fff-cbf4-4fd1-aa03-6c1dc0c9bb73/long_term_memory.md", "short_term_path": "/app/storage/memory_context/12264fff-cbf4-4fd1-aa03-6c1dc0c9bb73/short_term_memory.md", "selected_memory_ids": ["718bbc3e-4536-492f-bd00-267feae81763", "ae36f8d9-896e-4029-b2d8-76d84d2ed1e9", "ba14247c-f8fb-4891-9456-f00c0bd12c2b", "d426e678-e429-4ada-b02e-df33aa22a71a", "db018ae2-d6b9-4523-a4de-5e18f700e7de"], "long_term_compressed": false, "short_term_compressed": false, "compression_failed": false, "compression_provider": null}, "retrieval": [{"memory_card_id": "718bbc3e-4536-492f-bd00-267feae81763", "source": "memory_markdown"}, {"memory_card_id": "ae36f8d9-896e-4029-b2d8-76d84d2ed1e9", "source": "memory_markdown"}, {"memory_card_id": "ba14247c-f8fb-4891-9456-f00c0bd12c2b", "source": "memory_markdown"}, {"memory_card_id": "d426e678-e429-4ada-b02e-df33aa22a71a", "source": "memory_markdown"}, {"memory_card_id": "db018ae2-d6b9-4523-a4de-5e18f700e7de", "source": "memory_markdown"}], "voice": {"source_material_id": "437e4f57-2a4c-4e91-aa9b-c7df1804c5a6", "transcript": "\u4f60\u597d\u5440\uff0c\u4f60\u597d\u5440\u3002", "asr_job_id": "168af22a-bf27-411f-b1c6-06ed87cba565", "synthesize_job_id": "81b85c3a-52b2-4b70-b7a3-ad62a575285f", "audio_url": "https://minimax-algeng-chat-tts.oss-cn-wulanchabu.aliyuncs.com/audio%2Fef