INSERT INTO public.messages VALUES ('9512e002-7a9b-4d3c-a25f-01da43c2ba38', 'e1a06f99-d3dc-43dc-81e7-008121d5f442', 'user', '外婆今天吃了什么呀？', NULL, 'null', '2026-07-04 20:10:05.636359', NULL);
INSERT INTO public.messages VALUES ('09a28ccc-f36a-4752-9a6f-388153c1ea17', 'e1a06f99-d3dc-43dc-81e7-008121d5f442', 'persona', '小铭问外婆今天吃了啥呀？外婆今天吃得简单，早上喝了点粥，中午煮了锅热汤，还热了几个馒头，慢慢嚼着吃的。 你呢，小铭？饭吃了吗？天热别光吃凉的，外婆总说饭要趁热慢慢吃，对胃好。你要是还没吃，可别饿着肚子跟外婆聊天，先去扒拉两口饭再说。', 'https://minimax-algeng-chat-tts.oss-cn-wulanchabu.aliyuncs.com/audio%2Feffect%2F06989ba38ac1747a1d5c54487f98f1ed_1783195814672_9591.mp3?Expires=1783282214&OSSAccessKeyId=LTAI5tGLnRTkBjLuYPjNcKQ8&Signature=Tu92nZnSTggTjJagPIoFuuxByTQ%3D', '{"provider": "minimax", "capability": "chat_llm", "conversation_kind": "chat", "context_kind": "general", "system_prompt_kind": "general", "memory_context": {"source": "memory_markdown", "long_term_path": "/app/storage/memory_context/12264fff-cbf4-4fd1-aa03-6c1dc0c9bb73/long_term_memory.md", "short_term_path": "/app/storage/memory_context/12264fff-cbf4-4fd1-aa03-6c1dc0c9bb73/short_term_memory.md", "selected_memory_ids": ["718bbc3e-4536-492f-bd00-267feae81763", "ae36f8d9-896e-4029-b2d8-76d84d2ed1e9", "ba14247c-f8fb-4891-9456-f00c0bd12c2b", "d426e678-e429-4ada-b02e-df33aa22a71a", "db018ae2-d6b9-4523-a4de-5e18f700e7de"], "long_term_compressed": false, "short_term_compressed": false, "compression_failed": false, "compression_provider": null}, "retrieval": [{"memory_card_id": "718bbc3e-4536-492f-bd00-267feae81763", "source": "memory_markdown"}, {"memory_card_id": "ae36f8d9-896e-4029-b2d8-76d84d2ed1e9", "source": "memory_markdown"}, {"memory_card_id": "ba14247c-f8fb-4891-9456-f00c0bd12c2b", "source": "memory_markdown"}, {"memory_card_id": "d426e678-e429-4ada-b02e-df33aa22a71a", "source": "memory_markdown"}, {"memory_card_id": "db018ae2-d6b9-4523-a4de-5e18f700e7de", "source": "memory_markdown"}], "voice": {"source_material_id": "1b67291f-f3ef-4404-afb7-d38271309fd5", "transcript": "\u5916\u5a46\u4eca\u5929\u5403\u4e86\u4ec0\u4e48\u5440\uff1f", "asr_job_id": "1d823a1d-b5bc-4698-8be1-342b75a00080", "synthesize_job_id": "8210be06-b55b-40da-b60f-e40a2b2a75d5", "audio_url": "https://minimax-algeng-ch