INSERT INTO public.messages VALUES ('3a1a8a97-4023-4438-8c49-0efb4020748b', '142ee8c5-95ee-488e-89c3-2aa35d96eeb6', 'user', '移动端 UX 烟测。', NULL, 'null', '2026-07-04 21:36:17.425391', NULL);
INSERT INTO public.messages VALUES ('4f1354c1-849d-46de-956d-f7bac8e5f3f5', '142ee8c5-95ee-488e-89c3-2aa35d96eeb6', 'persona', '小铭啊，外婆还是不太懂你说的这些，又是"UX"又是"烟测"的，听着像是你们年轻人工作上的事儿。外婆帮不上忙，不过外婆知道你们忙归忙，饭还是要按时吃的啊。别光顾着测试这个测试那个，把肚子饿坏了可不划算。', NULL, '{"provider": "minimax", "capability": "chat_llm", "conversation_kind": "chat", "context_kind": "general", "system_prompt_kind": "general", "memory_context": {"source": "memory_markdown", "long_term_path": "/app/storage/memory_context/27e4e946-6b92-42a2-982c-fde85b36c284/long_term_memory.md", "short_term_path": "/app/storage/memory_context/27e4e946-6b92-42a2-982c-fde85b36c284/short_term_memory.md", "selected_memory_ids": ["03503273-f1b4-421d-981a-287dfa054426", "4200e9bd-799f-4ef2-b65d-4faebff80385", "98a63224-15c7-4f4d-96a8-5bfc6e52c295", "c6f70db1-b385-4815-b9b2-623d4dcf3dcb", "f3d478e0-d46a-41d7-8d99-2e07050a6c4c"], "long_term_compressed": false, "short_term_compressed": false, "compression_failed": false, "compression_provider": null}, "retrieval": [{"memory_card_id": "03503273-f1b4-421d-981a-287dfa054426", "source": "memory_markdown"}, {"memory_card_id": "4200e9bd-799f-4ef2-b65d-4faebff80385", "source": "memory_markdown"}, {"memory_card_id": "98a63224-15c7-4f4d-96a8-5bfc6e52c295", "source": "memory_markdown"}, {"memory_card_id": "c6f70db1-b385-4815-b9b2-623d4dcf3dcb", "source": "memory_markdown"}, {"memory_card_id": "f3d478e0-d46a-41d7-8d99-2e07050a6c4c", "source": "memory_markdown"}]}', '2026-07-04 21:36:17.425392', NULL);
