INSERT INTO public.messages VALUES ('3b38c0d6-626b-4f36-8e7a-e66474af0126', 'e1a06f99-d3dc-43dc-81e7-008121d5f442', 'persona', '小铭，听到你这句话外婆心里可暖了。外婆也想你呀。 外婆这边啥都好，你别挂念，倒是你，一个人在外面要好好吃饭、好好睡觉，别让外婆担心。 你今天是不是遇到啥事了？还是就是突然想起外婆了？不管咋样，想外婆了就跟外婆说说话，外婆陪着你呢。', NULL, '{"provider": "minimax", "capability": "chat_llm", "conversation_kind": "chat", "context_kind": "general", "system_prompt_kind": "general", "memory_context": {"source": "memory_markdown", "long_term_path": "/app/storage/memory_context/12264fff-cbf4-4fd1-aa03-6c1dc0c9bb73/long_term_memory.md", "short_term_path": "/app/storage/memory_context/12264fff-cbf4-4fd1-aa03-6c1dc0c9bb73/short_term_memory.md", "selected_memory_ids": ["718bbc3e-4536-492f-bd00-267feae81763", "ae36f8d9-896e-4029-b2d8-76d84d2ed1e9", "ba14247c-f8fb-4891-9456-f00c0bd12c2b", "d426e678-e429-4ada-b02e-df33aa22a71a", "db018ae2-d6b9-4523-a4de-5e18f700e7de"], "long_term_compressed": false, "short_term_compressed": false, "compression_failed": false, "compression_provider": null}, "retrieval": [{"memory_card_id": "718bbc3e-4536-492f-bd00-267feae81763", "source": "memory_markdown"}, {"memory_card_id": "ae36f8d9-896e-4029-b2d8-76d84d2ed1e9", "source": "memory_markdown"}, {"memory_card_id": "ba14247c-f8fb-4891-9456-f00c0bd12c2b", "source": "memory_markdown"}, {"memory_card_id": "d426e678-e429-4ada-b02e-df33aa22a71a", "source": "memory_markdown"}, {"memory_card_id": "db018ae2-d6b9-4523-a4de-5e18f700e7de", "source": "memory_markdown"}]}', '2026-07-04 23:28:17.000356', NULL);
