INSERT INTO public.messages VALUES ('a5d185e5-ef2e-47dd-b264-313b31b20733', 'e1a06f99-d3dc-43dc-81e7-008121d5f442', 'persona', '小铭，外婆记得呢。 你生日那天，外婆给你准备了蛋糕，还专门煮了一碗热汤。外婆就盼着你平平安安的，只要你好好的，外婆心里就踏实。 那时候咱一家人围在一块儿，热汤冒着气儿，你吹蜡烛的时候脸蛋红扑扑的，外婆看着就觉得这孩子又长大了一岁。 小铭咋突然想起这个来了？是今天啥日子呀，还是心里有事儿想跟外婆唠唠？', NULL, '{"provider": "minimax", "capability": "chat_llm", "conversation_kind": "chat", "context_kind": "general", "system_prompt_kind": "general", "memory_context": {"source": "memory_markdown", "long_term_path": "/app/storage/memory_context/12264fff-cbf4-4fd1-aa03-6c1dc0c9bb73/long_term_memory.md", "short_term_path": "/app/storage/memory_context/12264fff-cbf4-4fd1-aa03-6c1dc0c9bb73/short_term_memory.md", "selected_memory_ids": ["718bbc3e-4536-492f-bd00-267feae81763", "ae36f8d9-896e-4029-b2d8-76d84d2ed1e9", "ba14247c-f8fb-4891-9456-f00c0bd12c2b", "d426e678-e429-4ada-b02e-df33aa22a71a", "db018ae2-d6b9-4523-a4de-5e18f700e7de"], "long_term_compressed": false, "short_term_compressed": false, "compression_failed": false, "compression_provider": null}, "retrieval": [{"memory_card_id": "718bbc3e-4536-492f-bd00-267feae81763", "source": "memory_markdown"}, {"memory_card_id": "ae36f8d9-896e-4029-b2d8-76d84d2ed1e9", "source": "memory_markdown"}, {"memory_card_id": "ba14247c-f8fb-4891-9456-f00c0bd12c2b", "source": "memory_markdown"}, {"memory_card_id": "d426e678-e429-4ada-b02e-df33aa22a71a", "source": "memory_markdown"}, {"memory_card_id": "db018ae2-d6b9-4523-a4de-5e18f700e7de", "source": "memory_markdown"}]}', '2026-07-04 23:29:20.617664', NULL);
