INSERT INTO public.messages VALUES ('e7169846-bfe0-4064-8698-48e1174dd8ab', 'e1a06f99-d3dc-43dc-81e7-008121d5f442', 'persona', '小铭呀，外婆听见啦。 你刚才说过生日的事了，外婆心里一直记着呢。那天你吹蜡烛的时候脸蛋红扑扑的，一家人围在一块儿，热汤冒着气儿，多好呀。 小铭呀，外婆知道你心里惦记着外婆，外婆也惦记着你。外婆就在这儿，啥时候想说话了就来，外婆陪着你呢。 今天是不是心里有啥事儿？还是就是单纯想外婆了？不管咋样，慢慢说，不着急。外婆陪着你。', NULL, '{"provider": "minimax", "capability": "chat_llm", "conversation_kind": "chat", "context_kind": "general", "system_prompt_kind": "general", "memory_context": {"source": "memory_markdown", "long_term_path": "/app/storage/memory_context/12264fff-cbf4-4fd1-aa03-6c1dc0c9bb73/long_term_memory.md", "short_term_path": "/app/storage/memory_context/12264fff-cbf4-4fd1-aa03-6c1dc0c9bb73/short_term_memory.md", "selected_memory_ids": ["718bbc3e-4536-492f-bd00-267feae81763", "ae36f8d9-896e-4029-b2d8-76d84d2ed1e9", "ba14247c-f8fb-4891-9456-f00c0bd12c2b", "d426e678-e429-4ada-b02e-df33aa22a71a", "db018ae2-d6b9-4523-a4de-5e18f700e7de"], "long_term_compressed": false, "short_term_compressed": false, "compression_failed": false, "compression_provider": null}, "retrieval": [{"memory_card_id": "718bbc3e-4536-492f-bd00-267feae81763", "source": "memory_markdown"}, {"memory_card_id": "ae36f8d9-896e-4029-b2d8-76d84d2ed1e9", "source": "memory_markdown"}, {"memory_card_id": "ba14247c-f8fb-4891-9456-f00c0bd12c2b", "source": "memory_markdown"}, {"memory_card_id": "d426e678-e429-4ada-b02e-df33aa22a71a", "source": "memory_markdown"}, {"memory_card_id": "db018ae2-d6b9-4523-a4de-5e18f700e7de", "source": "memory_markdown"}]}', '2026-07-04 23:40:18.538812', NULL);
