INSERT INTO public.messages VALUES ('bbb61a1d-a752-4da8-a150-138019988d8d', 'e1a06f99-d3dc-43dc-81e7-008121d5f442', 'persona', '小铭呀，外婆不太懂你说的那个啥麦克风、语音的，外婆年纪大了，脑子转不过来这些新玩意儿。 外婆就知道，你今天说了两回想外婆了，外婆心里可暖乎。 小铭呀，你要是心里有啥事儿，就跟外婆说说，不用整那些花里胡哨的。外婆就盼着你好好吃饭、好好睡觉，平平安安的。 你今天是不是心里有啥事儿呀？还是就单纯想外婆了？不管咋样，外婆都在这儿陪着你呢。', 'https://minimax-algeng-chat-tts.oss-cn-wulanchabu.aliyuncs.com/audio%2Feffect%2F0698ccf7be20a0fb7ff6f8018c581bef_1783208442167_1446.mp3?Expires=1783294842&OSSAccessKeyId=LTAI5tGLnRTkBjLuYPjNcKQ8&Signature=AjTfKuvrjp0JnfbOjzrKxu3wuGE%3D', '{"provider": "minimax", "capability": "chat_llm", "conversation_kind": "chat", "context_kind": "general", "system_prompt_kind": "general", "memory_context": {"source": "memory_markdown", "long_term_path": "/app/storage/memory_context/12264fff-cbf4-4fd1-aa03-6c1dc0c9bb73/long_term_memory.md", "short_term_path": "/app/storage/memory_context/12264fff-cbf4-4fd1-aa03-6c1dc0c9bb73/short_term_memory.md", "selected_memory_ids": ["718bbc3e-4536-492f-bd00-267feae81763", "ae36f8d9-896e-4029-b2d8-76d84d2ed1e9", "ba14247c-f8fb-4891-9456-f00c0bd12c2b", "d426e678-e429-4ada-b02e-df33aa22a71a", "db018ae2-d6b9-4523-a4de-5e18f700e7de"], "long_term_compressed": false, "short_term_compressed": false, "compression_failed": false, "compression_provider": null}, "retrieval": [{"memory_card_id": "718bbc3e-4536-492f-bd00-267feae81763", "source": "memory_markdown"}, {"memory_card_id": "ae36f8d9-896e-4029-b2d8-76d84d2ed1e9", "source": "memory_markdown"}, {"memory_card_id": "ba14247c-f8fb-4891-9456-f00c0bd12c2b", "source": "memory_markdown"}, {"memory_card_id": "d426e678-e429-4ada-b02e-df33aa22a71a", "source": "memory_markdown"}, {"memory_card_id": "db018ae2-d6b9-4523-a4de-5e18f700e7de", "source": "memory_markdown"}], "voice": {"source_material_id": "4402589d-9006-482e-9320-f8e6b91b05dd", "transcript": "\u53ef\u4ee5\u7533\u8bf7\u8981\u8fd9\u4e2a\u9ea6\u514b\u98ce\u7684\u6743\u9650\uff0c\u7136\u540e\u8fd9\u91cc\u5c31\u5df2\u7ecf\u5728\u8fd9\u4e2a\u8bed\u97f3\u7684\u8f9