INSERT INTO public.parsed_chunks VALUES ('32d6b105-0e6b-4b17-84d3-4c649cfc5ba5', '7182da13-4f02-4aab-91ba-07b664d1d8f7', '7a2e0ce2-c076-4d37-bbc0-b1c2d6e36bd9', 'text', 'CHAPTER I. Down the Rabbit-Hole Alice was beginning to get very tired of sitting by her sister on the bank, and of having nothing to do: once or twice she had peeped into the book her sister was reading, but it had no pictures or conversations in it, “and what is the use of a book,” thought Alice “without pictures or conversations?” So she was considering in her own mind (as well as she could, for the hot day made her feel very sleepy and stupid), whether the pleasure of making a daisy-chain would be worth the trouble of getting up and picking the daisies, when suddenly a White Rabbit with pink eyes ran close by her. There was nothing so _very_ remarkable in that; nor did Alice think it so _very_ much out of the way to hear the Rabbit say to itself, “Oh dear! Oh dear! I shall be late!” (when she thought it over afterwards, it occurred to her that she ought to have wondered at this, but at the time it all seemed quite natural); but when the Rabbit actually _took a watch out of its waistcoat-pocket_, and looked at it, and then hurried on, Alice started to her feet, for it flashed across her mind that she had never before seen a rabbit with either a waistcoat-pocket, or a watch to take out of it, and burning with curiosity, she ran across the field after it, and fortunately was just in time to see it pop down a large rabbit-hole under the hedge. In another moment down went Alice after it, never once considering how in the world she was to get out again. The rabbit-hole went straight on like a tunnel for some way, and then dipped suddenly down, so suddenly that Alice had not a moment to think about stopping herself before she found herself falling down a very deep well. Either the well was very deep, or...', 'Alice, bored while sitting with her sister, notices a talking White Rabbit with pink eyes who checks a pocket watch and rushes away; intrigued by its unusual appearance and behavior, she follows it into a rabbit-hole and begins falling down a deep well.', 'text:alice-memory-trimmed.txt', NULL, NULL, '{"text_extraction": {"extractor": "plain_text", "source_location": "text:alice-memory-trimmed.txt", "file_name": "alice-memory-trimmed.txt", "mime_type": "text/plain", "has_text": true}, "text_parser": {"cleaned_text": "CHAPTER I. Down the Rabbit-Hole Alice was beginning to get very tired of sitting by her sister on the bank, and of having nothing to do: once or twice she had peeped into the book her sister was reading, but it had no pictures or conversations in it, \u201cand what is the use of a book,\u201d thought Alice \u201cwithout pictures or conversations?\u201d So she was considering in her own mind (as well as she could, for the hot day made her feel very sleepy and stupid), whether the pleasure of making a daisy-chain would be worth the trouble of getting up and picking the daisies, when suddenly a White Rabbit with pink eyes ran close by her. There was nothing so _very_ remarkable in that; nor did Alice think it so _very_ much out of the way to hear the Rabbit say to itself, \u201cOh dear! Oh dear! I shall be late!\u201d (when she thought it over afterwards, it occurred to her that she ought to have wondered at this, but at the time it all seemed quite natural); but when the Rabbit actually _took a watch out of its waistcoat-pocket_, and looked at it, and then hurried on, Alice started to her feet, for it flashed across her mind that she had never before seen a rabbit with either a waistcoat-pocket, or a watch to take out of it, and burning with curiosity, she ran across the field after it, and fortunately was just in time to see it pop down a large rabbit-hole under the hedge. In another moment down went Alice after it, never once considering how in the world she was to get out again. The rabbit-hole went straight on like a tunnel for some way, and then dipped suddenly down, so suddenly that Alice had not a moment to think about stopping herself before she found herself falling down a very deep well. Either the well was very deep, or...", "chunks": [{"chunk_type": "text", "content": "CHAPTER I. Down the Rabbit-Hole Alice was beginning to get very tired of sitting by her sister on the bank, and of having nothing to do: once or twice she had peeped into the book her sister was reading, but it had no pictures or conversations in it, \u201cand what is the use of a book,\u201d thought Alice \u201cwithout pictures or conversations?\u201d So she was considering in her own mind (as well as she could, for the hot day made her feel very sleepy and stupid), whether the pleasure of making a daisy-chain would be worth the trouble of getting up and picking the daisies, when suddenly a White Rabbit with pink eyes ran close by her. There was nothing so _very_ remarkable in that; nor did Alice think it so _very_ much out of the way to hear the Rabbit say to itself, \u201cOh dear! Oh dear! I shall be late!\u201d (when she thought it over afterwards, it occurred to her that she ought to have wondered at this, but at the time it all seemed quite natural); but when the Rabbit actually _took a watch out of its waistcoat-pocket_, and looked at it, and then hurried on, Alice started to her feet, for it flashed across her mind that she had never before seen a rabbit with either a waistcoat-pocket, or a watch to take out of it, and burning with curiosity, she ran across the field after it, and fortunately was just in time to see it pop down a large rabbit-hole under the hedge. In another moment down went Alice after it, never once considering how in the world she was to get out again. The rabbit-hole went straight on like a tunnel for some way, and then dipped suddenly down, so suddenly that Alice had not a moment to think about stopping herself before she found herself falling down a very deep well. Either the well was very deep, or...", "summary": "Alice, bored while sitting with her sister, notices a talking White Rabbit with pink eyes who checks a pocket watch and rushes away; intrigued by its unusual appearance and behavior, she follows it into a rabbit-hole and begins falling down a deep well.", "source_location": "text:alice-memory-trimmed.txt"}]}, "provider_type": "third_party"}', NULL, '2026-07-04 09:07:21.434178', NULL);
INSERT INTO public.parsed_chunks VALUES ('a36ff013-47b8-4498-8a6c-2213a9b1f522', '7182da13-4f02-4aab-91ba-07b664d1d8f7', '459b97bb-5581-445f-8f27-e77794b81df4', 'image', 'A standard red octagonal traffic sign with the word ''STOP'' written in large white capital letters.。STOP。During a walk, the persona used a public stop sign to teach the user to pause, stop, and look both ways for safety.', 'A standard red octagonal traffic sign with the word ''STOP'' written in large white capital letters.', 'image:stop-sign.png', NULL, NULL, '{"ocr": {"ocr_text": "STOP", "source_location": "image:stop-sign.png:ocr"}, "image_understanding": {"caption": "A standard red octagonal traffic sign with the word ''STOP'' written in large white capital letters.", "scene_metadata": {"scene_type": "traffic_sign", "detected_people_count": 0, "emotion_tone": "instructive"}, "memory_candidate_text": "During a walk, the persona used a public stop sign to teach the user to pause, stop, and look both ways for safety.", "source_location": "image:stop-sign.png"}, "provider_type": "third_party"}', NULL, '2026-07-04 09:07:44.373853', NULL);
INSERT INTO public.parsed_chunks VALUES ('fe8f9135-057d-46e6-9ccd-8de58f578e5b', '7182da13-4f02-4aab-91ba-07b664d1d8f7', 'e986ab43-6287-48d4-a970-23b17561d211', 'audio', 'This is a LibriVox recording. All LibriVox recordings are in the public domain. For more information or to volunteer, please visit LibriVox.org. Recording by Peter Yearsley. Abu Ben Adhem by Leigh Hunt. Abu Ben Adhem, may his tribe increase, awoke one night from a deep dream of peace, and saw within the moonlight in his room, making it rich and like a lily in bloom, an angel writing in a book of gold. Exceeding peace had made Ben Adhem bold, and to the presence in the room he said, "What writest thou?" The vision raised its head, and with a look made of all sweet accord answered, "The names of those who love the Lord." And is mine one? said Abu. "Nay, not so," replied the angel. Abu spoke more low, but cheerily still, and said, "I pray thee then, write me as one that loves his fellow men." The angel wrote and vanished. The next night it came again with a great wakening light, and showed the names whom love of God had blessed. And lo, Ben Adhem''s name led all the rest. End of recording.', 'This is a LibriVox recording. All LibriVox recordings are in the public domain. ', 'audio:abou-ben-adhem.mp3#00:00', 0, 5, '{"asr": {"transcript": "This is a LibriVox recording. All LibriVox recordings are in the public domain. For more information or to volunteer, please visit LibriVox.org. Recording by Peter Yearsley. Abu Ben Adhem by Leigh Hunt. Abu Ben Adhem, may his tribe increase, awoke one night from a deep dream of peace, and saw within the moonlight in his room, making it rich and like a lily in bloom, an angel writing in a book of gold. Exceeding peace had made Ben Adhem bold, and to the presence in the room he said, \"What writest thou?\" The vision raised its head, and with a look made of all sweet accord answered, \"The names of those who love the Lord.\" And is mine one? said Abu. \"Nay, not so,\" replied the angel. Abu spoke more low, but cheerily still, and said, \"I pray thee then, write me as one that loves his fellow men.\" The angel wrote and vanished. The next night it came again with a great wakening light, and showed the names whom love of God had blessed. And lo, Ben Adhem''s name led all the rest. End of recording.", "sample_metadata": {"start_time": "00:00", "end_time": null, "speaker": "unknown", "language": "zh"}, "source_location": "audio:abou-ben-adhem.mp3#00:00"}, "provider_type": "third_party"}', NULL, '2026-07-04 09:08:11.46207', NULL);
INSERT INTO public.parsed_chunks VALUES ('a2b75799-aa07-4d17-be8d-ffd9a9315afc', '7182da13-4f02-4aab-91ba-07b664d1d8f7', 'd5e51dfd-171e-4ce4-87d4-4854651d9c9b', 'video', '。根据您提供的视频关键帧和音频转写内容，以下是视频场景摘要： **视频场景摘要** 这段视频由美国地质调查局（USGS）制作，主要展示了火山熔岩流动的自然奇观。视频以 USGS 的标志开场，随后切入火山现场画面，展示了炽热的熔岩在冷却的黑色岩石地表上蜿蜒流淌的壮观景象，并标注了“VOLCANO Lava Sample”（火山熔岩样本），表明这是一段关于地质科学记录或样本展示的影像。 **详细说明：** * **人物：** 视频中未出现具体人物。隐含的主体是进行科学观测和记录的 USGS（美国地质调查局）科研人员。 * **地点：** 活跃的火山区域，具体为熔岩流经过的地带（地面覆盖着冷却的黑色熔岩）。 * **事件：** 视频记录了火山熔岩的流动过程，并将其定义为“熔岩样本”，旨在展示地质活动或为科学研究提供视觉资料。 * **情绪：** 震撼、壮观、敬畏自然。红色的熔岩与黑色的环境形成强烈对比，既危险又美丽，同时也带有科学记录的客观与严谨。 * **可作为记忆的片段：** 1. **开场标志：** 黑底白字的 USGS 标志及其标语“science for a changing world”（为变化的世界提供科学）。 2. **熔岩流淌：** 炽热的橙红色熔岩像河流一样，在灰黑色、崎岖不平的冷却熔岩地表上蜿蜒流动的特写镜头。 3. **文字标题：** 画面中央叠加的白色大字“VOLCANO Lava Sample”，明确了视频的主题。。根据您提供的视频关键帧和音频转写内容，以下是视频场景摘要： **视频场景摘要** 这段视频由美国地质调查局（USGS）制作，主要展示了火山熔岩流动的自然奇观。视频以 USGS 的标志开场，随后切入火山现场画面，展示了炽热的熔岩在冷却的黑色岩石地表上蜿蜒流淌的壮观景象，并标注了“VOLCANO Lava Sample”（火山熔岩样本），表明这是一段关于地质科学记录或样本展示的影像。 **详细说明：** * **人物：** 视频中未出现具体人物。隐含的主体是进行科学观测和记录的 USGS（美国地质调查局）科研人员。 * **地点：** 活跃的火山区域，具体为熔岩流经过的地带（地面覆盖着冷却的黑色熔岩）。 * **事件：** 视频记录了火山熔岩的流动过程，并将其定义为“熔岩样本”，旨在展示地质活动或为科学研究提供视觉资料。 * **情绪：** 震撼、壮观、敬畏自然。红色的熔岩与黑色的环境形成强烈对比，既危险又美丽，同时也带有科学记录的客观与严谨。 * **可作为记忆的片段：** 1. **开场标志：** 黑底白字的 USGS 标志及其标语“science for a changing world”（为变化的世界提供科学）。 2. **熔岩流淌：** 炽热的橙红色熔岩像河流一样，在灰黑色、崎岖不平的冷却熔岩地表上蜿蜒流动的特写镜头。 3. **文字标题：** 画面中央叠加的白色大字“VOLCANO Lava Sample”，明确了视频的主题。', '根据您提供的视频关键帧和音频转写内容，以下是视频场景摘要： **视频场景摘要** 这段视频由美国地质调查局（USGS）制作，主要展示了火山熔岩流动的自然奇观。视频以 USGS 的标志开场，随后切入火山现场画面，展示了炽热的熔岩在冷却的黑色岩石地表上蜿蜒流淌的壮观景象，并标注了“VOLCANO Lava Sample”（火山熔岩样本），表明这是一段关于地质科学记录或样本展示的影像。 **详细说明：** * **人物：** 视频中未出现具体人物。隐含的主体是进行科学观测和记录的 USGS（美国地质调查局）科研人员。 * **地点：** 活跃的火山区域，具体为熔岩流经过的地带（地面覆盖着冷却的黑色熔岩）。 * **事件：** 视频记录了火山熔岩的流动过程，并将其定义为“熔岩样本”，旨在展示地质活动或为科学研究提供视觉资料。 * **情绪：** 震撼、壮观、敬畏自然。红色的熔岩与黑色的环境形成强烈对比，既危险又美丽，同时也带有科学记录的客观与严谨。 * **可作为记忆的片段：** 1. **开场标志：** 黑底白字的 USGS 标志及其标语“science for a changing world”（为变化的世界提供科学）。 2. **熔岩流淌：** 炽热的橙红色熔岩像河流一样，在灰黑色、崎岖不平的冷却熔岩地表上蜿蜒流动的特写镜头。 3. **文字标题：** 画面中央叠加的白色大字“VOLCANO Lava Sample”，明确了视频的主题。', 'video:volcano-lava-smoke-clip.mp4#00:00', 0, 10, '{"video_understanding": {"transcript": "", "scene_summary": "\u6839\u636e\u60a8\u63d0\u4f9b\u7684\u89c6\u9891\u5173\u952e\u5e27\u548c\u97f3\u9891\u8f6c\u5199\u5185\u5bb9\uff0c\u4ee5\u4e0b\u662f\u89c6\u9891\u573a\u666f\u6458\u8981\uff1a **\u89c6\u9891\u573a\u666f\u6458\u8981** \u8fd9\u6bb5\u89c6\u9891\u7531\u7f8e\u56fd\u5730\u8d28\u8c03\u67e5\u5c40\uff08USGS\uff09\u5236\u4f5c\uff0c\u4e3b\u8981\u5c55\u793a\u4e86\u706b\u5c71\u7194\u5ca9\u6d41\u52a8\u7684\u81ea\u7136\u5947\u89c2\u3002\u89c6\u9891\u4ee5 USGS \u7684\u6807\u5fd7\u5f00\u573a\uff0c\u968f\u540e\u5207\u5165\u706b\u5c71\u73b0\u573a\u753b\u9762\uff0c\u5c55\u793a\u4e86\u70bd\u70ed\u7684\u7194\u5ca9\u5728\u51b7\u5374\u7684\u9ed1\u8272\u5ca9\u77f3\u5730\u8868\u4e0a\u873f\u8712\u6d41\u6dcc\u7684\u58ee\u89c2\u666f\u8c61\uff0c\u5e76\u6807\u6ce8\u4e86\u201cVOLCANO Lava Sample\u201d\uff08\u706b\u5c71\u7194\u5ca9\u6837\u672c\uff09\uff0c\u8868\u660e\u8fd9\u662f\u4e00\u6bb5\u5173\u4e8e\u5730\u8d28\u79d1\u5b66\u8bb0\u5f55\u6216\u6837\u672c\u5c55\u793a\u7684\u5f71\u50cf\u3002 **\u8be6\u7ec6\u8bf4\u660e\uff1a** * **\u4eba\u7269\uff1a** \u89c6\u9891\u4e2d\u672a\u51fa\u73b0\u5177\u4f53\u4eba\u7269\u3002\u9690\u542b\u7684\u4e3b\u4f53\u662f\u8fdb\u884c\u79d1\u5b66\u89c2\u6d4b\u548c\u8bb0\u5f55\u7684 USGS\uff08\u7f8e\u56fd\u5730\u8d28\u8c03\u67e5\u5c40\uff09\u79d1\u7814\u4eba\u5458\u3002 * **\u5730\u70b9\uff1a** \u6d3b\u8dc3\u7684\u706b\u5c71\u533a\u57df\uff0c\u5177\u4f53\u4e3a\u7194\u5ca9\u6d41\u7ecf\u8fc7\u7684\u5730\u5e26\uff08\u5730\u9762\u8986\u76d6\u7740\u51b7\u5374\u7684\u9ed1\u8272\u7194\u5ca9\uff09\u3002 * **\u4e8b\u4ef6\uff1a** \u89c6\u9891\u8bb0\u5f55\u4e86\u706b\u5c71\u7194\u5ca9\u7684\u6d41\u52a8\u8fc7\u7a0b\uff0c\u5e76\u5c06\u5176\u5b9a\u4e49\u4e3a\u201c\u7194\u5ca9\u6837\u672c\u201d\uff0c\u65e8\u5728\u5c55\u793a\u5730\u8d28\u6d3b\u52a8\u6216\u4e3a\u79d1\u5b66\u7814\u7a76\u63d0\u4f9b\u89c6\u89c9\u8d44\u6599