INSERT INTO public.parsed_chunks VALUES ('eff005c0-36a1-4f9b-afec-2fb7206fff66', '7182da13-4f02-4aab-91ba-07b664d1d8f7', '5bc8bdfa-a06e-407f-a51f-ae0ad329dd43', 'text', 'CHAPTER I. Down the Rabbit-Hole Alice was beginning to get very tired of sitting by her sister on the bank, and of having nothing to do: once or twice she had peeped into the book her sister was reading, but it had no pictures or conversations in it, and what is the use of a book, thought Alice, without pictures or conversations? So she was considering in her own mind (as well as she could, for the hot day made her feel very sleepy and stupid), whether the pleasure of making a daisy-chain would be worth the trouble of getting up and picking the daisies, when suddenly a White Rabbit with pink eyes ran close by her. There was nothing so very remarkable in that; nor did Alice think it so very much out of the way to hear the Rabbit say to itself, ''Oh dear! Oh dear! I shall be late!'' (when she thought it over afterwards, it occurred to her that she ought to have wondered at this, but at the time it all seemed quite natural); but when the Rabbit actually took a watch...', 'Introduction to Alice and the beginning of her adventure: she grows bored, observes her sister''s dull book, reflects on daisy-chaining, and is startled by a talking White Rabbit with a watch.', 'text:alice-derived.pdf, page 1', NULL, NULL, '{"text_extraction": {"extractor": "pypdf", "page_count": 1, "source_location": "text:alice-derived.pdf", "file_name": "alice-derived.pdf", "mime_type": "application/pdf", "has_text": true}, "text_parser": {"cleaned_text": "CHAPTER I. Down the Rabbit-Hole Alice was beginning to get very tired of sitting by her sister on the bank, and of having nothing to do: once or twice she had peeped into the book her sister was reading, but it had no pictures or conversations in it, and what is the use of a book, thought Alice, without pictures or conversations? So she was considering in her own mind (as well as she could, for the hot day made her feel very sleepy and stupid), whether the pleasure of making a daisy-chain would be worth the trouble of getting up and picking the daisies, when suddenly a White Rabbit with pink eyes ran close by her. There was nothing so very remarkable in that; nor did Alice think it so very much out of the way to hear the Rabbit say to itself, ''Oh dear! Oh dear! I shall be late!'' (when she thought it over afterwards, it occurred to her that she ought to have wondered at this, but at the time it all seemed quite natural); but when the Rabbit actually took a watch...", "chunks": [{"chunk_type": "text", "content": "CHAPTER I. Down the Rabbit-Hole Alice was beginning to get very tired of sitting by her sister on the bank, and of having nothing to do: once or twice she had peeped into the book her sister was reading, but it had no pictures or conversations in it, and what is the use of a book, thought Alice, without pictures or conversations? So she was considering in her own mind (as well as she could, for the hot day made her feel very sleepy and stupid), whether the pleasure of making a daisy-chain would be worth the trouble of getting up and picking the daisies, when suddenly a White Rabbit with pink eyes ran close by her. There was nothing so very remarkable in that; nor did Alice think it so very much out of the way to hear the Rabbit say to itself, ''Oh dear! Oh dear! I shall be late!'' (when she thought it over afterwards, it occurred to her that she ought to have wondered at this, but at the time it all seemed quite natural); but when the Rabbit actually took a watch...", "summary": "Introduction to Alice and the beginning of her adventure: she grows bored, observes her sister''s dull book, reflects on daisy-chaining, and is startled by a talking White Rabbit with a watch.", "source_location": "text:alice-derived.pdf, page 1"}]}, "provider_type": "third_party"}', NULL, '2026-07-04 09:08:53.46048', NULL);
