INSERT INTO public.parsed_chunks VALUES ('65a3f8eb-dd20-4f91-9efa-2e4048beaa24', '7182da13-4f02-4aab-91ba-07b664d1d8f7', '2fa35ab5-31c7-4ed3-8f21-a13d1bf8899d', 'text', 'CHAPTER I. Down the Rabbit-Hole Alice was beginning to get very tired of sitting by her sister on the bank, and of having nothing to do: once or twice she had peeped into the book her sister was reading, but it had no pictures or conversations in it, “and what is the use of a book,” thought Alice, “without pictures or conversations?” So she was considering in her own mind (as well as she could, for the hot day made her feel very sleepy and stupid), whether the pleasure of making a daisy-chain would be worth the trouble of getting up and picking the daisies, when suddenly a White Rabbit with pink eyes ran close by her. There was nothing so very remarkable in that; nor did Alice think it so very much out of the way to hear the Rabbit say to itself, “Oh dear! Oh dear! I shall be late!” (when she thought it over afterwards, it occurred to her that she ought to have wondered at this, but at the time it all seemed quite natural); but when the Rabbit actually took a watch.', 'Alice, bored while sitting with her sister, notices a talking White Rabbit with pink eyes who checks a watch and worries about being late — an event that initially seems ordinary to her despite its strangeness.', 'text:alice-derived.docx', NULL, NULL, '{"text_extraction": {"extractor": "docx", "source_location": "text:alice-derived.docx", "file_name": "alice-derived.docx", "mime_type": "application/vnd.openxmlformats-officedocument.wordprocessingml.document", "has_text": true}, "text_parser": {"cleaned_text": "CHAPTER I. Down the Rabbit-Hole Alice was beginning to get very tired of sitting by her sister on the bank, and of having nothing to do: once or twice she had peeped into the book her sister was reading, but it had no pictures or conversations in it, \u201cand what is the use of a book,\u201d thought Alice, \u201cwithout pictures or conversations?\u201d So she was considering in her own mind (as well as she could, for the hot day made her feel very sleepy and stupid), whether the pleasure of making a daisy-chain would be worth the trouble of getting up and picking the daisies, when suddenly a White Rabbit with pink eyes ran close by her. There was nothing so very remarkable in that; nor did Alice think it so very much out of the way to hear the Rabbit say to itself, \u201cOh dear! Oh dear! I shall be late!\u201d (when she thought it over afterwards, it occurred to her that she ought to have wondered at this, but at the time it all seemed quite natural); but when the Rabbit actually took a watch.", "chunks": [{"chunk_type": "text", "content": "CHAPTER I. Down the Rabbit-Hole Alice was beginning to get very tired of sitting by her sister on the bank, and of having nothing to do: once or twice she had peeped into the book her sister was reading, but it had no pictures or conversations in it, \u201cand what is the use of a book,\u201d thought Alice, \u201cwithout pictures or conversations?\u201d So she was considering in her own mind (as well as she could, for the hot day made her feel very sleepy and stupid), whether the pleasure of making a daisy-chain would be worth the trouble of getting up and picking the daisies, when suddenly a White Rabbit with pink eyes ran close by her. There was nothing so very remarkable in that; nor did Alice think it so very much out of the way to hear the Rabbit say to itself, \u201cOh dear! Oh dear! I shall be late!\u201d (when she thought it over afterwards, it occurred to her that she ought to have wondered at this, but at the time it all seemed quite natural); but when the Rabbit actually took a watch.", "summary": "Alice, bored while sitting with her sister, notices a talking White Rabbit with pink eyes who checks a watch and worries about being late \u2014 an event that initially seems ordinary to her despite its strangeness.", "source_location": "text:alice-derived.docx"}]}, "provider_type": "third_party"}', NULL, '2026-07-04 09:09:10.40179', NULL);
