INSERT INTO public.parsed_chunks VALUES ('73028df9-a285-45b6-acef-7b499240eb6f', '6e71e1ce-8524-4466-8957-b9bd518531f4', '218b4a0c-1881-4121-a3c2-1b217eac317d', 'audio', 'This is a LibriVox recording. All LibriVox recordings are in the public domain. For more information or to volunteer, please visit LibriVox.org. Recording by Peter Yearsley. Abu Ben Adhem by Leigh Hunt. Abu Ben Adhem, may his tribe increase, awoke one night from a deep dream of peace, and saw within the moonlight in his room, making it rich and like a lily in bloom, an angel writing in a book of gold. Exceeding peace had made Ben Adhem bold, and to the presence in the room he said, "What writest thou?" The vision raised its head, and with a look made of all sweet accord, answered, "The names of those who love the Lord." "And is mine one?" said Abu. "Nay, not so," replied the angel. Abu spoke more low, but cheerly still, and said, "I pray thee then, write me as one that loves his fellow men." The angel wrote, and vanished. The next night it came again with a great wakening light, and showed the names whom love of God had blessed. And lo, Ben Adhem''s name led all the rest. End of recording.', 'This is a LibriVox recording. All LibriVox recordings are in the public domain. ', 'audio:abou-ben-adhem.mp3#00:00', 0, 5, '{"asr": {"transcript": "This is a LibriVox recording. All LibriVox recordings are in the public domain. For more information or to volunteer, please visit LibriVox.org. Recording by Peter Yearsley. Abu Ben Adhem by Leigh Hunt. Abu Ben Adhem, may his tribe increase, awoke one night from a deep dream of peace, and saw within the moonlight in his room, making it rich and like a lily in bloom, an angel writing in a book of gold. Exceeding peace had made Ben Adhem bold, and to the presence in the room he said, \"What writest thou?\" The vision raised its head, and with a look made of all sweet accord, answered, \"The names of those who love the Lord.\" \"And is mine one?\" said Abu. \"Nay, not so,\" replied the angel. Abu spoke more low, but cheerly still, and said, \"I pray thee then, write me as one that loves his fellow men.\" The angel wrote, and vanished. The next night it came again with a great wakening light, and showed the names whom love of God had blessed. And lo, Ben Adhem''s name led all the rest. End of recording.", "sample_metadata": {"start_time": "00:00", "end_time": null, "speaker": "unknown", "language": "zh"}, "source_location": "audio:abou-ben-adhem.mp3#00:00"}, "provider_type": "third_party"}', NULL, '2026-07-04 10:07:10.862302', NULL);
INSERT INTO public.parsed_chunks VALUES ('d4f71332-5cd1-4ea2-8aaa-c5c37d1a6ea7', '6e71e1ce-8524-4466-8957-b9bd518531f4', '0875b9d4-8981-4c41-8eb7-3298aa48ceea', 'text', 'CHAPTER I. Down the Rabbit-Hole Alice was beginning to get very tired of sitting by her sister on the bank, and of having nothing to do: once or twice she had peeped into the book her sister was reading, but it had no pictures or conversations in it, and what is the use of a book, thought Alice without pictures or conversations? So she was considering in her own mind (as well as she could, for the hot day made her feel very sleepy and stupid), whether the pleasure of making a daisy-chain would be worth the trouble of getting up and picking the daisies, when suddenly a White Rabbit with pink eyes ran close by her. There was nothing so _very_ remarkable in that; nor did Alice think it so _very_ much out of the way to hear the Rabbit say to itself, Oh dear! Oh dear! I shall be late! (when she thought it over afterwards, it occurred to her that she ought to have wondered at this, but at the time it all seemed quite natural); but when the Rabbit actually _took a watch', 'Alice, bored while sitting with her sister, notices a talking White Rabbit with pink eyes who checks a watch and worries about being late — an event that initially seems ordinary to her despite its strangeness.', 'text:alice-derived.pdf, page 1', NULL, NULL, '{"text_extraction": {"extractor": "pypdf", "page_count": 1, "source_location": "text:alice-derived.pdf", "file_name": "alice-derived.pdf", "mime_type": "application/pdf", "has_text": true}, "text_parser": {"cleaned_text": "CHAPTER I. Down the Rabbit-Hole Alice was beginning to get very tired of sitting by her sister on the bank, and of having nothing to do: once or twice she had peeped into the book her sister was reading, but it had no pictures or conversations in it, and what is the use of a book, thought Alice without pictures or conversations? So she was considering in her own m