INSERT INTO public.parsed_chunks VALUES ('5880d0e4-5c53-416a-911a-e75d2917d797', '108d3084-31cf-4a3d-8b1c-d559df5baf96', '8eada434-ab6f-4ac9-a51b-531f5edf9ddd', 'manual', '外婆常说慢慢来，别急，心里难受的时候先把气喘匀。', '外婆教导遇情绪波动时应放缓节奏、先稳定呼吸。', 'manual:body', NULL, NULL, '{"text_extraction": {"extractor": "manual", "source_location": "manual:body", "has_text": true}, "text_parser": {"cleaned_text": "\u5916\u5a46\u5e38\u8bf4\u6162\u6162\u6765\uff0c\u522b\u6025\uff0c\u5fc3\u91cc\u96be\u53d7\u7684\u65f6\u5019\u5148\u628a\u6c14\u5598\u5300\u3002", "chunks": [{"chunk_type": "text", "content": "\u5916\u5a46\u5e38\u8bf4\u6162\u6162\u6765\uff0c\u522b\u6025\uff0c\u5fc3\u91cc\u96be\u53d7\u7684\u65f6\u5019\u5148\u628a\u6c14\u5598\u5300\u3002", "summary": "\u5916\u5a46\u6559\u5bfc\u9047\u60c5\u7eea\u6ce2\u52a8\u65f6\u5e94\u653e\u7f13\u8282\u594f\u3001\u5148\u7a33\u5b9a\u547c\u5438\u3002", "source_location": "manual:body"}]}, "provider_type": "third_party"}', NULL, '2026-07-04 14:28:52.86387', NULL);
INSERT INTO public.parsed_chunks VALUES ('55845b40-3448-4816-9cfb-c697c420610f', '108d3084-31cf-4a3d-8b1c-d559df5baf96', 'ed802ef0-ada5-464e-8476-3f6cf3194038', 'manual', '小铭生日那天，外婆准备了蛋糕和一碗热汤，笑着说只要小铭平安就好。', '外婆在小铭生日时准备蛋糕和热汤，并表达平安祝福。', 'manual:body', NULL, NULL, '{"text_extraction": {"extractor": "manual", "source_location": "manual:body", "has_text": true}, "text_parser": {"cleaned_text": "\u5c0f\u94ed\u751f\u65e5\u90a3\u5929\uff0c\u5916\u5a46\u51c6\u5907\u4e86\u86cb\u7cd5\u548c\u4e00\u7897\u70ed\u6c64\uff0c\u7b11\u7740\u8bf4\u53ea\u8981\u5c0f\u94ed\u5e73\u5b89\u5c31\u597d\u3002", "chunks": [{"chunk_type": "text", "content": "\u5c0f\u94ed\u751f\u65e5\u90a3\u5929\uff0c\u5916\u5a46\u51c6\u5907\u4e86\u86cb\u7cd5\u548c\u4e00\u7897\u70ed\u6c64\uff0c\u7b11\u7740\u8bf4\u53ea\u8981\u5c0f\u94ed\u5e73\u5b89\u5c31\u597d\u3002", "summary": "\u5916\u5a46\u5728\u5c0f\u94ed\u751f\u65e5\u65f6\u51c6\u5907\u86cb\u7cd5\u548c\u70ed\u6c64\uff0c\u5e76\u8868\u8fbe\u5e73\u5b89\u795d\u798f\u3002", "source_location": "manual:body"}]}, "provider_type": "third_party"}', NULL, '2026-07-04 14:28:57.668064', NULL);
INSERT INTO public.parsed_chunks VALUES ('208dab88-7a8b-4081-820f-860522ab7d30', '18b88e96-5633-4d75-b77a-0ad1988a846a', '3f5de67f-c167-4129-9948-e76ff91b0620', 'manual', '第一，他希望我不要太苛责自己。爷爷年轻时吃过很多苦，所以他知道人生不是每一步都能走得漂亮。他不会要求我永远成功，也不会要求我永远坚强。他会希望我在失败的时候，不要急着否定自己。他可能会对我说：“孩子，人这一生哪有不难的时候。爷爷当年在南洋，也有很多次觉得撑不下去。可是日子不是一天过完的，是一天天熬出来的。你不要因为一时走得慢，就觉得自己没用。”', '爷爷希望“我”接纳失败与不完美，不自我苛责，理解人生需耐心坚持。', 'manual:body', NULL, NULL, '{"text_extraction": {"extractor": "manual", "source_location": "manual:body", "has_text": true}, "text_parser": {"cleaned_text": "\u5341\u3001\u7237\u7237\u5bf9\u6211\u7684\u5fc3\u613f \u5982\u679c\u7237\u7237\u8fd8\u80fd\u5bf9\u6211\u8bf4\u8bdd\uff0c\u6211\u60f3\u4ed6\u5bf9\u6211\u7684\u5fc3\u613f\u4f1a\u975e\u5e38\u5177\u4f53\u3002 \u7b2c\u4e00\uff0c\u4ed6\u5e0c\u671b\u6211\u4e0d\u8981\u592a\u82db\u8d23\u81ea\u5df1\u3002\u7237\u7237\u5e74\u8f7b\u65f6\u5403\u8fc7\u5f88\u591a\u82e6\uff0c\u6240\u4ee5\u4ed6\u77e5\u9053\u4eba\u751f\u4e0d\u662f\u6bcf\u4e00\u6b65\u90fd\u80fd\u8d70\u5f97\u6f02\u4eae\u3002\u4ed6\u4e0d\u4f1a\u8981\u6c42\u6211\u6c38\u8fdc\u6210\u529f\uff0c\u4e5f\u4e0d\u4f1a\u8981\u6c42\u6211\u6c38\u8fdc\u575a\u5f3a\u3002\u4ed6\u4f1a\u5e0c\u671b\u6211\u5728\u5931\u8d25\u7684\u65f6\u5019\uff0c\u4e0d\u8981\u6025\u7740\u5426\u5b9a\u81ea\u5df1\u3002\u4ed6\u53ef\u80fd\u4f1a\u5bf9\u6211\u8bf4\uff1a\u201c\u5b69\u5b50\uff0c\u4eba\u8fd9\u4e00\u751f\u54ea\u6709\u4e0d\u96be\u7684\u65f6\u5019\u3002\u7237\u7237\u5f53\u5e74\u5728\u5357\u6d0b\uff0c\u4e5f\u6709\u5f88\u591a\u6b21\u89c9\u5f97\u6491\u4e0d\u4e0b\u53bb\u3002\u53ef\u662f\u65e5\u5b50\u4e0d\u662f\u4e00\u5929\u8fc7\u5b8c\u7684\uff0c\u662f\u4e00\u5929\u5929\u71ac\u51fa\u6765\u7684\u3002\u4f60\u4e0d\u8981\u56e0\u4e3a\u4e00\u65f6\u8d70\u5f97\u6162\uff0c\u5c31\u89c9\u5f97\u81ea\u5df1\u6ca1\u7528\u3002\u201d \u7b2c\u4e8c\uff0c\u4ed6\u5e0c\u671b\u6211\u8bb0\u5f97\u5bb6\u4ece\u54ea\u91cc\u6765\u3002\u4ed6\u5e0c\u671b\u6211\u4e0d\u8981\u628a\u4eca\u5929\u62e5\u6709\u7684\u4e00\u5207\u90fd\u770b\u5f97\u7406\u6240\u5f53\u7136\u3002\u5e0c\u671b\u6211\u8bb0\u5f97\uff0c\u6211\u4eec\u5bb6\u4e0d\u662f\u4e00\u5f00\u59cb\u5c31\u5b89\u7a33\u7684\uff0c\u662f\u6709\u4eba\u79bb\u5f00\u8fc7\u5bb6\u4e61\uff0c\u6709\u4eba\u5403\u8fc7\u82e6\uff0c\u6709\u4eba\u7b49\u8fc7\u5f88\u591a\u5e74\uff0c\u6709\u4eba\u628a\u94b1\u4e00\u5206\u4e00\u5206\u5bc4\u56de\u6765\uff0c\u624d\u6162\u6162\u6709\u4e86\u540e\u6765\u7684\u65e5\u5b50\u3002\u4ed6\u5e0c\u671b\u6211\u6709\u7a7a\u65f6\u56de\u8001\u5bb6\u770b\u770b\uff0c\u770b\u770b\u7956\u5c4b\uff0c\u770b\u770b\u6751\u53e3\u7684\u8def\uff0c\u770b\u770b\u4ed6\u548c\u963f\u5b37\u751f\u6d3b\u8fc7\u7684\u5730\u65b9\u3002\u4ed6\u5e0c\u671b\u6211\u77e5\u9053\uff0c\u5bb6\u4e0d\u662f\u4e00\u4e2a\u62bd\u8c61\u7684\u8bcd\uff0c\u800c\u662f\u6709\u4eba\u7528\u4e00\u751f\u5b88\u4f4f\u7684\u5730\u65b9\u3002 \u7b2c\u4e09\uff0c\u4ed6\u5e0c\u671b\u6211\u597d\u597d\u7167\u987e\u963f\u5b37\u548c\u5bb6\u91cc\u4eba\u3002\u4ed6\u4f1a\u5e0c\u671b\u6211\u9022\u5e74\u8fc7\u8282\u4e0d\u8981\u53ea\u53d1\u4e00\u53e5\u6d88\u606f\uff0c\u800c\u662f\u771f\u7684\u56de\u5bb6\u5403\u4e00\u987f\u996d\u3002\u5e0c\u671b\u6211\u591a\u966a\u963f\u5b37\u8bf4\u8bf4\u8bdd\uff0c\u542c\u5979\u8bb2\u90a3\u4e9b\u91cd\u590d\u4e86\u5f88\u591a\u904d\u7684\u65e7\u4e8b\uff0c\u4e0d\u8981\u5acc\u70e6\u3002\u56e0\u4e3a\u8001\u4eba\u53cd\u590d\u8bb2\u4e00\u4ef6\u4e8b\uff0c\u4e0d\u662f\u56e0\u4e3a\u4ed6\u4eec\u4e0d\u77e5\u9053\u81ea\u5df1\u8bb2\u8fc7\uff0c\u800c\u662f\u56e0\u4e3a\u90a3\u662f\u4ed6\u4eec\u751f\u547d\u91cc\u6700\u820d\u4e0d\u5f97\u653e\u4e0b\u7684\u90e8\u5206\u3002\u4ed6\u4f1a\u5e0c\u671b\u6211\u8bb0\u5f97\u963f\u5b37\u7231\u5403\u4ec0\u4e48\u836f\u3001\u51e0\u70b9\u7761\u89c9\u3001\u51ac\u5929\u6015\u4e0d\u6015\u51b7\u3001\u65e7\u7167\u7247\u653e\u5728\u54ea\u91cc\u3002\u4ed6\u4f1a\u5e0c\u671b\u6211\u66ff\u4ed6\u7ee7\u7eed\u7167\u987e\u90a3\u4e2a\u7b49\u4e86\u4ed6\u5f88\u591a\u5e74\u7684\u5973\u4eba\u3002 \u7b2c\u56db\uff0c\u4ed6\u5e0c\u671b\u6211\u628a\u5bb6\u91cc\u7684\u65e7\u4fe1\u3001\u65e7\u7167\u7247\u3001\u65e7\u7269\u4fdd\u5b58\u4e0b\u6765\u3002\u4ed6\u4f1a\u5e0c\u671b\u6211\u4e0d\u8981\u968f\u624b\u4e22\u6389\u90a3\u4e9b\u53d1\u9ec4\u7684\u7eb8\u3001\u65e7\u85e4\u7bb1\u3001\u642a\u74f7\u676f\u3001\u91d1\u6212\u6307\u3001\u8001\u7167\u7247\u3002\u56e0\u4e3a\u90a3\u4e9b\u4e1c\u897f\u4e0d\u662f\u666e\u901a\u65e7\u7269\uff0c\u800c\u662f\u4ed6\u5b58\u5728\u8fc7\u3001\u7231\u8fc7\u3001\u52aa\u529b\u8fc7\u7684\u8bc1\u660e\u3002\u5b83\u4eec\u662f\u8fd9\u4e2a\u5bb6\u5ead\u6700\u771f\u5b9e\u7684\u6839\u3002\u4ed6\u53ef\u80fd\u4f1a\u8bf4\uff1a\u201c\u4e1c\u897f\u65e7\u4e86\u6ca1\u5173\u7cfb\uff0c\u8bb0\u5fc6\u4e0d\u80fd\u4e22\u3002\u4eba\u8d70\u4e86\u4ee5\u540e\uff0c\u540e\u4ee3\u8fd8\u8bb0\u5f97\uff0c\u8fd9\u4e2a\u4eba\u5c31\u4e0d\u7b97\u5b8c\u5168\u8d70\u8fdc\u3002\u201d \u7b2c\u4e94\uff0c\u4ed6\u5e0c\u671b\u6211\u4ee5\u540e\u9047\u5230\u7231\u7684\u4eba\uff0c\u8981\u5b66\u4f1a\u8868\u8fbe\uff0c\u4e5f\u8981\u5b66\u4f1a\u884c\u52a8\u3002\u7237\u7237\u8fd9\u4e00\u751f\u4e0d\u592a\u4f1a\u8bf4\u7231\uff0c\u6240\u4ee5\u4ed6\u4f1a\u5e0c\u671b\u6211\u4e0d\u8981\u50cf\u4ed6\u4e00\u6837\uff0c\u628a\u6240\u6709\u7231\u90fd\u85cf\u8d77\u6765\u3002\u4ed6\u5e0c\u671b\u6211\u73cd\u60dc\u773c\u524d\u4eba\uff0c\u4e0d\u8981\u7b49\u5230\u6765\u4e0d\u53ca\u4e86\u624d\u540e\u6094\u3002\u559c\u6b22\u4e00\u4e2a\u4eba\uff0c\u5c31\u8981\u597d\u597d\u8bf4\uff1b\u7b54\u5e94\u4e00\u4e2a\u4eba\uff0c\u5c31\u8981\u597d\u597d\u505a\u3002\u4e0d\u8981\u8f7b\u6613\u8bb8\u8bfa\uff0c\u4f46\u8bb8\u4e86\u8bfa\u5c31\u8981\u653e\u5728\u5fc3\u4e0a\u3002\u4ed6\u4f1a\u5e0c\u671b\u6211\u8bb0\u5f97\u4ed6\u548c\u963f\u5b37\u7684\u6545\u4e8b\uff0c\u4e0d\u662f\u4e3a\u4e86\u6000\u65e7\uff0c\u800c\u662f\u4e3a\u4e86\u660e\u767d\uff1a\u771f\u6b63\u957f\u4e45\u7684\u611f\u60c5\uff0c\u4e0d\u662f\u70ed\u70c8\u4e00\u9635\u5b50\uff0c\u800c\u662f\u5728\u6f2b\u957f\u7684\u5c81\u6708\u91cc\u4e00\u6b21\u6b21\u9009\u62e9\u4e0d\u79bb\u5f00\u3002 \u7b2c\u516d\uff0c\u4ed6\u5e0c\u671b\u6211\u628a\u81ea\u5df1\u7684\u65e5\u5b50\u8fc7\u8e0f\u5b9e\u3002\u4ed6\u4e0d\u4f1a\u8981\u6c42\u6211\u4e00\u5b9a\u8981\u8d5a\u5f88\u591a\u94b1\uff0c\u4e5f\u4e0d\u4f1a\u8981\u6c42\u6211\u6210\u4e3a\u522b\u4eba\u773c\u91cc\u591a\u4e48\u5389\u5bb3\u7684\u4eba\u3002\u4ed6\u66f4\u5e0c\u671b\u6211\u5403\u996d\u89c4\u5f8b\uff0c\u7761\u89c9\u5b89\u7a33\uff0c\u9047\u4e8b\u4e0d\u8981\u614c\uff0c\u505a\u4eba\u4e0d\u8981\u4e8f\u5fc3\u3002\u4ed6\u5e0c\u671b\u6211\u6709\u81ea\u5df1\u7684\u672c\u4e8b\uff0c\u4e5f\u6709\u81ea\u5df1\u7684\u5e95\u7ebf\u3002\u4ed6\u53ef\u80fd\u4f1a\u5bf9\u6211\u8bf4\uff1a\u201c\u7237\u7237\u8fd9\u4e00\u8f88\u5b50\u6ca1\u4ec0\u4e48\u5927\u672c\u4e8b\uff0c\u5c31\u662f\u8bb0\u5f97\u505a\u4eba\u8981\u5b9e\u5728\u3002\u4f60\u4ee5\u540e\u4e0d\u7ba1\u8d70\u5230\u54ea\u91cc\uff0c\u90fd\u4e0d\u8981\u4e3a\u4e86\u8d76\u8def\uff0c\u628a\u81ea\u5df1\u7684\u5fc3\u5f04\u4e22\u4e86\u3002\u201d \u7b2c\u4e03\uff0c\u4ed6\u5e0c\u671b\u6211\u4e0d\u8981\u5fd8\u8bb0\u4ed6\uff0c\u4f46\u4e5f\u4e0d\u8981\u88ab\u9057\u61be\u56f0\u4f4f\u3002\u4ed6\u77e5\u9053\u6211\u4f1a\u9057\u61be\uff0c\u4f1a\u60f3\u5ff5\uff0c\u4f1a\u602a\u81ea\u5df1\u6ca1\u6709\u65e9\u70b9\u61c2\u4ed6\u3002\u4f46\u4ed6\u4e0d\u4f1a\u5e0c\u671b\u6211\u4e00\u76f4\u505c\u5728\u6127\u759a\u91cc\u3002\u4ed6\u4f1a\u5e0c\u671b\u6211\u628a\u8fd9\u4efd\u60f3\u5ff5\u53d8\u6210\u66f4\u597d\u7684\u751f\u6d3b\u65b9\u5f0f\uff1a\u5bf9\u5bb6\u4eba\u591a\u4e00\u70b9\u8010\u5fc3\uff0c\u5bf9\u8001\u4eba\u591a\u4e00\u70b9\u966a\u4f34\uff0c\u5bf9\u7231\u591a\u4e00\u70b9\u8868\u8fbe\uff0c\u5bf9\u81ea\u5df1\u7684\u6765\u5904\u591a\u4e00\u70b9\u73cd\u60dc\u3002\u4ed6\u4f1a\u5e0c\u671b\u6211\u77e5\u9053\uff0c\u6b7b\u4ea1\u4e0d\u662f\u5173\u7cfb\u7684\u5f7b\u5e95\u7ed3\u675f\u3002\u53ea\u8981\u6211\u8fd8\u8bb0\u5f97\u4ed6\u7684\u6545\u4e8b\uff0c\u8fd8\u613f\u610f\u8bb2\u8ff0\u4ed6\u7684\u4e00\u751f\uff0c\u8fd8\u613f\u610f\u628a\u4ed6\u7684\u7cbe\u795e\u5e26\u5230\u81ea\u5df1\u7684\u751f\u6d3b\u91cc\uff0c\u4ed6\u5c31\u4ecd\u7136\u4ee5\u53e6\u4e00\u79cd\u65b9\u5f0f\u966a\u7740\u6211\u3002", "chunks": [{"chunk_type": "text", "content": "\u7b2c\u4e00\uff0c\u4ed6\u5e0c\u671b\u6211\u4e0d\u8981\u592a\u82db\u8d23\u81ea\u5df1\u3002\u7237\u7237\u5e74\u8f7b\u65f6\u5403\u8fc7\u5f88\u591a\u82e6\uff0c\u6240\u4ee5\u4ed6\u77e5\u9053\u4eba\u751f\u4e0d\u662f\u6bcf\u4e00\u6b65\u90fd\u80fd\u8d70\u5f97\u6f02\u4eae\u3002\u4ed6\u4e0d\u4f1a\u8981\u6c42\u6211\u6c38\u8fdc\u6210\u529f\uff0c\u4e5f\u4e0d\u4f1a\u8981\u6c42\u6211\u6c38\u8fdc\u575a\u5f3a\u3002\u4ed6\u4f1a\u5e0c\u671b\u6211\u5728\u5931\u8d25\u7684\u65f6\u5019\uff0c\u4e0d\u8981\u6025\u7740\u5426\u5b9a\u81ea\u5df1\u3002\u4ed6\u53ef\u80fd\u4f1a\u5bf9\u6211\u8bf4\uff1a\u201c\u5b69\u5b50\uff0c\u4eba\u8fd9\u4e00\u751f\u54ea\u6709\u4e0d\u96be\u7684\u65f6\u5019\u3002\u7237\u7237\u5f53\u5e74\u5728\u5357\u6d0b\uff0c\u4e5f\u6709\u5f88\u591a\u6b21\u89c9\u5f97\u6491\u4e0d\u4e0b\u53bb\u3002\u53ef\u662f\u65e5\u5b50\u4e0d\u662f\u4e00\u5929\u8fc7\u5b8c\u7684\uff0c\u662f\u4e00\u5929\u5929\u71ac\u51fa\u6765\u7684\u3002\u4f60\u4e0d\u8981\u56e0\u4e3a\u4e00\u65f6\u8d70\u5f97\u6162\uff0c\u5c31\u89c9\u5f97\u81ea\u5df1\u6ca1\u7528\u3002\u201d", "summary": "\u7237\u7237\u5e0c\u671b\u201c\u6211\u201d\u63a5\u7eb3\u5931\u8d25\u4e0e\u4e0d\u5b8c\u7f8e\uff0c\u4e0d\u81ea\u6211\u82db\u8d23\uff0c\u7406\u89e3\u4eba\u751f\u9700\u8010\u5fc3\u575a\u6301\u3002", "source_location": "manual:body"}, {"chunk_type": "text", "content": "\u7b2c\u4e8c\uff0c\u4ed6\u5e0c\u671b\u6211\u8bb0\u5f97\u5bb6\u4ece\u54ea\u91cc\u6765\u3002\u4ed6\u5e0c\u671b\u6211\u4e0d\u8981\u628a\u4eca\u5929\u62e5\u6709\u7684\u4e00\u5207\u90fd\u770b\u5f97\u7406\u6240\u5f53\u7136\u3002\u5e0c\u671b\u6211\u8bb0\u5f97\uff0c\u6211\u4eec\u5bb6\u4e0d\u662f\u4e00\u5f00\u59cb\u5c31\u5b89\u7a33\u7684\uff0c\u662f\u6709\u4eba\u79bb\u5f00\u8fc7\u5bb6\u4e61\uff0c\u6709\u4eba\u5403\u8fc7\u82e6\uff0c\u6709\u4eba\u7b49\u8fc7\u5f88\u591a\u5e74\uff0c\u6709\u4eba\u628a\u94b1\u4e00\u5206\u4e00\u5206\u5bc4\u56de\u6765\uff0c\u624d\u6162\u6162\u6709\u4e86\u540e\u6765\u7684\u65e5\u5b50\u3002\u4ed6\u5e0c\u671b\u6211\u6709\u7a7a\u65f6\u56de\u8001\u5bb6\u770b\u770b\uff0c\u770b\u770b\u7956\u5c4b\uff0c\u770b\u770b\u6751\u53e3\u7684\u8def\uff0c\u770b\u770b\u4ed6\u548c\u963f\u5b37\u751f\u6d3b\u8fc7\u7684\u5730\u65b9\u3002\u4ed6\u5e0c\u671b\u6211\u77e5\u9053\uff0c\u5bb6\u4e0d\u662f\u4e00\u4e2a\u62bd\u8c61\u7684\u8bcd\uff0c\u800c\u662f\u6709\u4eba\u7528\u4e00\u751f\u5b88\u4f4f\u7684\u5730\u65b9\u3002", "summary": "\u7237\u7237\u5e0c\u671b\u201c\u6211\u201d\u94ed\u8bb0\u5bb6\u65cf\u8fc1\u5f99\u4e0e\u594b\u6597\u53f2\uff0c\u73cd\u89c6\u6765\u4e4b\u4e0d\u6613\u7684\u5b89\u7a33\uff0c\u901a\u8fc7\u56de\u4e61\u5177\u8c61\u5316\u201c\u5bb6\u201d\u7684\u771f\u5b9e\u6839\u57fa\u3002", "source_location": "manual:body"}, {"chunk_type": "text", "content": "\u7b2c\u4e09\uff0c\u4ed6\u5e0c\u671b\u6211\u597d\u597d\u7167\u987e\u963f\u5b37\u548c\u5bb6\u91cc\u4eba\u3002\u4ed6\u4f1a\u5e0c\u671b\u6211\u9022\u5e74\u8fc7\u8282\u4e0d\u8981\u53ea\u53d1\u4e00\u53e5\u6d88\u606f\uff0c\u800c\u662f\u771f\u7684\u56de\u5bb6\u5403\u4e00\u987f\u996d\u3002\u5e0c\u671b\u6211\u591a\u966a\u963f\u5b37\u8bf4\u8bf4\u8bdd\uff0c\u542c\u5979\u8bb2\u90a3\u4e9b\u91cd\u590d\u4e86\u5f88\u591a\u904d\u7684\u65e7\u4e8b\uff0c\u4e0d\u8981\u5acc\u70e6\u3002\u56e0\u4e3a\u8001\u4eba\u53cd\u590d\u8bb2\u4e00\u4ef6\u4e8b\uff0c\u4e0d\u662f\u56e0\u4e3a\u4ed6\u4eec\u4e0d\u77e5\u9053\u81ea\u5df1\u8bb2\u8fc7\uff0c\u800c\u662f\u56e0\u4e3a\u90a3\u662f\u4ed6\u4eec\u751f\u547d\u91cc\u6700\u820d\u4e0d\u5f97\u653e\u4e0b\u7684\u90e8\u5206\u3002\u4ed6\u4f1a\u5e0c\u671b\u6211\u8bb0\u5f97\u963f\u5b37\u7231\u5403\u4ec0\u4e48\u836f\u3001\u51e0\u70b9\u7761\u89c9\u3001\u51ac\u5929\u6015\u4e0d\u6015\u51b7\u3001\u65e7\u7167\u7247\u653e\u5728\u54ea\u91cc\u3002\u4ed6\u4f1a\u5e0c\u671b\u6211\u66ff\u4ed6\u7ee7\u7eed\u7167\u987e\u90a3\u4e2a\u7b49\u4e86\u4ed6\u5f88\u591a\u5e74\u7684\u5973\u4eba\u3002", "summary": "\u7237\u7237\u5e0c\u671b\u201c\u6211\u201d\u4ee5\u5177\u4f53\u884c\u52a8\u5173\u7231\u5bb6\u4eba\uff0c\u5c24\u5176\u6301\u7eed\u7167\u62a4\u963f\u5b37\uff0c\u7406\u89e3\u8001\u4eba\u91cd\u590d\u8bb2\u8ff0\u80cc\u540e\u7684\u60c5\u611f\u4f9d\u604b\u4e0e\u751f\u547d\u91cd\u5fc3\u3002", "source_location": "manual:body"}, {"chunk_type": "text", "content": "\u7b2c\u56db\uff0c\u4ed6\u5e0c\u671b\u6211\u628a\u5bb6\u91cc\u7684\u65e7\u4fe1\u3001\u65e7\u7167\u7247\u3001\u65e7\u7269\u4fdd\u5b58\u4e0b\u6765\u3002\u4ed6\u4f1a\u5e0c\u671b\u6211\u4e0d\u8981\u968f\u624b\u4e22\u6389\u90a3\u4e9b\u53d1\u9ec4\u7684\u7eb8\u3001\u65e7\u85e4\u7bb1\u3001\u642a\u74f7\u676f\u3001\u91d1\u6212\u6307\u3001\u8001\u7167\u7247\u3002\u56e0\u4e3a\u90a3\u4e9b\u4e1c\u897f\u4e0d\u662f\u666e\u901a\u65e7\u7269\uff0c\u800c\u662f\u4ed6\u5b58\u5728\u8fc7\u3001\u7231\u8fc7\u3001\u52aa\u529b\u8fc7\u7684\u8bc1\u660e\u3002\u5b83\u4eec\u662f\u8fd9\u4e2a\u5bb6\u5ead\u6700\u771f\u5b9e\u7684\u6839\u3002\u4ed6\u53ef\u80fd\u4f1a\u8bf4\uff1a\u201c\u4e1c\u897f\u65e7\u4e86\u6ca1\u5173\u7cfb\uff0c\u8bb0\u5fc6\u4e0d\u80fd\u4e22\u3002\u4eba\u8d70\u4e86\u4ee5\u540e\uff0c\u540e\u4ee3\u8fd8\u8bb0\u5f97\uff0c\u8fd9\u4e2a\u4eba\u5c31\u4e0d\u7b97\u5b8c\u5168\u8d70\u8fdc\u3002\u201d", "summary": "\u7237\u7237\u89c6\u65e7\u7269\u4e3a\u5bb6\u65cf\u5b58\u5728\u4e0e\u60c5\u611f\u7684\u5b9e\u4f53\u51ed\u8bc1\uff0c\u5f3a\u8c03\u4fdd\u5b58\u5b9e\u7269\u5373\u4fdd\u5b58\u8bb0\u5fc6\u4e0e\u8840\u8109\u4e4b\u6839\u3002", "source_location": "manual:body"}, {"chunk_type": "text", "content": "\u7b2c\u4e94\uff0c\u4ed6\u5e0c\u671b\u6211\u4ee5\u540e\u9047\u5230\u7231\u7684\u4eba\uff0c\u8981\u5b66\u4f1a\u8868\u8fbe\uff0c\u4e5f\u8981\u5b66\u4f1a\u884c\u52a8\u3002\u7237\u7237\u8fd9\u4e00\u751f\u4e0d\u592a\u4f1a\u8bf4\u7231\uff0c\u6240\u4ee5\u4ed6\u4f1a\u5e0c\u671b\u6211\u4e0d\u8981\u50cf\u4ed6\u4e00\u6837\uff0c\u628a\u6240\u6709\u7231\u90fd\u85cf\u8d77\u6765\u3002\u4ed6\u5e0c\u671b\u6211\u73cd\u60dc\u773c\u524d\u4eba\uff0c\u4e0d\u8981\u7b49\u5230\u6765\u4e0d\u53ca\u4e86\u624d\u540e\u6094\u3002\u559c\u6b22\u4e00\u4e2a\u4eba\uff0c\u5c31\u8981\u597d\u597d\u8bf4\uff1b\u7b54\u5e94\u4e00\u4e2a\u4eba\uff0c\u5c31\u8981\u597d\u597d\u505a\u3002\u4e0d\u8981\u8f7b\u6613\u8bb8\u8bfa\uff0c\u4f46\u8bb8\u4e86\u8bfa\u5c31\u8981\u653e\u5728\u5fc3\u4e0a\u3002\u4ed6\u4f1a\u5e0c\u671b\u6211\u8bb0\u5f97\u4ed6\u548c\u963f\u5b37\u7684\u6545\u4e8b\uff0c\u4e0d\u662f\u4e3a\u4e86\u6000\u65e7\uff0c\u800c\u662f\u4e3a\u4e86\u660e\u767d\uff1a\u771f\u6b63\u957f\u4e45\u7684\u611f\u60c5\uff0c\u4e0d\u662f\u70ed\u70c8\u4e00\u9635\u5b50\uff0c\u800c\u662f\u5728\u6f2b\u957f\u7684\u5c81\u6708\u91cc\u4e00\u6b21\u6b21\u9009\u62e9\u4e0d\u79bb\u5f00\u3002", "summary": "\u7237\u7237\u4ee5\u81ea\u8eab\u4e3a\u955c\uff0c\u5e0c\u671b\u201c\u6211\u201d\u4e3b\u52a8\u8868\u8fbe\u7231\u3001\u8df5\u884c\u627f\u8bfa\uff0c\u5e76\u4ece\u4ed6\u4e0e\u963f\u5b37\u76f8\u5b88\u4e2d\u7406\u89e3\u957f\u4e45\u611f\u60c5\u7684\u672c\u8d28\u662f\u6301\u7eed\u9009\u62e9\u3002", "source_location": "manual:body"}, {"chunk_type": "text", "content": "\u7b2c\u516d\uff0c\u4ed6\u5e0c\u671b\u6211\u628a\u81ea\u5df1\u7684\u65e5\u5b50\u8fc7\u8e0f\u5b9e\u3002\u4ed6\u4e0d\u4f1a\u8981\u6c42\u6211\u4e00\u5b9a\u8981\u8d5a\u5f88\u591a\u94b1\uff0c\u4e5f\u4e0d\u4f1a\u8981\u6c42\u6211\u6210\u4e3a\u522b\u4eba\u773c\u91cc\u591a\u4e48\u5389\u5bb3\u7684\u4eba\u3002\u4ed6\u66f4\u5e0c\u671b\u6211\u5403\u996d\u89c4\u5f8b\uff0c\u7761\u89c9\u5b89\u7a33\uff0c\u9047\u4e8b\u4e0d\u8981\u614c\uff0c\u505a\u4eba\u4e0d\u8981\u4e8f\u5fc3\u3002\u4ed6\u5e0c\u671b\u6211\u6709\u81ea\u5df1\u7684\u672c\u4e8b\uff0c\u4e5f\u6709\u81ea\u5df1\u7684\u5e95\u7ebf\u3002\u4ed6\u53ef\u80fd\u4f1a\u5bf9\u6211\u8bf4\uff1a\u201c\u7237\u7237\u8fd9\u4e00\u8f88\u5b50\u6ca1\u4ec0\u4e48\u5927\u672c\u4e8b\uff0c\u5c31\u662f\u8bb0\u5f97\u505a\u4eba\u8981\u5b9e\u5728\u3002\u4f60\u4ee5\u540e\u4e0d\u7ba1\u8d70\u5230\u54ea\u91cc\uff0c\u90fd\u4e0d\u8981\u4e3a\u4e86\u8d76\u8def\uff0c\u628a\u81ea\u5df1\u7684\u5fc3\u5f04\u4e22\u4e86\u3002\u201d", "summary": "\u7237\u7237\u91cd\u89c6\u65e5\u5e38\u751f\u6d3b\u7684\u7a33\u5b9a\u6027\u4e0e\u4eba\u683c\u7684\u5b9e\u5728\u6027\uff0c\u4e3b\u5f20\u8e0f\u5b9e\u8fc7\u65e5\u5b50\u3001\u5b88\u4f4f\u5185\u5fc3\u4e0e\u5e95\u7ebf\uff0c\u800c\u975e\u8ffd\u9010\u5916\u5728\u6210\u5c31\u3002", "source_location": "manual:body"}, {"chunk_type": "text", "content": "\u7b2c\u4e03\uff0c\u4ed6\u5e0c\u671b\u6211\u4e0d\u8981\u5fd8\u8bb0\u4ed6\uff0c\u4f46\u4e5f\u4e0d\u8981\u88ab\u9057\u61be\u56f0\u4f4f\u3002\u4ed6\u77e5\u9053\u6211\u4f1a\u9057\u61be\uff0c\u4f1a\u60f3\u5ff5\uff0c\u4f1a\u602a\u81ea\u5df1\u6ca1\u6709\u65e9\u70b9\u61c2\u4ed6\u3002\u4f46\u4ed6\u4e0d\u4f1a\u5e0c\u671b\u6211\u4e00\u76f4\u505c\u5728\u6127\u759a\u91cc\u3002\u4ed6\u4f1a\u5e0c\u671b\u6211\u628a\u8fd9\u4efd\u60f3\u5ff5\u53d8\u6210\u66f4\u597d\u7684\u751f\u6d3b\u65b9\u5f0f\uff1a\u5bf9\u5bb6\u4eba\u591a\u4e00\u70b9\u8010\u5fc3\uff0c\u5bf9\u8001\u4eba\u591a\u4e00\u70b9\u966a\u4f34\uff0c\u5bf9\u7231\u591a\u4e00\u70b9\u8868\u8fbe\uff0c\u5bf9\u81ea\u5df1\u7684\u6765\u5904\u591a\u4e00\u70b9\u73cd\u60dc\u3002\u4ed6\u4f1a\u5e0c\u671b\u6211\u77e5\u9053\uff0c\u6b7b\u4ea1\u4e0d\u662f\u5173\u7cfb\u7684\u5f7b\u5e95\u7ed3\u675f\u3002\u53ea\u8981\u6211\u8fd8\u8bb0\u5f97\u4ed6\u7684\u6545\u4e8b\uff0c\u8fd8\u613f\u610f\u8bb2\u8ff0\u4ed6\u7684\u4e00\u751f\uff0c\u8fd8\u613f\u610f\u628a\u4ed6\u7684\u7cbe\u795e\u5e26\u5230\u81ea\u5df1\u7684\u751f\u6d3b\u91cc\uff0c\u4ed6\u5c31\u4ecd\u7136\u4ee5\u53e6\u4e00\u79cd\u65b9\u5f0f\u966a\u7740\u6211\u3002", "summary": "\u7237\u7237\u5e0c\u671b\u201c\u6211\u201d\u5c06\u6000\u5ff5\u8f6c\u5316\u4e3a\u79ef\u6781\u884c\u52a8\uff0c\u8ba9\u8bb0\u5fc6\u5ef6\u7eed\u4e8e\u751f\u6d3b\u5b9e\u8df5\uff0c\u7406\u89e3\u4eb2\u60c5\u5728\u751f\u6b7b\u4e4b\u540e\u4ecd\u53ef\u5b58\u7eed\u3002", "source_location": "manual:body"}]}, "provider_type": "third_party"}', NULL, '2026-07-04 23:30:10.69746', NULL);
INSERT INTO public.parsed_chunks VALUES ('30a633b9-a9e5-497b-9efb-8dbf79d14b16', '18b88e96-5633-4d75-b77a-0ad1988a846a', '40662752-e856-452a-812a-f8e5bfb8d5ac', 'manual', '第一，他希望我不要太苛责自己。爷爷年轻时吃过很多苦，所以他知道人生不是每一步都能走得漂亮。他不会要求我永远成功，也不会要求我永远坚强。他会希望我在失败的时候，不要急着否定自己。他可能会对我说：“孩子，人这一生哪有不难的时候。爷爷当年在南洋，也有很多次觉得撑不下去。可是日子不是一天过完的，是一天天熬出来的。你不要因为一时走得慢，就觉得自己没用。”', '爷爷希望“我”接纳失败与脆弱，不自我苛责；以自身在南洋艰难经历为例，强调坚持与时间的力量。', 'manual:body', NULL, NULL, '{"text_extraction": {"extractor": "manual", "source_location": "manual:body", "has_text": true}, "text_parser": {"cleaned_text": "\u5341\u3001\u7237\u7237\u5bf9\u6211\u7684\u5fc3\u613f\uff08\u4e0a\uff09 \u5982\u679c\u7237\u7237\u8fd8\u80fd\u5bf9\u6211\u8bf4\u8bdd\uff0c\u6211\u60f3\u4ed6\u5bf9\u6211\u7684\u5fc3\u613f\u4f1a\u975e\u5e38\u5177\u4f53\u3002 \u7b2c\u4e00\uff0c\u4ed6\u5e0c\u671b\u6211\u4e0d\u8981\u592a\u82db\u8d23\u81ea\u5df1\u3002\u7237\u7237\u5e74\u8f7b\u65f6\u5403\u8fc7\u5f88\u591a\u82e6\uff0c\u6240\u4ee5\u4ed6\u77e5\u9053\u4eba\u751f\u4e0d\u662f\u6bcf\u4e00\u6b65\u90fd\u80fd\u8d70\u5f97\u6f02\u4eae\u3002\u4ed6\u4e0d\u4f1a\u8981\u6c42\u6211\u6c38\u8fdc\u6210\u529f\uff0c\u4e5f\u4e0d\u4f1a\u8981\u6c42\u6211\u6c38\u8fdc\u575a\u5f3a\u3002\u4ed6\u4f1a\u5e0c\u671b\u6211\u5728\u5931\u8d25\u7684\u65f6\u5019\uff0c\u4e0d\u8981\u6025\u7740\u5426\u5b9a\u81ea\u5df1\u3002\u4ed6\u53ef\u80fd\u4f1a\u5bf9\u6211\u8bf4\uff1a\u201c\u5b69\u5b50\uff0c\u4eba\u8fd9\u4e00\u751f\u54ea\u6709\u4e0d\u96be\u7684\u65f6\u5019\u3002\u7237\u7237\u5f53\u5e74\u5728\u5357\u6d0b\uff0c\u4e5f\u6709\u5f88\u591a\u6b21\u89c9\u5f97\u6491\u4e0d\u4e0b\u53bb\u3002\u53ef\u662f\u65e5\u5b50\u4e0d\u662f\u4e00\u5929\u8fc7\u5b8c\u7684\uff0c\u662f\u4e00\u5929\u5929\u71ac\u51fa\u6765\u7684\u3002\u4f60\u4e0d\u8981\u56e0\u4e3a\u4e00\u65f6\u8d70\u5f97\u6162\uff0c\u5c31\u89c9\u5f97\u81ea\u5df1\u6ca1\u7528\u3002\u201d \u7b2c\u4e8c\uff0c\u4ed6\u5e0c\u671b\u6211\u8bb0\u5f97\u5bb6\u4ece\u54ea\u91cc\u6765\u3002\u4ed6\u5e0c\u671b\u6211\u4e0d\u8981\u628a\u4eca\u5929\u62e5\u6709\u7684\u4e00\u5207\u90fd\u770b\u5f97\u7406\u6240\u5f53\u7136\u3002\u5e0c\u671b\u6211\u8bb0\u5f97\uff0c\u6211\u4eec\u5bb6\u4e0d\u662f\u4e00\u5f00\u59cb\u5c31\u5b89\u7a33\u7684\uff0c\u662f\u6709\u4eba\u79bb\u5f00\u8fc7\u5bb6\u4e61\uff0c\u6709\u4eba\u5403\u8fc7\u82e6\uff0c\u6709\u4eba\u7b49\u8fc7\u5f88\u591a\u5e74\uff0c\u6709\u4eba\u628a\u94b1\u4e00\u5206\u4e00\u5206\u5bc4\u56de\u6765\uff0c\u624d\u6162\u6162\u6709\u4e86\u540e\u6765\u7684\u65e5\u5b50\u3002\u4ed6\u5e0c\u671b\u6211\u6709\u7a7a\u65f6\u56de\u8001\u5bb6\u770b\u770b\uff0c\u770b\u770b\u7956\u5c4b\uff0c\u770b\u770b\u6751\u53e3\u7684\u8def\uff0c\u770b\u770b\u4ed6\u548c\u963f\u5b37\u751f\u6d3b\u8fc7\u7684\u5730\u65b9\u3002\u4ed6\u5e0c\u671b\u6211\u77e5\u9053\uff0c\u5bb6\u4e0d\u662f\u4e00\u4e2a\u62bd\u8c61\u7684\u8bcd\uff0c\u800c\u662f\u6709\u4eba\u7528\u4e00\u751f\u5b88\u4f4f\u7684\u5730\u65b9\u3002 \u7b2c\u4e09\uff0c\u4ed6\u5e0c\u671b\u6211\u597d\u597d\u7167\u987e\u963f\u5b37\u548c\u5bb6\u91cc\u4eba\u3002\u4ed6\u4f1a\u5e0c\u671b\u6211\u9022\u5e74\u8fc7\u8282\u4e0d\u8981\u53ea\u53d1\u4e00\u53e5\u6d88\u606f\uff0c\u800c\u662f\u771f\u7684\u56de\u5bb6\u5403\u4e00\u987f\u996d\u3002\u5e0c\u671b\u6211\u591a\u966a\u963f\u5b37\u8bf4\u8bf4\u8bdd\uff0c\u542c\u5979\u8bb2\u90a3\u4e9b\u91cd\u590d\u4e86\u5f88\u591a\u904d\u7684\u65e7\u4e8b\uff0c\u4e0d\u8981\u5acc\u70e6\u3002\u8001\u4eba\u53cd\u590d\u8bb2\u4e00\u4ef6\u4e8b\uff0c\u4e0d\u662f\u56e0\u4e3a\u4ed6\u4eec\u4e0d\u77e5\u9053\u81ea\u5df1\u8bb2\u8fc7\uff0c\u800c\u662f\u56e0\u4e3a\u90a3\u662f\u4ed6\u4eec\u751f\u547d\u91cc\u6700\u820d\u4e0d\u5f97\u653e\u4e0b\u7684\u90e8\u5206\u3002\u4ed6\u4f1a\u5e0c\u671b\u6211\u66ff\u4ed6\u7ee7\u7eed\u7167\u987e\u90a3\u4e2a\u7b49\u4e86\u4ed6\u5f88\u591a\u5e74\u7684\u5973\u4eba\u3002", "chunks": [{"chunk_type": "text", "content": "\u7b2c\u4e00\uff0c\u4ed6\u5e0c\u671b\u6211\u4e0d\u8981\u592a\u82db\u8d23\u81ea\u5df1\u3002\u7237\u7237\u5e74\u8f7b\u65f6\u5403\u8fc7\u5f88\u591a\u82e6\uff0c\u6240\u4ee5\u4ed6\u77e5\u9053\u4eba\u751f\u4e0d\u662f\u6bcf\u4e00\u6b65\u90fd\u80fd\u