INSERT INTO public.parsed_chunks VALUES ('37384cab-b865-4049-8097-f1fb72496f75', 'ec32a56f-8961-4f5e-9550-a804ae3918fa', 'f3ce2ea3-1905-4bc0-829b-90baa6d80848', 'manual', '外婆常说慢慢来，别急，心里难受的时候先把气喘匀。', '外婆教导遇事勿急，情绪不适时先调整呼吸。', 'manual:body', NULL, NULL, '{"text_extraction": {"extractor": "manual", "source_location": "manual:body", "has_text": true}, "text_parser": {"cleaned_text": "\u5916\u5a46\u5e38\u8bf4\u6162\u6162\u6765\uff0c\u522b\u6025\uff0c\u5fc3\u91cc\u96be\u53d7\u7684\u65f6\u5019\u5148\u628a\u6c14\u5598\u5300\u3002", "chunks": [{"chunk_type": "text", "content": "\u5916\u5a46\u5e38\u8bf4\u6162\u6162\u6765\uff0c\u522b\u6025\uff0c\u5fc3\u91cc\u96be\u53d7\u7684\u65f6\u5019\u5148\u628a\u6c14\u5598\u5300\u3002", "summary": "\u5916\u5a46\u6559\u5bfc\u9047\u4e8b\u52ff\u6025\uff0c\u60c5\u7eea\u4e0d\u9002\u65f6\u5148\u8c03\u6574\u547c\u5438\u3002", "source_location": "manual:body"}]}, "provider_type": "third_party"}', NULL, '2026-07-04 16:10:06.306595', NULL);
INSERT INTO public.parsed_chunks VALUES ('2edbee1c-b144-4073-b4ae-9c75a6337c52', 'e19a2da5-b6ba-40bb-a2fb-3631484a99a5', '8c059e8d-cd10-4d84-b6aa-33330fefb259', 'image', '一张详细的中文个人简历长图，顶部显示姓名刘勤铭及联系方式，右上角附有一张身穿深色上衣的男士半身照。正文内容密集，分为教育背景、实习经历（包括滴滴、字节跳动、猎聘网、德国大陆）、项目经历、荣誉证书、专业技能和自我评价等板块，排版清晰专业。。刘勤铭 24岁 | 男 | 个人网站: 123.57.129.175 15395006575 | qinming218@163.com | 微信: idealism218 教育背景 北京师范大学 - 硕士 2024年9月-2027年7月 系统科学专业 中国地质大学(北京) - 本科 2019年9月-2023年7月 软件工程专业 GPA 3.86/4 93.74/100 专业排名 3/63 实习经历 滴滴 - 国际金融Fintech - 支付风险组Payment Risk 实习生 - 风控算法 2025年10月-2026年6月 • 阻挡指标动标根因分析：开发支付风险指标异常因动根异常系统，覆盖外卖、出行、钱包、借贷等多业务场景，围绕打抗率、拒绝率、3DS率、CB金额、CB资损率等核心指标，搭建“异常识别-维度下钻-贡献度归因-结果输出”自动化链路，支持按国家、业务线、支付方式、策略组、用户分层等维度定位异常来源，提升风险波动排查效率。 • 巴西钱包风险模型：参与巴西钱包 XGBoost 风险模型建设与策略评估，基于用户画像、交易行为、设备环境、地理位置、支付卡信息、历史拒付表现等特征输出订单风险分，结合命中率、拒绝率、3DS率、通过率、打抗率等指标评估模型效果，为高/中/低风险分层治理和支付风控策略优化提供依据。 • 支付风险策略规则自动调优与效果追踪系统：面向支付风控策略快速迭代场景，针对实验组策略调整后指标链路难以自动承接、策略效果依赖人工复盘的问题，开发策略映射、规则标准化、指标追逐与规则调优闭环。系统自动识别迭代前后策略映射关系，持续监控实验组策略调整后的命中率、唯一命中率、订单拒拒率、3DS率、通过率、打抗率等核心指标；当某一策略规则导致其对应的关键词指标出现较大波动时，自动定位异常规则并生成参数调整或规则修正建议，持续追踪修改后的指标效果，辅助策略同学在风险拦截收益与用户打扰成本之间取得更优平衡。 • 头寸时间序列预测：参与国际金融头寸预测建模，基于历史入金、出金交易额构建 LSTM 时间序列预测模型，分析交易额趋势、周期性波动和异常变化，支持未来资金流入流出预测，为资金调度、风险预警和运营决策提供数据依据。 字节跳动 - 国际电商TTS - 用户增长 UG 商业化广告组 实习生 - 数据分析 2025年5月-2025年9月 • ToB/ToC 广告数据分析：维护国际电商商业化广告场景 ToB/ToC 效果数据集，开发对应看板，支持业务决策与广告效果分析。 响应业务需求完成多次核心表的字段新增和2张业务表的数据体系搭建，SparkSQL优化数据链路并完成全量数据验证，确保 GMV 等核心指标差异控制在±0.1内，提升数据链路运行效率缩短时长30%。解决指标异动分析、广告链接解析丢失等oncall问题，共输出5次分析报告并提供业务应建议。 • ROI2 新指标开发：主导新开国ToB广告看板 ROI2 升级口径开发，并通过AB测试验证按 ROI2 优化的投放组 vs 原投放组，同等点击率效果下曝光成本降低5%。 高LTV精准人群：完善高LTV人群指标体系，聚类等分析发现当前高LTV有一批人退货率较高，主动对接风险团队，创新控低风险分标签融入LTV人群判定逻辑，优化人群圈选精准度。进行AB测试验证新LTV人群组vs原LTV人群组，同等营销投入下成交单量提升约5%，GMV提升约2%。 猎聘网 - 技术部AI中心 算法组 实习生-大模型算法 2025年1月-2025年5月 • 模型训练：负责招聘岗位说明 JD 与候选人简历 CV 整体匹配项目的模型蒸馏，通过SFT和DPO方法垂类逻辑推理能力。目前在 3B 模型上，准确率 P 达 87%，召回率 R 达 71%，逼近通用模型 Qwen2.5 - 72B 水平（准确率 P 达 80%，召回率 R 达 75%） • 数据清洗：快速对接新产品方，接手模型数据全流程，包括Spark取240w原始数据-正负样本合并-写Promptt模型总结字段-数据分层次清洗-embedding聚类去重数据-数据打质量分准度分-合并9w训练数据集等，实习期间持续产出5次标准结构化数据集，并负责验证数据集有效性。 • 质量质量：分析数据分布形态，输出字段统计分布图，模型打分分布图等反馈调整数据管线策略，发现并解决10余次多层次数据质量问题，确保高质量数据输出，最终保障模型训练质量，实习期间训练指标在3B模型上准确率P与召回率R均提高15%左右，基本完成小型化目标。 德国大陆 (外企) - 信息部 供应链与数据分析组 实习生-产品&数据分析 2023年10月-2024年2月 • 产品经理：协助项目经理负责新工厂 HR 系统项目，针对多部门参与需求分析会议10余次，完成供应商竞品调研报告8份，独立完成系统解决方案设计（含Axure绘制简单原型图），经统计满意度95%以上。项目已进入实施阶段，负责跟踪和监控项目进度，并解决需求变更问题2次。 • 数据分析：为改善物流部效率，完善LMS货运指标体系，Tableau搭建货运看板，从准时发货率、准时交付率等维度搭建可视化日报周报，协助物流经理做问题跟踪，客户投诉率从3.5%下降到2.7%；针对海运数据不清晰，FineBI开发海运订单轨迹可视化平台，海运订单问题数减少10%以上。 • 协助优化：协助建立货运长期问题跟踪反馈机制，策划并主持双周配送商复盘会，每日发放配送商KPI数据，及时发现异常数据并协助解决，配送商KPI指标得分提升5%以上。 项目经历 个人主页 / BingoChat 数字分身项目 面向个人展示、面试沟通和在线互动场景的 AI 个人主页 Demo，将个人经历、项目作品、技术栈、留言表单和 /bingo 数字分身聊天集成在同一个站点中。系统基于 HTML/CSS/JavaScript + Flask；聊天链路使用 SKILL.md 作为人格化系统提示，调用Token API完成第一人称问答，跑通 “访问主页 -> 了解经历 -> 提问交流 / 留言联系” 的闭环。项目同时支持 Windows 本地一键启动和 Linux ECS上的Gunicorn + Nginx + symdlt部署。 项目地址: github.com/Yuki-RM-f/blog_template，演示地址: 123.57.129.175 text2sql智能取数项目 / multi-agent智能数仓 面向数据分析日常取数场景的 Text2SQL Demo，用自然语言需求驱动 SQL 生成，执行和结果校验。系统基于 Streamlit + SQLite + LangGraph，通过 Router、Schema、Coder、Reviewer 四个 Agent 跑通 “自然语言需求 -> SQL -> 取数结果” 的闭环。 项目地址: github.com/Yuki-RM-f/text2sql-demo，演示地址: 123.57.129.175:8501 信用卡风控评分平台Demo 面向个人信贷审批与风控运营场景的信用评分平台 Demo，使用 Home Credit 高线训练模型产物，模拟 “申请接入 -> 模型评分 -> 策略决策 -> 上人工复核 -> 标签回放 -> 监控报表” 的完整业务闭环。系统基于 Streamlit + SQLite + XGBoost + SHAP，实现低/中/高风险客户样例评分、四步式申请录入、自动通过/人工复核/自动拒绝分流、策略阈值 t1/t2 与成本矩阵估算、模型效果评估、原台的解释、Lift/Calibration/SHAP 指标展示和日/周/月报表分析，帮助业务侧直观看到信用评分模型从高线 artifact 到风控审批后台的产品化落地过程。 项目地址: github.com/Yuki-RM-f/Credit-Risk-Control-Scoring-Platform，演示地址: 123.57.129.175:8502 荣誉证书 国家奖学金、校三好学生、优秀学生干部、优秀志愿者、一等奖学金等，其余各类校级荣誉奖项10余项 全国大学生数学建模竞赛省二等奖、“互联网+”大学生创新创业大赛省三等奖等 专业技能 • 编程与英语技能：Python、C/C++、Pytorch框架、Git、CET-4（524分）、CET-6（494分） • 数据分析与可视化：Excel、SQL、Python、FineBI、Tableau等 • 其他技能：Office、Axure、Visio、Xmind、秀米等 校园工作与实践经历 中国地质大学(北京)信息工程学院学业辅导部 部长 • 开展校内学业问题答疑上百次，讲授高等数学，数据结构等期末复习课十余场，每场辅导50人左右。 中国地质大学(北京)志愿者服务协会 副会长 • 负责组织大型会议，央视节目等多项志愿活动十余次，个人累计志愿服务时长153.5h，获“海淀区一星级志愿者”称号。 自我评价 专业基础：专业课优秀率95%，数理基础扎实（高等数学、概率统计、大学物理均为满分100），具备一定数据分析与可视化能力。 项目能力：熟悉ERP、CRM等有关的内部系统业务流程，具体参与过项目调研、进度管理、流程优化等业务。 综合素养：目标导向型，擅长需求分析，分解复杂问题，把握事务关键节点；快速学习、持续自主学习能力；良好的沟通表达能力。。用户说明这是创建星星页上传的珍贵回忆。图片内容为一份个人简历，简历显示姓名为刘勤铭，24岁，北京师范大学系统科学专业硕士（2024-2027），中国地质大学软件工程本科。简历详细记录了在滴滴（风控算法）、字节跳动（数据分析）、猎聘网（大模型算法）及德国大陆的实习经历，以及Text2SQL、信用卡风控评分平台等项目经验，技能涵盖Python、SQL及数据分析。', '一张详细的中文个人简历长图，顶部显示姓名刘勤铭及联系方式，右上角附有一张身穿深色上衣的男士半身照。正文内容密集，分为教育背景、实习经历（包括滴滴、字节跳动、猎聘网、德国大陆）、项目经历、荣誉证书、专业技能和自我评价等板块，排版清晰专业。', 'image:简历.png', NULL, NULL, '{"ocr": {"ocr_text": "\u5218\u52e4\u94ed 24\u5c81 | \u7537 | \u4e2a\u4eba\u7f51\u7ad9: 123.57.129.175 15395006575 | qinming218@163.com | \u5fae\u4fe1: idealism218 \u6559\u80b2\u80cc\u666f \u5317\u4eac\u5e08\u8303\u5927\u5b66 - \u7855\u58eb 2024\u5e749\u6708-2027\u5e747\u6708 \u7cfb\u7edf\u79d1\u5b66\u4e13\u4e1a \u4e2d\u56fd\u5730\u8d28\u5927\u5b66(\u5317\u4eac) - \u672c\u79d1 2019\u5e749\u6708-2023\u5e747\u6708 \u8f6f\u4ef6\u5de5\u7a0b\u4e13\u4e1a GPA 3.86/4 93.74/100 \u4e13\u4e1a\u6392\u540d 3/63 \u5b9e\u4e60\u7ecf\u5386 \u6ef4\u6ef4 - \u56fd\u9645\u91d1\u878dFintech - \u652f\u4ed8\u98ce\u9669\u7ec4Payment Risk \u5b9e\u4e60\u751f - \u98ce\u63a7\u7b97\u6cd5 2025\u5e7410\u6708-2026\u5e746\u6708 \u2022 \u963b\u6321\u6307\u6807\u52a8\u6807\u6839\u56e0\u5206\u6790\uff1a\u5f00\u53d1\u652f\u4ed8\u98ce\u9669\u6307\u6807\u5f02\u5e38\u56e0\u52a8\u6839\u5f02\u5e38\u7cfb\u7edf\uff0c\u8986\u76d6\u5916\u5356\u3001\u51fa\u884c\u3001\u94b1\u5305\u3001\u501f\u8d37\u7b49\u591a\u4e1a\u52a1\u573a\u666f\uff0c\u56f4\u7ed5\u6253\u6297\u7387\u3001\u62d2\u7edd\u7387\u30013DS\u7387\u3001CB\u91d1\u989d\u3001CB\u8d44\u635f\u7387\u7b49\u6838\u5fc3\u6307\u6807\uff0c\u642d\u5efa\u201c\u5f02\u5e38\u8bc6\u522b-\u7ef4\u5ea6\u4e0b\u94bb-\u8d21\u732e\u5ea6\u5f52\u56e0-\u7ed3\u679c\u8f93\u51fa\u201d\u81ea\u52a8\u5316\u94fe\u8def\uff0c\u652f\u6301\u6309\u56fd\u5bb6\u3001\u4e1a\u52a1\u7ebf\u3001\u652f\u4ed8\u65b9\u5f0f\u3001\u7b56\u7565\u7ec4\u3001\u7528\u6237\u5206\u5c42\u7b49\u7ef4\u5ea6\u5b9a\u4f4d\u5f02\u5e38\u6765\u6e90\uff0c\u63d0\u5347\u98ce\u9669\u6ce2\u52a8\u6392\u67e5\u6548\u7387\u3002 \u2022 \u5df4\u897f\u94b1\u5305\u98ce\u9669\u6a21\u578b\uff1a\u53c2\u4e0e\u5df4\u897f\u94b1\u5305 XGBoost \u98ce\u9669\u6a21\u578b\u5efa\u8bbe\u4e0e\u7b56\u7565\u8bc4\u4f30\uff0c\u57fa\u4e8e\u7528\u6237\u753b\u50cf\u3001\u4ea4\u6613\u884c\u4e3a\u3001\u8bbe\u5907\u73af\u5883\u3001\u5730\u7406\u4f4d\u7f6e\u3001\u652f\u4ed8\u5361\u4fe1\u606f\u3001\u5386\u53f2\u62d2\u4ed8\u8868\u73b0\u7b49\u7279\u5f81\u8f93\u51fa\u8ba2\u5355\u98ce\u9669\u5206\uff0c\u7ed3\u5408\u547d\u4e2d\u7387\u3001\u62d2\u7edd\u7387\u30013DS\u7387\u3001\u901a\u8fc7\u7387\u3001\u6253\u6297\u7387\u7b49\u6307\u6807\u8bc4\u4f30\u6a21\u578b\u6548\u679c\uff0c\u4e3a\u9ad8/\u4e2d/\u4f4e\u98ce\u9669\u5206\u5c42\u6cbb\u7406\u548c\u652f\u4ed8\u98ce\u63a7\u7b56\u7565\u4f18\u5316\u63d0\u4f9b\u4f9d\u636e\u3002 \u2022 \u652f\u4ed8\u98ce\u9669\u7b56\u7565\u89c4\u5219\u81ea\u52a8\u8c03\u4f18\u4e0e\u6548\u679c\u8ffd\u8e2a\u7cfb\u7edf\uff1a\u9762\u5411\u652f\u4ed8\u98ce\u63a7\u7b56\u7565\u5feb\u901f\u8fed\u4ee3\u573a\u666f\uff0c\u9488\u5bf9\u5b9e\u9a8c\u7ec4\u7b56\u7565\u8c03\u6574\u540e\u6307\u6807\u94fe\u8def\u96be\u4ee5\u81ea\u52a8\u627f\u63a5\u3001\u7b56\u7565\u6548\u679c\u4f9d\u8d56\u4eba\u5de5\u590d\u76d8\u7684\u95ee\u9898\uff0c\u5f00\u53d1\u7b56\u7565\u6620\u5c04\u3001\u89c4\u5219\u6807\u51c6\u5316\u3001\u6307\u6807\u8ffd\u9010\u4e0e\u89c4\u5219\u8c03\u4f18\u95ed\u73af\u3002\u7cfb\u7edf\u81ea\u52a8\u8bc6\u522b\u8fed\u4ee3\u524d\u540e\u7b56\u7565\u6620\u5c04\u5173\u7cfb\uff0c\u6301\u7eed\u76d1\u63a7\u5b9e\u9a8c\u7ec4\u7b56\u7565\u8c03\u6574\u540e\u7684\u547d\u4e2d\u7387\u3001\u552f\u4e00\u547d\u4e2d\u7387\u3001\u8ba2\u5355\u62d2\u62d2\u7387\u30013DS\u7387\u3001\u901a\u8fc7\u7387\u3001\u6253\u6297\u7387\u7b49\u6838\u5fc3\u6307\u6807\uff1b\u5f53\u67d0\u4e00\u7b56\u7565\u89c4\u5219\u5bfc\u81f4\u5176\u5bf9\u5e94\u7684\u5173\u952e\u8bcd\u6307\u6807\u51fa\u73b0\u8f83\u5927\u6ce2\u52a8\u65f6\uff0c\u81ea\u52a8\u5b9a\u4f4d\u5f02\u5e38\u89c4\u5219\u5e76\u751f\u6210\u53c2\u6570\u8c03\u6574\u6216\u89c4\u5219\u4fee\u6b63\u5efa\u8bae\uff0c\u6301\u7eed\u8ffd\u8e2a\u4fee\u6539\u540e\u7684\u6307\u6807\u6548\u679c\uff0c\u8f85\u52a9\u7b56\u7565\u540c\u5b66\u5728\u98ce\u9669\u62e6\u622a\u6536\u76ca\u4e0e\u7528\u6237\u6253\u6270\u6210\u672c\u4e4b\u95f4\u53d6\u5f97\u66f4\u4f18\u5e73\u8861\u3002 \u2022 \u5934\u5bf8\u65f6\u95f4\u5e8f\u5217\u9884\u6d4b\uff1a\u53c2\u4e0e\u56fd\u9645\u91d1\u878d\u5934\u5bf8\u9884\u6d4b\u5efa\u6a21\uff0c\u57fa\u4e8e\u5386\u53f2\u5165\u91d1\u3001\u51fa\u91d1\u4ea4\u6613\u989d\u6784\u5efa LSTM \u65f6\u95f4\u5e8f\u5217\u9884\u6d4b\u6a21\u578b\uff0c\u5206\u6790\u4ea4\u6613\u989d\u8d8b\u52bf\u3001\u5468\u671f\u6027\u6ce2\u52a8\u548c\u5f02\u5e38\u53d8\u5316\uff0c\u652f\u6301\u672a\u6765\u8d44\u91d1\u6d41\u5165\u6d41\u51fa\u9884\u6d4b\uff0c\u4e3a\u8d44\u91d1\u8c03\u5ea6\u3001\u98ce\u9669\u9884\u8b66\u548c\u8fd0\u8425\u51b3\u7b56\u63d0\u4f9b\u6570\u636e\u4f9d\u636e\u3002 \u5b57\u8282\u8df3\u52a8 - \u56fd\u9645\u7535\u5546TTS - \u7528\u6237\u589e\u957f UG \u5546\u4e1a\u5316\u5e7f\u544a\u7ec4 \u5b9e\u4e60\u751f - \u6570\u636e\u5206\u6790 2025\u5e745\u6708-2025\u5e749\u6708 \u2022 ToB/ToC \u5e7f\u544a\u6570\u636e\u5206\u6790\uff1a\u7ef4\u62a4\u56fd\u9645\u7535\u5546\u5546\u4e1a\u5316\u5e7f\u544a\u573a\u666f ToB/ToC \u6548\u679c\u6570\u636e\u96c6\uff0c\u5f00\u53d1\u5bf9\u5e94\u770b\u677f\uff0c\u652f\u6301\u4e1a\u52a1\u51b3\u7b56\u4e0e\u5e7f\u544a\u6548\u679c\u5206\u6790\u3002 \u54cd\u5e94\u4e1a\u52a1\u9700\u6c42\u5b8c\u6210\u591a\u6b21\u6838\u5fc3\u8868\u7684\u5b57\u6bb5\u65b0\u589e\u548c2\u5f20\u4e1a\u52a1\u8868\u7684\u6570\u636e\u4f53\u7cfb\u642d\u5efa\uff0cSparkSQL\u4f18\u5316\u6570\u636e\u94fe\u8def\u5e76\u5b8c\u6210\u5168\u91cf\u6570\u636e\u9a8c\u8bc1\uff0c\u786e\u4fdd GMV \u7b49\u6838\u5fc3\u6307\u6807\u5dee\u5f02\u63a7\u5236\u5728\u00b10.1\u5185\uff0c\u63d0\u5347\u6570\u636e\u94fe\u8def\u8fd0\u884c\u6548\u7387\u7f29\u77ed\u65f6\u957f30%\u3002\u89e3\u51b3\u6307\u6807\u5f02\u52a8\u5206\u6790\u3001\u5e7f\u544a\u94fe\u63a5\u89e3\u6790\u4e22\u5931\u7b49oncall\u95ee\u9898\uff0c\u5171\u8f93\u51fa5\u6b21\u5206\u6790\u62a5\u544a\u5e76\u63d0\u4f9b\u4e1a\u52a1\u5e94\u5efa\u8bae\u3002 \u2022 ROI2 \u65b0\u6307\u6807\u5f00\u53d1\uff1a\u4e3b\u5bfc\u65b0\u5f00\u56fdToB\u5e7f\u544a\u770b\u677f ROI2 \u5347\u7ea7\u53e3\u5f84\u5f00\u53d1\uff0c\u5e76\u901a\u8fc7AB\u6d4b\u8bd5\u9a8c\u8bc1\u6309 ROI2 \u4f18\u5316\u7684\u6295\u653e\u7ec4 vs \u539f\u6295\u653e\u7ec4\uff0c\u540c\u7b49\u70b9\u51fb\u7387\u6548\u679c\u4e0b\u66dd\u5149\u6210\u672c\u964d\u4f4e5%\u3002 \u9ad8LTV\u7cbe\u51c6\u4eba\u7fa4\uff1a\u5b8c\u5584\u9ad8LTV\u4eba\u7fa4\u6307\u6807\u4f53\u7cfb\uff0c\u805a\u7c7b\u7b49\u5206\u6790\u53d1\u73b0\u5f53\u524d\u9ad8LTV\u6709\u4e00\u6279\u4eba\u9000\u8d27\u7387\u8f83\u9ad8\uff0c\u4e3b\u52a8\u5bf9\u63a5\u98ce\u9669\u56e2\u961f\uff0c\u521b\u65b0\u63a7\u4f4e\u98ce\u9669\u5206\u6807\u7b7e\u878d\u5165LTV\u4eba\u7fa4\u5224\u5b9a\u903b\u8f91\uff0c\u4f18\u5316\u4eba\u7fa4\u5708\u9009\u7cbe\u51c6\u5ea6\u3002\u8fdb\u884cAB\u6d4b\u8bd5\u9a8c\u8bc1\u65b0LTV\u4eba\u7fa4\u7ec4vs\u539fLTV\u4eba\u7fa4\u7ec4\uff0c\u540c\u7b49\u8425\u9500\u6295\u5165\u4e0b\u6210\u4ea4\u5355\u91cf\u63d0\u5347\u7ea65%\uff0cGMV\u63d0\u5347\u7ea62%\u3002 \u730e\u8058\u7f51 - \u6280\u672f\u90e8AI\u4e2d\u5fc3 \u7b97\u6cd5\u7ec4 \u5b9e\u4e60\u751f-\u5927\u6a21\u578b\u7b97\u6cd5 2025\u5e741\u6708-2025\u5e745\u6708 \u2022 \u6a21\u578b\u8bad\u7ec3\uff1a\u8d1f\u8d23\u62db\u8058\u5c97\u4f4d\u8bf4\u660e JD \u4e0e\u5019\u9009\u4eba\u7b80\u5386 CV \u6574\u4f53\u5339\u914d\u9879\u76ee\u7684\u6a21\u578b\u84b8\u998f\uff0c\u901a\u8fc7SFT\u548cDPO\u65b9\u6cd5\u5782\u7c7b\u903b\u8f91\u63a8\u7406\u80fd\u529b\u3002\u76ee\u524d\u5728 3B \u6a21\u578b\u4e0a\uff0c\u51c6\u786e\u7387 P \u8fbe 87%\uff0c\u53ec\u56de\u7387 R \u8fbe 71%\uff0c\u903c\u8fd1\u901a\u7528\u6a21\u578b Qwen2.5 - 72B \u6c34\u5e73\uff08\u51c6\u786e\u7387 P \u8fbe 80%\uff0c\u53ec\u56de\u7387 R \u8fbe 75%\uff09 \u2022 \u6570\u636e\u6e05\u6d17\uff1a\u5feb\u901f\u5bf9\u63a5\u65b0\u4ea7\u54c1\u65b9\uff0c\u63a5\u624b\u6a21\u578b\u6570\u636e\u5168\u6d41\u7a0b\uff0c\u5305\u62ecSpark\u53d6240w\u539f\u59cb\u6570\u636e-\u6b63\u8d1f\u6837\u672c\u5408\u5e76-\u5199Promptt\u6a21\u578b\u603b\u7ed3\u5b57\u6bb5-\u6570\u636e\u5206\u5c42\u6b21\u6e05\u6d17-embedding\u805a\u7c7b\u53bb\u91cd\u6570\u636e-\u6570\u636e\u6253\u8d28\u91cf\u5206\u51c6\u5ea6\u5206-\u5408\u5e769w\u8bad\u7ec3\u6570\u636e\u96c6\u7b49\uff0c\u5b9e\u4e60\u671f\u95f4\u6301\u7eed\u4ea7\u51fa5\u6b21\u6807\u51c6\u7ed3\u6784\u5316\u6570\u636e\u96c6\uff0c\u5e76\u8d1f\u8d23\u9a8c\u8bc1\u6570\u636e\u96c6\u6709\u6548\u6027\u3002 \u2022 \u8d28\u91cf\u8d28\u91cf\uff1a\u5206\u6790\u6570\u636e\u5206\u5e03\u5f62\u6001\uff0c\u8f93\u51fa\u5b57\u6bb5\u7edf\u8ba1\u5206\u5e03\u56fe\uff0c\u6a21\u578b\u6253\u5206\u5206\u5e03\u56fe\u7b49\u53cd\u9988\u8c03\u6574\u6570\u636e\u7ba1\u7ebf\u7b56\u7565\uff0c\u53d1\u73b0\u5e76\u89e3\u51b310\u4f59\u6b21\u591a\u5c42\u6b21\u6570\u636e\u8d28\u91cf\u95ee\u9898\uff0c\u786e\u4fdd\u9ad8\u8d28\u91cf\u6570\u636e\u8f93\u51fa\uff0c\u6700\u7ec8\u4fdd\u969c\u6a21\u578b\u8bad\u7ec3\u8d28\u91cf\uff0c\u5b9e\u4e60\u671f\u95f4\u8bad\u7ec3\u6307\u6807\u57283B\u6a21\u578b\u4e0a\u51c6\u786e\u7387P\u4e0e\u53ec\u56de\u7387R\u5747\u63d0\u9ad815%\u5de6\u53f3\uff0c\u57fa\u672c\u5b8c\u6210\u5c0f\u578b\u5316\u76ee\u6807\u3002 \u5fb7\u56fd\u5927\u9646 (\u5916\u4f01) - \u4fe1\u606f\u90e8 \u4f9b\u5e94\u94fe\u4e0e\u6570\u636e\u5206\u6790\u7ec4 \u5b9e\u4e60\u751f-\u4ea7\u54c1&\u6570\u636e\u5206\u6790 2023\u5e7410\u6708-2024\u5e742\u6708 \u2022 \u4ea7\u54c1\u7ecf\u7406\uff1a\u534f\u52a9\u9879\u76ee\u7ecf\u7406\u8d1f\u8d23\u65b0\u5de5\u5382 HR \u7cfb\u7edf\u9879\u76ee\uff0c\u9488\u5bf9\u591a\u90e8\u95e8\u53c2\u4e0e\u9700\u6c42\u5206\u6790\u4f1a\u8bae10\u4f59\u6b21\uff0c\u5b8c\u6210\u4f9b\u5e94\u5546\u7ade\u54c1\u8c03\u7814\u62a5\u544a8\u4efd\uff0c\u72ec\u7acb\u5b8c\u6210\u7cfb\u7edf\u89e3\u51b3\u65b9\u6848\u8bbe\u8ba1\uff08\u542bAxure\u7ed8\u5236\u7b80\u5355\u539f\u578b\u56fe\uff09\uff0c\u7ecf\u7edf\u8ba1\u6ee1\u610f\u5ea695%\u4ee5\u4e0a\u3002\u9879\u76ee\u5df2\u8fdb\u5165\u5b9e\u65bd\u9636\u6bb5\uff0c\u8d1f\u8d23\u8ddf\u8e2a\u548c\u76d1\u63a7\u9879\u76ee\u8fdb\u5ea6\uff0c\u5e76\u89e3\u51b3\u9700\u6c42\u53d8\u66f4\u95ee\u98982\u6b21\u3002 \u2022 \u6570\u636e\u5206\u6790\uff1a\u4e3a\u6539\u5584\u7269\u6d41\u90e8\u6548\u7387\uff0c\u5b8c\u5584LMS\u8d27\u8fd0\u6307\u6807\u4f53\u7cfb\uff0cTableau\u642d\u5efa\u8d27\u8fd0\u770b\u677f\uff0c\u4ece\u51c6\u65f6\u53d1\u8d27\u7387\u3001\u51c6\u65f6\u4ea4\u4ed8\u7387\u7b49\u7ef4\u5ea6\u642d\u5efa\u53ef\u89c6\u5316\u65e5\u62a5\u5468\u62a5\uff0c\u534f\u52a9\u7269\u6d41\u7ecf\u7406\u505a\u95ee\u9898\u8ddf\u8e2a\uff0c\u5ba2\u6237\u6295\u8bc9\u7387\u4ece3.5%\u4e0b\u964d\u52302.7%\uff1b\u9488\u5bf9\u6d77\u8fd0\u6570\u636e\u4e0d\u6e05\u6670\uff0cFineBI\u5f00\u53d1\u6d77\u8fd0\u8ba2\u5355\u8f68\u8ff9\u53ef\u89c6\u5316\u5e73\u53f0\uff0c\u6d77\u8fd0\u8ba2\u5355\u95ee\u9898\u6570\u51cf\u5c1110%\u4ee5\u4e0a\u3002 \u2022 \u534f\u52a9\u4f18\u5316\uff1a\u534f\u52a9\u5efa\u7acb\u8d27\u8fd0\u957f\u671f\u95ee\u9898\u8ddf\u8e2a\u53cd\u9988\u673a\u5236\uff0c\u7b56\u5212\u5e76\u4e3b\u6301\u53cc\u5468\u914d\u9001\u5546\u590d\u76d8\u4f1a\uff0c\u6bcf\u65e5\u53d1\u653e\u914d\u9001\u5546KPI\u6570\u636e\uff0c\u53ca\u65f6\u53d1\u73b0\u5f02\u5e38\u6570\u636e\u5e76\u534f\u52a9\u89e3\u51b3\uff0c\u914d\u9001\u5546KPI\u6307\u6807\u5f97\u5206\u63d0\u53475%\u4ee5\u4e0a\u3002 \u9879\u76ee\u7ecf\u5386 \u4e2a\u4eba\u4e3b\u9875 / BingoChat \u6570\u5b57\u5206\u8eab\u9879\u76ee \u9762\u5411\u4e2a\u4eba\u5c55\u793a\u3001\u9762\u8bd5\u6c9f\u901a\u548c\u5728\u7ebf\u4e92\u52a8\u573a\u666f\u7684 AI \u4e2a\u4eba\u4e3b\u9875 Demo\uff0c\u5c06\u4e2a\u4eba\u7ecf\u5386\u3001\u9879\u76ee\u4f5c\u54c1\u3001\u6280\u672f\u6808\u3001\u7559\u8a00\u8868\u5355\u548c /bingo \u6570\u5b57\u5206\u8eab\u804a\u5929\u96c6\u6210\u5728\u540c\u4e00\u4e2a\u7ad9\u70b9\u4e2d\u3002\u7cfb\u7edf\u57fa\u4e8e HTML/CSS/JavaScript + Flask\uff1b\u804a\u5929\u94fe\u8def\u4f7f\u7528 SK