INSERT INTO public.parsed_chunks VALUES ('177d2004-8158-45c3-a678-46f72b52d09f', 'ce5d34a3-8124-41f2-ae0e-109cc7c50283', '3e0b5f0b-ed6f-4466-b50b-d305b30247af', 'manual', '外婆喜欢给小铭包馄饨，也常说饭要趁热慢慢吃。', '外婆为小铭包馄饨，并叮嘱饭要趁热慢慢吃。', 'manual:body', NULL, NULL, '{"text_extraction": {"extractor": "manual", "source_location": "manual:body", "has_text": true}, "text_parser": {"cleaned_text": "\u5916\u5a46\u559c\u6b22\u7ed9\u5c0f\u94ed\u5305\u9984\u9968\uff0c\u4e5f\u5e38\u8bf4\u996d\u8981\u8d81\u70ed\u6162\u6162\u5403\u3002", "chunks": [{"chunk_type": "text", "content": "\u5916\u5a46\u559c\u6b22\u7ed9\u5c0f\u94ed\u5305\u9984\u9968\uff0c\u4e5f\u5e38\u8bf4\u996d\u8981\u8d81\u70ed\u6162\u6162\u5403\u3002", "summary": "\u5916\u5a46\u4e3a\u5c0f\u94ed\u5305\u9984\u9968\uff0c\u5e76\u53ee\u5631\u996d\u8981\u8d81\u70ed\u6162\u6162\u5403\u3002", "source_location": "manual:body"}]}, "provider_type": "third_party"}', NULL, '2026-07-04 17:36:05.059976', NULL);
INSERT INTO public.parsed_chunks VALUES ('57586330-ea3e-4389-84a2-59962ee5a422', '68ec4c84-bea4-4b84-96f6-1e7c09a4bbdf', 'e0f161b6-76b9-4bad-9462-49c768ca753c', 'manual', '小铭生日那天，外婆准备了蛋糕和一碗热汤，笑着说只要小铭平安就好。', '外婆在小铭生日时准备蛋糕和热汤，并表达对其平安的祝愿。', 'manual:body', NULL, NULL, '{"text_extraction": {"extractor": "manual", "source_location": "manual:body", "has_text": true}, "text_parser": {"cleaned_text": "\u5c0f\u94ed\u751f\u65e5\u90a3\u5929\uff0c\u5916\u5a46\u51c6\u5907\u4e86\u86cb\u7cd5\u548c\u4e00\u7897\u70ed\u6c64\uff0c\u7b11\u7740\u8bf4\u53ea\u8981\u5c0f\u94ed\u5e73\u5b89\u5c31\u597d\u3002", "chunks": [{"chunk_type": "text", "content": "\u5c0f\u94ed\u751f\u65e5\u90a3\u5929\uff0c\u5916\u5a46\u51c6\u5907\u4e86\u86cb\u7cd5\u548c\u4e00\u7897\u70ed\u6c64\uff0c\u7b11\u7740\u8bf4\u53ea\u8981\u5c0f\u94ed\u5e73\u5b89\u5c31\u597d\u3002", "summary": "\u5916\u5a46\u5728\u5c0f\u94ed\u751f\u65e5\u65f6\u51c6\u5907\u86cb\u7cd5\u548c\u70ed\u6c64\uff0c\u5e76\u8868\u8fbe\u5bf9\u5176\u5e73\u5b89\u7684\u795d\u613f\u3002", "source_location": "manual:body"}]}, "provider_type": "third_party"}', NULL, '2026-07-04 17:37:29.356004', NULL);
INSERT INTO public.parsed_chunks VALUES ('1478a856-0fef-4175-ac45-d8985e3f0e8b', '9183ebe2-437b-4d69-be7f-2dec45a29d55', '9251c854-6ad8-4468-a337-694a3e93c2d7', 'video', '小伟，记得保管好阿妈的情书。。基于您提供的视频画面（AI生成的老宅老人图像）和音频转写，以下是为您创建的“星星页”珍贵回忆场景摘要： **场景摘要：老宅前的叮嘱** * **人物**： * **画面主角**：一位满头银发、穿着浅色衬衫和卡其色长裤的老爷爷（可能是父亲或祖父）。他双手背在身后，神态安详。 * **提及人物**：“小伟”（被叮嘱的晚辈）、“阿妈”（情感的核心人物，老爷爷的伴侣或长辈）。 * **地点**： * 一座充满岁月痕迹的传统老宅庭院门口。斑驳的墙壁、贴着褪色红对联的木门、以及旁边的盆栽和木椅，营造出一种怀旧、宁静的老家氛围。 * **事件**： * 老人站在老屋门前，面带微笑地注视着前方（仿佛看着小伟）。他在叮嘱小伟要妥善保管好“阿妈”的情书，这是一个关于传承家族记忆和珍视情感的瞬间。 * **情绪**： * **慈祥与温暖**：老人的笑容非常温和，给人一种安全感。 * **怀旧与深情**：提到“阿妈的情书”，让画面充满了浪漫与岁月的沉淀感，是对过去美好时光的珍视。 * **可引用记忆**： * “小伟，记得保管好阿妈的情书。”（这句话是这段回忆的核心，象征着爱的传承和珍贵的家族历史。）。小伟，记得保管好阿妈的情书。。基于您提供的视频画面（AI生成的老宅老人图像）和音频转写，以下是为您创建的“星星页”珍贵回忆场景摘要： **场景摘要：老宅前的叮嘱** * **人物**： * **画面主角**：一位满头银发、穿着浅色衬衫和卡其色长裤的老爷爷（可能是父亲或祖父）。他双手背在身后，神态安详。 * **提及人物**：“小伟”（被叮嘱的晚辈）、“阿妈”（情感的核心人物，老爷爷的伴侣或长辈）。 * **地点**： * 一座充满岁月痕迹的传统老宅庭院门口。斑驳的墙壁、贴着褪色红对联的木门、以及旁边的盆栽和木椅，营造出一种怀旧、宁静的老家氛围。 * **事件**： * 老人站在老屋门前，面带微笑地注视着前方（仿佛看着小伟）。他在叮嘱小伟要妥善保管好“阿妈”的情书，这是一个关于传承家族记忆和珍视情感的瞬间。 * **情绪**： * **慈祥与温暖**：老人的笑容非常温和，给人一种安全感。 * **怀旧与深情**：提到“阿妈的情书”，让画面充满了浪漫与岁月的沉淀感，是对过去美好时光的珍视。 * **可引用记忆**： * “小伟，记得保管好阿妈的情书。”（这句话是这段回忆的核心，象征着爱的传承和珍贵的家族历史。）', '基于您提供的视频画面（AI生成的老宅老人图像）和音频转写，以下是为您创建的“星星页”珍贵回忆场景摘要： **场景摘要：老宅前的叮嘱** * **人物**： * **画面主角**：一位满头银发、穿着浅色衬衫和卡其色长裤的老爷爷（可能是父亲或祖父）。他双手背在身后，神态安详。 * **提及人物**：“小伟”（被叮嘱的晚辈）、“阿妈”（情感的核心人物，老爷爷的伴侣或长辈）。 * **地点**： * 一座充满岁月痕迹的传统老宅庭院门口。斑驳的墙壁、贴着褪色红对联的木门、以及旁边的盆栽和木椅，营造出一种怀旧、宁静的老家氛围。 * **事件**： * 老人站在老屋门前，面带微笑地注视着前方（仿佛看着小伟）。他在叮嘱小伟要妥善保管好“阿妈”的情书，这是一个关于传承家族记忆和珍视情感的瞬间。 * **情绪**： * **慈祥与温暖**：老人的笑容非常温和，给人一种安全感。 * **怀旧与深情**：提到“阿妈的情书”，让画面充满了浪漫与岁月的沉淀感，是对过去美好时光的珍视。 * **可引用记忆**： * “小伟，记得保管好阿妈的情书。”（这句话是这段回忆的核心，象征着爱的传承和珍贵的家族历史。）', 'video:爷爷视频.mp4#00:00', 0, 10, '{"video_understanding": {"transcript": "\u5c0f\u4f1f\uff0c\u8bb0\u5f97\u4fdd\u7ba1\u597d\u963f\u5988\u7684\u60c5\u4e66\u3002", "scene_summary": "\u57fa\u4e8e\u60a8\u63d0\u4f9b\u7684\u89c6\u9891\u753b\u9762\uff08AI\u751f\u6210\u7684\u8001\u5b85\u8001\u4eba\u56fe\u50cf\uff