INSERT INTO public.parsed_chunks VALUES ('769fc531-2180-462d-b7d7-19caa57f9a9f', '9183ebe2-437b-4d69-be7f-2dec45a29d55', '68da93b0-5d74-484f-81ef-c71d82a18e49', 'image', '一位头发花白的长者站在传统老宅的木门前，身穿浅灰色衬衫和卡其色长裤，双手背在身后，面带慈祥的微笑。背景是斑驳的墙壁、红色的对联以及绿植盆栽，充满了浓厚的生活气息和岁月感。。造福苍生福报接接。这是创建星星页上传的珍贵回忆。画面中的长者站在贴有红色对联的老门前，笑容温和。结合OCR文本‘造福苍生福报接接’，这张照片仿佛定格了岁月的静好与深厚的福报，记录下一份庄重而温暖的瞬间。', '一位头发花白的长者站在传统老宅的木门前，身穿浅灰色衬衫和卡其色长裤，双手背在身后，面带慈祥的微笑。背景是斑驳的墙壁、红色的对联以及绿植盆栽，充满了浓厚的生活气息和岁月感。', 'image:爷爷图片.png', NULL, NULL, '{"ocr": {"ocr_text": "\u9020\u798f\u82cd\u751f\u798f\u62a5\u63a5\u63a5", "source_location": "image:\u7237\u7237\u56fe\u7247.png:ocr"}, "image_understanding": {"caption": "\u4e00\u4f4d\u5934\u53d1\u82b1\u767d\u7684\u957f\u8005\u7ad9\u5728\u4f20\u7edf\u8001\u5b85\u7684\u6728\u95e8\u524d\uff0c\u8eab\u7a7f\u6d45\u7070\u8272\u886c\u886b\u548c\u5361\u5176\u8272\u957f\u88e4\uff0c\u53cc\u624b\u80cc\u5728\u8eab\u540e\uff0c\u9762\u5e26\u6148\u7965\u7684\u5fae\u7b11\u3002\u80cc\u666f\u662f\u6591\u9a73\u7684\u5899\u58c1\u3001\u7ea2\u8272\u7684\u5bf9\u8054\u4ee5\u53ca\u7eff\u690d\u76c6\u683d\uff0c\u5145\u6ee1\u4e86\u6d53\u539a\u7684\u751f\u6d3b\u6c14\u606f\u548c\u5c81\u6708\u611f\u3002", "scene_metadata": {"scene_type": "\u4f20\u7edf\u5ead\u9662/\u8001\u5b85\u95e8\u524d", "detected_people_count": 1, "emotion_tone": "\u6e29\u99a8\u3001\u6000\u65e7\u3001\u5b81\u9759"}, "memory_candidate_text": "\u8fd9\u662f\u521b\u5efa\u661f\u661f\u9875\u4e0a\u4f20\u7684\u73cd\u8d35\u56de\u5fc6\u3002\u753b\u9762\u4e2d\u7684\u957f\u8005\u7ad9\u5728\u8d34\u6709\u7ea2\u8272\u5bf9\u8054\u7684\u8001\u95e8\u524d\uff0c\u7b11\u5bb9\u6e29\u548c\u3002\u7ed3\u5408OCR\u6587\u672c\u2018\u9020\u798f\u82cd\u751f\u798f\u62a5\u63a5\u63a5\u2019\uff0c\u8fd9\u5f20\u7167\u7247\u4eff\u4f5b\u5b9a\u683c\u4e86\u5c81\u6708\u7684\u9759\u597d\u4e0e\u6df1\u539a\u7684\u798f\u62a5\uff0c\u8bb0\u5f55\u4e0b\u4e00\u4efd\u5e84\u91cd\u800c\u6e29\u6696\u7684\u77ac\u95f4\u3002", "source_location": "image:\u7237\u7237\u56fe\u7247.png"}, "provider_type": "third_party"}', NULL, '2026-07-04 17:10:02.14974', '2026-07-04 17:21:08.129722');
