INSERT INTO public.parsed_chunks VALUES ('9eca1062-1ffa-4b37-bc53-a5ec670791ec', '8c5ba672-adf0-486e-ab34-c3f9ae794aed', '8207d744-2375-4083-9560-d67fc237effc', 'manual', '小铭生日那天，外婆准备了蛋糕和一碗热汤，笑着说只要小铭平安就好。', '外婆在小铭生日时准备蛋糕和热汤，并表达对小铭平安的祝愿。', 'manual:body', NULL, NULL, '{"text_extraction": {"extractor": "manual", "source_location": "manual:body", "has_text": true}, "text_parser": {"cleaned_text": "\u5c0f\u94ed\u751f\u65e5\u90a3\u5929\uff0c\u5916\u5a46\u51c6\u5907\u4e86\u86cb\u7cd5\u548c\u4e00\u7897\u70ed\u6c64\uff0c\u7b11\u7740\u8bf4\u53ea\u8981\u5c0f\u94ed\u5e73\u5b89\u5c31\u597d\u3002", "chunks": [{"chunk_type": "text", "content": "\u5c0f\u94ed\u751f\u65e5\u90a3\u5929\uff0c\u5916\u5a46\u51c6\u5907\u4e86\u86cb\u7cd5\u548c\u4e00\u7897\u70ed\u6c64\uff0c\u7b11\u7740\u8bf4\u53ea\u8981\u5c0f\u94ed\u5e73\u5b89\u5c31\u597d\u3002", "summary": "\u5916\u5a46\u5728\u5c0f\u94ed\u751f\u65e5\u65f6\u51c6\u5907\u86cb\u7cd5\u548c\u70ed\u6c64\uff0c\u5e76\u8868\u8fbe\u5bf9\u5c0f\u94ed\u5e73\u5b89\u7684\u795d\u613f\u3002", "source_location": "manual:body"}]}, "provider_type": "third_party"}', NULL, '2026-07-04 17:35:34.578731', NULL);
