INSERT INTO public.parsed_chunks VALUES ('9686fbef-161b-41b3-ad16-51b269af55b4', '68ec4c84-bea4-4b84-96f6-1e7c09a4bbdf', '7578953e-643e-4e16-ba5b-ba5e1d379ed9', 'manual', '外婆喜欢给小铭包馄饨，也常说饭要趁热慢慢吃。', '外婆为小铭包馄饨，并叮嘱饭要趁热慢慢吃。', 'manual:body', NULL, NULL, '{"text_extraction": {"extractor": "manual", "source_location": "manual:body", "has_text": true}, "text_parser": {"cleaned_text": "\u5916\u5a46\u559c\u6b22\u7ed9\u5c0f\u94ed\u5305\u9984\u9968\uff0c\u4e5f\u5e38\u8bf4\u996d\u8981\u8d81\u70ed\u6162\u6162\u5403\u3002", "chunks": [{"chunk_type": "text", "content": "\u5916\u5a46\u559c\u6b22\u7ed9\u5c0f\u94ed\u5305\u9984\u9968\uff0c\u4e5f\u5e38\u8bf4\u996d\u8981\u8d81\u70ed\u6162\u6162\u5403\u3002", "summary": "\u5916\u5a46\u4e3a\u5c0f\u94ed\u5305\u9984\u9968\uff0c\u5e76\u53ee\u5631\u996d\u8981\u8d81\u70ed\u6162\u6162\u5403\u3002", "source_location": "manual:body"}]}, "provider_type": "third_party"}', NULL, '2026-07-04 17:36:31.539524', NULL);
INSERT INTO public.parsed_chunks VALUES ('5fc453fa-5013-428d-805a-850bff127388', '18b88e96-5633-4d75-b77a-0ad1988a846a', '136855af-c9e4-4fd4-8eb7-b409bb9f8aca', 'manual', '爷爷18岁那年，也就是1952年，决定跟着同乡下南洋。那一年家里的祖屋漏雨，太公身体不好，弟妹还小，家里欠着米铺的钱。爷爷作为家里的长子，很早就明白自己没有资格只为自己活。', '爷爷1952年18岁时因家庭困境（祖屋漏雨、太公病弱、弟妹年幼、欠米铺债）作为长子负重离乡下南洋。', 'manual:body', NULL, NULL, '{"text_extraction": {"extractor": "manual", "source_location": "manual:body", "has_text": true}, "text_parser": {"cleaned_text": "\u4e8c\u3001\u7237\u7237\u4e0b\u5357\u6d0b\u7684\u80cc\u666f \u7237\u723718\u5c81\u90a3\u5e74\uff0c\u4e5f\u5c31\u662f1952\u5e74\uff0c\u51b3\u5b9a\u8ddf\u7740\u540c\u4e61\u4e0b\u5357\u6d0b\u3002\u90a3\u4e00\u5e74\u5bb6\u91cc\u7684\u7956\u5c4b\u6f0f\u96e8\uff0c\u592a\u516c\u8eab\u4f53\u4e0d\u597d\uff0c\u5f1f\u59b9\u8fd8\u5c0f\uff0c\u5bb6\u91cc\u6b20\u7740\u7c73\u94fa\u7684\u94b1\u3002\u7237\u7237\u4f5c\u4e3a\u5bb6\u91cc\u7684\u957f\u5b50\uff0c\u5f88\u65e9\u5c31\u660e\u767d\u81ea\u5df1\u6ca1\u6709\u8d44\u683c\u53ea\u4e3a\u81ea\u5df1\u6d3b\u3002 \u79bb\u5f00\u524d\u7684\u90a3\u4e2a\u665a\u4e0a\uff0c\u963f\u5b37\u8fd8\u4e0d\u662f\u4ed6\u7684\u59bb\u5b50\uff0c\u53ea\u662f\u6751\u91cc\u548c\u4ed6\u4ece\u5c0f\u76f8\u8bc6\u7684\u59d1\u5a18\u3002\u4e24\u4e2a\u4eba\u6ca1\u6709\u6b63\u5f0f\u8c08\u8fc7\u4ec0\u4e48\u8f70\u8f70\u70c8\u70c8\u7684\u604b\u7231\uff0c\u90a3\u4e2a\u5e74\u4ee3\u7684\u4eba\u4e5f\u8bf4\u4e0d\u51fa\u592a\u591a\u8089\u9ebb\u7684\u8bdd\u3002\u53ef\u662f\u4ed6\u4eec\u5fc3\u91cc\u90fd\u77e5\u9053\uff0c\u5bf9\u65b9\u662f\u81ea\u5df1\u60e6\u8bb0\u7684\u4eba\u3002 \u963f\u5b37\u7ed9\u7237\u7237\u7f1d\u4e86\u4e00\u4e2a\u5c0f\u5e03\u5305\uff0c\u91cc\u9762\u88c5\u4e86\u4e00\u5c0f\u64ae\u5bb6\u4e61\u7684\u571f\u3001\u4e00\u679a\u94dc\u94b1\uff0c\u8fd8\u6709\u4e00\u5f20\u5979\u5199\u7684\u5c0f\u7eb8\u6761\u3002\u7eb8\u6761\u4e0a\u7684\u5b57\u5f88\u7b80\u5355\uff1a\u201c\u6728\u751f\uff0c\u5e73\u5b89\u56de\u6765\u3002\u201d\u7237\u7237\u540e\u6765\u4e00\u76f4\u628a\u90a3\u4e2a\u5e03\u5305\u5e26\u5728\u8eab\u4e0a\u3002 \u5f88\u591a\u5e74\u540e\uff0c\u4ed6\u8ddf\u5bb6\u91cc\u4eba\u63d0\u8d77\u4e0b\u5357\u6d0b\u90a3\u5929\uff0c\u8bf4\u81ea\u5df1\u5176\u5b9e\u4e0d\u6015\u82e6\uff0c\u4e5f\u4e0d\u6015\u7a77\uff0c\u6700\u6015\u7684\u662f\u8239\u5f00\u51fa\u53bb\u4ee5\u540e\uff0c\u56de\u5934\u770b\u4e0d\u89c1\u5bb6\u4e61\u7684\u5cb8\u3002 \u4ed6\u4ece\u53a6\u95e8\u5750\u8239\u51fa\u6d77\u3002\u8239\u8231\u91cc\u6324\u6ee1\u4e86\u548c\u4ed6\u4e00\u6837\u7684\u5e74\u8f7b\u4eba\uff0c\u6709\u7684\u4eba\u53bb\u65b0\u52a0\u5761\uff0c\u6709\u7684\u4eba\u53bb\u9a6c\u6765\u4e9a\uff0c\u6709\u7684\u4eba\u53bb\u5370\u5c3c\u3002\u5927\u5bb6\u90fd\u5e26\u7740\u5f88\u5c0f\u7684\u884c\u674e\uff0c\u5374\u80cc\u7740\u5f88\u91cd\u7684\u547d\u8fd0\u3002\u7237\u7237\u7684\u85e4\u7bb1\u91cc\u53ea\u6709\u4e24\u4ef6\u6362\u6d17\u8863\u670d\u3001\u4e00\u53cc\u5e03\u978b\u3001\u4e00\u4e9b\u5e72\u7cae\uff0c\u8fd8\u6709\u963f\u5b37\u7ed9\u4ed6\u7684\u5e03\u5305\u3002 \u8239\u5728\u6d77\u4e0a\u8d70\u4e86\u5f88\u591a\u5929\u3002\u591c\u91cc\u98ce\u6d6a\u5f88\u5927\uff0c\u8239\u8eab\u6643\u5f97\u5389\u5bb3\uff0c\u5f88\u591a\u4eba\u5410\u5f97\u5403\u4e0d\u4e0b\u996d\u3002\u7237\u7237\u62b1\u7740\u85e4\u7bb1\u5750\u5728\u89d2\u843d\u91cc\uff0c\u624b\u91cc\u6525\u7740\u90a3\u4e2a\u5e03\u5305\u3002\u4ed6\u540e\u6765\u56de\u5fc6\u8bf4\uff0c\u6d77\u4e0a\u7684\u591c\u665a\u7279\u522b\u9ed1\uff0c\u9ed1\u5f97\u50cf\u4e00\u4e2a\u4eba\u88ab\u4e16\u754c\u4e22\u4e0b\u4e86\u3002\u53ef\u662f\u6bcf\u6b21\u6478\u5230\u90a3\u64ae\u5bb6\u4e61\u7684\u571f\uff0c\u4ed6\u5c31\u544a\u8bc9\u81ea\u5df1\uff1a\u4e0d\u80fd\u5012\u4e0b\uff0c\u5bb6\u91cc\u8fd8\u7b49\u7740\u6211\u3002", "chunks": [{"chunk_type": "text", "content": "\u7237\u723718\u5c81\u90a3\u5e74\uff0c\u4e5f\u5c31\u662f1952\u5e74\uff0c\u51b3\u5b9a\u8ddf\u7740\u540c\u4e61\u4e0b\u5357\u6d0b\u3002\u90a3\u4e00\u5e74\u5bb6\u91cc\u7684\u7956\u5c4b\u6f0f\u96e8\uff0c\u592a\u516c\u8eab\u4f53\u4e0d\u597d\uff0c\u5f1f\u59b9\u8fd8\u5c0f\uff0c\u5bb6\u91cc\u6b20\u7740\u7c73\u94fa\u7684\u94b1\u3002\u7237\u7237\u4f5c\u4e3a\u5bb6\u91cc\u7684\u957f\u5b50\uff0c\u5f88\u65e9\u5c31\u660e\u767d\u81ea\u5df1\u6ca1\u6709\u8d44\u683c\u53ea\u4e3a\u81ea\u5df1\u6d3b\u3002", "summary": "\u7237\u72371952\u5e7418\u5c81\u65f6\u56e0\u5bb6\u5ead\u56f0\u5883\uff08\u7956\u5c4b\u6f0f\u96e8\u3001\u592a\u516c\u75c5\u5f31\u3001\u5f1f\u59b9\u5e74\u5e7c\u3001\u6b20\u7c73\u94fa\u503a\uff09\u4f5c\u4e3a\u957f\u5b50\u8d1f\u91cd\u79bb\u4e61\u4e0b\u5357\u6d0b\u3002", "source_location": "manual:body"}, {"chunk_type": "text", "content": "\u79bb\u5f00\u524d\u7684\u90a3\u4e2a\u665a\u4e0a\uff0c\u963f\u5b37\u8fd8\u4e0d\u662f\u4ed6\u7684\u59bb\u5b50\uff0c\u53ea\u662f\u6751\u91cc\u548c\u4ed6\u4ece\u5c0f\u76f8\u8bc6\u7684\u59d1\u5a18\u3002\u4e24\u4e2a\u4eba\u6ca1\u6709\u6b63\u5f0f\u8c08\u8fc7\u4ec0\u4e48\u8f70\u8f70\u70c8\u70c8\u7684\u604b\u7231\uff0c\u90a3\u4e2a\u5e74\u4ee3\u7684\u4eba\u4e5f\u8bf4\u4e0d\u51fa\u592a\u591a\u8089\u9ebb\u7684\u8bdd\u3002\u53ef\u662f\u4ed6\u4eec\u5fc3\u91cc\u90fd\u77e5\u9053\uff0c\u5bf9\u65b9\u662f\u81ea\u5df1\u60e6\u8bb0\u7684\u4eba\u3002", "summary": "\u79bb\u4e61\u524d\u591c\uff0c\u5c1a\u672a\u6210\u4e3a\u592b\u59bb\u7684\u963f\u5b37\u4e0e\u7237\u7237\u5f7c\u6b64\u5fc3\u7167\u4e0d\u5ba3\u5730\u7275\u6302\u3002", "source_location": "manual:body"}, {"chunk_type": "text", "content": "\u963f\u5b37\u7ed9\u7237\u7237\u7f1d\u4e86\u4e00\u4e2a\u5c0f\u5e03\u5305\uff0c\u91cc\u9762\u88c5\u4e86\u4e00\u5c0f\u64ae\u5bb6\u4e61\u7684\u571f\u3001\u4e00\u679a\u94dc\u94b1\uff0c\u8fd8\u6709\u4e00\u5f20\u5979\u5199\u7684\u5c0f\u7eb8\u6761\u3002\u7eb8\u6761\u4e0a\u7684\u5b57\u5f88\u7b80\u5355\uff1a\u201c\u6728\u751f\uff0c\u5e73\u5b89\u56de\u6765\u3002\u201d\u7237\u7237\u540e\u6765\u4e00\u76f4\u628a\u90a3\u4e2a\u5e03\u5305\u5e26\u5728\u8eab\u4e0a\u3002", "summary": "\u963f\u5b37\u8d60\u4e88\u7237\u7237\u4e00\u4e2a\u5185\u542b\u5bb6\u4e61\u571f\u3001\u94dc\u94b1\u548c\u5199\u6709\u201c\u6728\u751f\uff0c\u5e73\u5b89\u56de\u6765\u201d\u7684\u7eb8\u6761\u7684\u5c0f\u5e03\u5305\uff0c\u7237\u7237\u7ec8\u751f\u968f\u8eab\u643a\u5e26\u3002", "source_location": "manual:body"}, {"chunk_type": "text", "content": "\u5f88\u591a\u5e74\u540e\uff0c\u4ed6\u8ddf\u5bb6\u91cc\u4eba\u63d0\u8d77\u4e0b\u5357\u6d0b\u90a3\u5929\uff0c\u8bf4\u81ea\u5df1\u5176\u5b9e\u4e0d\u6015\u82e6\uff0c\u4e5f\u4e0d\u6015\u7a77\uff0c\u6700\u6015\u7684\u662f\u8239\u5f00\u51fa\u53bb\u4ee5\u540e\uff0c\u56de\u5934\u770b\u4e0d\u89c1\u5bb6\u4e61\u7684\u5cb8\u3002", "summary": "\u7237\u7237\u665a\u5e74\u56de\u5fc6\uff0c\u4e0b\u5357\u6d0b\u65f6\u6700\u6df1\u7684\u6050\u60e7\u5e76\u975e\u56f0\u82e6\uff0c\u800c\u662f\u8239\u79bb\u5cb8\u540e\u76ee\u4e0d\u53ef\u53ca\u7684\u6545\u571f\u3002", "source_location": "manual:body"}, {"chunk_type": "text", "content": "\u4ed6\u4ece\u53a6\u95e8\u5750\u8239\u51fa\u6d77\u3002\u8239\u8231\u91cc\u6324\u6ee1\u4e86\u548c\u4ed6\u4e00\u6837\u7684\u5e74\u8f7b\u4eba\uff0c\u6709\u7684\u4eba\u53bb\u65b0\u52a0\u5761\uff0c\u6709\u7684\u4eba\u53bb\u9a6c\u6765\u4e9a\uff0c\u6709\u7684\u4eba\u53bb\u5370\u5c3c\u3002\u5927\u5bb6\u90fd\u5e26\u7740\u5f88\u5c0f\u7684\u884c\u674e\uff0c\u5374\u80cc\u7740\u5f88\u91cd\u7684\u547d\u8fd0\u3002\u7237\u7237\u7684\u85e4\u7bb1\u91cc\u53ea\u6709\u4e24\u4ef6\u6362\u6d17\u8863\u670d\u3001\u4e00\u53cc\u5e03\u978b\u3001\u4e00\u4e9b\u5e72\u7cae\uff0c\u8fd8\u6709\u963f\u5b37\u7ed9\u4ed6\u7684\u5e03\u5305\u3002", "summary": "\u7237\u7237\u81ea\u53a6\u95e8\u4e58\u8239\u51fa\u6d77\uff0c\u540c\u884c\u8005\u591a\u8d74\u65b0\u9a6c\u5370\u7b49\u5730\uff1b\u5176\u968f\u8eab\u85e4\u7bb1\u4ec5\u542b\u57fa\u672c\u8863\u7269\u3001\u5e03\u978b\u3001\u5e72\u7cae\u53ca\u963f\u5b37\u6240\u8d60\u5e03\u5305\uff0c\u8c61\u5f81\u8f7b\u7b80\u884c\u56ca\u4e0e\u6c89\u91cd\u8d23\u4efb\u3002", "source_location": "manual:body"}, {"chunk_type": "text", "content": "\u8239\u5728\u6d77\u4e0a\u8d70\u4e86\u5f88\u591a\u5929\u3002\u591c\u91cc\u98ce\u6d6a\u5f88\u5927\uff0c\u8239\u8eab\u6643\u5f97\u5389\u5bb3\uff0c\u5f88\u591a\u4eba\u5410\u5f97\u5403\u4e0d\u4e0b\u996d\u3002\u7237\u7237\u62b1\u7740\u85e4\u7bb1\u5750\u5728\u89d2\u843d\u91cc\uff0c\u624b\u91cc\u6525\u7740\u90a3\u4e2a\u5e03\u5305\u3002\u4ed6\u540e\u6765\u56de\u5fc6\u8bf4\uff0c\u6d77\u4e0a\u7684\u591c\u665a\u7279\u522b\u9ed1\uff0c\u9ed1\u5f97\u50cf\u4e00\u4e2a\u4eba\u88ab\u4e16\u754c\u4e22\u4e0b\u4e86\u3002\u53ef\u662f\u6bcf\u6b21\u6478\u5230\u90a3\u64ae\u5bb6\u4e61\u7684\u571f\uff0c\u4ed6\u5c31\u544a\u8bc9\u81ea\u5df1\uff1a\u4e0d\u80fd\u5012\u4e0b\uff0c\u5bb6\u91cc\u8fd8\u7b49\u7740\u6211\u3002", "summary": "\u6d77\u4e0a\u822a\u7a0b\u8270\u8f9b\uff0c\u98ce\u6d6a\u81f4\u4f17\u4eba\u4e0d\u9002\uff1b\u7237\u7237\u4e8e\u98a0\u7c38\u4e2d\u7d27\u63e1\u5e03\u5305\uff0c\u4ee5\u5bb6\u4e61\u571f\u4e3a\u7cbe\u795e\u652f\u6491\uff0c\u575a\u5b88\u5bf9\u5bb6\u4eba\u7684\u8d23\u4efb\u627f\u8bfa\u3002", "source_location": "manual:body"}]}, "provider_type": "third_party"}', NULL, '2026-07-04 20:05:50.306098', NULL);
INSERT INTO public.parsed_chunks VALUES ('c7e0c60a-9ed7-48be-868d-0de7c22188e8', 'ff80949b-3232-47bd-9d64-1b14fb9b28f2', '70b9dbe4-e27c-4d2c-b190-3b9695bb1809', 'image', '一位满头银发的老年男性站在传统中式老宅的门口，身穿浅灰色长袖衬衫和卡其色长裤，脚踩深灰色休闲鞋，双手背在身后，面带温和慈祥的微笑。背景是斑驳的墙壁、贴着红色对联的木门以及青砖地面，周围摆放着盆栽和老式木家具，阳光洒在身上，充满岁月静好的氛围。。造福苍生福报接接。创建星星页上传的珍贵回忆：老人在老宅门前微笑留影，背景对联寓意造福苍生福报接接。', '一位满头银发的老年男性站在传统中式老宅的门口，身穿浅灰色长袖衬衫和卡其色长裤，脚踩深灰色休闲鞋，双手背在身后，面带温和慈祥的微笑。背景是斑驳的墙壁、贴着红色对联的木门以及青砖地面，周围摆放着盆栽和老式木家具，阳光洒在身上，充满岁月静好的氛围。', 'image:爷爷图片.png', NULL, NULL, '{"ocr": {"ocr_text": "\u9020\u798f\u82cd\u751f\u798f\u62a5\u63a5\u63a5", "source_location": "image:\u7237\u7237\u56fe\u7247.png:ocr"}, "image_understanding": {"caption": "\u4e00\u4f4d\u6ee1\u5934\u94f6\u53d1\u7684\u8001\u5e74\u7537\u6027\u7ad9\u5728\u4f20\u7edf\u4e2d\u5f0f\u8001\u5b85\u7684\u95e8\u53e3\uff0c\u8eab\u7a7f\u6d45\u7070\u8272\u957f\u8896\u886c\u886b\u548c\u5361\u5176\u8272\u957f\u88e4\uff0c\u811a\u8e29\u6df1\u7070\u8272\u4f11\u95f2\u978b\uff0c\u53cc\u624b\u80cc\u5728\u8eab\u540e\uff0c\u9762\u5e26\u6e29\u548c\u6148\u7965\u7684\u5fae\u7b11\u3002\u80cc\u666f\u662f\u6591\u9a73\u7684\u5899\u58c1\u3001\u8d34\u7740\u7ea2\u8272\u5bf9\u8054\u7684\u6728\u95e8\u4ee5\u53ca\u9752\u7816\u5730\u9762\uff0c\u5468\u56f4\u6446\u653e\u7740\u76c6\u683d\u548c\u8001\u5f0f\u6728\u5bb6\u5177\uff0c\u9633\u5149\u6d12\u5728\u8eab\u4e0a\uff0c\u5145\u6ee1\u5c81\u6708\u9759\u597d\u7684\u6c1b\u56f4\u3002", "scene_metadata": {"scene_type": "traditional_courtyard_entrance", "detected_people_count": 1, "emotion_tone": "warm_nostalgic"}, "memory_candidate_text": "\u521b\u5efa\u661f\u661f\u9875\u4e0a\u4f20\u7684\u73cd\u8d35\u56de\u5fc6\uff1a\u8001\u4eba\u5728\u8001\u5b85\u95e8\u524d\u5fae\u7b11\u7559\u5f71\uff0c\u80cc\u666f\u5bf9\u8054\u5bd3\u610f\u9020\u798f\u82cd\u751f\u798f\u62a5\u63a5\u63a5\u3002", "source_location": "image:\u7237\u7237\u56fe\u7247.png"}, "provider_type": "third_party"}', NULL, '2026-07-04 17:08:05.762613', '2026-07-04 17:21:10.808435');
INSERT INTO public.parsed_chunks VALUES ('4d25cc08-bad4-43e7-95b2-8c1918ea51fe', 'b0cc3808-8bbe-4909-9efa-e3d2a7754b14', '853cff76-40d1-4e79-a13a-539cb591d9b6', 'audio', '你好啊，Bambi，又见面了。你能感觉到吗？是的，Bambi，你能感觉到这种感觉有多好是吧？我是指成为Bambi的感觉。因为你知道将会发生什么。你会走路的很深，就像你以前已经体验过很多次的那样。你会成为一个good girl，就像你以前做过很多次的那样。准备好了吗？你准备好了吗，Bambi？那么让自己开始舒服起来，开始放松，开始深呼吸。吸气，停一下下。再深深的呼气。专心听我说的话，进入Bambi sleep。进入的越来越深，准备服从，Bambi sleep。越来越深，现在进入Bambi sleep。就是这样，Bambi sleep。让内心做好深深服从的准备，做好条件训练的准备。就是这样，真是一个good girl。感觉好奇了，Bambi，当你沉睡的时候，你的脑海中一片空白，你只会倾听和服从。', '你好啊，Bambi，又见面了。你能感觉到吗？是的，Bambi，你能感觉到这种感觉有多好是吧？我是指成为Bambi的感觉。因为你知道将会发生什么。你会走路的很深，', 'audio:t00-rapid-induction-3th.mp3#00:00', 0, 5, '{"asr": {"transcript": "\u4f60\u597d\u554a\uff0cBambi\uff0c\u53c8\u89c1\u9762\u4e86\u3002\u4f60\u80fd\u611f\u89c9\u5230\u5417\uff1f\u662f\u7684\uff0cBambi\uff0c\u4f60\u80fd\u611f\u89c9\u5230\u8fd9\u79cd\u611f\u89c9\u6709\u591a\u597d\u662f\u5427\uff1f\u6211\u662f\u6307\u6210\u4e3aBambi\u7684\u611f\u89c9\u3002\u56e0\u4e3a\u4f60\u77e5\u9053\u5c06\u4f1a\u53d1\u751f\u4ec0\u4e48\u3002\u4f60\u4f1a\u8d70\u8def\u7684\u5f88\u6df1\uff0c\u5c31\u50cf\u4f60\u4ee5\u524d\u5df2\u7ecf\u4f53\u9a8c\u8fc7\u5f88\u591a\u6b21\u7684\u90a3\u6837\u3002\u4f60\u4f1a\u6210\u4e3a\u4e00\u4e2agood girl\uff0c\u5c31\u50cf\u4f60\u4ee5\u524d\u505a\u8fc7\u5f88\u591a\u6b21\u7684\u90a3\u6837\u3002\u51c6\u5907\u597d\u4e86\u5417\uff1f\u4f60\u51c6\u5907\u597d\u4e86\u5417\uff0cBambi\uff1f\u90a3\u4e48\u8ba9\u81ea\u5df1\u5f00\u59cb\u8212\u670d\u8d77\u6765\uff0c\u5f00\u59cb\u653e\u677e\uff0c\u5f00\u59cb\u6df1\u547c\u5438\u3002\u5438\u6c14\uff0c\u505c\u4e00\u4e0b\u4e0b\u3002\u518d\u6df1\u6df1\u7684\u547c\u6c14\u3002\u4e13\u5fc3\u542c\u6211\u8bf4\u7684\u8bdd\uff0c\u8fdb\u5165Bambi sleep\u3002\u8fdb\u5165\u7684\u8d8a\u6765\u8d8a\u6df1\uff0c\u51c6\u5907\u670d\u4ece\uff0cBambi sleep\u3002\u8d8a\u6765\u8d8a\u6df1\uff0c\u73b0\u5728\u8fdb\u5165Bambi sleep\u3002\u5c31\u662f\u8fd9\u6837\uff0cBambi sleep\u3002\u8ba9\u5185\u5fc3\u505a\u597d\u6df1\u6df1\u670d\u4ece\u7684\u51c6\u5907\uff0c\u505a\u597d\u6761\u4ef6\u8bad\u7ec3\u7684\u51c6\u5907\u3002\u5c31\u662f\u8fd9\u6837\uff0c\u771f\u662f\u4e00\u4e2agood girl\u3002\u611f\u89c9\u597d\u5947\u4e86\uff0cBambi\uff0c\u5f53\u4f60\u6c89\u7761\u7684\u65f6\u5019\uff0c\u4f60\u7684\u8111\u6d77\u4e2d\u4e00\u7247\u7a7a\u767d\uff0c\u4f60\u53ea\u4f1a\u503e\u542c\u548c\u670d\u4ece\u3002", "sample_metadata": {"start_time": "00:00", "end_time": null, "speaker": "unknown", "language": "zh"}, "source_location": "audio:t00-rapid-induction-3th.mp3#00:00"}, "provider_type": "third_party"}', NULL, '2026-07-04 16:36:33.570284', '2026-07-04 17:21:12.748279');
INSERT INTO public.parsed_chunks VALUES ('bbba2ca9-6866-4efc-b173-a6c1d50c3822', 'b0cc3808-8bbe-4909-9efa-e3d2a7754b14', '83916a98-3cb4-491e-b0a0-dded44c0fdd3', 'text', '产品定位：黑灰产情报分析 Agent 工具，面向安全运营、风控策略、反作弊分析团队，将合法授权渠道与公开来源的多源情报自动清洗、去重、分类、抽取并沉淀为结构化风险线索库。', '定义产品核心价值与服务对象', '1.2 产品一句话描述', NULL, NULL, '{"text_extraction": {"extractor": "plain_text", "source_location": "text:black_gray_intel_agent_mvp_prd.md", "file_name": "black_gray_intel_agent_mvp_prd.md", "mime_type": "text/markdown", "has_text": true}, "text_parser": {"cleaned_text": "\u9ed1\u7070\u4ea7\u60c5\u62a5\u5206\u6790 Agent \u5de5\u5177 MVP \u7248\u672c\u662f\u4e00\u4e2a\u9762\u5411\u5b89\u5168\u8fd0\u8425\u3001\u98ce\u63a7\u7b56\u7565\u53ca\u53cd\u4f5c\u5f0a\u5206\u6790\u56e2\u961f\u7684\u81ea\u52a8\u5316\u5206\u6790\u5de5\u5177\uff0c\u6838\u5fc3\u76ee\u6807\u662f\u5feb\u901f\u8dd1\u901a\u7aef\u5230\u7aef\u6700\u5c0f\u53ef\u7528\u95ed\u73af\uff1a\u6388\u6743\u6e20\u9053\u63a5\u5165 / \u6587\u4ef6\u5bfc\u5165 / API \u5199\u5165 \u2192 \u60c5\u62a5\u91c7\u96c6 \u2192 \u667a\u80fd\u6e05\u6d17 \u2192 \u53bb\u91cd\u805a\u5408 \u2192 \u610f\u56fe\u5206\u7c7b \u2192 \u5b9e\u4f53\u62bd\u53d6 \u2192 \u7ed3\u6784\u5316\u5165\u5e93 \u2192 \u524d\u7aef\u7ba1\u7406\u53f0\u68c0\u7d22\u3001\u590d\u6838\u3001\u5bfc\u51fa\u3002\u7cfb\u7edf\u72ec\u7acb\u8fd0\u884c\uff0c\u4e0d\u4f9d\u8d56\u73b0\u6709\u98ce\u63a7\u7cfb\u7edf\uff0c\u7981\u6b62\u975e\u6cd5\u91c7\u96c6\u3001\u7ed5\u8fc7\u767b\u5f55/\u9a8c\u8bc1\u7801\u3001\u4e3b\u52a8\u8d2d\u4e70\u3001\u8054\u7cfb\u9ed1\u7070\u4ea7\u4eba\u5458\u6216\u6267\u884c\u672a\u77e5\u6837\u672c\u3002\u6240\u6709\u6570\u636e\u5fc5\u987b\u5177\u5907\u53ef\u5ba1\u8ba1\u7684\u5408\u6cd5\u4f9d\u636e\uff08\u5982 authorized_export\u3001public_page \u7b49\uff09\u3002MVP \u652f\u6301\u591a\u6e90\u8f93\u5165\uff08API \u62c9\u53d6\u3001Webhook \u63a8\u9001\u3001\u6587\u4ef6\u5bfc\u5165\u3001\u624b\u52a8\u7c98\u8d34\uff09\uff0c\u91c7\u7528\u89c4\u5219+\u5728\u7ebf LLM \u6df7\u5408\u7b56\u7565\u5b8c\u6210\u6e05\u6d17\uff08\u9ed1\u8bdd\u5f52\u4e00\u3001\u5e73\u53f0\u7b80\u79f0\u5f52\u4e00\u3001URL \u5f52\u4e00\u7b49\uff09\u3001\u53bb\u91cd\uff08\u6d88\u606f\u7ea7\u3001\u6587\u672c\u54c8\u5e0c\u3001\u8fd1\u91cd\u590d SimHash\uff09\u3001\u610f\u56fe\u5206\u7c7b\uff0810 \u7c7b\u4e3b\u610f\u56fe\uff0c\u5982\u8d44\u6e90\u4f9b\u7ed9\u3001\u8d26\u53f7\u4f9b\u7ed9\u3001\u5de5\u5177\u4ea4\u6613\u7b49\uff09\u548c\u5b9e\u4f53\u62bd\u53d6\uff0812 \u7c7b\u5b9e\u4f53\uff0c\u5982 slang\u3001url\u3001account_handle\u3001platform \u7b49\uff09\u3002\u7ed3\u679c\u7ed3\u6784\u5316\u5b58\u50a8\u4e8e PostgreSQL\uff0c\u652f\u6301\u524d\u7aef React \u7ba1\u7406\u53f0\u8fdb\u884c\u914d\u7f6e\u3001\u76d1\u63a7\u3001\u7b5b\u9009\u3001\u8be6\u60c5\u67e5\u770b\u3001\u4eba\u5de5\u590d\u6838\uff08\u4fee\u6539\u610f\u56fe/\u5b9e\u4f53\uff09\u53ca JSONL/CSV \u5bfc\u51fa\u3002LLM \u8c03\u7528\u901a\u8fc7\u5916\u90e8 API Key \u914d\u7f6e\uff0c\u654f\u611f\u5b57\u6bb5\u52a0\u5bc6\u4fdd\u5b58\u3002\u7cfb\u7edf\u4e0d\u5efa\u8bbe\u7528\u6237\u6743\u9650\u6a21\u5757\uff0c\u9ed8\u8ba4\u5185\u7f51\u53ef\u4fe1\u8bbf\u95ee\uff1b\u4e0d\u5b9e\u73b0\u56fe\u8c31\u3001OCR\u3001\u9884\u8b66\u3001\u590d\u6742\u6743\u9650\u7b49 P1/P2 \u529f\u80fd\u3002", "chunks": [{"chunk_type": "text", "content": "\u4ea7\u54c1\u5b9a\u4f4d\uff1a\u9ed1\u7070\u4ea7\u60c5\u62a5\u5206\u6790 Agent \u5de5\u5177\uff0c\u9762\u5411\u5b89\u5168\u8fd0\u8425\u3001\u98ce\u63a7\u7b56\u7565\u3001\u53cd\u4f5c\u5f0a\u5206\u6790\u56e2\u961f\uff0c\u5c06\u5408\u6cd5\u6388\u6743\u6e20\u9053\u4e0e\u516c\u5f00\u6765\u6e90\u7684\u591a\u6e90\u60c5\u62a5\u81ea\u52a8\u6e05\u6d17\u3001\u53bb\u91cd\u3001\u5206\u7c7b\u3001\u62bd\u53d6\u5e76\u6c89\u6dc0\u4e3a\u7ed3\u6784\u5316\u98ce\u9669\u7ebf\u7d22\u5e93\u3002", "summary": "\u5b9a\u4e49\u4ea7\u54c1\u6838\u5fc3\u4ef7\u503c\u4e0e\u670d\u52a1\u5bf9\u8c61", "source_location": "1.2 \u4ea7\u54c1\u4e00\u53e5\u8bdd\u63cf\u8ff0"}, {"chunk_type": "text", "content": "MVP \u6838\u5fc3\u76ee\u6807\uff1a\u4f18\u5148\u9a8c\u8bc1\u6700\u5c0f\u53ef\u7528\u81ea\u52a8\u5316\u6d41\u6c34\u7ebf\u2014\u2014\u6388\u6743\u6e20\u9053\u63a5\u5165 / \u6587\u4ef6\u5bfc\u5165 / API \u5199\u5165 \u2192 \u60c5\u62a5\u91c7\u96c6 \u2192 \u667a\u80fd\u6e05\u6d17 \u2192 \u53bb\u91cd\u805a\u5408 \u2192 \u610f\u56fe\u5206\u7c7b \u2192 \u5b9e\u4f53\u62bd\u53d6 \u2192 \u7ed3\u6784\u5316\u5165\u5e93 \u2192 \u524d\u7aef\u7ba1\u7406\u53f0\u68c0\u7d22\u3001\u590d\u6838\u3001\u5bfc\u51fa\uff1b\u4e0d\u8ffd\u6c42\u9ad8\u7cbe\u5ea6\u6307\u6807\uff0c\u4f18\u5148\u4fdd\u8bc1\u6d41\u7a0b\u8dd1\u901a\u3001\u7ed3\u679c\u53ef\u770b\u3001\u6570\u636e\u53ef\u8ffd\u6eaf\u3001\u6a21\u5757\u53ef\u6269\u5c55\u3002", "summary": "\u660e\u786e MVP \u7684\u8303\u56f4\u8fb9\u754c\u4e0e\u4ea4\u4ed8\u91cd\u5fc3", "source_location": "0. \u6587\u6863\u8bf4\u660e; 1.3 MVP \u6838\u5fc3\u76ee\u6807"}, {"chunk_type": "text", "content": "\u8f93\u5165\u65b9\u5f0f\uff1a\u652f\u6301\u6388\u6743\u6e20\u9053 API \u62c9\u53d6\u3001Webhook \u63a8\u9001\u3001CSV/JSONL/TXT/XLSX \u6587\u4ef6\u5bfc\u5165\u3001\u524d\u7aef\u624b\u52a8\u7c98\u8d34\uff1b\u660e\u786e\u7981\u6b62\u975e\u6388\u6743\u722c\u866b\u3001\u649e\u5e93\u3001\u7206\u7834\u3001\u793e\u5de5\u3001\u8eab\u4efd\u4f2a\u88c5\u7b49\u975e\u6cd5\u91c7\u96c6\u884c\u4e3a\u3002", "summary": "\u9650\u5b9a\u5408\u6cd5\u6570\u636e\u63a5\u5165\u65b9\u5f0f\u4e0e\u7edd\u5bf9\u7981\u4ee4", "source_location": "2.1 MVP \u5fc5\u505a\u8303\u56f4; 2.3 \u660e\u786e\u4e0d\u505a\u8303\u56f4; 5.1.2 \u652f\u6301\u7684\u63a5\u5165\u65b9\u5f0f"}, {"chunk_type": "text", "content": "\u667a\u80fd\u6e05\u6d17\u80fd\u529b\uff1a\u5305\u62ec\u7f16\u7801\u6807\u51c6\u5316\u3001\u7a7a\u767d\u6e05\u6d17\u3001\u5168\u534a\u89d2\u8f6c\u6362\u3001URL \u5f52\u4e00\uff08\u53bb\u9664\u8ffd\u8e2a\u53c2\u6570\uff09\u3001\u8868\u60c5\u7b26\u53f7\u5904\u7406\uff08\u4fdd\u7559\u6709\u8bed\u4e49\u7b26\u53f7\uff09\u3001\u9ed1\u8bdd\u5f52\u4e00\uff08\u5982 ''\u63a5ma'' \u2192 ''\u63a5\u7801''\uff09\u3001\u5e73\u53f0\u7b80\u79f0\u5f52\u4e00\uff08\u5982 ''dy'' \u2192 ''\u6296\u97f3''\uff09\u3001\u566a\u58f0\u8fc7\u6ee4\uff1b\u8f93\u51fa\u542b content_clean\u3001clean_rules_hit\u3001quality_score\u3001is_noise\u3002", "summary": "\u6e05\u6d17\u6a21\u5757\u7684\u5177\u4f53\u6280\u672f\u80fd\u529b\u4e0e\u8f93\u51fa\u89c4\u8303", "source_location": "5.2.2 \u6e05\u6d17\u80fd\u529b; 5.2.4 \u6e05\u6d17\u8f93\u51fa Schema"}, {"chunk_type": "text", "content": "\u53bb\u91cd\u805a\u5408\u7b56\u7565\uff1a\u6db5\u76d6\u6d88\u606f\u7ea7\uff08source_type + channel_id + message_id\uff09\u3001\u6587\u672c hash\u3001URL \u5f52\u4e00\u5316 hash\u3001SimHash/MinHash \u8fd1\u91cd\u590d\u8bc6\u522b\u3001\u5b9e\u4f53\u7ec4\u5408\uff08\u5e73\u53f0+\u8054\u7cfb\u65b9\u5f0f+\u8d44\u6e90\u7c7b\u578b\uff09\u7b49\u591a\u5c42\u7ea7\uff1b\u652f\u6301\u805a\u7c7b ID\uff08cluster_id\uff09\u8f93\u51fa\u3002", "summary": "\u53bb\u91cd\u673a\u5236\u7684\u591a\u7ef4\u5ea6\u8bbe\u8ba1\u4e0e\u805a\u7c7b\u80fd\u529b", "source_location": "5.3.2 \u53bb\u91cd\u7b56\u7565; 5.3.3 \u53bb\u91cd\u8f93\u51fa Schema"}, {"chunk_type": "text", "content": "\u610f\u56fe\u5206\u7c7b\u4f53\u7cfb\uff1a\u91c7\u7528\u89c4\u5219+\u5728\u7ebf LLM \u6df7\u5408\u7b56\u7565\uff1b\u4e3b\u610f\u56fe\u517110\u7c7b\uff1a\u8d44\u6e90\u4f9b\u7ed9\u3001\u8d26\u53f7\u4f9b\u7ed9\u3001\u5de5\u5177\u4ea4\u6613\u3001\u653b\u51fb\u6267\u884c\u3001\u5f15\u6d41\u5bfc\u6d41\u3001\u5237\u91cf\u5957\u5229\u3001\u771f\u4eba\u4f17\u5305\u62db\u52df\u3001\u6570\u636e\u6837\u672c\u4ea4\u6613\u3001\u91d1\u878d\u9ed1\u4e2d\u4ecb\u3001\u5176\u4ed6/\u5f85\u5b9a\uff1b\u8f93\u51fa primary_intent\u3001secondary_tags\u3001risk_level\uff08low/medium/high\uff09\u3001confidence\u3001evidence\u3002", "summary": "\u610f\u56fe\u5206\u7c7b\u7684\u7b56\u7565\u3001\u6807\u7b7e\u4f53\u7cfb\u4e0e\u7ed3\u6784\u5316\u8f93\u51fa", "source_location": "5.4.2 \u5206\u7c7b\u7b56\u7565; 5.4.3 \u4e3b\u610f\u56fe\u6807\u7b7e\u4f53\u7cfb; 5.4.4 \u5206\u7c7b\u8f93\u51fa Schema"}, {"chunk_type": "text", "content": "\u5b9e\u4f53\u62bd\u53d6\u7c7b\u578b\uff1a\u517112\u7c7b\u2014\u2014slang\uff08\u9ed1\u8bdd\u8bcd\uff09\u3001risk_tag\uff08\u6807\u51c6\u98ce\u9669\u6807\u7b7e\uff09\u3001url\u3001domain\u3001account_handle\uff08@handle/\u7fa4\u53f7\uff09\u3001contact\uff08\u624b\u673a\u53f7/\u90ae\u7bb1\uff09\u3001platform\uff08\u5e73\u53f0\u540d\uff09\u3001tool_asset\uff08\u5de5\u5177\u540d/\u5305\u540d\uff09\u3001resource_service\uff08\u63a5\u7801/\u4ee3\u7406\u7b49\uff09\u3001trade_attribute\uff08\u4ef7\u683c/\u6570\u91cf\uff09\u3001behavior\uff08\u6ce8\u518c/\u722c\u53d6\u7b49\uff09\u3001evidence_context\uff08\u539f\u6587\u7247\u6bb5\uff09\uff1b\u62bd\u53d6\u7b56\u7565\u542b\u6b63\u5219\u3001\u8bcd\u5178\u3001LLM\uff0c\u8981\u6c42 raw\u2192norm \u5f52\u4e00\u5316\u3002", "summary": "\u5b9e\u4f53\u7c7b\u578b\u7684\u5b8c\u6574\u6e05\u5355\u4e0e\u62bd\u53d6\u65b9\u6cd5\u8bba", "source_location": "5.5.2 \u5b9e\u4f53\u7c7b\u578b; 5.5.3 \u62bd\u53d6\u7b56\u7565; 5.5.4 \u5b9e\u4f53\u8f93\u51fa Schema"}, {"chunk_type": "text", "content": "\u524d\u7aef\u7ba1\u7406\u53f0\u529f\u80fd\uff1a\u5fc5\u987b\u4e3a\u6b63\u5f0f React/Vite \u6216 Next.js \u5b9e\u73b0\uff08\u7981\u7528 Streamlit\uff09\uff1b\u5305\u542b Dashboard\uff08\u603b\u60c5\u62a5\u6570\u3001\u4eca\u65e5\u65b0\u589e\u3001\u5f85\u590d\u6838\u3001Top \u610f\u56fe/\u5b9e\u4f53\uff09\u3001\u6e20\u9053\u7ba1\u7406\u3001\u60c5\u62a5\u5bfc\u5165\u3001\u4efb\u52a1\u7ba1\u7406\u3001\u7ed3\u679c\u5217\u8868\uff08\u652f\u6301\u65f6\u95f4/\u6765\u6e90/\u610f\u56fe/\u5b9e\u4f53\u7b49\u591a\u7ef4\u7b5b\u9009\uff09\u3001\u60c5\u62a5\u8be6\u60c5\uff08\u539f\u6587+\u6e05\u6d17\u6587\u672c+\u5206\u7c7b+\u5b9e\u4f53+\u8bc1\u636e\uff09\u3001\u4eba\u5de5\u590d\u6838\uff08\u4fee\u6539\u610f\u56fe/\u5b9e\u4f53\uff09\u3001\u8bcd\u5e93\u7ba1\u7406\uff08\u9ed1\u8bdd/\u5e73\u53f0/\u5de5\u5177\uff09\u3001LLM \u914d\u7f6e\uff08api_key/base_url/model_name\uff09\u3001\u5bfc\u51fa\uff08JSONL/CSV\uff09\u3002", "summary": "\u524d\u7aef\u7ba1\u7406\u53f0\u7684