INSERT INTO public.parsed_chunks VALUES ('c1cfd582-241a-42d9-9760-ca7b3887bb8a', '815b4953-6d73-4dd9-9985-af8aa2f83175', '07775a62-1b9e-4dc9-a6fd-e0635d8d7bce', 'manual', '外婆喜欢给小铭包馄饨，也常说饭要趁热慢慢吃。', '外婆为小铭包馄饨，并叮嘱饭要趁热慢慢吃。', 'manual:body', NULL, NULL, '{"text_extraction": {"extractor": "manual", "source_location": "manual:body", "has_text": true}, "text_parser": {"cleaned_text": "\u5916\u5a46\u559c\u6b22\u7ed9\u5c0f\u94ed\u5305\u9984\u9968\uff0c\u4e5f\u5e38\u8bf4\u996d\u8981\u8d81\u70ed\u6162\u6162\u5403\u3002", "chunks": [{"chunk_type": "text", "content": "\u5916\u5a46\u559c\u6b22\u7ed9\u5c0f\u94ed\u5305\u9984\u9968\uff0c\u4e5f\u5e38\u8bf4\u996d\u8981\u8d81\u70ed\u6162\u6162\u5403\u3002", "summary": "\u5916\u5a46\u4e3a\u5c0f\u94ed\u5305\u9984\u9968\uff0c\u5e76\u53ee\u5631\u996d\u8981\u8d81\u70ed\u6162\u6162\u5403\u3002", "source_location": "manual:body"}]}, "provider_type": "third_party"}', NULL, '2026-07-04 19:03:39.117918', NULL);
INSERT INTO public.parsed_chunks VALUES ('ab20c82d-bc83-4290-b484-f0562b85bbba', '18b88e96-5633-4d75-b77a-0ad1988a846a', '884394cb-d3e8-4743-9831-7f51f2d3fd4f', 'manual', '爷爷刚到南洋时，先在码头做苦力。码头的活很重，要扛米袋、搬木箱、卸货。一袋米压在肩上，走几步肩膀就像被刀割一样疼。那时候他年纪小，身子又瘦，常常被老工人嫌弃力气不够。他不争辩，只是咬牙多扛几趟。', '初到南洋在码头做苦力，负重劳作身体不堪，默默坚持。', 'manual:body', NULL, NULL, '{"text_extraction": {"extractor": "manual", "source_location": "manual:body", "has_text": true}, "text_parser": {"cleaned_text": "\u4e09\u3001\u5357\u6d0b\u5c81\u6708\uff1a\u4ed6\u5982\u4f55\u628a\u82e6\u65e5\u5b50\u71ac\u6210\u5bb6\u4eba\u7684\u751f\u8def \u7237\u7237\u521a\u5230\u5357\u6d0b\u65f6\uff0c\u5148\u5728\u7801\u5934\u505a\u82e6\u529b\u3002\u7801\u5934\u7684\u6d3b\u5f88\u91cd\uff0c\u8981\u625b\u7c73\u888b\u3001\u642c\u6728\u7bb1\u3001\u5378\u8d27\u3002\u4e00\u888b\u7c73\u538b\u5728\u80a9\u4e0a\uff0c\u8d70\u51e0\u6b65\u80a9\u8180\u5c31\u50cf\u88ab\u5200\u5272\u4e00\u6837\u75bc\u3002\u90a3\u65f6\u5019\u4ed6\u5e74\u7eaa\u5c0f\uff0c\u8eab\u5b50\u53c8\u7626\uff0c\u5e38\u5e38\u88ab\u8001\u5de5\u4eba\u5acc\u5f03\u529b\u6c14\u4e0d\u591f\u3002\u4ed6\u4e0d\u4e89\u8fa9\uff0c\u53ea\u662f\u54ac\u7259\u591a\u625b\u51e0\u8d9f\u3002 \u540e\u6765\uff0c\u4ed6\u53c8\u8ddf\u7740\u540c\u4e61\u53bb\u4e86\u6a61\u80f6\u56ed\u5272\u80f6\u3002\u6bcf\u5929\u51cc\u6668\u5929\u8fd8\u6ca1\u4eae\u5c31\u8981\u8d77\u6765\uff0c\u80cc\u7740\u5de5\u5177\u8fdb\u6797\u5b50\u3002\u6a61\u80f6\u6797\u91cc\u6e7f\u6c14\u91cd\uff0c\u868a\u866b\u591a\uff0c\u811a\u5e95\u5e38\u5e38\u8e29\u5728\u6ce5\u6c34\u91cc\u3002\u624b\u88ab\u6811\u76ae\u5212\u7834\u662f\u5e38\u4e8b\uff0c\u6c57\u6c34\u6d41\u8fdb\u4f24\u53e3\uff0c\u75bc\u5f97\u94bb\u5fc3\u3002\u4ed6\u6700\u6015\u4e0b\u96e8\uff0c\u56e0\u4e3a\u96e8\u6c34\u4e00\u6765\uff0c\u80f6\u6c34\u5c31\u6536\u4e0d\u6210\uff0c\u4e00\u5929\u7684\u5de5\u94b1\u53ef\u80fd\u5c31\u6ca1\u4e86\u3002 \u53ef\u662f\u7237\u7237\u4ece\u6765\u4e0d\u5728\u5bc4\u56de\u5bb6\u7684\u4fe1\u91cc\u8bf4\u8fd9\u4e9b\u3002\u4ed6\u6015\u5bb6\u91cc\u4eba\u62c5\u5fc3\uff0c\u4e5f\u6015\u963f\u5b37\u5fc3\u75bc\u3002\u4ed6\u5728\u4fe1\u91cc\u5199\u7684\uff0c\u5e38\u5e38\u662f\u4e00\u4e9b\u5f88\u8f7b\u7684\u4e8b\u3002 \u4ed6\u8bf4\u5357\u6d0b\u7684\u6708\u4eae\u548c\u5bb6\u4e61\u4e00\u6837\u5706\u3002 \u4ed6\u8bf4\u8fd9\u91cc\u7684\u6d77\u98ce\u4e5f\u6709\u54b8\u5473\uff0c\u53ea\u662f\u95fb\u8d77\u6765\u4e0d\u50cf\u664b\u6c5f\u7684\u6d77\u3002 \u4ed6\u8bf4\u81ea\u5df1\u5403\u5f97\u9971\uff0c\u4f4f\u5f97\u4e0b\uff0c\u5de5\u53cb\u4e5f\u7167\u987e\u4ed6\u3002 \u4ed6\u8bf4\u7b49\u8d5a\u591f\u94b1\uff0c\u5c31\u56de\u5bb6\u3002 \u771f\u5b9e\u7684\u60c5\u51b5\u662f\uff0c\u4ed6\u5e38\u5e38\u4e00\u7897\u767d\u7ca5\u914d\u4e00\u70b9\u54b8\u83dc\u5c31\u8fc7\u4e00\u5929\u3002\u4ed6\u820d\u4e0d\u5f97\u4e70\u65b0\u8863\u670d\uff0c\u4e5f\u820d\u4e0d\u5f97\u4e70\u836f\u3002\u6709\u4e00\u6b21\u4ed6\u53d1\u9ad8\u70e7\uff0c\u5de5\u53cb\u529d\u4ed6\u4f11\u606f\uff0c\u4ed6\u5374\u575a\u6301\u53bb\u5272\u80f6\uff0c\u56e0\u4e3a\u90a3\u5929\u5982\u679c\u4e0d\u53bb\uff0c\u5c31\u5c11\u4e00\u5929\u5de5\u94b1\u3002\u540e\u6765\u4ed6\u6655\u5012\u5728\u6797\u5b50\u91cc\uff0c\u88ab\u4eba\u80cc\u56de\u5de5\u68da\u3002 \u4ed6\u9192\u6765\u540e\u7b2c\u4e00\u4ef6\u4e8b\uff0c\u4e0d\u662f\u95ee\u81ea\u5df1\u75c5\u5f97\u91cd\u4e0d\u91cd\uff0c\u800c\u662f\u6478\u53e3\u888b\u91cc\u7684\u94b1\u8fd8\u5728\u4e0d\u5728\u3002\u56e0\u4e3a\u90a3\u4e2a\u6708\u7684\u94b1\uff0c\u4ed6\u51c6\u5907\u5bc4\u56de\u5bb6\u91cc\u4fee\u5c4b\u9876\u3002 \u7237\u7237\u6bcf\u4e2a\u6708\u53d1\u4e86\u5de5\u94b1\uff0c\u90fd\u4f1a\u5206\u6210\u4e09\u4efd\uff1a\u4e00\u4efd\u5bc4\u56de\u798f\u5efa\u7ed9\u7236\u6bcd\u548c\u5f1f\u59b9\uff0c\u4e00\u4efd\u6258\u4eba\u5e26\u56de\u53bb\u7ed9\u963f\u5b37\uff0c\u4e00\u4efd\u7559\u7ed9\u81ea\u5df1\u5403\u996d\u3002\u7559\u7ed9\u81ea\u5df1\u7684\u90a3\u4e00\u4efd\uff0c\u6c38\u8fdc\u662f\u6700\u5c11\u7684\u3002 \u4ed6\u4e0d\u662f\u4e0d\u60f3\u8fc7\u597d\u4e00\u70b9\u3002\u4ed6\u53ea\u662f\u89c9\u5f97\uff0c\u81ea\u5df1\u5728\u5916\u9762\u591a\u82e6\u4e00\u70b9\uff0c\u5bb6\u91cc\u4eba\u5c31\u80fd\u5c11\u82e6\u4e00\u70b9\u3002", "chunks": [{"chunk_type": "text", "content": "\u7237\u7237\u521a\u5230\u5357\u6d0b\u65f6\uff0c\u5148\u5728\u7801\u5934\u505a\u82e6\u529b\u3002\u7801\u5934\u7684\u6d3b\u5f88\u91cd\uff0c\u8981\u625b\u7c73\u888b\u3001\u642c\u6728\u7bb1\u3001\u5378\u8d27\u3002\u4e00\u888b\u7c73\u538b\u5728\u80a9\u4e0a\uff0c\u8d70\u51e0\u6b65\u80a9\u8180\u5c31\u50cf\u88ab\u5200\u5272\u4e00\u6837\u75bc\u3002\u90a3\u65f6\u5019\u4ed6\u5e74\u7eaa\u5c0f\uff0c\u8eab\u5b50\u53c8\u7626\uff0c\u5e38\u5e38\u88ab\u8001\u5de5\u4eba\u5acc\u5f03\u529b\u6c14\u4e0d\u591f\u3002\u4ed6\u4e0d\u4e89\u8fa9\uff0c\u53ea\u662f\u54ac\u7259\u591a\u625b\u51e0\u8d9f\u3002", "summary": "\u521d\u5230\u5357\u6d0b\u5728\u7801\u5934\u505a\u82e6\u529b\uff0c\u8d1f\u91cd\u52b3\u4f5c\u8eab\u4f53\u4e0d\u582a\uff0c\u9ed8\u9ed8\u575a\u6301\u3002", "source_location": "manual:body"}, {"chunk_type": "text", "content": "\u540e\u6765\uff0c\u4ed6\u53c8\u8ddf\u7740\u540c\u4e61\u53bb\u4e86\u6a61\u80f6\u56ed\u5272\u80f6\u3002\u6bcf\u5929\u51cc\u6668\u5929\u8fd8\u6ca1\u4eae\u5c31\u8981\u8d77\u6765\uff0c\u80cc\u7740\u5de5\u5177\u8fdb\u6797\u5b50\u3002\u6a61\u80f6\u6797\u91cc\u6e7f\u6c14\u91cd\uff0c\u868a\u866b\u591a\uff0c\u811a\u5e95\u5e38\u5e38\u8e29\u5728\u6ce5\u6c34\u91cc\u3002\u624b\u88ab\u6811\u76ae\u5212\u7834\u662f\u5e38\u4e8b\uff0c\u6c57\u6c34\u6d41\u8fdb\u4f24\u53e3\uff0c\u75bc\u5f97\u94bb\u5fc3\u3002\u4ed6\u6700\u6015\u4e0b\u96e8\uff0c\u56e0\u4e3a\u96e8\u6c34\u4e00\u6765\uff0c\u80f6\u6c34\u5c31\u6536\u4e0d\u6210\uff0c\u4e00\u5929\u7684\u5de5\u94b1\u53ef\u80fd\u5c31\u6ca1\u4e86\u3002", "summary": "\u8f6c\u81f3\u6a61\u80f6\u56ed\u5272\u80f6\uff0c\u5de5\u4f5c\u73af\u5883\u6076\u52a3\uff0c\u52b3\u52a8\u5f3a\u5ea6\u5927\uff0c\u6536\u5165\u53d7\u5929\u6c14\u5f71\u54cd\u663e\u8457\u3002", "source_location": "manual:body"}, {"chunk_type": "text", "content": "\u53ef\u662f\u7237\u7237\u4ece\u6765\u4e0d\u5728\u5bc4\u56de\u5bb6\u7684\u4fe1\u91cc\u8bf4\u8fd9\u4e9b\u3002\u4ed6\