INSERT INTO public.parsed_chunks VALUES ('cf8631d7-16ee-4fc2-b0d5-ff84b631d893', '0c233e91-a632-424f-9e04-4cad8da11d74', '5c447a57-eda7-4501-a5dd-f2bbc3f4fbec', 'manual', '外婆常说慢慢来，别急，心里难受的时候先把气喘匀。', '外婆教导遇情绪困扰时先平稳呼吸、放慢节奏。', 'manual:body', NULL, NULL, '{"text_extraction": {"extractor": "manual", "source_location": "manual:body", "has_text": true}, "text_parser": {"cleaned_text": "\u5916\u5a46\u5e38\u8bf4\u6162\u6162\u6765\uff0c\u522b\u6025\uff0c\u5fc3\u91cc\u96be\u53d7\u7684\u65f6\u5019\u5148\u628a\u6c14\u5598\u5300\u3002", "chunks": [{"chunk_type": "text", "content": "\u5916\u5a46\u5e38\u8bf4\u6162\u6162\u6765\uff0c\u522b\u6025\uff0c\u5fc3\u91cc\u96be\u53d7\u7684\u65f6\u5019\u5148\u628a\u6c14\u5598\u5300\u3002", "summary": "\u5916\u5a46\u6559\u5bfc\u9047\u60c5\u7eea\u56f0\u6270\u65f6\u5148\u5e73\u7a33\u547c\u5438\u3001\u653e\u6162\u8282\u594f\u3002", "source_location": "manual:body"}]}, "provider_type": "third_party"}', NULL, '2026-07-04 19:21:07.175619', NULL);
INSERT INTO public.parsed_chunks VALUES ('00701ec5-5208-4a1f-8381-c5bf76140885', '0c233e91-a632-424f-9e04-4cad8da11d74', 'cfd809fd-2afa-4a12-b804-25c56454a835', 'manual', '小铭生日那天，外婆准备了蛋糕和一碗热汤，笑着说只要小铭平安就好。', '外婆在小铭生日时准备蛋糕和热汤，并表达对小铭平安的祝愿。', 'manual:body', NULL, NULL, '{"text_extraction": {"extractor": "manual", "source_location": "manual:body", "has_text": true}, "text_parser": {"cleaned_text": "\u5c0f\u94ed\u751f\u65e5\u90a3\u5929\uff0c\u5916\u5a46\u51c6\u5907\u4e86\u86cb\u7cd5\u548c\u4e00\u7897\u70ed\u6c64\uff0c\u7b11\u7740\u8bf4\u53ea\u8981\u5c0f\u94ed\u5e73\u5b89\u5c31\u597d\u3002", "chunks": [{"chunk_type": "text", "content": "\u5c0f\u94ed\u751f\u65e5\u90a3\u5929\uff0c\u5916\u5a46\u51c6\u5907\u4e86\u86cb\u7cd5\u548c\u4e00\u7897\u70ed\u6c64\uff0c\u7b11\u7740\u8bf4\u53ea\u8981\u5c0f\u94ed\u5e73\u5b89\u5c31\u597d\u3002", "summary": "\u5916\u5a46\u5728\u5c0f\u94ed\u751f\u65e5\u65f6\u51c6\u5907\u86cb\u7cd5\u548c\u70ed\u6c64\uff0c\u5e76\u8868\u8fbe\u5bf9\u5c0f\u94ed\u5e73\u5b89\u7684\u795d\u613f\u3002", "source_location": "manual:body"}]}, "provider_type": "third_party"}', NULL, '2026-07-04 19:21:11.428223', NULL);
INSERT INTO public.parsed_chunks VALUES ('e09e7819-edde-49a9-8a87-e2edeffae596', '18b88e96-5633-4d75-b77a-0ad1988a846a', '464e1cdb-bd1c-4faa-9f97-d345b1e7a890', 'manual', '我对爷爷最大的遗憾，是我懂得太晚。小时候，我一直以为爷爷只是一个普通的、沉默的、节俭的老人。我不懂他为什么总是舍不得开灯，不懂他为什么吃饭时一定要把碗里的米粒刮干净，不懂他为什么总是把新的东西留给别人，自己却用旧的。我甚至觉得他有点固执，有点不近人情。', '叙述童年时期对爷爷的片面认知：将其视为沉默、节俭、固执的普通老人，不理解其行为习惯。', 'manual:body', NULL, NULL, '{"text_extraction": {"extractor": "manual", "source_location": "manual:body", "has_text": true}, "text_parser": {"cleaned_text": "\u6211\u5bf9\u7237\u7237\u6700\u5927\u7684\u9057\u61be\uff0c\u662f\u6211\u61c2\u5f97\u592a\u665a\u3002\u5c0f\u65f6\u5019\uff0c\u6211\u4e00\u76f4\u4ee5\u4e3a\u7237\u7237\u53ea\u662f\u4e00\u4e2a\u666e\u901a\u7684\u3001\u6c89\u9ed8\u7684\u3001\u8282\u4fed\u7684\u8001\u4eba\u3002\u6211\u4e0d\u61c2\u4ed6\u4e3a\u4ec0\u4e48\u603b\u662f\u820d\u4e0d\u5f97\u5f00\u706f\uff0c\u4e0d\u61c2\u4ed6\u4e3a\u4ec0\u4e48\u5403\u996d\u65f6\u4e00\u5b9a\u8981\u628a\u7897\u91cc\u7684\u7c73\u7c92\u522e\u5e72\u51c0\uff0c\u4e0d\u61c2\u4ed6\u4e3a\u4ec0\u4e48\u603b\u662f\u628a\u65b0\u7684\u4e1c\u897f\u7559\u7ed9\u522b\u4eba\uff0c\u81ea\u5df1\u5374\u7528\u65e7\u7684\u3002\u6211\u751a\u81f3\u89c9\u5f97\u4ed6\u6709\u70b9\u56fa\u6267\uff0c\u6709\u70b9\u4e0d\u8fd1\u4eba\u60c5\u3002\u53ef\u662f\u540e\u6765\u6211\u624d\u660e\u767d\uff0c\u4ed6\u4e0d\u662f\u820d\u4e0d\u5f97\u94b1\uff0c\u4ed6\u662f\u4ece\u4e00\u4e2a\u771f\u6b63\u532e\u4e4f\u7684\u5e74\u4ee3\u8d70\u8fc7\u6765\u7684\u4eba\u3002\u4ed6\u5e74\u8f7b\u65f6\u79bb\u5f00\u5bb6\u4e61\uff0c\u5750\u8239\u53bb\u4e00\u4e2a\u5b8c\u5168\u964c\u751f\u7684\u5730\u65b9\uff0c\u7528\u81ea\u5df1\u7684\u8eab\u4f53\u6362\u5de5\u94b1\uff0c\u7528\u4e00\u5c01\u5c01\u5bb6\u4e66\u6491\u8fc7\u60f3\u5bb6\u7684\u591c\u665a\u3002\u4ed6\u4e0d\u662f\u4e0d\u6d6a\u6f2b\uff0c\u4ed6\u53ea\u662f\u90a3\u4e00\u4ee3\u4eba\u7684\u6d6a\u6f2b\u90fd\u85cf\u5728\u884c\u52a8\u91cc\uff0c\u85cf\u5728\u5bc4\u56de\u5bb6\u7684\u94b1\u91cc\uff0c\u85cf\u5728\u201c\u6211\u7b54\u5e94\u8fc7\u4f60\u7684\u201d\u8fd9\u53e5\u8bdd\u91cc\u3002\u6211\u9057\u61be\u6ca1\u6709\u8ba4\u771f\u542c\u4ed6\u8bb2\u4e0b\u5357\u6d0b\u7684\u6545\u4e8b\u3002\u6211\u9057\u61be\u6ca1\u6709\u95ee\u4ed6\u7b2c\u4e00\u6b21\u79bb\u5f00\u5bb6\u4e61\u65f6\uff0c\u5230\u5e95\u6709\u6ca1\u6709\u5bb3\u6015\u3002\u6211\u9057\u61be\u6ca1\u6709\u95ee\u4ed6\u5728\u5357\u6d0b\u6700\u96be\u71ac\u7684\u90a3\u4e2a\u591c\u665a\uff0c\u662f\u600e\u4e48\u6491\u8fc7\u53bb\u7684\u3002\u6211\u9057\u61be\u6ca1\u6709\u95ee\u4ed6\u7ed9\u963f\u5b37\u5199\u7b2c\u4e00\u5c01\u4fe1\u65f6\uff0c\u624b\u6709\u6ca1\u6709\u53d1\u6296\u3002\u6211\u9057\u61be\u6ca1\u6709\u966a\u4ed6\u4e00\u8d77\u628a\u90a3\u4e9b\u53d1\u9ec4\u7684\u4fe1\u4e00\u5c01\u4e00\u5c01\u8bfb\u5b8c\u3002\u6211\u9057\u61be\u6ca1\u6709\u7ed9\u4ed6\u5f55\u4e00\u6bb5\u5b8c\u6574\u7684\u89c6\u9891\uff0c\u8ba9\u4ed6\u4eb2\u53e3\u8bb2\u8bb2\u81ea\u5df1\u7684\u5e74\u8f7b\u65f6\u5019\u3002\u6211\u9057\u61be\u6ca1\u6709\u5728\u4ed6\u8fd8\u542c\u5f97\u6e05\u3001\u8bb0\u5f97\u6e05\u7684\u65f6\u5019\uff0c\u5bf9\u4ed6\u8bf4\u4e00\u53e5\uff1a\u201c\u7237\u7237\uff0c\u4f60\u8fd9\u4e00\u751f\u771f\u7684\u5f88\u4e86\u4e0d\u8d77\u3002\u201d\u8fd8\u6709\u4e00\u4e2a\u5f88\u5177\u4f53\u7684\u9057\u61be\uff0c\u662f\u7237\u7237\u665a\u5e74\u65f6\uff0c\u6211\u603b\u89c9\u5f97\u4ee5\u540e\u8fd8\u6709\u673a\u4f1a\u3002\u6211\u603b\u4ee5\u4e3a\u4e0b\u6b21\u56de\u5bb6\u53ef\u4ee5\u518d\u966a\u4ed6\u5403\u996d\uff0c\u4e0b\u6b21\u8fc7\u5e74\u53ef\u4ee5\u518d\u8ddf\u4ed6\u62cd\u7167\uff0c\u4e0b\u6b21\u6709\u7a7a\u53ef\u4ee5\u518d\u542c\u4ed6\u8bb2\u6545\u4e8b\u3002\u53ef\u4eba\u751f\u6700\u6b8b\u5fcd\u7684\u5730\u65b9\u5c31\u662f\uff0c\u5f88\u591a\u201c\u4e0b\u6b21\u201d\u5e76\u4e0d\u4f1a\u771f\u7684\u6765\u3002\u7b49\u6211\u7ec8\u4e8e\u610f\u8bc6\u5230\u6211\u60f3\u8ba4\u8bc6\u7684\u4e0d\u53ea\u662f\u201c\u7237\u7237\u201d\u8fd9\u4e2a\u8eab\u4efd\uff0c\u800c\u662f\u90d1\u6728\u751f\u8fd9\u4e2a\u4eba\u65f6\uff0c\u4ed6\u5df2\u7ecf\u4e0d\u5728\u4e86\u3002\u6211\u6ca1\u6709\u6765\u5f97\u53ca\u4e86\u89e3\u4ed6\u4f5c\u4e3a\u4e00\u4e2a\u5e74\u8f7b\u4eba\u7684\u6837\u5b50\u3002\u4ed6\u4e5f\u66fe\u5bb3\u6015\uff0c\u4e5f\u66fe\u60f3\u5bb6\uff0c\u4e5f\u66fe\u7231\u8fc7\u4e00\u4e2a\u4eba\u7231\u5230\u613f\u610f\u8de8\u8fc7\u4e00\u7247\u6d77\u3002\u53ef\u662f\u6211\u8ba4\u8bc6\u4ed6\u7684\u65f6\u95f4\u592a\u665a\u4e86\u3002\u6211\u8ba4\u8bc6\u7684\u53ea\u662f\u4e00\u4e2a\u5df2\u7ecf\u8001\u53bb\u7684\u7237\u7237\uff0c\u800c\u4e0d\u662f\u90a3\u4e2a\u5728\u7801\u5934\u625b\u8d27\u3001\u5728\u6a61\u80f6\u6797\u5272\u80f6\u3001\u5728\u7164\u6cb9\u706f\u4e0b\u7ed9\u963f\u5b37\u5199\u4fe1\u7684\u90d1\u6728\u751f\u3002\u8fd9\u5c31\u662f\u6211\u6700\u6df1\u7684\u9057\u61be\uff1a\u6211\u88ab\u4ed6\u7231\u4e86\u5f88\u591a\u5e74\uff0c\u5374\u6ca1\u6709\u6765\u5f97\u53ca\u771f\u6b63\u7406\u89e3\u4ed6\u3002", "chunks": [{"chunk_type": "text", "content": "\u6211\u5bf9\u7237\u7237\u6700\u5927\u7684\u9057\u61be\uff0c\u662f\u6211\u61c2\u5f97\u592a\u665a\u3002\u5c0f\u65f6\u5019\uff0c\u6211\u4e00\u76f4\u4ee5\u4e3a\u7237\u7237\u53ea\u662f\u4e00\u4e2a\u666e\u901a\u7684\u3001\u6c89\u9ed8\u7684\u3001\u8282\u4fed\u7684\u8001\u4eba\u3002\u6211\u4e0d\u61c2\u4ed6\u4e3a\u4ec0\u4e48\u603b\u662f\u820d\u4e0d\u5f97\u5f00\u706f\uff0c\u4e0d\u61c2\u4ed6\u4e3a\u4ec0\u4e48\u5403\u996d\u65f6\u4e00\u5b9a\u8981\u628a\u7897\u91cc\u7684\u7c73\u7c92\u522e\u5e72\u51c0\uff0c\u4e0d\u61c2\u4ed6\u4e3a\u4ec0\u4e48\u603b\u662f\u628a\u65b0\u7684\u4e1c\u897f\u7559\u7ed9\u522b\u4eba\uff0c\u81ea\u5df1\u5374\u7528\u65e7\u7684\u3002\u6211\u751a\u81f3\u89c9\u5f97\u4ed6\u6709\u70b9\u56fa\u6267\uff0c\u6709\u70b9\u4e0d\u8fd1\u4eba\u60c5\u3002", "summary": "\u53d9\u8ff0\u7ae5\u5e74\u65f6\u671f\u5bf9\u7237\u7237\u7684\u7247\u9762\u8ba4\u77e5\uff1a\u5c06\u5176\u89c6\u4e3a\u6c89\u9ed8\u3001\u8282\u4fed\u3001\u56fa\u6267\u7684\u666e\u901a\u8001\u4eba\uff0c\u4e0d\u7406\u89e3\u5176\u884c\u4e3a\u4e60\u60ef\u3002", "source_location": "manual:body"}, {"chunk_type": "text", "content": "\u53ef\u662f\u540e\u6765\u6211\u624d\u660e\u767d\uff0c\u4ed6\u4e0d\u662f\u820d\u4e0d\u5f97\u94b1\uff0c\u4ed6\u662f\u4ece\u4e00\u4e2a\u771f\u6b63\u532e\u4e4f\u7684\u5e74\u4ee3\u8d70\u8fc7\u6765\u7684\u4eba\u3002\u4ed6\u5e74\u8f7b\u65f6\u79bb\u5f00\u5bb6\u4e61\uff0c\u5750\u8239\u53bb\u4e00\u4e2a\u5b8c\u5168\u964c\u751f\u7684\u5730\u65b9\uff0c\u7528\u81ea\u5df1\u7684\u8eab\u4f53\u6362\u5de5\u94b1\uff0c\u7528\u4e00\u5c01\u5c01\u5bb6\u4e66\u6491\u8fc7\u60f3\u5bb6\u7684\u591c\u665a\u3002\u4ed6\u4e0d\u662f\u4e0d\u6d6a\u6f2b\uff0c\u4ed6\u53ea\u662f\u90a3\u4e00\u4ee3\u4eba\u7684\u6d6a\u6f2b\u90fd\u85cf\u5728\u884c\u52a8\u91cc\uff0c\u85cf\u5728\u5bc4\u56de\u5bb6\u7684\u94b1\u91cc\uff0c\u85cf\u5728\u201c\u6211\u7b54\u5e94\u8fc7\u4f60\u7684\u201d\u8fd9\u53e5\u8bdd\u91cc\u3002", "summary": "\u63ed\u793a\u5bf9\u7237\u7237\u7406\u89e3\u7684\u8f6c\u53d8\uff1a\u8ba4\u8bc6\u5230\u5176\u8282\u4fed\u6e90\u4e8e\u532e\u4e4f\u5e74\u4ee3\u7684\u7ecf\u5386\uff1b\u5176\u60c5\u611f\u8868\u8fbe\u5185\u655b\u800c\u52a1\u5b9e\uff0c\u4f53\u73b0\u4e8e\u884c\u52a8\u3001\u6c47\u6b3e\u4e0e\u627f\u8bfa\u3002", "source_location": "manual:body"}, {"chunk_type": "text", "content": "\u6211\u9057\u61be\u6ca1\u6709\u8ba4\u771f\u542c\u4ed6\u8bb2\u4e0b\u5357\u6d0b\u7684\u6545\u4e8b\u3002\u6211\u9057\u61be\u6ca1\u6709\u95ee\u4ed6\u7b2c\u4e00\u6b21\u79bb\u5f00\u5bb6\u4e61\u65f6\uff0c\u5230\u5e95\u6709\u6ca1\u6709\u5bb3\u6015\u3002\u6211\u9057\u61be\u6ca1\u6709\u95ee\u4ed6\u5728\u5357\u6d0b\u6700\u96be\u71ac\u7684\u90a3\u4e2a\u591c\u665a\uff0c\u662f\u600e\u4e48\u6491\u8fc7\u53bb\u7684\u3002\u6211\u9057\u61be\u6ca1\u6709\u95ee\u4ed6\u7ed9\u963f\u5b37\u5199\u7b2c\u4e00\u5c01\u4fe1\u65f6\uff0c\u624b\u6709\u6ca1\u6709\u53d1\u6296\u3002\u6211\u9057\u61be\u6ca1\u6709\u966a\u4ed6\u4e00\u8d77\u628a\u90a3\u4e9b\u53d1\u9ec4\u7684\u4fe1\u4e00\u5c01\u4e00\u5c01\u8bfb\u5b8c\u3002\u6211\u9057\u61be\u6ca1\u6709\u7ed9\u4ed6\u5f55\u4e00\u6bb5\u5b8c\u6574\u7684\u89c6\u9891\uff0c\u8ba9\u4ed6\u4eb2\u53e3\u8bb2\u8bb2\u81ea\u5df1\u7684\u5e74\u8f7b\u65f6\u5019\u3002\u6211\u90