INSERT INTO public.parsed_chunks VALUES ('6972462e-03bc-4d03-8f23-330de1fa9013', '18b88e96-5633-4d75-b77a-0ad1988a846a', 'b393bc2c-b467-4cd0-8655-0a8ad5d861f7', 'image', '一位满头银发的老人站在古朴的老宅木门前，身穿浅灰色长袖衬衫和卡其色长裤，双手背在身后，面带温和慈祥的笑容。门框两侧贴着红色的对联，周围摆放着盆栽、木椅和陶罐，地面铺着石板，阳光洒在身上，画面充满岁月静好的生活气息。。造福苍生福报接接。这是创建星星页上传的珍贵回忆。记录了长辈在老宅前的慈祥身影，背景红联寓意着‘造福苍生福报接接’，愿这份福气与温暖长存。', '一位满头银发的老人站在古朴的老宅木门前，身穿浅灰色长袖衬衫和卡其色长裤，双手背在身后，面带温和慈祥的笑容。门框两侧贴着红色的对联，周围摆放着盆栽、木椅和陶罐，地面铺着石板，阳光洒在身上，画面充满岁月静好的生活气息。', 'image:爷爷图片.png', NULL, NULL, '{"ocr": {"ocr_text": "\u9020\u798f\u82cd\u751f\u798f\u62a5\u63a5\u63a5", "source_location": "image:\u7237\u7237\u56fe\u7247.png:ocr"}, "image_understanding": {"caption": "\u4e00\u4f4d\u6ee1\u5934\u94f6\u53d1\u7684\u8001\u4eba\u7ad9\u5728\u53e4\u6734\u7684\u8001\u5b85\u6728\u95e8\u524d\uff0c\u8eab\u7a7f\u6d45\u7070\u8272\u957f\u8896\u886c\u886b\u548c\u5361\u5176\u8272\u957f\u88e4\uff0c\u53cc\u624b\u80cc\u5728\u8eab\u540e\uff0c\u9762\u5e26\u6e29\u548c\u6148\u7965\u7684\u7b11\u5bb9\u3002\u95e8\u6846\u4e24\u4fa7\u8d34\u7740\u7ea2\u8272\u7684\u5bf9\u8054\uff0c\u5468\u56f4\u6446\u653e\u7740\u76c6\u683d\u3001\u6728\u6905\u548c\u9676\u7f50\uff0c\u5730\u9762\u94fa\u7740\u77f3\u677f\uff0c\u9633\u5149\u6d12\u5728\u8eab\u4e0a\uff0c\u753b\u9762\u5145\u6ee1\u5c81\u6708\u9759\u597d\u7684\u751f\u6d3b\u6c14\u606f\u3002", "scene_metadata": {"scene_type": "\u4f20\u7edf\u6c11\u5c45\u5ead\u9662", "detected_people_count": 1, "emotion_tone": "\u6e29\u99a8\u3001\u6000\u65e7\u3001\u7965\u548c"}, "memory_candidate_text": "\u8fd9\u662f\u521b\u5efa\u661f\u661f\u9875\u4e0a\u4f20\u7684\u73cd\u8d35\u56de\u5fc6\u3002\u8bb0\u5f55\u4e86\u957f\u8f88\u5728\u8001\u5b85\u524d\u7684\u6148\u7965\u8eab\u5f71\uff0c\u80cc\u666f\u7ea2\u8054\u5bd3\u610f\u7740\u2018\u9020\u798f\u82cd\u751f\u798f\u62a5\u63a5\u63a5\u2019\uff0c\u613f\u8fd9\u4efd\u798f\u6c14\u4e0e\u6e29\u6696\u957f\u5b58\u3002", "source_location": "image:\u7237\u7237\u56fe\u7247.png"}, "provider_type": "third_party"}', NULL, '2026-07-04 19:42:01.533242', NULL);
