INSERT INTO public.parsed_chunks VALUES ('780d1f09-389e-4f4c-82ed-afc298aee26c', 'f89b1c7c-7194-4c90-8cba-5fbb6b0aba3f', '4d600fbc-47da-4771-9561-c02af61ceb11', 'image', '一位头发花白的老年男性身穿浅灰色长袖衬衫和卡其色长裤，双手背在身后，面带慈祥的微笑站在传统中式老宅的木门前。背景是斑驳的墙壁和贴着红色对联的门框，门内隐约可见瓦顶和红灯笼，周围摆放着盆栽植物和旧式木椅，阳光洒在身上，氛围宁静祥和。。造福苍生福报接接。造福苍生福报接接', '一位头发花白的老年男性身穿浅灰色长袖衬衫和卡其色长裤，双手背在身后，面带慈祥的微笑站在传统中式老宅的木门前。背景是斑驳的墙壁和贴着红色对联的门框，门内隐约可见瓦顶和红灯笼，周围摆放着盆栽植物和旧式木椅，阳光洒在身上，氛围宁静祥和。', 'image:爷爷图片.png', NULL, NULL, '{"ocr": {"ocr_text": "\u9020\u798f\u82cd\u751f\u798f\u62a5\u63a5\u63a5", "source_location": "image:\u7237\u7237\u56fe\u7247.png:ocr"}, "image_understanding": {"caption": "\u4e00\u4f4d\u5934\u53d1\u82b1\u767d\u7684\u8001\u5e74\u7537\u6027\u8eab\u7a7f\u6d45\u7070\u8272\u957f\u8896\u886c\u886b\u548c\u5361\u5176\u8272\u957f\u88e4\uff0c\u53cc\u624b\u80cc\u5728\u8eab\u540e\uff0c\u9762\u5e26\u6148\u7965\u7684\u5fae\u7b11\u7ad9\u5728\u4f20\u7edf\u4e2d\u5f0f\u8001\u5b85\u7684\u6728\u95e8\u524d\u3002\u80cc\u666f\u662f\u6591\u9a73\u7684\u5899\u58c1\u548c\u8d34\u7740\u7ea2\u8272\u5bf9\u8054\u7684\u95e8\u6846\uff0c\u95e8\u5185\u9690\u7ea6\u53ef\u89c1\u74e6\u9876\u548c\u7ea2\u706f\u7b3c\uff0c\u5468\u56f4\u6446\u653e\u7740\u76c6\u683d\u690d\u7269\u548c\u65e7\u5f0f\u6728\u6905\uff0c\u9633\u5149\u6d12\u5728\u8eab\u4e0a\uff0c\u6c1b\u56f4\u5b81\u9759\u7965\u548c\u3002", "scene_metadata": {"scene_type": "\u4f20\u7edf\u4e2d\u5f0f\u5ead\u9662/\u8001\u5b85\u95e8\u53e3", "detected_people_count": 1, "emotion_tone": "\u6148\u7965\u3001\u5feb\u4e50\u3001\u5b81\u9759"}, "memory_candidate_text": "\u9020\u798f\u82cd\u751f\u798f\u62a5\u63a5\u63a5", "source_location": "image:\u7237\u7237\u56fe\u7247.png"}, "provider_type": "third_party"}', NULL, '2026-07-04 20:54:03.010432', NULL);
INSERT INTO public.parsed_chunks VALUES ('2495e61f-e1f3-48c0-a961-ea1b82309e97', 'f89b1c7c-7194-4c90-8cba-5fbb6b0aba3f', '6c4c5dcf-dc7c-498b-8ebe-b0bb0d5f3a4b', 'video', '小伟，记得保管好阿妈的情书。。基于您提供的视频帧和音频转写，以下是场景摘要分析： **场景摘要** * **人物**：一位头发花白的老年男性（身穿浅灰色长袖衬衫和卡其色长裤），面容慈祥，双手背在身后。 * **地点**：一处充满岁月痕迹的老式传统民居庭院门口。背景可见斑驳的墙壁、褪色的红对联（春联）、老式木门以及盆栽植物，具有浓厚的生活气息和历史感。 * **事件**：老人站在老宅门前，面带微笑地看着镜头（或看着面前的某人）。结合音频内容，他正在叮嘱一位名叫“小伟”的晚辈，要妥善保管好“阿妈”（母亲）的情书。这似乎是一个关于家族记忆传承或情感寄托的时刻。 * **情绪**：温馨、怀旧、慈爱、平静。老人的笑容传达出一种对往事的怀念和对晚辈的关切，整体氛围略带感伤但充满温情。 * **可引用记忆**：“小伟，记得保管好阿妈的情书。”（这句话揭示了视频的核心叙事线索，关于爱与记忆的传承）。。小伟，记得保管好阿妈的情书。。基于您提供的视频帧和音频转写，以下是场景摘要分析： **场景摘要** * **人物**：一位头发花白的老年男性（身穿浅灰色长袖衬衫和卡其色长裤），面容慈祥，双手背在身后。 * **地点**：一处充满岁月痕迹的老式传统民居庭院门口。背景可见斑驳的墙壁、褪色的红对联（春联）、老式木门以及盆栽植物，具有浓厚的生活气息和历史感。 * **事件**：老人站在老宅门前，面带微笑地看着镜头（或看着面前的某人）。结合音频内容，他正在叮嘱一位名叫“小伟”的晚辈，要妥善保管好“阿妈”（母亲）的情书。这似乎是一个关于家族记忆传承或情感寄托的时刻。 * **情绪**：温馨、怀旧、慈爱、平静。老人的笑容传达出一种对往事的怀念和对晚辈的关切，整体氛围略带感伤但充满温情。 * **可引用记忆**：“小伟，记得保管好阿妈的情书。”（这句话揭示了视频的核心叙事线索，关于爱与记忆的传承）。', '基于您提供的视频帧和音频转写，以下是场景摘要分析： **场景摘要** * **人物**：一位头发花白的老年男性（身穿浅灰色长袖衬衫和卡其色长裤），面容慈祥，双手背在身后。 * **地点**：一处充满岁月痕迹的老式传统民居庭院门口。背景可见斑驳的墙壁、褪色的红对联（春联）、老式木门以及盆栽植物，具有浓厚的生活气息和历史感。 * **事件**：老人站在老宅门前，面带微笑地看着镜头（或看着面前的某人）。结合音频内容，他正在叮嘱一位名叫“小伟”的晚辈，要妥善保管好“阿妈”（母亲）的情书。这似乎是一个关于家族记忆传承或情感寄托的时刻。 * **情绪**：温馨、怀旧、慈爱、平静。老人的笑容传达出一种对往事的怀念和对晚辈的关切，整体氛围略带感伤但充满温情。 * **可引用记忆**：“小伟，记得保管好阿妈的情书。”（这句话揭示了视频的核心叙事线索，关于爱与记忆的传承）。', 'video:爷爷视频.mp4#00:00', 0, 10, '{"video_understanding": {"transcript": "\u5c0f\u4f1f\uff0c\u8bb0\u5f97\u4fdd\u7ba1\u597d\u963f\u5988\u7684\u60c5\u4e66\u3002", "scene_summary": "\u57fa\u4e8e\u60a8\u63d0\u4f9b\u7684\u89c6\u9891\u5e27\u548c\u97f3\u9891\u8f6c\u5199\uff0c\u4ee5\u4e0b\u662f\u573a\u666f\u6458\u8981\u5206\u6790\uff1a **\u573a\u666f\u6458\u8981** * **\u4eba\u7269**\uff1a\u4e00\u4f4d\u5934\u53d1\u82b1\u767d\u7684\u8001\u5e74\u7537\u6027\uff08\u8eab\u7a7f\u6d45\u7070\u8272\u957f\u8896\u886c\u886b\u548c\u5361\u5176\u8272\u957f\u88e4\uff09\uff0c\u9762\u5bb9\u6148\u7965\uff0c\u53cc\u624b\u80cc\u5728\u8eab\u540e\u3002 * **\u5730\u70b9*