INSERT INTO public.parsed_chunks VALUES ('986f3f70-e824-4d8f-a3bc-355a0cb2d4ed', '18b88e96-5633-4d75-b77a-0ad1988a846a', '5b58f0bb-489b-4da3-901c-06a230ec735c', 'manual', '爷爷刚到南洋时，先在码头做苦力。码头的活很重，要扛米袋、搬木箱、卸货。一袋米压在肩上，走几步肩膀就像被刀割一样疼。那时候他年纪小，身子又瘦，常常被老工人嫌弃力气不够。他不争辩，只是咬牙多扛几趟。', '初到南洋，在码头做苦力，负重劳作，体弱受嫌，默默坚持。', 'manual:body', NULL, NULL, '{"text_extraction": {"extractor": "manual", "source_location": "manual:body", "has_text": true}, "text_parser": {"cleaned_text": "\u4e09\u3001\u5357\u6d0b\u5c81\u6708\uff1a\u4ed6\u5982\u4f55\u628a\u82e6\u65e5\u5b50\u71ac\u6210\u5bb6\u4eba\u7684\u751f\u8def \u7237\u7237\u521a\u5230\u5357\u6d0b\u65f6\uff0c\u5148\u5728\u7801\u5934\u505a\u82e6\u529b\u3002\u7801\u5934\u7684\u6d3b\u5f88\u91cd\uff0c\u8981\u625b\u7c73\u888b\u3001\u642c\u6728\u7bb1\u3001\u5378\u8d27\u3002\u4e00\u888b\u7c73\u538b\u5728\u80a9\u4e0a\uff0c\u8d70\u51e0\u6b65\u80a9\u8180\u5c31\u50cf\u88ab\u5200\u5272\u4e00\u6837\u75bc\u3002\u90a3\u65f6\u5019\u4ed6\u5e74\u7eaa\u5c0f\uff0c\u8eab\u5b50\u53c8\u7626\uff0c\u5e38\u5e38\u88ab\u8001\u5de5\u4eba\u5acc\u5f03\u529b\u6c14\u4e0d\u591f\u3002\u4ed6\u4e0d\u4e89\u8fa9\uff0c\u53ea\u662f\u54ac\u7259\u591a\u625b\u51e0\u8d9f\u3002 \u540e\u6765\uff0c\u4ed6\u53c8\u8ddf\u7740\u540c\u4e61\u53bb\u4e86\u6a61\u80f6\u56ed\u5272\u80f6\u3002\u6bcf\u5929\u51cc\u6668\u5929\u8fd8\u6ca1\u4eae\u5c31\u8981\u8d77\u6765\uff0c\u80cc\u7740\u5de5\u5177\u8fdb\u6797\u5b50\u3002\u6a61\u80f6\u6797\u91cc\u6e7f\u6c14\u91cd\uff0c\u868a\u866b\u591a\uff0c\u811a\u5e95\u5e38\u5e38\u8e29\u5728\u6ce5\u6c34\u91cc\u3002\u624b\u88ab\u6811\u76ae\u5212\u7834\u662f\u5e38\u4e8b\uff0c\u6c57\u6c34\u6d41\u8fdb\u4f24\u53e3\uff0c\u75bc\u5f97\u94bb\u5fc3\u3002\u4ed6\u6700\u6015\u4e0b\u96e8\uff0c\u56e0\u4e3a\u96e8\u6c34\u4e00\u6765\uff0c\u80f6\u6c34\u5c31\u6536\u4e0d\u6210\uff0c\u4e00\u5929\u7684\u5de5\u94b1\u53ef\u80fd\u5c31\u6ca1\u4e86\u3002 \u53ef\u662f\u7237\u7237\u4ece\u6765\u4e0d\u5728\u5bc4\u56de\u5bb6\u7684\u4fe1\u91cc\u8bf4\u8fd9\u4e9b\u3002\u4ed6\u6015\u5bb6\u91cc\u4eba\u62c5\u5fc3\uff0c\u4e5f\u6015\u963f\u5b37\u5fc3\u75bc\u3002\u4ed6\u5728\u4fe1\u91cc\u5199\u7684\uff0c\u5e38\u5e38\u662f\u4e00\u4e9b\u5f88\u8f7b\u7684\u4e8b\u3002 \u4ed6\u8bf4\u5357\u6d0b\u7684\u6708\u4eae\u548c\u5bb6\u4e61\u4e00\u6837\u5706\u3002 \u4ed6\u8bf4\u8fd9\u91cc\u7684\u6d77\u98ce\u4e5f\u6709\u54b8\u5473\uff0c\u53ea\u662f\u95fb\u8d77\u6765\u4e0d\u50cf\u664b\u6c5f\u7684\u6d77\u3002 \u4ed6\u8bf4\u81ea\u5df1\u5403\u5f97\u9971\uff0c\u4f4f\u5f97\u4e0b\uff0c\u5de5\u53cb\u4e5f\u7167\u987e\u4ed6\u3002 \u4ed6\u8bf4\u7b49\u8d5a\u591f\u94b1\uff0c\u5c31\u56de\u5bb6\u3002 \u771f\u5b9e\u7684\u60c5\u51b5\u662f\uff0c\u4ed6\u5e38\u5e38\u4e00\u7897\u767d\u7ca5\u914d\u4e00\u70b9\u54b8\u83dc\u5c31\u8fc7\u4e00\u5929\u3002\u4ed6\u820d\u4e0d\u5f97\u4e70\u65b0\u8863\u670d\uff0c\u4e5f\u820d\u4e0d\u5f97\u4e70\u836f\u3002\u6709\u4e00\u6b21\u4ed6\u53d1\u9ad8\u70e7\uff0c\u5de5\u53cb\u529d\u4ed6\u4f11\u606f\uff0c\u4ed6\u5374\u575a\u6301\u53bb\u5272\u80f6\uff0c\u56e0\u4e3a\u90a3\u5929\u5982\u679c\u4e0d\u53bb\uff0c\u5c31\u5c11\u4e00\u5929\u5de5\u94b1\u3002\u540e\u6765\u4ed6\u6655\u5012\u5728\u6797\u5b50\u91cc\uff0c\u88ab\u4eba\u80cc\u56de\u5de5\u68da\u3002 \u4ed6\u9192\u6765\u540e\u7b2c\u4e00\u4ef6\u4e8b\uff0c\u4e0d\u662f\u95ee\u81ea\u5df1\u75c5\u5f97\u91cd\u4e0d\u91cd\uff0c\u800c\u662f\u6478\u53e3\u888b\u91cc\u7684\u94b1\u8fd8\u5728\u4e0d\u5728\u3002\u56e0\u4e3a\u90a3\u4e2a\u6708\u7684\u94b1\uff0c\u4ed6\u51c6\u5907\u5bc4\u56de\u5bb6\u91cc\u4fee\u5c4b\u9876\u3002 \u7237\u7237\u6bcf\u4e2a\u6708\u53d1\u4e86\u5de5\u94b1\uff0c\u90fd\u4f1a\u5206\u6210\u4e09\u4efd\uff1a\u4e00\u4efd\u5bc4\u56de\u798f\u5efa\u7ed9\u7236\u6bcd\u548c\u5f1f\u59b9\uff0c\u4e00\u4efd\u6258\u4eba\u5e26\u56de\u53bb\u7ed9\u963f\u5b37\uff0c\u4e00\u4efd\u7559\u7ed9\u81ea\u5df1\u5403\u996d\u3002\u7559\u7ed9\u81ea\u5df1\u7684\u90a3\u4e00\u4efd\uff0c\u6c38\u8fdc\u662f\u6700\u5c11\u7684\u3002 \u4ed6\u4e0d\u662f\u4e0d\u60f3\u8fc7\u597d\u4e00\u70b9\u3002\u4ed6\u53ea\u662f\u89c9\u5f97\uff0c\u81ea\u5df1\u5728\u5916\u9762\u591a\u82e6\u4e00\u70b9\uff0c\u5bb6\u91cc\u4eba\u5c31\u80fd\u5c11\u82e6\u4e00\u70b9\u3002", "chunks": [{"chunk_type": "text", "content": "\u7237\u7237\u521a\u5230\u5357\u6d0b\u65f6\uff0c\u5148\u5728\u7801\u5934\u505a\u82e6\u529b\u3002\u7801\u5934\u7684\u6d3b\u5f88\u91cd\uff0c\u8981\u625b\u7c73\u888b\u3001\u642c\u6728\u7bb1\u3001\u5378\u8d27\u3002\u4e00\u888b\u7c73\u538b\u5728\u80a9\u4e0a\uff0c\u8d70\u51e0\u6b65\u80a9\u8180\u5c31\u50cf\u88ab\u5200\u5272\u4e00\u6837\u75bc\u3002\u90a3\u65f6\u5019\u4ed6\u5e74\u7eaa\u5c0f\uff0c\u8eab\u5b50\u53c8\u7626\uff0c\u5e38\u5e38\u88ab\u8001\u5de5\u4eba\u5acc\u5f03\u529b\u6c14\u4e0d\u591f\u3002\u4ed6\u4e0d\u4e89\u8fa9\uff0c\u53ea\u662f\u54ac\u7259\u591a\u625b\u51e0\u8d9f\u3002", "summary": "\u521d\u5230\u5357\u6d0b\uff0c\u5728\u7801\u5934\u505a\u82e6\u529b\uff0c\u8d1f\u91cd\u52b3\u4f5c\uff0c\u4f53\u5f31\u53d7\u5acc\uff0c\u9ed8\u9ed8\u575a\u6301\u3002", "source_location": "manual:body"}, {"chunk_type": "text", "content": "\u540e\u6765\uff0c\u4ed6\u53c8\u8ddf\u7740\u540c\u4e61\u53bb\u4e86\u6a61\u80f6\u56ed\u5272\u80f6\u3002\u6bcf\u5929\u51cc\u6668\u5929\u8fd8\u6ca1\u4eae\u5c31\u8981\u8d77\u6765\uff0c\u80cc\u7740\u5de5\u5177\u8fdb\u6797\u5b50\u3002\u6a61\u80f6\u6797\u91cc\u6e7f\u6c14\u91cd\uff0c\u868a\u866b\u591a\uff0c\u811a\u5e95\u5e38\u5e38\u8e29\u5728\u6ce5\u6c34\u91cc\u3002\u624b\u88ab\u6811\u76ae\u5212\u7834\u662f\u5e38\u4e8b\uff0c\u6c57\u6c34\u6d41\u8fdb\u4f24\u53e3\uff0c\u75bc\u5f97\u94bb\u5fc3\u3002\u4ed6\u6700\u6015\u4e0b\u96e8\uff0c\u56e0\u4e3a\u96e8\u6c34\u4e00\u6765\uff0c\u80f6\u6c34\u5c31\u6536\u4e0d\u6210\uff0c\u4e00\u5929\u7684\u5de5\u94b1\u53ef\u80fd\u5c31\u6ca1\u4e86\u3002", "summary": "\u8f6c\u81f3\u6a61\u80f6\u56ed\u5272\u80f6\uff0c\u8d77\u65e9\u8d2a\u9ed1\uff0c\u73af\u5883\u6076\u52a3\uff0c\u53d7\u4f24\u9891\u53d1\uff0c\u6536\u5165\u53d7\u5929\u6c14\u5f71\u54cd\u5927\u3002", "source_location": "manual:body"}, {"chunk_type": "text", "content": "\u53ef\u662f\u7237\u7237\u4ece\u6765\u4e0d\u5728\u5bc4\u56de\u5bb6\u7684\u4fe1\u91cc\u8bf4\u8fd9\u4e9b\u3002\u4ed6\u6015\u5bb6\u91cc\u4eba\u62c5\u5fc3\uff0c\u4e5f\u6015\u963f\u5b37\u5fc3\u75bc\u3002\u4ed6\u5728\u4fe1\u91cc\u5199\u7684\uff0c\u5e38\u5e38\u662f\u4e00\u4e9b\u5f88\u8f7b\u7684\u4e8b\u3002 \u4ed6\u8bf4\u5357\u6d0b\u7684\u6708\u4eae\u548c\u5bb6\u4e61\u4e00\u6837\u5706\u3002 \u4ed6\u8bf4\u8fd9\u91cc\u7684\u6d77\u98ce\u4e5f\u6709\u54b8\u5473\uff0c\u53ea\u662f\u95fb\u8d77\u6765\u4e0d\u50cf\u664b\u6c5f\u7684\u6d77\u3002 \u4ed6\u8bf4\u81ea\u5df1\u5403\u5f97\u9971\uff0c\u4f4f\u5f97\u4e0b\uff0c\u5de5\u53cb\u4e5f\u7167\u987e\u4ed6\u3002 \u4ed6\u8bf4\u7b49\u8d5a\u591f\u94b1\uff0c\u5c31\u56de\u5bb6\u3002", "summary": "\u5411\u5bb6\u4eba\u9690\u7792\u8270\u8f9b\uff0c\u4fe1\u4e2d\u53ea\u62a5\u5e73\u5b89\u4e0e\u6e29\u60c5\uff0c\u5f3a\u8c03\u6708\u5706\u3001\u6d77\u98ce\u3001\u6e29\u9971\u3001\u5f52\u671f\u7b49\u6170\u85c9\u6027\u5185\u5bb9\u3002", "source_location": "manual:body"}, {"chunk_type": "text", "content": "\u771f\u5b9e\u7684\u60c5\u51b5\u662f\uff0c\u4ed6\u5e38\u5e38\u4e00\u7897\u767d\u7ca5\u914d\u4e00\u70b9\u54b8\u83dc\u5c31\u8fc7\u4e00\u5929\u3002\u4ed6\u820d\u4e0d\u5f97\u4e70\u65b0\u8863\u670d\uff0c\u4e5f\u820d\u4e0d\u5f97\u4e70\u836f\u3002\u6709\u4e00\u6b21\u4ed6\u53d1\u9ad8\u70e7\uff0c\u5de5\u53cb\u529d\u4ed6\u4f11\u606f\uff0c\u4ed6\u5374\u575a\u6301\u53bb\u5272\u80f6\uff0c\u56e0\u4e3a\u90a3\u5929\u5982\u679c\u4e0d\u53bb\uff0c\u5c31\u5c11\u4e00\u5929\u5de5\u94b1\u3002\u540e\u6765\u4ed6\u6655\u5012\u5728\u6797\u5b50\u91cc\uff0c\u88ab\u4eba\u80cc\u56de\u5de5\u68da\u3002 \u4ed6\u9192\u6765\u540e\u7b2c\u4e00\u4ef6\u4e8b\uff0c\u4e0d\u662f\u95ee\u81ea\u5df1\u75c5\u5f97\u91cd\u4e0d\u91cd\uff0c\u800c\u662f\u6478\u53e3\u888b\u91cc\u7684\u94b1\u8fd8\u5728\u4e0d\u5728\u3002\u56e0\u4e3a\u90a3\u4e2a\u6708\u7684\u94b1\uff0c\u4ed6\u51c6\u5907\u5bc4\u56de\u5bb6\u91cc\u4fee\u5c4b\u9876\u3002", "summary": "\u5b9e\u9645\u751f\u6d3b\u6781\u5ea6\u8282\u4fed\uff0c\u5e26\u75c5\u575a\u6301\u52b3\u4f5c\u81f4\u6655\u53a5\uff0c\u9192\u540e\u9996\u8981\u786e\u8ba4\u5bc4\u56de\u5bb6\u4fee\u5c4b\u9876\u7684\u94b1\u662f\u5426\u5b89\u5168\u3002", "source_location": "manual:body"}, {"chunk_type": "text", "content": "\u7237\u7237\u6bcf\u4e2a\u6708\u53d1\u4e86\u5de5\u94b1\uff0c\u90fd\u4f1a\u5206\u6210\u4e09\u4efd\uff1a\u4e00\u4efd\u5bc4\u56de\u798f\u5efa\u7ed9\u7236\u6bcd\u548c\u5f1f\u59b9\uff0c\u4e00\u4efd\u6258\u4eba\u5e26\u56de\u53bb\u7ed9\u963f\u5b37\uff0c\u4e00\u4efd\u7559\u7ed9\u81ea\u5df1\u5403\u996d\u3002\u7559\u7ed9\u81ea\u5df1\u7684\u90a3\u4e00\u4efd\uff0c\u6c38\u8fdc\u662f\u6700\u5c11\u7684\u3002 \u4ed6\u4e0d\u662f\u4e0d\u60f3\u8fc7\u597d\u4e00\u70b9\u3002\u4ed6\u53ea\u662f\u89c9\u5f97\uff0c\u81ea\u5df1\u5728\u5916\u9762\u591a\u82e6\u4e00\u70b9\uff0c\u5bb6\u91cc\u4eba\u5c31\u80fd\u5c11\u82e6\u4e00\u70b9\u3002", "summary": "\u5de5\u8d44\u4e25\u683c\u4e09\u5206\u4e3a\u8d61\u517b\u7236\u6bcd\u5f1f\u59b9\u3001\u63a5\u6d4e\u963f\u5b37\u3001\u81ea\u7528\uff0c\u81ea\u7528\u6700\u5c11\uff1b\u5176\u82e6\u71ac\u6e90\u4e8e\u4e3b\u52a8\u627f\u62c5\u5bb6\u5ead\u8d23\u4efb\u7684\u6734\u7d20\u4fe1\u5ff5\u3002", "source_location": "manual:body"}]}, "provider_type": "third_party"}', NULL, '2026-07-04 21:00:02.246035', NULL);
INSERT INTO public.parsed_chunks VALUES ('7ab111f1-26a5-4f44-9fe1-15d3c5e0a5ab', '27e4e946-6b92-42a2-982c-fde85b36c284', '4d7d2282-32b5-453a-b167-ee39194cfb06', 'audio', '你好啊，Bambi，又见面了。你能感觉到吗？是的，Bambi，你能感觉到这种感觉有多好是吧？我是指成为Bambi的感觉。因为你知道将会发生什么。你会走路的很深，就像你以前已经体验过很多次的那样。你会成为一个good girl，就像你以前做过很多次的那样。准备好了吗？你准备好了吗，Bambi？那么让自己开始舒服起来，开始放松，开始深呼吸。吸气，停一下下。再深深的呼气。专心听我说的话，进入Bambi sleep。进入的越来越深，准备服从，Bambi sleep。越来越深，现在进入Bambi sleep。就是这样，Bambi sleep。让内心做好深深服从的准备，做好条件训练的准备。就是这样，真是一个good girl。感觉好奇了，Bambi，当你沉睡的时候，你的脑海中一片空白，你只会倾听和服从。', '你好啊，Bambi，又见面了。你能感觉到吗？是的，Bambi，你能感觉到这种感觉有多好是吧？我是指成为Bambi的感觉。因为你知道将会发生什么。你会走路的很深，', 'audio:t00-rapid-induction-3th.mp3#00:00', 0, 5, '{"asr": {"transcript": "\u4f60\u597d\u554a\uff0cBambi\uff0c\u53c8\u89c1\u9762\u4e86\u3002\u4f60\u80fd\u611f\u89c9\u5230\u5417\uff1f\u662f\u7684\uff0cBambi\uff0c\u4f60\u80fd\u611f\u89c9\u5230\u8fd9\u79cd\u611f\u89c9\u6709\u591a\u597d\u662f\u5427\uff1f\u6211\u662f\u6307\u6210\u4e3aBambi\u7684\u611f\u89c9\u3002\u56e0\u4e3a\u4f60\u77e5\u9053\u5c06\u4f1a\u53d1\u751f\u4ec0\u4e48\u3002\u4f60\u4f1a\u8d70\u8def\u7684\u5f88\u6df1\uff0c\u5c31\u50cf\u4f60\u4ee5\u524d\u5df2\u7ecf\u4f53\u9a8c\u8fc7\u5f88\u591a\u6b21\u7684\u90a3\u6837\u3002\u4f60\u4f1a\u6210\u4e3a\u4e00\u4e2agood girl\uff0c\u5c31\u50cf\u4f60\u4ee5\u524d\u505a\u8fc7\u5f88\u591a\u6b21\u7684\u90a3\u6837\u3002\u51c6\u5907\u597d\u4e86\u5417\uff1f\u4f60\u51c6\u5907\u597d\u4e86\u5417\uff0cBambi\uff1f\u90a3\u4e48\u8ba9\u81ea\u5df1\u5f00\u59cb\u8212\u670d\u8d77\u6765\uff0c\u5f00\u59cb\u653e\u677e\uff0c\u5f00\u59cb\u6df1\u547c\u5438\u3002\u5438\u6c14\uff0c\u505c\u4e00\u4e0b\u4e0b\u3002\u518d\u6df1\u6df1\u7684\u547c\u6c14\u3002\u4e13\u5fc3\u542c\u6211\u8bf4\u7684\u8bdd\uff0c\u8fdb\u5165Bambi sleep\u3002\u8fdb\u5165\u7684\u8d8a\u6765\u8d8a\u6df1\uff0c\u51c6\u5907\u670d\u4ece\uff0cBambi sleep\u3002\u8d8a\u6765\u8d8a\u6df1\uff0c\u73b0\u5728\u8fdb\u5165Bambi sleep\u3002\u5c31\u662f\u8fd9\u6837\uff0cBambi sleep\u3002\u8ba9\u5185\u5fc3\u505a\u597d\u6df1\u6df1\u670d\u4ece\u7684\u51c6\u5