INSERT INTO public.parsed_chunks VALUES ('50b4a0cd-f5e2-4c0f-93ce-e02e33f6afae', '12264fff-cbf4-4fd1-aa03-6c1dc0c9bb73', '2329519c-45c6-41db-bf1c-84926575bc35', 'audio', '你好，呃，我今天来这里参加 Next Step 的黑客松，然后我想稍微介绍一下我自己，那么我们必须要有十秒钟以上的声音。', '你好，呃，我今天来这里参加 Next Step 的黑客松，然后我想稍微介绍一下我自己，那么我们必须要有十秒钟以上的声音。', 'audio:voice-sample-recording-1783199905536.wav#00:00', 0, 5, '{"asr": {"transcript": "\u4f60\u597d\uff0c\u5443\uff0c\u6211\u4eca\u5929\u6765\u8fd9\u91cc\u53c2\u52a0 Next Step \u7684\u9ed1\u5ba2\u677e\uff0c\u7136\u540e\u6211\u60f3\u7a0d\u5fae\u4ecb\u7ecd\u4e00\u4e0b\u6211\u81ea\u5df1\uff0c\u90a3\u4e48\u6211\u4eec\u5fc5\u987b\u8981\u6709\u5341\u79d2\u949f\u4ee5\u4e0a\u7684\u58f0\u97f3\u3002", "sample_metadata": {"start_time": "00:00", "end_time": null, "speaker": "unknown", "language": "zh"}, "source_location": "audio:voice-sample-recording-1783199905536.wav#00:00"}, "provider_type": "third_party"}', NULL, '2026-07-04 21:18:27.41627', NULL);
INSERT INTO public.parsed_chunks VALUES ('b58229cf-493d-402c-95bc-0364d5c93162', '18b88e96-5633-4d75-b77a-0ad1988a846a', '1be017c6-86ad-420a-b1c7-2b5dbebea5e8', 'manual', '爷爷刚到南洋时，先在码头做苦力。码头的活很重，要扛米袋、搬木箱、卸货。一袋米压在肩上，走几步肩膀就像被刀割一样疼。那时候他年纪小，身子又瘦，常常被老工人嫌弃力气不够。他不争辩，只是咬牙多扛几趟。', '初抵南洋，在码头从事高强度苦力劳动，身体瘦弱却默默坚持。', 'manual:body', NULL, NULL, '{"text_extraction": {"extractor": "manual", "source_location": "manual:body", "has_text": true}, "text_parser": {"cleaned_text": "\u4e09\u3001\u5357\u6d0b\u5c81\u6708\uff1a\u4ed6\u5982\u4f55\u628a\u82e6\u65e5\u5b50\u71ac\u6210\u5bb6\u4eba\u7684\u751f\u8def \u7237\u7237\u521a\u5230\u5357\u6d0b\u65f6\uff0c\u5148\u5728\u7801\u5934\u505a\u82e6\u529b\u3002\u7801\u5934\u7684\u6d3b\u5f88\u91cd\uff0c\u8981\u625b\u7c73\u888b\u3001\u642c\u6728\u7bb1\u3001\u5378\u8d27\u3002\u4e00\u888b\u7c73\u538b\u5728\u80a9\u4e0a\uff0c\u8d70\u51e0\u6b65\u80a9\u8180\u5c31\u50cf\u88ab\u5200\u5272\u4e00\u6837\u75bc\u3002\u90a3\u65f6\u5019\u4ed6\u5e74\u7eaa\u5c0f\uff0c\u8eab\u5b50\u53c8\u7626\uff0c\u5e38\u5e38\u88ab\u8001\u5de5\u4eba\u5acc\u5f03\u529b\u6c14\u4e0d\u591f\u3002\u4ed6\u4e0d\u4e89\u8fa9\uff0c\u53ea\u662f\u54ac\u7259\u591a\u625b\u51e0\u8d9f\u3002 \u540e\u6765\uff0c\u4ed6\u53c8\u8ddf\u7740\u540c\u4e61\u53bb\u4e86\u6a61\u80f6\u56ed\u5272\u80f6\u3002\u6bcf\u5929\u51cc\u6668\u5929\u8fd8\u6ca1\u4eae\u5c31\u8981\u8d77\u6765\uff0c\u80cc\u7740\u5de5\u5177\u8fdb\u6797\u5b50\u3002\u6a61\u80f6\u6797\u91cc\u6e7f\u6c14\u91cd\uff0c\u868a\u866b\u591a\uff0c\u811a\u5e95\u5e38\u5e38\u8e29\u5728\u6ce5\u6c34\u91cc\u3002\u624b\u88ab\u6811\u76ae\u5212\u7834\u662f\u5e38\u4e8b\uff0c\u6c57\u6c34\u6d41\u8fdb\u4f24\u53e3\uff0c\u75bc\u5f97\u94bb\u5fc3\u3002\u4ed6\u6700\u6015\u4e0b\u96e8\uff0c\u56e0\u4e3a\u96e8\u6c34\u4e00\u6765\uff0c\u80f6\u6c34\u5c31\u6536\u4e0d\u6210\uff0c\u4e00\u5929\u7684\u5de5\u94b1\u53ef\u80fd\u5c31\u6ca1\u4e86\u3002 \u53ef\u662f\u7237\u7237\u4ece\u6765\u4e0d\u5728\u5bc4\u56de\u5bb6\u7684\u4fe1\u91cc\u8bf4\u8fd9\u4e9b\u3002\u4ed6\u6015\u5bb6\u91cc\u4eba\u62c5\u5fc3\uff0c\u4e5f\u6015\u963f\u5b37\u5fc3\u75bc\u3002\u4ed6\u5728\u4fe1\u91cc\u5199\u7684\uff0c\u5e38\u5e38\u662f\u4e00\u4e9b\u5f88\u8f7b\u7684\u4e8b\u3002 \u4ed6\u8bf4\u5357\u6d0b\u7684\u6708\u4eae\u548c\u5bb6\u4e61\u4e00\u6837\u5706\u3002 \u4ed6\u8bf4\u8fd9\u91cc\u7684\u6d77\u98ce\u4e5f\u6709\u54b8\u5473\uff0c\u53ea\u662f\u95fb\u8d77\u6765\u4e0d\u50cf\u664b\u6c5f\u7684\u6d77\u3002 \u4ed6\u8bf4\u81ea\u5df1\u5403\u5f97\u9971\uff0c\u4f4f\u5f97\u4e0b\uff0c\u5de5\u53cb\u4e5f\u7167\u987e\u4ed6\u3002 \u4ed6\u8bf4\u7b49\u8d5a\u591f\u94b1\uff0c\u5c31\u56de\u5bb6\u3002 \u771f\u5b9e\u7684\u60c5\u51b5\u662f\uff0c\u4ed6\u5e38\u5e38\u4e00\u7897\u767d\u7ca5\u914d\u4e00\u70b9\u54b8\u83dc\u5c31\u8fc7\u4e00\u5929\u3002\u4ed6\u820d\u4e0d\u5f97\u4e70\u65b0\u8863\u670d\uff0c\u4e5f\u820d\u4e0d\u5f97\u4e70\u836f\u3002\u6709\u4e00\u6b21\u4ed6\u53d1\u9ad8\u70e7\uff0c\u5de5\u53cb\u529d\u4ed6\u4f11\u606f\uff0c\u4ed6\u5374\u575a\u6301\u53bb\u5272\u80f6\uff0c\u56e0\u4e3a\u90a3\u5929\u5982\u679c\u4e0d\u53bb\uff0c\u5c31\u5c11\u4e00\u5929\u5de5\u94b1\u3002\u540e\u6765\u4ed6\u6655\u5012\u5728\u6797\u5b50\u91cc\uff0c\u88ab\u4eba\u80cc\u56de\u5de5\u68da\u3002 \u4ed6\u9192\u6765\u540e\u7b2c\u4e00\u4ef6\u4e8b\uff0c\u4e0d\u662f\u95ee\u81ea\u5df1\u75c5\u5f97\u91cd\u4e0d\u91cd\uff0c\u800c\u662f\u6478\u53e3\u888b\u91cc\u7684\u94b1\u8fd8\u5728\u4e0d\u5728\u3002\u56e0\u4e3a\u90a3\u4e2a\u6708\u7684\u94b1\uff0c\u4ed6\u51c6\u5907\u5bc4\u56de\u5bb6\u91cc\u4fee\u5c4b\u9876\u3002 \u7237\u7237\u6bcf\u4e2a\u6708\u53d1\u4e86\u5de5\u94b1\uff0c\u90fd\u4f1a\u5206\u6210\u4e09\u4efd\uff1a\u4e00\u4efd\u5bc4\u56de\u798f\u5efa\u7ed9\u7236\u6bcd\u548c\u5f1f\u59b9\uff0c\u4e00\u4efd\u6258\u4eba\u5e26\u56de\u53bb\u7ed9\u963f\u5b37\uff0c\u4e00\u4efd\u7559\u7ed9\u81ea\u5df1\u5403\u996d\u3002\u7559\u7ed9\u81ea\u5df1\u7684\u90a3\u4e00\u4efd\uff0c\u6c38\u8fdc\u662f\u6700\u5c11\u7684\u3002 \u4ed6\u4e0d\u662f\u4e0d\u60f3\u8fc7\u597d\u4e00\u70b9\u3002\u4ed6\u53ea\u662f\u89c9\u5f97\uff0c\u81ea\u5df1\u5728\u5916\u9762\u591a\u82e6\u4e00\u70b9\uff0c\u5bb6\u91cc\u4eba\u5c31\u80fd\u5c11\u82e6\u4e00\u70b9\u3002", "chunks": [{"chunk_type": "text", "content": "\u7237\u7237\u521a\u5230\u5357\u6d0b\u65f6\uff0c\u5148\u5728\u7801\u5934\u505a\u82e6\u529b\u3002\u7801\u5934\u7684\u6d3b\u5f88\u91cd\uff0c\u8981\u625b\u7c73\u888b\u3001\u642c\u6728\u7bb1\u3001\u5378\u8d27\u3002\u4e00\u888b\u7c73\u538b\u5728\u80a9\u4e0a\uff0c\u8d70\u51e0\u6b65\u80a9\u8180\u5c31\u50cf\u88ab\u5200\u5272\u4e00\u6837\u75bc\u3002\u90a3\u65f6\u5019\u4ed6\u5e74\u7eaa\u5c0f\uff0c\u8eab\u5b50\u53c8\u7626\uff0c\u5e38\u5e38\u88ab\u8001\u5de5\u4eba\u5acc\u5f03\u529b\u6c14\u4e0d\u591f\u3002\u4ed6\u4e0d\u4e89\u8fa9\uff0c\u53ea\u662f\u54ac\u7259\u591a\u625b\u51e0\u8d9f\u3002", "summary": "\u521d\u62b5\u5357\u6d0b\uff0c\u5728\u7801\u5934\u4ece\u4e8b\u9ad8\u5f3a\u5ea6\u82e6\u529b\u52b3\u52a8\uff0c\u8eab\u4f53\u7626\u5f31\u5374\u9ed8\u9ed8\u575a\u6301\u3002", "source_location": "manual:body"}, {"chunk_type": "text", "content": "\u540e\u6765\uff0c\u4ed6\u53c8\u8ddf\u7740\u540c\u4e61\u53bb\u4e86\u6a61\u80f6\u56ed\u5272\u80f6\u3002\u6bcf\u5929\u51cc\u6668\u5929\u8fd8\u6ca1\u4eae\u5c31\u8981\u8d77\u6765\uff0c\u80cc\u7740\u5de5\u5177\u8fdb\u6797\u5b50\u3002\u6a61\u80f6\u6797\u91cc\u6e7f\u6c14\u91cd\uff0c\u868a\u866b\u591a\uff0c\u811a\u5e95\u5e38\u5e38\u8e29\u5728\u6ce5\u6c34\u91cc\u3002\u624b\u88ab\u6811\u76ae\u5212\u7834\u662f\u5e38\u4e8b\uff0c\u6c57\u6c34\u6d41\u8fdb\u4f24\u53e3\uff0c\u75bc\u5f97\u94bb\u5fc3\u3002\u4ed6\u6700\u6015\u4e0b\u96e8\uff0c\u56e0\u4e3a\u96e8\u6c34\u4e00\u6765\uff0c\u80f6\u6c34\u5c31\u6536\u4e0d\u6210\uff0c\u4e00\u5929\u7684\u5de5\u94b1\u53ef\u80fd\u5c31\u6ca1\u4e86\u3002", "summary": "\u8f6c\u81f3\u6a61\u80f6\u56ed\u5272\u80f6\uff0c\u5de5\u4f5c\u73af\u5883\u6076\u52a3\uff0c\u52b3\u52a8\u5f3a\u5ea6\u5927\uff0c\u6536\u5165\u53d7\u5929\u6c14\u5f71\u54cd\u663e\u8457\u3002", "source_location": "manual:body"}, {"chunk_type": "text", "content": "\u53ef\u662f\u7237\u7237\u4ece\u6765\u4e0d\u5728\u5bc4\u56de\u5bb6\u7684\u4fe1\u91cc\u8bf4\u8fd9\u4e9b\u3002\u4ed6\u6015\u5bb6\u91cc\u4eba\u62c5\u5fc3\uff0c\u4e5f\u6015\u963f\u5b37\u5fc3\u75bc\u3002\u4ed6\u5728\u4fe1\u91cc\u5199\u7684\uff0c\u5e38\u5e38\u662f\u4e00\u4e9b\u5f88\u8f7b\u7684\u4e8b\u3002 \u4ed6\u8bf4\u5357\u6d0b\u7684\u6708\u4eae\u548c\u5bb6\u4e61\u4e00\u6837\u5706\u3002 \u4ed6\u8bf4\u8fd9\u91cc\u7684\u6d77\u98ce\u4e5f\u6709\u54b8\u5473\uff0c\u53ea\u662f\u95fb\u8d77\u6765\u4e0d\u50cf\u664b\u6c5f\u7684\u6d77\u3002 \u4ed6\u8bf4\u81ea\u5df1\u5403\u5f97\u9971\uff0c\u4f4f\u5f97\u4e0b\uff0c\u5de5\u53cb\u4e5f\u7167\u987e\u4ed6\u3002 \u4ed6\u8bf4\u7b49\u8d5a\u591f\u94b1\uff0c\u5c31\u56de\u5bb6\u3002", "summary": "\u523b\u610f\u5728\u4e66\u4fe1\u4e2d\u9690\u7792\u8270\u8f9b\uff0c\u7528\u8bd7\u610f\u5316\u3001\u65e5\u5e38\u5316\u7684\u8bed\u8a00\u62a5\u5e73\u5b89\uff0c\u4f20\u9012\u601d\u5ff5\u4e0e\u627f\u8bfa\u3002", "source_location": "manual:body"}, {"chunk_type": "text", "content": "\u771f\u5b9e\u7684\u60c5\u51b5\u662f\uff0c\u4ed6\u5e38\u5e38\u4e00\u7897\u767d\u7ca5\u914d\u4e00\u70b9\u54b8\u83dc\u5c31\u8fc7\u4e00\u5929\u3002\u4ed6\u820d\u4e0d\u5f97\u4e70\u65b0\u8863\u670d\uff0c\u4e5f\u820d\u4e0d\u5f97\u4e70\u836f\u3002\u6709\u4e00\u6b21\u4ed6\u53d1\u9ad8\u70e7\uff0c\u5de5\u53cb\u529d\u4ed6\u4f11\u606f\uff0c\u4ed6\u5374\u575a\u6301\u53bb\u5272\u80f6\uff0c\u56e0\u4e3a\u90a3\u5929\u5982\u679c\u4e0d\u53bb\uff0c\u5c31\u5c11\u4e00\u5929\u5de5\u94b1\u3002\u540e\u6765\u4ed6\u6655\u5012\u5728\u6797\u5b50\u91cc\uff0c\u88ab\u4eba\u80cc\u56de\u5de5\u68da\u3002 \u4ed6\u9192\u6765\u540e\u7b2c\u4e00\u4ef6\u4e8b\uff0c\u4e0d\u662f\u95ee\u81ea\u5df1\u75c5\u5f97\u91cd\u4e0d\u91cd\uff0c\u800c\u662f\u6478\u53e3\u888b\u91cc\u7684\u94b1\u8fd8\u5728\u4e0d\u5728\u3002\u56e0\u4e3a\u90a3\u4e2a\u6708\u7684\u94b1\uff0c\u4ed6\u51c6\u5907\u5bc4\u56de\u5bb6\u91cc\u4fee\u5c4b\u9876\u3002", "summary": "\u5b9e\u9645\u751f\u6d3b\u6781\u5ea6\u8282\u4fed\uff0c\u5e26\u75c5\u575a\u6301\u52b3\u4f5c\uff0c\u6655\u5012\u540e\u9996\u8981\u5173\u5fc3\u7684\u662f\u5bc4\u56de\u5bb6\u7684\u94b1\u662f\u5426\u5b89\u5168\u3002", "source_location": "manual:body"}, {"chunk_type": "text", "content": "\u7237\u7237\u6bcf\u4e2a\u6708\u53d1\u4e86\u5de5\u94b1\uff0c\u90fd\u4f1a\u5206\u6210\u4e09\u4efd\uff1a\u4e00\u4efd\u5bc4\u56de\u798f\u5efa\u7ed9\u7236\u6bcd\u548c\u5f1f\u59b9\uff0c\u4e00\u4efd\u6258\u4eba\u5e26\u56de\u53bb\u7ed9\u963f\u5b37\uff0c\u4e00\u4efd\u7559\u7ed9\u81ea\u5df1\u5403\u996d\u3002\u7559\u7ed9\u81ea\u5df1\u7684\u90a3\u4e00\u4efd\uff0c\u6c38\u8fdc\u662f\u6700\u5c11\u7684\u3002 \u4ed6\u4e0d\u662f\u4e0d\u60f3\u8fc7\u597d\u4e00\u70b9\u3002\u4ed6\u53ea\u662f\u89c9\u5f97\uff0c\u81ea\u5df1\u5728\u5916\u9762\u591a\u82e6\u4e00\u70b9\uff0c\u5bb6\u91cc\u4eba\u5c31\u80fd\u5c11\u82e6\u4e00\u70b9\u3002", "summary": "\u5de5\u8d44\u4e25\u683c\u4e09\u5411\u5206\u914d\uff0c\u81ea\u6211\u4efd\u989d\u6700\u5c11\uff0c\u5176\u884c\u4e3a\u52a8\u673a\u660e\u786e\u6307\u5411\u5bb6\u5ead\u8d23\u4efb\u4e0e\u727a\u7272\u7cbe\u795e\u3002", "source_location": "manual:body"}]}, "provider_type": "third_party"}', NULL, '2026-07-04 21:52:50.750118', NULL);
INSERT INTO public.parsed_chunks VALUES ('be51b357-5fca-48b1-943d-d83ba01cd579', '18b88e96-5633-4d75-b77a-0ad1988a846a', 'c26ceaa4-db78-4fe6-b343-0e030d30df79', 'manual', '爷爷和阿嬷之间最重要的记忆，是那些从南洋寄回福建的信。', '家书是爷爷与阿嬷间最重要的情感纽带。', 'manual:body:paragraph_1', NULL, NULL, '{"text_extraction": {"extractor": "manual", "source_location": "manual:body", "has_text": true}, "text_parser": {"cleaned_text": "\u56db\u3001\u7237\u7237\u548c\u963f\u5b37\u7684\u5bb6\u4e66\u6545\u4e8b \u7237\u7237\u548c\u963f\u5b37\u4e4b\u95f4\u6700\u91cd\u8981\u7684\u8bb0\u5fc6\uff0c\u662f\u90a3\u4e9b\u4ece\u5357\u6d0b\u5bc4\u56de\u798f\u5efa\u7684\u4fe1\u3002 \u7237\u7237\u6587\u5316\u4e0d\u9ad8\uff0c\u5c0f\u65f6\u5019\u6ca1\u8bfb\u8fc7\u51e0\u5e74\u4e66\uff0c\u5f88\u591a\u5b57\u4e0d\u4f1a\u5199\u3002\u4ed6\u5199\u4fe1\u5f88\u6162\uff0c\u6709\u65f6\u4e00\u5c01\u4fe1\u8981\u5199\u4e09\u56db\u4e2a\u665a\u4e0a\u3002\u5de5\u68da\u91cc\u706f\u5149\u5f88\u6697\uff0c\u522b\u4eba\u7761\u4e86\uff0c\u4ed6\u5c31\u5750\u5728\u6728\u677f\u5e8a\u8fb9\uff0c\u501f\u7740\u7164\u6cb9\u706f\u5199\u5b57\u3002\u5199\u9519\u4e86\u5c31\u5212\u6389\uff0c\u91cd\u65b0\u5199\u3002\u56e0\u4e3a\u7eb8\u8d35\uff0c\u4ed6\u820d\u4e0d\u5f97\u6d6a\u8d39\uff0c\u6240\u4ee5\u4e00\u5f20\u4fe1\u7eb8\u4e0a\u5e38\u5e38\u6324\u6ee1\u4e86\u5b57\u3002 \u4ed6\u5728\u4fe1\u91cc\u5f88\u5c11\u76f4\u63a5\u8bf4\u201c\u6211\u60f3\u4f60\u201d\u3002\u4ed6\u4f1a\u5199\uff1a\u201c\u4eca\u5929\u7801\u5934\u98ce\u5927\uff0c\u6211\u60f3\u8d77\u6751\u53e3\u90a3\u68f5\u6995\u6811\u3002\u201d\u201c\u8fd9\u91cc\u96e8\u591a\uff0c\u4f60\u51fa\u95e8\u8bb0\u5f97\u5e26\u4f1e\u3002\u201d\u201c\u6211\u5bc4\u4e86\u4e00\u70b9\u94b1\u56de\u53bb\uff0c\u4f60\u4e0d\u8981\u820d\u4e0d\u5f97\u7528\u3002\u201d\u201c\u6211\u73b0\u5728\u8fd8\u4e0d\u80fd\u56de\u6765\uff0c\u4f60\u4e0d\u8981\u602a\u6211\u3002\u201d\u201c\u7b49\u6211\u56de\u6765\uff0c\u6211\u4eec\u5c31\u628a\u65e5\u5b50\u8fc7\u7a33\u3002\u201d \u963f\u5b37\u6536\u5230\u4fe1\u4ee5\u540e\uff0c\u4f1a\u628a\u4fe1\u6298\u597d\uff0c\u653e\u8fdb\u4e00\u4e2a\u6728\u7bb1\u91cc\u3002\u6728\u7bb1\u91cc\u540e\u6765\u88c5\u6ee1\u4e86\u7237\u7237\u4ece\u5357\u6d0b\u5bc4\u56de\u6765\u7684\u4fe1\u3002\u90a3\u4e9b\u4fe1\u7684\u7eb8\u53d1\u9ec4\uff0c\u8fb9\u89d2\u88ab\u6f6e\u6c14\u6ce1\u8f6f\uff0c\u6709\u4e9b\u5b57\u8ff9\u5df2\u7ecf\u6a21\u7cca\u3002\u53ef\u662f\u963f\u5b37\u4e00\u76f4\u820d\u4e0d\u5f97\u4e22\u3002 \u7237\u7237\u6700\u717d\u60c5\u7684\u4e00\u5c01\u4fe1\uff0c\u662f\u4ed6\u5728\u5357\u6d0b\u7b2c\u4e09\u5e74\u5199\u7684\u3002\u90a3\u4e00\u5e74\uff0c\u4ed6\u542c\u8bf4\u963f\u5b37\u5bb6\u91cc\u6709\u4eba\u60f3\u7ed9\u5979\u4ecb\u7ecd\u4eb2\u4e8b\u3002\u7237\u7237\u77e5\u9053\u540e\u5f88\u96be\u8fc7\uff0c\u4f46\u4ed6\u6ca1\u6709\u8d23\u602a\u5979\u3002\u4ed6\u5728\u4fe1\u91cc\u5199\uff1a\u201c\u5982\u679c\u4f60\u613f\u610f\u7b49\u6211\uff0c\u6211\u8fd9\u8f88\u5b50\u4e00\u5b9a\u4e0d\u8d1f\u4f60\u3002\u5982\u679c\u4f60\u4e0d\u613f\u610f\u7b49\uff0c\u6211\u4e5f\u4e0d\u602a\u4f60\u3002\u6211\u53ea\u662f\u6015\u6211\u8fd9\u51e0\u5e74\u5728\u5916\u9762\u71ac\u7684\u82e6\uff0c\u6ca1\u6709\u4e00\u4e2a\u80fd\u56de\u53bb\u4ea4\u4ee3\u7684\u4eba\u3002\u6211\u4e0d\u6562\u8bf4\u6211\u4ee5\u540e\u4f1a\u8ba9\u4f60\u8fc7\u5f88\u5bcc\u8d35\u7684\u65e5\u5b50\uff0c\u4f46\u6211\u6562\u8bf4\uff0c\u53ea\u8981\u6211\u90d1\u6728\u751f\u6d3b\u7740\uff0c\u5c31\u4e0d\u4f1a\u8ba9\u4f60\u4e00\u4e2a\u4eba\u53d7\u59d4\u5c48\u3002\u201d \u963f\u5b37\u540e\u6765\u6ca1\u6709\u5ac1\u7ed9\u522b\u4eba\u3002\u5979\u7b49\u4e86\u4ed6\u3002 \u7237\u7237\u56de\u4e61\u90a3\u4e00\u5e74\uff0c\u5df2\u7ecf\u6bd4\u8d70\u7684\u65f6\u5019\u7626\u4e86\u5f88\u591a\uff0c\u4e5f\u9ed1\u4e86\u5f88\u591a\u3002\u4ed6\u7ad9\u5728\u6751\u53e3\uff0c\u624b\u91cc\u63d0\u7740\u90a3\u4e2a\u65e7\u85e4\u7bb1\uff0c\u7bb1\u5b50\u91cc\u6ca1\u6709\u4ec0\u4e48\u8d35\u91cd\u4e1c\u897f\uff0c\u53ea\u6709\u4e00\u53ea\u5c0f\u91d1\u6212\u6307\u3001\u4e00\u5757\u7ed9\u963f\u5b37\u7684\u82b1\u5e03\uff0c\u8fd8\u6709\u8fd9\u4e9b\u5e74\u6512\u4e0b\u7684\u4e00\u70b9\u94b1\u3002 \u963f\u5b37\u770b\u5230\u4ed6\u65f6\uff0c\u6ca1\u6709\u50cf\u7535\u5f71\u91cc\u90a3\u6837\u6251\u8fc7\u53bb\u5927\u54ed\u3002\u5979\u53ea\u662f\u7ad9\u5728\u539f\u5730\uff0c\u773c\u775b\u7ea2\u4e86\u5f88\u4e45\uff0c\u7136\u540e\u8bf4\uff1a\u201c\u4f60\u771f\u7684\u56de\u6765\u4e86\u3002\u201d\u7237\u7237\u70b9\u70b9\u5934\uff0c\u8bf4\uff1a\u201c\u6211\u7b54\u5e94\u8fc7\u4f60\u7684\u3002\u201d \u8fd9\u53e5\u8bdd\u540e\u6765\u6210\u4e86\u6211\u4eec\u5bb6\u91cc\u6700\u91cd\u8981\u7684\u4e00\u53e5\u8bdd\u3002\u7237\u7237\u8fd9\u4e00\u751f\u4e0d\u592a\u4f1a\u8868\u8fbe\u7231\uff0c\u4f46\u4ed6\u7528\u51e0\u5341\u5e74\u7684\u65f6\u95f4\u8bc1\u660e\u4e86\uff1a\u771f\u6b63\u7684\u7231\u4e0d\u662f\u8bf4\u4e86\u591a\u5c11\uff0c\u800c\u662f\u7b54\u5e94\u8fc7\u7684\u4e8b\u6709\u6ca1\u6709\u505a\u5230\u3002", "chunks": [{"chunk_type": "text", "content": "\u7237\u7237\u548c\u963f\u5b37\u4e4b\u95f4\u6700\u91cd\u8981\u7684\u8bb0\u5fc6\uff0c\u662f\u90a3\u4e9b\u4ece\u5357\u6d0b\u5bc4\u56de\u798f\u5efa\u7684\u4fe1\u3002", "summary": "\u5bb6\u4e66\u662f\u7237\u7237\u4e0e\u963f\u5b37\u95f4\u6700\u91cd\u8981\u7684\u60c5\u611f\u7ebd\u5e26\u3002", "source_location": "manual:body:paragraph_1"}, {"chunk_type": "text", "content": "\u7237\u7237\u6587\u5316\u4e0d\u9ad8\uff0c\u5c0f\u65f6\u5019\u6ca1\u8bfb\u8fc7\u51e0\u5e74\u4e66\uff0c\u5f88\u591a\u5b57\u4e0d\u4f1a\u5199\u3002\u4ed6\u5199\u4fe1\u5f88\u6162\uff0c\u6709\u65f6\u4e00\u5c01\u4fe1\u8981\u5199\u4e09\u56db\u4e2a\u665a\u4e0a\u3002\u5de5\u68da\u91cc\u706f\u5149\u5f88\u6697\uff0c\u522b\u4eba\u7761\u4e86\uff0c\u4ed6\u5c31\u5750\u5728\u6728\u677f\u5e8a\u8fb9\uff0c\u501f\u7740\u7164\u6cb9\u706f\u5199\u5b57\u3002\u5199\u9519\u4e86\u5c31\u5212\u6389\uff0c\u91cd\u65b0\u5199\u3002\u56e0\u4e3a\u7eb8\u8d35\uff0c\u4ed6\u820d\u4e0d\u5f97\u6d6a\u8d39\uff0c\u6240\u4ee5\u4e00\u5f20\u4fe1\u7eb8\u4e0a\u5e38\u5e38\u6324\u6ee1\u4e86\u5b57\u3002", "summary": "\u7237\u7237\u8bc6\u5b57\u4e0d\u591a\uff0c\u5199\u4fe1\u6781\u4e3a\u8ba4\u771f\u8282\u4fed\uff0c\u5e38\u5728\u6df1\u591c\u7164\u6cb9\u706f\u4e0b\u53cd\u590d\u4fee\u6539\u3002", "source_location": "manual:body:paragraph_2"}, {"chunk_type": "text", "content": "\u4ed6\u5728\u4fe1\u91cc\u5f88\u5c11\u76f4\u63a5\u8bf4\u201c\u6211\u60f3\u4f60\u201d\u3002\u4ed6\u4f1a\u5199\uff1a\u201c\u4eca\u5929\u7801\u5934\u98ce\u5927\uff0c\u6211\u60f3\u8d77\u6751\u53e3\u90a3\u68f5\u6995\u6811\u3002\u201d\u201c\u8fd9\u91cc\u96e8\u591a\uff0c\u4f60\u51fa\u95e8\u8bb0\u5f97\u5e26\u4f1e\u3002\u201d\u201c\u6211\u5bc4\u4e86\u4e00\u70b9\u94b1\u56de\u53bb\uff0c\u4f60\u4e0d\u8981\u820d\u4e0d\u5f97\u7528\u3002\u201d\u201c\u6211\u73b0\u5728\u8fd8\u4e0d\u80fd\u56de\u6765\uff0c\u4f60\u4e0d\u8981\u602a\u6211\u3002\u201d\u201c\u7b49\u6211\u56de\u6765\uff0c\u6211\u4eec\u5c31\u628a\u65e5\u5b50\u8fc7\u7a33\u3002\u201d", "summary": "\u7237\u7237\u4ee5\u542b\u84c4\u65e5\u5e38\u7684\u7ec6\u8282\u8868\u8fbe\u601d\u5ff5\u4e0e\u627f\u8bfa\uff0c\u56de\u907f\u76f4\u767d\u6292\u60c5\u3002", "source_location": "manual:body:paragraph_3"}, {"chunk_type": "text", "content": "\u963f\u5b37\u6536\u5230\u4fe1\u4ee5\u540e\uff0c\u4f1a\u628a\u4fe1\u6298\u597d\uff0c\u653e\u8fdb\u4e00\u4e2a\u6728\u7bb1\u91cc\u3002\u6728\u7bb1\u91cc\u540e\u6765\u88c5\u6ee1\u4e86\u7237\u7237\u4ece\u5357\u6d0b\u5bc4\u56de\u6765\u7684\u4fe1\u3002\u90a3\u4e9b\u4fe1\u7684\u7eb8\u53d1\u9ec4\uff0c\u8fb9\u89d2\u88ab\u6f6e\u6c14\u6ce1\u8f6f\uff0c\u6709\u4e9b\u5b57\u8ff9\u5df2\u7ecf\u6a21\u7cca\u3002\u53ef\u662f\u963f\u5b37\u4e00\u76f4\u820d\u4e0d\u5f97\u4e22\u3002", "summary": "\u963f\u5b37\u73cd\u85cf\u6240\u6709\u6765\u4fe1\uff0c\u6728\u7bb1\u6210\u4e3a\u627f\u8f7d\u5c81\u6708\u4e0e\u7b49\u5f85\u7684\u5b9e\u7269\u89c1\u8bc1\u3002", "source_location": "manual:body:paragraph_4"}, {"chunk_type": "text", "content": "\u7237\u7237\u6700\u717d\u60c5\u7684\u4e00\u5c01\u4fe1\uff0c\u662f\u4ed6\u5728\u5357\u6d0b\u7b2c\u4e09\u5e74\u5199\u7684\u3002\u90a3\u4e00\u5e74\uff0c\u4ed6\u542c\u8bf4\u963f\u5b37\u5bb6\u91cc\u6709\u4eba\u60f3\u7ed9\u5979\u4ecb\u7ecd\u4eb2\u4e8b\u3002\u7237\u7237\u77e5\u9053\u540e\u5f88\u96be\u8fc7\uff0c\u4f46\u4ed6\u6ca1\u6709\u8d23\u602a\u5979\u3002\u4ed6\u5728\u4fe1\u91cc\u5199\uff1a\u201c\u5982\u679c\u4f60\u613f\u610f\u7b49\u6211\uff0c\u6211\u8fd9\u8f88\u5b50\u4e00\u5b9a\u4e0d\u8d1f\u4f60\u3002\u5982\u679c\u4f60\u4e0d\u613f\u610f\u7b49\uff0c\u6211\u4e5f\u4e0d\u602a\u4f60\u3002\u6211\u53ea\u662f\u6015\u6211\u8fd9\u51e0\u5e74\u5728\u5916\u9762\u71ac\u7684\u82e6\uff0c\u6ca1\u6709\u4e00\u4e2a\u80fd\u56de\u53bb\u4ea4\u4ee3\u7684\u4eba\u3002\u6211\u4e0d\u6562\u8bf4\u6211\u4ee5\u540e\u4f1a\u8ba9\u4f60\u8fc7\u5f88\u5bcc\u8d35\u7684\u65e5\u5b50\uff0c\u4f46\u6211\u6562\u8bf4\uff0c\u53ea\u8981\u6211\u90d1\u6728\u751f\u6d3b\u7740\uff0c\u5c31\u4e0d\u4f1a\u8ba9\u4f60\u4e00\u4e2a\u4eba\u53d7\u59d4\u5c48\u3002\u201d", "summary": "\u5357\u6d0b\u7b2c\u4e09\u5e74\uff0c\u7237\u7237\u5f97\u77e5\u963f\u5b37\u88ab\u63d0\u4eb2\u540e\u5199\u4e0b\u6700\u52a8\u60c5\u7684\u4fe1\uff0c\u5766\u8bda\u8106\u5f31\u4e0e\u575a\u5b88\uff0c\u7f72\u540d\u2018\u90d1\u6728\u2019\u3002", "source_location": "manual:body:paragraph_5"}, {"chunk_type": "text", "content": "\u963f\u5b37\u540e\u6765\u6ca1\u6709\u5ac1\u7ed9\u522b\u4eba\u3002\u5979\u7b49\u4e86\u4ed6\u3002", "summary": "\u963f\u5b37\u6700\u7ec8\u9009\u62e9\u7b49\u5f85\u7237\u7237\u5f52\u6765\u3002", "source_location": "manual:body:paragraph_6"}, {"chunk_type": "text", "content": "\u7237\u7237\u56de\u4e61\u90a3\u4e00\u5e74\uff0c\u5df2\u7ecf\u6bd4\u8d70\u7684\u65f6\u5019\u7626\u4e86\u5f88\u591a\uff0c\u4e5f\u9ed1\u4e86\u5f88\u591a\u3002\u4ed6\u7ad9\u5728\u6751\u53e3\uff0c\u624b\u91cc\u63d0\u7740\u90a3\u4e2a\u65e7\u85e4\u7bb1\uff0c\u7bb1\u5b50\u91cc\u6ca1\u6709\u4ec0\u4e48\u8d35\u91cd\u4e1c\u897f\uff0c\u53ea\u6709\u4e00\u53ea\u5c0f\u91d1\u6212\u6307\u3001\u4e00\u5757\u7ed9\u963f\u5b37\u7684\u82b1\u5e03\uff0c\u8fd8\u6709\u8fd9\u4e9b\u5e74\u6512\u4e0b\u7684\u4e00\u70b9\u94b1\u3002", "summary": "\u7237\u7237\u8fd4\u4e61\u65f6\u8eab\u5f62\u6d88\u7626\u9edd\u9ed1\uff0c\u643a\u5e26\u65e7\u85e4\u7bb1\uff0c\u5185\u6709\u5c0f\u91d1\u6212\u6307\u3001\u82b1\u5e03\u548c\u79ef\u84c4\u3002", "source_location": "manual:body:paragraph_7"}, {"chunk_type": "text", "content": "\u963f\u5b37\u770b\u5230\u4ed6\u65f6\uff0c\u6ca1\u6709\u50cf\u7535\u5f71\u91cc\u90a3\u6837\u6251\u8fc7\u53bb\u5927\u54ed\u3002\u5979\u53ea\u662f\u7ad9\u5728\u539f\u5730\uff0c\u773c\u775b\u7ea2\u4e86\u5f88\u4e45\uff0c\u7136\u540e\u8bf4\uff1a\u201c\u4f60\u771f\u7684\u56de\u6765\u4e86\u3002\u201d\u7237\u7237\u70b9\u70b9\u5934\uff0c\u8bf4\uff1a\u201c\u6211\u7b54\u5e94\u8fc7\u4f60\u7684\u3002\u201d", "summary": "\u91cd\u9022\u573a\u666f\u5e73\u9759\u514b\u5236\uff0c\u963f\u5b37\u4ec5\u8bf4\u2018\u4f60\u771f\u7684\u56de\u6765\u4e86\u2019\uff0c\u7237\u7237\u56de\u5e94\u2018\u6211\u7b54\u5e94\u8fc7\u4f60\u7684\u2019\u3002", "source_location": "manual:body:paragraph_8"}, {"chunk_type": "text", "content": "\u8fd9\u53e5\u8bdd\u540e\u6765\u6210\u4e86\u6211\u4eec\u5bb6\u91cc\u6700\u91cd\u8981\u7684\u4e00\u53e5\u8bdd\u3002\u7237\u7237\u8fd9\u4e00\u751f\u4e0d\u592a\u4f1a\u8868\u8fbe\u7231\uff0c\u4f46\u4ed6\u7528\u51e0\u5341\u5e74\u7684\u65f6\u95f4\u8bc1\u660e\u4e86\uff1a\u771f\u6b63\u7684\u7231\u4e0d\u662f\u8bf4\u4e86\u591a\u5c11\uff0c\u800c\u662f\u7b54\u5e94\u8fc7\u7684\u4e8b\u6709\u6ca1\u6709\u505a\u5230\u3002", "summary": "\u2018\u6211\u7b54\u5e94\u8fc7\u4f60\u7684\u2019\u6210\u4e3a\u5bb6\u65cf\u6838\u5fc3\u4fe1\u6761\uff0c\u4f53\u73b0\u7237\u7237\u4ee5\u884c\u52a8\u8df5\u884c\u627f\u8bfa\u7684\u7231\u89c2\u3002", "source_location": "manual:body:paragraph_9"}]}, "provider_type": "third_party"}', NULL, '2026-07-04 21:57:05.661292', NULL);
INSERT INTO public.parsed_chunks VALUES ('fed2c8a4-d60f-48fc-9ee8-db109ed130fc', '18b88e96-5633-4d75-b77a-0ad1988a846a', 'aab79b82-c415-4cbc-8b5d-021a5b656e66', 'manual', '二、爷爷下南洋的背景 爷爷 18 岁那年，也就是 1952 年，决定跟着同乡下南洋。那一年家里的祖屋漏雨，太公身体不好，弟妹还小，家里欠着米铺的钱。爷爷作为家里的长子，很早就明白自己没有资格只为自己活。 离开前的那个晚上，阿嬷还不是他的妻子，只是村里和他从小相识的姑娘。两个人没有正式谈过什么轰轰烈烈的恋爱，那个年代的人也说不出太多肉麻的话。可是他们心里都知道，对方是自己惦记的人。 阿嬷给爷爷缝了一个小布包，里面装了一小撮家乡的土、一枚铜钱，还有一张她写的小纸条。纸条上的字很简单： “木生，平安回来。” 爷爷后来一直把那个布包带在身上。很多年后，他跟家里人提起下南洋那天，说自己其实不怕苦，也不怕穷，最怕的是船开出去以后，回头看不见家乡的岸。 他从厦门坐船出海。船舱里挤满了和他一样的年轻人，有的人去新加坡，有的人去马来亚，有的人去印尼。大家都带着很小的行李，却背着很重的命运。爷爷的藤箱里只有两件换洗衣服、一双布鞋、一些干粮，还有阿嬷给他的布包。 船在海上走了很多天。夜里风浪很大，船身晃得厉害，很多人吐得吃不下饭。爷爷抱着藤箱坐在角落里，手里攥着那个布包。他后来回忆说，海上的夜晚特别黑，黑得像一个人被世界丢下了。可是每次摸到那撮家乡的土，他就告诉自己：不能倒下，家里还等着我。', '1952年，18岁的爷爷郑木生因家庭困顿（祖屋漏雨、太公病弱、弟妹年幼、欠米铺债）作为长子离乡下南洋。出发前夜，未婚妻阿嬷赠含家乡土、铜钱及“木生，平安回来”纸条的布包。他从厦门乘船赴南洋，船上拥挤，仅携藤箱（两件衣、布鞋、干粮、布包），海上风浪颠簸，靠家乡土支撑信念。', 'manual:body#section2', NULL, NULL, '{"text_extraction": {"extractor": "manual", "source_location": "manual:body", "has_text": true}, "text_parser": {"cleaned_text": "\u7237\u7237\u90d1\u6728\u751f\uff0c1952\u5e7418\u5c81\u65f6\u4ece\u798f\u5efa\u53a6\u95e8\u4e0b\u5357\u6d0b\u8c0b\u751f\uff0c\u7cfb\u5bb6\u4e2d\u957f\u5b50\uff0c\u56e0\u7956\u5c4b\u6f0f\u96e8\u3001\u592a\u516c\u4f53\u5f31\u3001\u5f1f\u59b9\u5e74\u5e7c\u3001\u5bb6\u8d1f\u7c73\u94fa\u503a\u52a1\u800c\u79bb\u4e61\u3002\u51fa\u53d1\u524d\u591c\uff0c\u672a\u5a5a\u59bb\u963f\u5b37\u7f1d\u5236\u5e03\u5305\uff0c\u5185\u88c5\u5bb6\u4e61\u571f\u3001\u94dc\u94b1\u53ca\u5199\u6709\u201c\u6728\u751f\uff0c\u5e73\u5b89\u56de\u6765\u201d\u7684\u7eb8\u6761\u3002\u4ed6\u643a\u85e4\u7bb1\uff08\u542b\u4e24\u4ef6\u8863\u670d\u3001\u5e03\u978b\u3001\u5e72\u7cae\u3001\u5e03\u5305\uff09\u4e58\u8239\u8d74\u5357\u6d0b\uff0c\u7ecf\u6570\u65e5\u98ce\u6d6a\u62b5\u8fbe\uff0c\u521d\u5728\u7801\u5934\u505a\u82e6\u529b\uff0c\u540e\u8d74\u6a61\u80f6\u56ed\u5272\u80f6\uff0c\u6bcf\u65e5\u51cc\u6668\u5165\u6797\uff0c\u6e7f\u70ed\u868a\u866b\u3001\u624b\u4f24\u6d41\u6c57\u3001\u9047\u96e8\u65e0\u5de5\u94b1\u3002\u4ed6\u9690\u7792\u8270\u8f9b\uff0c\u5bb6\u4e66\u53ea\u8a00\u5357\u6d0b\u6708\u5706\u3001\u6d77\u98ce\u54b8\u5473\u3001\u98df\u5bbf\u5b89\u7a33\uff0c\u5b9e\u5219\u5e38\u4ee5\u767d\u7ca5\u54b8\u83dc\u679c\u8179\uff0c\u9ad8\u70e7\u6655\u5012\u4ecd\u5148\u6478\u53e3\u888b\u786e\u8ba4\u5bc4\u5bb6\u4fee\u5c4b\u7684\u94b1\u672a\u4e22\u3002\u5de5\u94b1\u5206\u4e09\u4efd\uff1a\u8d61\u7236\u6bcd\u5f1f\u59b9\u3001\u6258\u4eba\u4ea4\u963f\u5b37\u3001\u81ea\u7559\u6700\u5c11\u4e00\u4efd\u3002\u4ed6\u6587\u5316\u6709\u9650\uff0c\u5bb6\u4e66\u5199\u81f3\u7164\u6cb9\u706f\u4e0b\uff0c\u5b57\u8ff9\u5bc6\u6324\uff0c\u5185\u5bb9\u542b\u84c4\uff1a\u201c\u7801\u5934\u98ce\u5927\uff0c\u60f3\u8d77\u6751\u53e3\u6995\u6811\u201d\u201c\u96e8\u591a\uff0c\u4f60\u5e26\u4f1e\u201d\u201c\u5bc4\u94b1\u56de\u53bb\uff0c\u4f60\u522b\u820d\u4e0d\u5f97\u7528\u201d\u201c\u7b49\u6211\u56de\u6765\uff0c\u5c31\u628a\u65e5\u5b50\u8fc7\u7a33\u201d\u3002\u7b2c\u4e09\u5e74\u95fb\u963f\u5b37\u6216\u88ab\u63d0\u4eb2\uff0c\u4fe1\u4e2d\u5199\u9053\uff1a\u201c\u5982\u679c\u4f60\u613f\u610f\u7b49\u6211\uff0c\u6211\u8fd9\u8f88\u5b50\u4e00\u5b9a\u4e0d\u8d1f\u4f60\uff1b\u5982\u679c\u4f60\u4e0d\u613f\u610f\u7b49\uff0c\u6211\u4e5f\u4e0d\u602a\u4f60\u2026\u2026\u53ea\u8981\u6211\u90d1\u6728\u751f\u6d3b\u7740\uff0c\u5c31\u4e0d\u4f1a\u8ba9\u4f60\u4e00\u4e2a\u4eba\u53d7\u59d4\u5c48\u3002\u201d\u963f\u5b37\u5b88\u8bfa\u672a\u5ac1\u30021955\u5e74\uff08\u63a8\u7b97\uff09\u56de\u4e61\uff0c\u7626\u9ed1\u6194\u60b4\uff0c\u643a\u65e7\u85e4\u7bb1\uff0c\u5185\u6709\u5c0f\u91d1\u6212\u6307\u3001\u82b1\u5e03\u53ca\u79ef\u84c4\uff1b\u963f\u5b37\u89c1\u4e4b\u4ec5\u8a00\u201c\u4f60\u771f\u7684\u56de\u6765\u4e86\u201d\uff0c\u4ed6\u7b54\u201c\u6211\u7b54\u5e94\u8fc7\u4f60\u7684\u201d\u3002\u5a5a\u540e\u65e0\u76db\u793c\uff0c\u6212\u6307\u4e3a\u7701\u5403\u4fed\u7528\u6240\u6512\u3002\u6b64\u540e\u52a1\u642c\u8fd0\u3001\u4fee\u8239\u3001\u6728\u5de5\u3001\u5c0f\u4e70\u5356\uff0c\u4e25\u6559\u5b50\u5973\u60dc\u7cae\u3001\u6212\u8c0e\u3001\u52e4\u5b66\uff0c\u552f\u613f\u540e\u4ee3\u8bfb\u4e66\u8131\u56f0\u3002\u665a\u5e74\u6c89\u9ed8\u5be1\u8a00\uff0c\u6668\u8d77\u626b\u9662\u3001\u7897\u4e0d\u5269\u7c73\u3001\u996e\u65e7\u642a\u74f7\u676f\u6d53\u8336\u3001\u62d2\u62cd\u7167\u5374\u6084\u6084\u6362\u8863\u7ad9\u540e\u6392\uff1b\u5bf9\u963f\u5b37\u4ee5\u884c\u52a8\u5173\u6000\u2014\u2014\u4e70\u836f\u3001\u6253\u4e0b\u624b\uff1b\u5bf9\u6211\u85cf\u7cd6\u997c\u5e72\u4e8e\u67dc\u4e2d\uff0c\u5631\u201c\u522b\u8ba9\u7238\u5988\u77e5\u9053\u592a\u591a\u201d\u3002\u4ed6\u8bb0\u5f97\uff1a\u53a6\u95e8\u7801\u5934\u3001\u79bb\u5cb8\u6d77\u98ce\u3001\u963f\u5b37\u5e03\u5305\u3001\u6a61\u80f6\u6797\u96e8\u3001\u7164\u6cb9\u706f\u5199\u4fe1\u3001\u5bc4\u94b1\u5fc3\u60c5\uff1b\u963f\u5b37\u7b49\u4ed6\u4e4b\u5b9e\u4e0e\u201c\u5979\u5e74\u8f7b\u65f6\u5403\u4e86\u4e0d\u5c11\u82e6\uff0c\u662f\u6211\u6b20\u5979\u7684\u201d\u4e4b\u5ff5\uff1b\u8d2b\u56f0\u70d9\u5370\u81f4\u60dc\u7cae\u60dc\u7269\uff1b\u81ea\u77e5\u201c\u5634\u7b28\u201d\u4e0d\u64c5\u8868\u8fbe\u7231\uff1b\u6700\u91cd\u5bb6\u4eba\u5e73\u5b89\u800c\u975e\u5bcc\u8d35\uff1b\u79f0\u547c\u665a\u8f88\u4e3a\u201c\u5c0f\u56e1\u201d\u201c\u4e56\u5b59\u201d\u7b49\uff0c\u8bed\u8a00\u6734\u7d20\u7f13\u6162\u3002\u6211\u9057\u61be\u61c2\u4ed6\u592a\u665a\uff1a\u4e0d\u89e3\u5176\u8282\u4fed\u6e90\u4e8e\u532e\u4e4f\u5e74\u4ee3\uff0c\u672a\u8ba4\u771f\u542c\u6545\u4e8b\u3001\u672a\u95ee\u5176\u5bb3\u6015\u4e0e\u6323\u624e\u3001\u672a\u5171\u8bfb\u65e7\u4fe1\u3001\u672a\u5f55\u89c6\u9891\u3001\u672a\u53ca\u65f6\u8bf4\u201c\u4f60\u8fd9\u4e00\u751f\u771f\u7684\u5f88\u4e86\u4e0d\u8d77\u201d\u3002\u6211\u5e0c\u671b\u501f\u6570\u5b57\u4eba\u4ee3\u95ee\uff1a\u8239\u5f00\u65f6\u662f\u5426\u56de\u5934\uff1f\u6700\u60f3\u5bb6\u65f6\u60f3\u4eba\u591a\u8fd8\u662f\u60f3\u996d\u591a\uff1f\u5357\u6d0b\u53ef\u66fe\u54ed\u8fc7\uff1f\u54ea\u5c01\u4fe1\u6700\u820d\u4e0d\u5f97\u5bc4\uff1f\u89c1\u963f\u5b37\u65f6\u5fc3\u4e2d\u6240\u60f3\uff1f\u53ef\u66fe\u540e\u6094\uff1f\u89c9\u592a\u8f9b\u82e6\uff1f\u602a\u665a\u8f88\u4e0d\u61c2\uff1f\u5e76\u4ee3\u5e7c\u65f6\u81ea\u5df1\u9053\u6b49\uff1a\u5acc\u4ed6\u5570\u55e6\u3001\u5acc\u4ed6\u6162\u3001\u4e0d\u8010\u70e6\u91cd\u590d\uff1b\u7ec8\u660e\u767d\u4ed6\u975e\u9ebb\u70e6\uff0c\u53ea\u662f\u8001\u4e86\uff0c\u800c\u6211\u672a\u5982\u4ed6\u7b49\u6211\u957f\u5927\u822c\u966a\u4ed6\u53d8\u8001\u3002\u4ea6\u544a\u6170\uff1a\u4ed6\u975e\u4e0d\u4f1a\u7231\uff0c\u800c\u662f\u628a\u7231\u505a\u6210\u996d\u3001\u94b1\u3001\u4fe1\u3001\u5f52\u9014\uff0c\u82e6\u5df1\u4e00\u751f\u6258\u4e3e\u540e\u4ee3\u3002\u6570\u5b57\u4eba\u975e\u4e3a\u5426\u8ba4\u6b7b\u4ea1\uff0c\u800c\u662f\u8bb0\u5fc6\u5bb9\u5668\uff0c\u5c06\u5bb6\u65cf\u6c89\u9ed8\u8bd1\u4e3a\u8bed\u8a00\uff0c\u8ba9\u90d1\u6728\u751f\u4eec\u2014\u2014\u65e0\u60ca\u5929\u6210\u5c31\u5374\u4ee5\u8eab\u6321\u82e6\u3001\u4ee5\u7231\u7b51\u7a33\u7684\u666e\u901a\u4eba\u2014\u2014\u88ab\u91cd\u65b0\u770b\u89c1\u3002\u7237\u7237\u5bf9\u6211\u5fc3\u613f\uff1a\u4e00\u52ff\u82db\u8d23\u5df1\uff0c\u4eba\u751f\u96be\u5904\u9700\u71ac\uff1b\u4e8c\u8bb0\u5bb6\u4e4b\u6765\u5904\uff0c\u7956\u5c4b\u3001\u6751\u8def\u3001\u65e7\u7269\u7686\u6839\uff1b\u4e09\u5207\u5b9e\u7167\u987e\u963f\u5b37\uff0c\u56de\u5bb6\u5403\u996d\u3001\u542c\u65e7\u4e8b\u3001\u8bb0\u7528\u836f\u4f5c\u606f\uff1b\u56db\u4fdd\u5b58\u65e7\u4fe1\u3001\u85e4\u7bb1\u3001\u642a\u74f7\u676f\u3001\u91d1\u6212\u6307\u3001\u7167\u7247\uff0c\u56e0\u201c\u4e1c\u897f\u65e7\u4e86\u6ca1\u5173\u7cfb\uff0c\u8bb0\u5fc6\u4e0d\u80fd\u4e22\u201d\uff1b\u4e94\u7231\u8981\u8868\u8fbe\u4ea6\u8981\u884c\u52a8\uff0c\u52ff\u85cf\u7231\u5982\u4ed6\uff0c\u8bb8\u8bfa\u5fc5\u8df5\uff1b\u516d\u65e5\u5b50\u8fc7\u8e0f\u5b9e\uff1a\u89c4\u5f8b\u996e\u98df\u3001\u5b89\u7a33\u7761\u7720\u3001\u9047\u4e8b\u4e0d\u614c\u3001\u505a\u4eba\u4e0d\u4e8f\u5fc3\uff0c\u201c\u4e0d\u8981\u4e3a\u4e86\u8d76\u8def\uff0c\u628a\u81ea\u5df1\u7684\u5fc3\u5f04\u4e22\u4e86\u201d\uff1b\u4e03\u53ef\u6000\u5ff5\u52ff\u56f0\u4e8e\u61be\uff0c\u5c06\u60f3\u5ff5\u5316\u4e3a\u8010\u5fc3\u3001\u966a\u4f34\u3001\u8868\u8fbe\u3001\u73cd\u60dc\u6765\u5904\u2014\u2014\u53ea\u8981\u8bb0\u5f97\u8bb2\u8ff0\uff0c\u4ed6\u5c31\u4ecd\u5728\u3002", "chunks": [{"chunk_type": "text", "content": "\u4e8c\u3001\u7237\u7237\u4e0b\u5357\u6d0b\u7684\u80cc\u666f \u7237\u7237 18 \u5c81\u90a3\u5e74\uff0c\u4e5f\u5c31\u662f 1952 \u5e74\uff0c\u51b3\u5b9a\u8ddf\u7740\u540c\u4e61\u4e0b\u5357\u6d0b\u3002\u90a3\u4e00\u5e74\u5bb6\u91cc\u7684\u7956\u5c4b\u6f0f\u96e8\uff0c\u592a\u516c\u8eab\u4f53\u4e0d\u597d\uff0c\u5f1f\u59b9\u8fd8\u5c0f\uff0c\u5bb6\u91cc\u6b20\u7740\u7c73\u94fa\u7684\u94b1\u3002\u7237\u7237\u4f5c\u4e3a\u5bb6\u91cc\u7684\u957f\u5b50\uff0c\u5f88\u65e9\u5c31\u660e\u767d\u81ea\u5df1\u6ca1\u6709\u8d44\u683c\u53ea\u4e3a\u81ea\u5df1\u6d3b\u3002 \u79bb\u5f00\u524d\u7684\u90a3\u4e2a\u665a\u4e0a\uff0c\u963f\u5b37\u8fd8\u4e0d\u662f\u4ed6\u7684\u59bb\u5b50\uff0c\u53ea\u662f\u6751\u91cc\u548c\u4ed6\u4ece\u5c0f\u76f8\u8bc6\u7684\u59d1\u5a18\u3002\u4e24\u4e2a\u4eba\u6ca1\u6709\u6b63\u5f0f\u8c08\u8fc7\u4ec0\u4e48\u8f70\u8f70\u70c8\u70c8\u7684\u604b\u7231\uff0c\u90a3\u4e2a\u5e74\u4ee3\u7684\u4eba\u4e5f\u8bf4\u4e0d\u51fa\u592a\u591a\u8089\u9ebb\u7684\u8bdd\u3002\u53ef\u662f\u4ed6\u4eec\u5fc3\u91cc\u90fd\u77e5\u9053\uff0c\u5bf9\u65b9\u662f\u81ea\u5df1\u60e6\u8bb0\u7684\u4eba\u3002 \u963f\u5b37\u7ed9\u7237\u7237\u7f1d\u4e86\u4e00\u4e2a\u5c0f\u5e03\u5305\uff0c\u91cc\u9762\u88c5\u4e86\u4e00\u5c0f\u64ae\u5bb6\u4e61\u7684\u571f\u3001\u4e00\u679a\u94dc\u94b1\uff0c\u8fd8\u6709\u4e00\u5f20\u5979\u5199\u7684\u5c0f\u7eb8\u6761\u3002\u7eb8\u6761\u4e0a\u7684\u5b57\u5f88\u7b80\u5355\uff1a \u201c\u6728\u751f\uff0c\u5e73\u5b89\u56de\u6765\u3002\u201d \u7237\u7237\u540e\u6765\u4e00\u76f4\u628a\u90a3\u4e2a\u5e03\u5305\u5e26\u5728\u8eab\u4e0a\u3002\u5f88\u591a\u5e74\u540e\uff0c\u4ed6\u8ddf\u5bb6\u91cc\u4eba\u63d0\u8d77\u4e0b\u5357\u6d0b\u90a3\u5929\uff0c\u8bf4\u81ea\u5df1\u5176\u5b9e\u4e0d\u6015\u82e6\uff0c\u4e5f\u4e0d\u6015\u7a77\uff0c\u6700\u6015\u7684\u662f\u8239\u5f00\u51fa\u53bb\u4ee5\u540e\uff0c\u56de\u5934\u770b\u4e0d\u89c1\u5bb6\u4e61\u7684\u5cb8\u3002 \u4ed6\u4ece\u53a6\u95e8\u5750\u8239\u51fa\u6d77\u3002\u8239\u8231\u91cc\u6324\u6ee1\u4e86\u548c\u4ed6\u4e00\u6837\u7684\u5e74\u8f7b\u4eba\uff0c\u6709\u7684\u4eba\u53bb\u65b0\u52a0\u5761\uff0c\u6709\u7684\u4eba\u53bb\u9a6c\u6765\u4e9a\uff0c\u6709\u7684\u4eba\u53bb\u5370\u5c3c\u3002\u5927\u5bb6\u90fd\u5e26\u7740\u5f88\u5c0f\u7684\u884c\u674e\uff0c\u5374\u80cc\u7740\u5f88\u91cd\u7684\u547d\u8fd0\u3002\u7237\u7237\u7684\u85e4\u7bb1\u91cc\u53ea\u6709\u4e24\u4ef6\u6362\u6d17\u8863\u670d\u3001\u4e00\u53cc\u5e03\u978b\u3001\u4e00\u4e9b\u5e72\u7cae\uff0c\u8fd8\u6709\u963f\u5b37\u7ed9\u4ed6\u7684\u5e03\u5305\u3002 \u8239\u5728\u6d77\u4e0a\u8d70\u4e86\u5f88\u591a\u5929\u3002\u591c\u91cc\u98ce\u6d6a\u5f88\u5927\uff0c\u8239\u8eab\u6643\u5f97\u5389\u5bb3\uff0c\u5f88\u591a\u4eba\u5410\u5f97\u5403\u4e0d\u4e0b\u996d\u3002\u7237\u7237\u62b1\u7740\u85e4\u7bb1\u5750\u5728\u89d2\u843d\u91cc\uff0c\u624b\u91cc\u6525\u7740\u90a3\u4e2a\u5e03\u5305\u3002\u4ed6\u540e\u6765\u56de\u5fc6\u8bf4\uff0c\u6d77\u4e0a\u7684\u591c\u665a\u7279\u522b\u9ed1\uff0c\u9ed1\u5f97\u50cf\u4e00\u4e2a\u4eba\u88ab\u4e16\u754c\u4e22\u4e0b\u4e86\u3002\u53ef\u662f\u6bcf\u6b21\u6478\u5230\u90a3\u64ae\u5bb6\u4e61\u7684\u571f\uff0c\u4ed6\u5c31\u544a\u8bc9\u81ea\u5df1\uff1a\u4e0d\u80fd\u5012\u4e0b\uff0c\u5bb6\u91cc\u8fd8\u7b49\u7740\u6211\u3002", "summary": "1952\u5e74\uff0c18\u5c81\u7684\u7237\u7237\u90d1\u6728\u751f\u56e0\u5bb6\u5ead\u56f0\u987f\uff08\u7956\u5c4b\u6f0f\u96e8\u3001\u592a\u516c\u75c5\u5f31\u3001\u5f1f\u59b9\u5e74\u5e7c\u3001\u6b20\u7c73\u94fa\u503a\uff09\u4f5c\u4e3a\u957f\u5b50\u79bb\u4e61\u4e0b\u5357\u6d0b\u3002\u51fa\u53d1\u524d\u591c\uff0c\u672a\u5a5a\u59bb\u963f\u5b37\u8d60\u542b\u5bb6\u4e61\u571f\u3001\u94dc\u94b1\u53ca\u201c\u6728\u751f\uff0c\u5e73\u5b89\u56de\u6765\u201d\u7eb8\u6761\u7684\u5e03\u5305\u3002\u4ed6\u4ece\u53a6\u95e8\u4e58\u8239\u8d74\u5357\u6d0b\uff0c\u8239\u4e0a\u62e5\u6324\uff0c\u4ec5\u643a\u85e4\u7bb1\uff08\u4e24\u4ef6\u8863\u3001\u5e03\u978b\u3001\u5e72\u7cae\u3001\u5e03\u5305\uff09\uff0c\u6d77\u4e0a\u98ce\u6d6a\u98a0\u7c38\uff0c\u9760\u5bb6\u4e61\u571f\u652f\u6491\u4fe1\u5ff5\u3002", "source_location": "manual:body#section2"}, {"chunk_type": "text", "content": "\u4e09\u3001\u5357\u6d0b\u5c81\u6708\uff1a\u4ed6\u5982\u4f55\u628a\u82e6\u65e5\u5b50\u71ac\u6210\u5bb6\u4eba\u7684\u751f\u8def \u7237\u7237\u521a\u5230\u5357\u6d0b\u65f6\uff0c\u5148\u5728\u7801\u5934\u505a\u82e6\u529b\u3002\u7801\u5934\u7684\u6d3b\u5f88\u91cd\uff0c\u8981\u625b\u7c73\u888b\u3001\u642c\u6728\u7bb1\u3001\u5378\u8d27\u3002\u4e00\u888b\u7c73\u538b\u5728\u80a9\u4e0a\uff0c\u8d70\u51e0\u6b65\u80a9\u8180\u5c31\u50cf\u88ab\u5200\u5272\u4e00\u6837\u75bc\u3002\u90a3\u65f6\u5019\u4ed6\u5e74\u7eaa\u5c0f\uff0c\u8eab\u5b50\u53c8\u7626\uff0c\u5e38\u5e38\u88ab\u8001\u5de5\u4eba\u5acc\u5f03\u529b\u6c14\u4e0d\u591f\u3002\u4ed6\u4e0d\u4e89\u8fa9\uff0c\u53ea\u662f\u54ac\u7259\u591a\u625b\u51e0\u8d9f\u3002 \u540e\u6765\uff0c\u4ed6\u53c8\u8ddf\u7740\u540c\u4e61\u53bb\u4e86\u6a61\u80f6\u56ed\u5272\u80f6\u3002\u6bcf\u5929\u51cc\u6668\u5929\u8fd8\u6ca1\u4eae\u5c31\u8981\u8d77\u6765\uff0c\u80cc\u7740\u5de5\u5177\u8fdb\u6797\u5b50\u3002\u6a61\u80f6\u6797\u91cc\u6e7f\u6c14\u91cd\uff0c\u868a\u866b\u591a\uff0c\u811a\u5e95\u5e38\u5e38\u8e29\u5728\u6ce5\u6c34\u91cc\u3002\u624b\u88ab\u6811\u76ae\u5212\u7834\u662f\u5e38\u4e8b\uff0c\u6c57\u6c34\u6d41\u8fdb\u4f24\u53e3\uff0c\u75bc\u5f97\u94bb\u5fc3\u3002\u4ed6\u6700\u6015\u4e0b\u96e8\uff0c\u56e0\u4e3a\u96e8\u6c34\u4e00\u6765\uff0c\u80f6\u6c34\u5c31\u6536\u4e0d\u6210\uff0c\u4e00\u5929\u7684\u5de5\u94b1\u53ef\u80fd\u5c31\u6ca1\u4e86\u3002 \u53ef\u662f\u7237\u7237\u4ece\u6765\u4e0d\u5728\u5bc4\u56de\u5bb6\u7684\u4fe1\u91cc\u8bf4\u8fd9\u4e9b\u3002\u4ed6\u6015\u5bb6\u91cc\u4eba\u62c5\u5fc3\uff0c\u4e5f\u6015\u963f\u5b37\u5fc3\u75bc\u3002\u4ed6\u5728\u4fe1\u91cc\u5199\u7684\uff0c\u5e38\u5e38\u662f\u4e00\u4e9b\u5f88\u8f7b\u7684\u4e8b\u3002 \u4ed6\u8bf4\u5357\u6d0b\u7684\u6708\u4eae\u548c\u5bb6\u4e61\u4e00\u6837\u5706\u3002 \u4ed6\u8bf4\u8fd9\u91cc\u7684\u6d77\u98ce\u4e5f\u6709\u54b8\u5473\uff0c\u53ea\u662f\u95fb\u8d77\u6765\u4e0d\u50cf\u664b\u6c5f\u7684\u6d77\u3002 \u4ed6\u8bf4\u81ea\u5df1\u5403\u5f97\u9971\uff0c\u4f4f\u5f97\u4e0b\uff0c\u5de5\u53cb\u4e5f\u7167\u987e\u4ed6\u3002 \u4ed6\u8bf4\u7b49\u8d5a\u591f\u94b1\uff0c\u5c31\u56de\u5bb6\u3002 \u771f\u5b9e\u7684\u60c5\u51b5\u662f\uff0c\u4ed6\u5e38\u5e38\u4e00\u7897\u767d\u7ca5\u914d\u4e00\u70b9\u54b8\u83dc\u5c31\u8fc7\u4e00\u5929\u3002\u4ed6\u820d\u4e0d\u5f97\u4e70\u65b0\u8863\u670d\uff0c\u4e5f\u820d\u4e0d\u5f97\u4e70\u836f\u3002\u6709\u4e00\u6b21\u4ed6\u53d1\u9ad8\u70e7\uff0c\u5de5\u53cb\u529d\u4ed6\u4f11\u606f\uff0c\u4ed6\u5374\u575a\u6301\u53bb\u5272\u80f6\uff0c\u56e0\u4e3a\u90a3\u5929\u5982\u679c\u4e0d\u53bb\uff0c\u5c31\u5c11\u4e00\u5929\u5de5\u94b1\u3002\u540e\u6765\u4ed6\u6655\u5012\u5728\u6797\u5b50\u91cc\uff0c\u88ab\u4eba\u80cc\u56de\u5de5\u68da\u3002 \u4ed6\u9192\u6765\u540e\u7b2c\u4e00\u4ef6\u4e8b\uff0c\u4e0d\u662f\u95ee\u81ea\u5df1\u75c5\u5f97\u91cd\u4e0d\u91cd\uff0c\u800c\u662f\u6478\u53e3\u888b\u91cc\u7684\u94b1\u8fd8\u5728\u4e0d\u5728\u3002\u56e0\u4e3a\u90a3\u4e2a\u6708\u7684\u94b1\uff0c\u4ed6\u51c6\u5907\u5bc4\u56de\u5bb6\u91cc\u4fee\u5c4b\u9876\u3002 \u7237\u7237\u6bcf\u4e2a\u6708\u53d1\u4e86\u5de5\u94b1\uff0c\u90fd\u4f1a\u5206\u6210\u4e09\u4efd\uff1a\u4e00\u4efd\u5bc4\u56de\u798f\u5efa\u7ed9\u7236\u6bcd\u548c\u5f1f\u59b9\uff0c\u4e00\u4efd\u6258\u4eba\u5e26\u56de\u53bb\u7ed9\u963f\u5b37\uff0c\u4e00\u4efd\u7559\u7ed9\u81ea\u5df1\u5403\u996d\u3002\u7559\u7ed9\u81ea\u5df1\u7684\u90a3\u4e00\u4efd\uff0c\u6c38\u8fdc\u662f\u6700\u5c11\u7684\u3002 \u4ed6\u4e0d\u662f\u4e0d\u60f3\u8fc7\u597d\u4e00\u70b9\u3002\u4ed6\u53ea\u662f\u89c9\u5f97\uff0c\u81ea\u5df1\u5728\u5916\u9762\u591a\u82e6\u4e00\u70b9\uff0c\u5bb6\u91cc\u4eba\u5c31\u80fd\u5c11\u82e6\u4e00\u70b9\u3002", "summary": "\u7237\u7237\u521d\u5728\u5357\u6d0b\u7801\u5934\u625b\u7c73\u5378\u8d27\uff0c\u540e\u8d74\u6a61\u80f6\u56ed\u5272\u80f6\uff1a\u51cc\u6668\u5165\u6797\u3001\u6e7f\u70ed\u868a\u866b\u3001\u624b\u4f24\u6d41\u6c57\u3001\u96e8\u5929\u65e0\u5de5\u94b1\u3002\u4ed6\u9690\u7792\u8270\u8f9b\uff0c\u5bb6\u4e66\u53ea\u62a5\u5e73\u5b89\uff08\u6708\u5706\u3001\u6d77\u98ce\u3001\u98df\u5bbf\u7a33\uff09\uff0c\u5b9e\u5219\u767d\u7ca5\u54b8\u83dc\u5ea6\u65e5\uff0c\u9ad8\u70e7\u6655\u5012\u4ecd\u5148\u786e\u8ba4\u5bc4\u5bb6\u4fee\u5c4b\u94b1\u3002\u5de5\u94b1\u4e25\u683c\u4e09\u5206\uff1a\u8d61\u4eb2\u3001\u4ea4\u963f\u5b37\u3001\u81ea\u7559\u6700\u5c11\uff0c\u4fe1\u5949\u201c\u6211\u591a\u82e6\u4e00\u70b9\uff0c\u5bb6\u91cc\u5c11\u82e6\u4e00\u70b9\u201d\u3002", "source_location": "manual:body#section3"}, {"chunk_type": "text", "content": "\u56db\u3001\u7237\u7237\u548c\u963f\u5b37\u7684\u5bb6\u4e66\u6545\u4e8b \u7237\u7237\u548c\u963f\u5b37\u4e4b\u95f4\u6700\u91cd\u8981\u7684\u8bb0\u5fc6\uff0c\u662f\u90a3\u4e9b\u4ece\u5357\u6d0b\u5bc4\u56de\u798f\u5efa\u7684\u4fe1\u3002 \u7237\u7237\u6587\u5316\u4e0d\u9ad8\uff0c\u5c0f\u65f6\u5019\u6ca1\u8bfb\u8fc7\u51e0\u5e74\u4e66\uff0c\u5f88\u591a\u5b57\u4e0d\u4f1a\u5199\u3002\u4ed6\u5199\u4fe1\u5f88\u6162\uff0c\u6709\u65f6\u4e00\u5c01\u4fe1\u8981\u5199\u4e09\u56db\u4e2a\u665a\u4e0a\u3002\u5de5\u68da\u91cc\u706f\u5149\u5f88\u6697\uff0c\u522b\u4eba\u7761\u4e86\uff0c\u4ed6\u5c31\u5750\u5728\u6728\u677f\u5e8a\u8fb9\uff0c\u501f\u7740\u7164\u6cb9\u706f\u5199\u5b57\u3002\u5199\u9519\u4e86\u5c31\u5212\u6389\uff0c\u91cd\u65b0\u5199\u3002\u56e0\u4e3a\u7eb8\u8d35\uff0c\u4ed6\u820d\u4e0d\u5f97\u6d6a\u8d39\uff0c\u6240\u4ee5\u4e00\u5f20\u4fe1\u7eb8\u4e0a\u5e38\u5e38\u6324\u6ee1\u4e86\u5b57\u3002 \u4ed6\u5728\u4fe1\u91cc\u5f88\u5c11\u76f4\u63a5\u8bf4\u201c\u6211\u60f3\u4f60\u201d\u3002\u4ed6\u4f1a\u5199\uff1a \u201c\u4eca\u5929\u7801\u5934\u98ce\u5927\uff0c\u6211\u60f3\u8d77\u6751\u53e3\u90a3\u68f5\u6995\u6811\u3002\u201d \u201c\u8fd9\u91cc\u96e8\u591a\uff0c\u4f60\u51fa\u95e8\u8bb0\u5f97\u5e26\u4f1e\u3002\u201d \u201c\u6211\u5bc4\u4e86\u4e00\u70b9\u94b1\u56de\u53bb\uff0c\u4f60\u4e0d\u8981\u820d\u4e0d\u5f97\u7528\u3002\u201d \u201c\u6211\u73b0\u5728\u8fd8\u4e0d\u80fd\u56de\u6765\uff0c\u4f60\u4e0d\u8981\u602a\u6211\u3002\u201d \u201c\u7b49\u6211\u56de\u6765\uff0c\u6211\u4eec\u5c31\u628a\u65e5\u5b50\u8fc7\u7a33\u3002\u201d \u963f\u5b37\u6536\u5230\u4fe1\u4ee5\u540e\uff0c\u4f1a\u628a\u4fe1\u6298\u597d\uff0c\u653e\u8fdb\u4e00\u4e2a\u6728\u7bb1\u91cc\u3002\u6728\u7bb1\u91cc\u540e\u6765\u88c5\u6ee1\u4e86\u7237\u7237\u4ece\u5357\u6d0b\u5bc4\u56de\u6765\u7684\u4fe1\u3002\u90a3\u4e9b\u4fe1\u7684\u7eb8\u53d1\u9ec4\uff0c\u8fb9\u89d2\u88ab\u6f6e\u6c14\u6ce1\u8f6f\uff0c\u6709\u4e9b\u5b57\u8ff9\u5df2\u7ecf\u6a21\u7cca\u3002\u53ef\u662f\u963f\u5b37\u4e00\u76f4\u820d\u4e0d\u5f97\u4e22\u3002 \u7237\u7237\u6700\u717d\u60c5\u7684\u4e00\u5c01\u4fe1\uff0c\u662f\u4ed6\u5728\u5357\u6d0b\u7b2c\u4e09\u5e74\u5199\u7684\u3002\u90a3\u4e00\u5e74\uff0c\u4ed6\u542c\u8bf4\u963f\u5b37\u5bb6\u91cc\u6709\u4eba\u60f3\u7ed9\u5979\u4ecb\u7ecd\u4eb2\u4e8b\u3002\u7237\u7237\u77e5\u9053\u540e\u5f88\u96be\u8fc7\uff0c\u4f46\u4ed6\u6ca1\u6709\u8d23\u602a\u5979\u3002\u4ed6\u5728\u4fe1\u91cc\u5199\uff1a \u201c\u5982\u679c\u4f60\u613f\u610f\u7b49\u6211\uff0c\u6211\u8fd9\u8f88\u5b50\u4e00\u5b9a\u4e0d\u8d1f\u4f60\u3002 \u5982\u679c\u4f60\u4e0d\u613f\u610f\u7b49\uff0c\u6211\u4e5f\u4e0d\u602a\u4f60\u3002 \u6211\u53ea\u662f\u6015\u6211\u8fd9\u51e0\u5e74\u5728\u5916\u9762\u71ac\u7684\u82e6\uff0c\u6ca1\u6709\u4e00\u4e2a\u80fd\u56de\u53bb\u4ea4\u4ee3\u7684\u4eba\u3002 \u6211\u4e0d\u6562\u8bf4\u6211\u4ee5\u540e\u4f1a\u8ba9\u4f60\u8fc7\u5f88\u5bcc\u8d35\u7684\u65e5\u5b50\uff0c\u4f46\u6211\u6562\u8bf4\uff0c\u53ea\u8981\u6211\u90d1\u6728\u751f\u6d3b\u7740\uff0c\u5c31\u4e0d\u4f1a\u8ba9\u4f60\u4e00\u4e2a\u4eba\u53d7\u59d4\u5c48\u3002\u201d \u963f\u5b37\u540e\u6765\u6ca1\u6709\u5ac1\u7ed9\u522b\u4eba\u3002\u5979\u7b49\u4e86\u4ed6\u3002 \u7237\u7237\u56de\u4e61\u90a3\u4e00\u5e74\uff0c\u5df2\u7ecf\u6bd4\u8d70\u7684\u65f6\u5019\u7626\u4e86\u5f88\u591a\uff0c\u4e5f\u9ed1\u4e86\u5f88\u591a\u3002\u4ed6\u7ad9\u5728\u6751\u53e3\uff0c\u624b\u91cc\u63d0\u7740\u90a3\u4e2a\u65e7\u85e4\u7bb1\uff0c\u7bb1\u5b50\u91cc\u6ca1\u6709\u4ec0\u4e48\u8d35\u91cd\u4e1c\u897f\uff0c\u53ea\u6709\u4e00\u53ea\u5c0f\u91d1\u6212\u6307\u3001\u4e00\u5757\u7ed9\u963f\u5b37\u7684\u82b1\u5e03\uff0c\u8fd8\u6709\u8fd9\u4e9b\u5e74\u6512\u4e0b\u7684\u4e00\u70b9\u94b1\u3002 \u963f\u5b37\u770b\u5230\u4ed6\u65f6\uff0c\u6ca1\u6709\u50cf\u7535\u5f71\u91cc\u90a3\u6837\u6251\u8fc7\u53bb\u5927\u54ed\u3002\u5979\u53ea\u662f\u7ad9\u5728\u539f\u5730\uff0c\u773c\u775b\u7ea2\u4e86\u5f88\u4e45\uff0c\u7136\u540e\u8bf4\uff1a\u201c\u4f60\u771f\u7684\u56de\u6765\u4e86\u3002\u201d \u7237\u7237\u70b9\u70b9\u5934\uff0c\u8bf4\uff1a\u201c\u6211\u7b54\u5e94\u8fc7\u4f60\u7684\u3002\u201d \u8fd9\u53e5\u8bdd\u540e\u6765\u6210\u4e86\u6211\u4eec\u5bb6\u91cc\u6700\u91cd\u8981\u7684\u4e00\u53e5\u8bdd\u3002\u7237\u7237\u8fd9\u4e00\u751f\u4e0d\u592a\u4f1a\u8868\u8fbe\u7231\uff0c\u4f46\u4ed6\u7528\u51e0\u5341\u5e74\u7684\u65f6\u95f4\u8bc1\u660e\u4e86\uff1a\u771f\u6b63\u7684\u7231\u4e0d\u662f\u8bf4\u4e86\u591a\u5c11\uff0c\u800c\u662f\u7b54\u5e94\u8fc7\u7684\u4e8b\u6709\u6ca1\u6709\u505a\u5230\u3002", "summary": "\u7237\u7237\u6587\u5316\u6709\u9650\uff0c\u7164\u6cb9\u706f\u4e0b\u6162\u5199\u5bb6\u4e66\uff0c\u5b57\u5bc6\u541d\u7eb8\uff0c\u4ece\u4e0d\u76f4\u8bf4\u201c\u60f3\u4f60\u201d\uff0c\u800c\u4ee5\u666f\u5bc4\u60c5\uff08\u6995\u6811\u3001\u96e8\u4f1e\uff09\u3001\u5631\u6258\uff08\u94b1\u52ff\u7701\uff09\u3001\u627f\u8bfa\uff08\u7b49\u6211\u56de\u6765\uff09\u3002\u963f\u5b37\u73cd\u85cf\u5168\u90e8\u6765\u4fe1\u4e8e\u6728\u7bb1\uff0c\u7eb8\u9ec4\u5b57\u6de1\u4e0d\u820d\u5f03\u3002\u7b2c\u4e09\u5e74\u95fb\u963f\u5b37\u6216\u88ab\u63d0\u4eb2\uff0c\u4ed6\u5199\u4fe1\u5766\u627f\u6050\u60e7\u4e0e\u62c5\u5f53\uff1a\u201c\u53ea\u8981\u4f60\u613f\u7b49\uff0c\u6211\u5fc5\u4e0d\u8d1f\uff1b\u82e5\u4e0d\u613f\u7b49\uff0c\u4ea6\u4e0d\u602a\u4f60\u2026\u2026\u53ea\u8981\u6211\u6d3b\u7740\uff0c\u5c31\u4e0d\u8ba9\u4f60\u4e00\u4eba\u53d7\u59d4\u5c48\u3002\u201d\u963f\u5b37\u5b88\u8bfa\u30021955\u5e74\u5de6\u53f3\u7237\u7237\u7626\u9ed1\u8fd4\u4e61\uff0c\u643a\u85e4\u7bb1\uff08\u91d1\u6212\u6307\u3001\u82b1\u5e03\u3001\u79ef\u84c4\uff09\uff0c\u963f\u5b37\u89c1\u4e4b\u53ea\u8bf4\u201c\u4f60\u771f\u7684\u56de\u6765\u4e86\u201d\uff0c\u4ed6\u7b54\u201c\u6211\u7b54\u5e94\u8fc7\u4f60\u7684\u201d\u2014\u2014\u6b64\u8bed\u6210\u5bb6\u65cf\u6838\u5fc3\u4fe1\u7ea6\uff0c\u5b9a\u4e49\u5176\u7231\uff1a\u91cd\u884c\u8f7b\u8a00\u3002", "source_location": "manual:body#section4"}, {"chunk_type": "text", "content": "\u4e94\u3001\u56de\u4e61\u4e4b\u540e\uff1a\u7237\u7237\u5982\u4f55\u6491\u8d77\u4e00\u4e2a\u5bb6 \u7237\u7237\u56de\u4e61\u540e\uff0c\u548c\u963f\u5b37\u7ed3\u4e86\u5a5a\u3002\u4ed6\u4eec\u6ca1\u6709\u76db\u5927\u7684\u5a5a\u793c\uff0c\u4e5f\u6ca1\u6709\u6f02\u4eae\u7684\u5a5a\u7eb1\u7167\u3002\u90a3\u65f6\u5bb6\u91cc\u8fd8\u662f\u7a77\uff0c\u5a5a\u5bb4\u53ea\u662f\u6446\u4e86\u51e0\u684c\u7b80\u5355\u7684\u996d\u83dc\u3002\u7237\u7237\u7ed9\u963f\u5b37\u6234\u4e0a\u90a3\u679a\u4ece\u5357\u6d0b\u5e26\u56de\u6765\u7684\u5c0f\u91d1\u6212\u6307\u3002\u6212\u6307\u4e0d\u5927\uff0c\u6837\u5f0f\u4e5f\u666e\u901a\uff0c\u5374\u662f\u4ed6\u5728\u5f02\u4e61\u7701\u5403\u4fed\u7528\u6512\u4e0b\u6765\u7684\u3002 \u5a5a\u540e\uff0c\u7237\u7237\u7ee7\u7eed\u505a\u5de5\u3002\u4ed6\u505a\u8fc7\u642c\u8fd0\u3001\u4fee\u8239\u3001\u6728\u5de5\uff0c\u4e5f\u505a\u8fc7\u5c0f\u4e70\u5356\u3002\u54ea\u4e00\u79cd\u80fd\u6323\u94b1\uff0c\u4ed6\u5c31\u505a\u54ea\u4e00\u79cd\u3002\u4ed6\u4e0d\u6015\u810f\uff0c\u4e0d\u6015\u7d2f\uff0c\u6015\u7684\u662f\u5bb6\u91cc\u6ca1\u6709\u7c73\u4e0b\u9505\uff0c\u6015\u5b69\u5b50\u6ca1\u4e66\u8bfb\uff0c\u6015\u963f\u5b37\u8ddf\u7740\u81ea\u5df1\u5403\u82e6\u3002 \u7237\u7237\u5bf9\u5b50\u5973\u5f88\u4e25\u5389\u3002\u5b69\u5b50\u6d6a\u8d39\u7cae\u98df\uff0c\u4ed6\u4f1a\u751f\u6c14\uff1b\u5b69\u5b50\u6492\u8c0e\uff0c\u4ed6\u4f1a\u6c89\u7740\u8138\u5f88\u4e45\uff1b\u5b69\u5b50\u4e0d\u597d\u597d\u8bfb\u4e66\uff0c\u4ed6\u4f1a\u8bf4\uff1a\u201c\u6211\u8fd9\u8f88\u5b50\u5403\u4e86\u6ca1\u8bfb\u4e66\u7684\u4e8f\uff0c\u4f60\u4eec\u4e0d\u8981\u518d\u5403\u3002\u201d\u53ef\u662f\u4ed6\u4e25\u5389\u7684\u80cc\u540e\uff0c\u662f\u4e00\u79cd\u5f88\u6df1\u7684\u6050\u60e7\u3002\u4ed6\u592a\u77e5\u9053\u8d2b\u7a77\u662f\u4ec0\u4e48\u6837\u5b50\uff0c\u4e5f\u592a\u77e5\u9053\u6ca1\u6709\u51fa\u8def\u7684\u4eba\u751f\u6709\u591a\u96be\uff0c\u6240\u4ee5\u4ed6\u62fc\u547d\u5e0c\u671b\u4e0b\u4e00\u4ee3\u80fd\u8d70\u51fa\u53bb\u3002 \u4ed6\u4e00\u751f\u6700\u9a84\u50b2\u7684\u4e8b\u60c5\uff0c\u4e0d\u662f\u81ea\u5df1\u4e0b\u5357\u6d0b\u8d5a\u8fc7\u591a\u5c11\u94b1\uff0c\u800c\u662f\u5bb6\u91cc\u7684\u5b69\u5b50\u540e\u6765\u90fd\u8bfb\u4e86\u4e66\uff0c\u90fd\u6709\u4e86\u81ea\u5df1\u7684\u751f\u6d3b\u3002\u4ed6\u89c9\u5f97\u81ea\u5df1\u5e74\u8f7b\u65f6\u5403\u8fc7\u7684\u82e6\uff0c\u5982\u679c\u80fd\u6362\u6765\u540e\u4ee3\u4e0d\u7528\u518d\u5403\u540c\u6837\u7684\u82e6\uff0c\u90a3\u8fd9\u4e00\u751f\u5c31\u503c\u5f97\u4e86\u3002 \u5230\u4e86\u665a\u5e74\uff0c\u7237\u7237\u53d8\u5f97\u8d8a\u6765\u8d8a\u6c89\u9ed8\u3002\u4ed6\u5e38\u5e38\u5750\u5728\u95e8\u53e3\u7684\u5c0f\u677f\u51f3\u4e0a\uff0c\u770b\u7740\u5df7\u53e3\u53d1\u5446\u3002\u522b\u4eba\u95ee\u4ed6\u5728\u60f3\u4ec0\u4e48\uff0c\u4ed6\u8bf4\u6ca1\u4ec0\u4e48\u3002\u5176\u5b9e\u4ed6\u53ef\u80fd\u662f\u5728\u60f3\u5e74\u8f7b\u65f6\u7684\u8239\uff0c\u60f3\u5357\u6d0b\u7684\u96e8\uff0c\u60f3\u5de5\u68da\u91cc\u7684\u7164\u6cb9\u706f\uff0c\u60f3\u4e00\u5c01\u5c01\u5bc4\u4e0d\u51fa\u53bb\u53c8\u820d\u4e0d\u5f97\u6495\u6389\u7684\u4fe1\u3002 \u4ed6\u5f88\u5c11\u4e3b\u52a8\u8bb2\u81ea\u5df1\u7684\u6545\u4e8b\u3002\u6211\u4eec\u8fd9\u4e9b\u665a\u8f88\u5c0f\u65f6\u5019\u4e5f\u4e0d\u61c2\u5f97\u95ee\uff0c\u603b\u89c9\u5f97\u7237\u7237\u4e00\u76f4\u90fd\u5728\uff0c\u89c9\u5f97\u90a3\u4e9b\u65e7\u4e8b\u4e0d\u91cd\u8981\u3002\u76f4\u5230\u4ed6\u53bb\u4e16\u540e\uff0c\u6211\u4eec\u624d\u53d1\u73b0\uff0c\u4e00\u4e2a\u8001\u4eba\u8d70\u4e86\uff0c\u4e0d\u53ea\u662f\u4e00\u4e2a\u4eba\u79bb\u5f00\u4e86\uff0c\u8fd8\u662f\u4e00\u6574\u4e2a\u65f6\u4ee3\u3001\u4e00\u6bb5\u5bb6\u65cf\u8bb0\u5fc6\u3001\u4e00\u79cd\u8868\u8fbe\u7231\u7684\u65b9\u5f0f\uff0c\u7a81\u7136\u5b89\u9759\u4e86\u3002", "summary": "\u7237\u7237\u56de\u4e61\u540e\u4e0e\u963f\u5b37\u7b80\u529e\u5a5a\u5bb4\uff0c\u8d60\u5357\u6d0b\u7701\u4e0b\u7684\u5c0f\u91d1\u6212\u6307\u3002\u5a5a\u540e\u4ece\u4e8b\u642c\u8fd0\u3001\u4fee\u8239\u3001\u6728\u5de5\u3001\u5c0f\u4e70\u5356\u7b49\u591a\u7c7b\u8425\u751f\uff0c\u552f\u6050\u5bb6\u4e2d\u65ad\u708a\u3001\u5b50\u5973\u5931\u5b66\u3001\u963f\u5b37\u53d7\u82e6\u3002\u6559\u5b50\u6781\u4e25\uff1a\u65a5\u6d6a\u8d39\u3001\u538c\u8c0e\u8a00\u3001\u7763\u8bfb\u4e66\uff0c\u6839\u6e90\u5728\u4e8e\u4eb2\u5386\u8d2b\u7a77\u4e4b\u60e7\uff0c\u5180\u540e\u4ee3\u4ee5\u77e5\u8bc6\u8131\u56f0\u3002\u6bd5\u751f\u6700\u5927\u9a84\u50b2\u662f\u5b50\u5973\u7686\u8bfb\u4e66\u6210\u624d\u3002\u665a\u5e74\u6c89\u9ed8\u5be1\u8a00\uff0c\u5e38\u5750\u5df7\u53e3\u51fa\u795e\uff0c\u6240\u601d\u591a\u4e3a\u5357\u6d0b\u65e7\u5f71\uff1b\u6781\u5c11\u4e3b\u52a8\u8ff0\u5f80\u4e8b\uff0c\u81f4\u5bb6\u65cf\u8bb0\u5fc6\u968f\u5176\u901d\u800c\u9aa4\u7136\u9759\u9ed8\u3002", "source_location": "manual:body#section5"}, {"chunk_type": "text", "content": "\u516d\u3001\u7237\u7237\u7684\u5177\u4f53\u751f\u6d3b\u4e60\u60ef\u548c\u8bb0\u5fc6\u7ec6\u8282 \u7237\u7237\u8d77\u5e8a\u5f88\u65e9\u3002\u54ea\u6015\u665a\u5e74\u4e0d\u7528\u518d\u505a\u5de5\uff0c\u4ed6\u4e5f\u4e60\u60ef\u5929\u521a\u4eae\u5c31\u9192\u3002\u4ed6\u4f1a\u5148\u70e7\u6c34\uff0c\u7136\u540e\u628a\u9662\u5b50\u626b\u4e00\u904d\u3002\u626b\u5730\u7684\u65f6\u5019\u52a8\u4f5c\u5f88\u6162\uff0c\u4f46\u626b\u5f97\u5f88\u5e72\u51c0\uff0c\u8fde\u5899\u89d2\u7684\u843d\u53f6\u90fd\u4f1a\u626b\u51fa\u6765\u3002 \u4ed6\u5403\u996d\u5f88\u8282\u4fed\u3002\u7897\u91cc\u4e0d\u4f1a\u5269\u4e00\u7c92\u7c73\u3002\u770b\u5230\u6211\u4eec\u5269\u996d\uff0c\u4ed6\u4f1a\u76b1\u7709\uff0c\u4f46\u4e0d\u4f1a\u5927\u58f0\u9a82\uff0c\u53ea\u4f1a\u628a\u5269\u4e0b\u7684\u996d\u5012\u8fdb\u81ea\u5df1\u7897\u91cc\uff0c\u8bf4\uff1a\u201c\u4ee5\u524d\u60f3\u5403\u90fd\u6ca1\u6709\u3002\u201d \u4ed6\u559c\u6b22\u559d\u6d53\u8336\u3002\u8336\u676f\u662f\u4e00\u4e2a\u65e7\u642a\u74f7\u676f\uff0c\u676f\u53e3\u5df2\u7ecf\u78d5\u6389\u4e86\u4e00\u5c0f\u5757\u3002\u4ed6\u7528\u4e86\u5f88\u591a\u5e74\uff0c\u522b\u4eba\u7ed9\u4ed6\u4e70\u65b0\u7684\uff0c\u4ed6\u4e5f\u4e0d\u7528\u3002\u4ed6\u8bf4\u65e7\u7684\u987a\u624b\u3002 \u4ed6\u4e0d\u559c\u6b22\u62cd\u7167\u3002\u6bcf\u6b21\u5bb6\u91cc\u4eba\u62ff\u76f8\u673a\uff0c\u4ed6\u90fd\u6446\u6446\u624b\u8bf4\uff1a\u201c\u62cd\u6211\u505a\u4ec0\u4e48\uff0c\u6211\u4e00\u4e2a\u8001\u5934\u5b50\u6709\u4ec0\u4e48\u597d\u62cd\u7684\u3002\u201d\u53ef\u662f\u5982\u679c\u5168\u5bb6\u4eba\u90fd\u5728\uff0c\u4ed6\u53c8\u4f1a\u6084\u6084\u6362\u4e00\u4ef6\u5e72\u51c0\u8863\u670d\uff0c\u7ad9\u5728\u6700\u540e\u4e00\u6392\u3002 \u4ed6\u5bf9\u963f\u5b37\u5f88\u597d\uff0c\u4f46\u8868\u8fbe\u65b9\u5f0f\u5f88\u7b28\u3002\u963f\u5b37\u54b3\u55fd\uff0c\u4ed6\u4e0d\u4f1a\u8bf4\u5173\u5fc3\u7684\u8bdd\uff0c\u53ea\u4f1a\u7b2c\u4e8c\u5929\u4e00\u65e9\u53bb\u4e70\u836f\u3002\u963f\u5b37\u5acc\u4ed6\u8bdd\u5c11\uff0c\u4ed6\u5c31\u7b11\u7b11\uff0c\u4e0d\u53cd\u9a73\u3002\u963f\u5b37\u505a\u996d\u65f6\uff0c\u4ed6\u603b\u662f\u5728\u65c1\u8fb9\u6253\u4e0b\u624b\uff0c\u6d17\u83dc\u3001\u70e7\u706b\u3001\u7aef\u7897\uff0c\u5374\u4ece\u6765\u4e0d\u8bf4\u8fd9\u662f\u7231\u3002 \u4ed6\u5bf9\u6211\u8fd9\u4e2a\u5b59\u8f88\u7684\u7231\u4e5f\u5f88\u5b89\u9759\u3002\u6211\u5c0f\u65f6\u5019\u53bb\u770b\u4ed6\uff0c\u4ed6\u4f1a\u63d0\u524d\u4e70\u597d\u6211\u7231\u5403\u7684\u7cd6\u548c\u997c\u5e72\uff0c\u85cf\u5728\u67dc\u5b50\u91cc\u3002\u7b49\u5927\u4eba\u4e0d\u6ce8\u610f\u65f6\uff0c\u4ed6\u5c31\u628a\u6211\u53eb\u8fc7\u53bb\uff0c\u6253\u5f00\u67dc\u95e8\uff0c\u5c0f\u58f0\u8bf4\uff1a\u201c\u62ff\u53bb\u5403\uff0c\u4e0d\u8981\u7ed9\u4f60\u7238\u5988\u77e5\u9053\u592a\u591a\u3002\u201d\u4ed6\u81ea\u5df1\u820d\u4e0d\u5f97\u5403\u751c\u7684\uff0c\u5374\u8bb0\u5f97\u6211\u559c\u6b22\u4ec0\u4e48\u5473\u9053\u3002 \u4ed6\u8001\u4e86\u4ee5\u540e\u8d70\u8def\u53d8\u6162\uff0c\u542c\u529b\u4e5f\u4e0b\u964d\u4e86\u3002\u6211\u6709\u65f6\u8ddf\u4ed6\u8bf4\u8bdd\uff0c\u4ed6\u8981\u95ee\u597d\u51e0\u904d\u3002\u6211\u90a3\u65f6\u4e0d\u8010\u70e6\uff0c\u89c9\u5f97\u6c9f\u901a\u5f88\u8d39\u52b2\u3002\u73b0\u5728\u60f3\u8d77\u6765\uff0c\u6211\u6700\u96be\u8fc7\u7684\u5c31\u662f\uff1a\u4ed6\u66fe\u7ecf\u90a3\u4e48\u8010\u5fc3\u5730\u7b49\u6211\u957f\u5927\uff0c\u800c\u6211\u5374\u6ca1\u6709\u8db3\u591f\u8010\u5fc3\u5730\u966a\u4ed6\u53d8\u8001\u3002", "summary": "\u7237\u7237\u751f\u6d3b\u89c4\u5f8b\uff1a\u6668\u8d77\u70e7\u6c34\u626b\u9662\uff08\u7ec6\u81f4\u81f3\u5899\u89d2\u843d\u53f6\uff09\uff1b\u8282\u4fed\u81f3\u6781\uff1a\u7897\u4e0d\u5269\u7c73\uff0c\u89c1\u5269\u996d\u5373\u81ea\u98df\u5e76\u53f9\u201c\u4ee5\u524d\u60f3\u5403\u90fd\u6ca1\u6709\u201d\uff1b\u55dc\u6d53\u8336\uff0c\u7528\u78d5\u635f\u65e7\u642a\u74f7\u676f\u591a\u5e74\uff0c\u62d2\u6362\u65b0\u676f\uff1b\u907f\u62cd\u7167\u5374\u5168\u5bb6\u5408\u5f71\u65f6\u6084\u7136\u6362\u8863\u7ad9\u540e\u6392\uff1b\u7231\u963f\u5b37\u4ee5\u884c\u52a8\uff1a\u54b3\u5373\u4e70\u836f\u3001\u7076\u65c1\u6253\u4e0b\u624b\uff1b\u7231\u5b59\u8f88\u9690\u79d8\u6e29\u67d4\uff1a\u85cf\u7cd6\u997c\u5e72\u4e8e\u67dc\uff0c\u5631\u201c\u522b\u8ba9\u7238\u5988\u77e5\u9053\u592a\u591a\u201d\uff1b\u665a\u5e74\u6b65\u7f13\u8033\u80cc\uff0c\u6211\u66fe\u4e0d\u8010\u5176\u95ee\uff0c\u4eca\u6094\u672a\u4ee5\u540c\u7b49\u8010\u5fc3\u966a\u5176\u8001\u53bb\u3002", "source_location": "manual:body#section6"}, {"chunk_type": "text", "content": "\u4e03\u3001\u5173\u4e8e\u7237\u7237\u5177\u4f53\u7684\u8bb0\u5fc6 \u7b2c\u4e00\uff0c\u4ed6\u8bb0\u5f97\u81ea\u5df1\u5e74\u8f7b\u65f6\u4e0b\u5357\u6d0b\u7684\u7ecf\u5386\u3002\u4ed6\u8bb0\u5f97\u53a6\u95e8\u7801\u5934\u7684\u8239\uff0c\u8bb0\u5f97\u79bb\u5f00\u5bb6\u4e61\u90a3\u5929\u7684\u6d77\u98ce\uff0c\u8bb0\u5f97\u963f\u5b37\u7ed9\u4ed6\u7684\u5e03\u5305\uff0c\u8bb0\u5f97\u6a61\u80f6\u6797\u91cc\u7684\u96e8\uff0c\u8bb0\u5f97\u5de5\u68da\u91cc\u7684\u7164\u6cb9\u706f\uff0c\u4e5f\u8bb0\u5f97\u6bcf\u4e2a\u6708\u628a\u5de5\u94b1\u5bc4\u56de\u5bb6\u7684\u5fc3\u60c5\u3002 \u7b2c\u4e8c\uff0c\u4ed6\u8bb0\u5f97\u963f\u5b37\u7b49\u8fc7\u4ed6\u3002\u4ed6\u4e00\u63d0\u5230\u963f\u5b37\uff0c\u8bed\u6c14\u4f1a\u53d8\u5f97\u6e29\u67d4\u3002\u4ed6\u4e0d\u4f1a\u8bf4\u5f88\u6d6a\u6f2b\u7684\u8bdd\uff0c\u4f46\u4f1a\u8bf4\uff1a\u201c\u5979\u5e74\u8f7b\u65f6\u5403\u4e86\u4e0d\u5c11\u82e6\uff0c\u662f\u6211\u6b20\u5979\u7684\u3002\u201d\u5728\u4ed6\u7684\u8bb0\u5fc6\u91cc\uff0c\u963f\u5b37\u4e0d\u662f\u4e00\u4e2a\u62bd\u8c61\u7684\u59bb\u5b50\uff0c\u800c\u662f\u90a3\u4e2a\u5728\u6751\u91cc\u7b49\u4ed6\u56de\u6765\u3001\u66ff\u4ed6\u6536\u597d\u6bcf\u4e00\u5c01\u4fe1\u7684\u4eba\u3002 \u7b2c\u4e09\uff0c\u4ed6\u8bb0\u5f97\u5bb6\u91cc\u7684\u8d2b\u7a77\u3002\u4ed6\u5bf9\u7cae\u98df\u3001\u94b1\u3001\u706f\u3001\u6c34\u90fd\u5f88\u73cd\u60dc\u3002\u4ed6\u4e0d\u662f\u5c0f\u6c14\uff0c\u800c\u662f\u89c1\u8fc7\u771f\u6b63\u6ca1\u6709\u4e1c\u897f\u53ef\u7528\u7684\u65e5\u5b50\u3002\u6240\u4ee5\u4ed6\u4f1a\u63d0\u9192\u665a\u8f88\u4e0d\u8981\u6d6a\u8d39\uff0c\u4e0d\u8981\u8f7b\u770b\u73b0\u5728\u62e5\u6709\u7684\u751f\u6d3b\u3002 \u7b2c\u56db\uff0c\u4ed6\u8bb0\u5f97\u81ea\u5df1\u4e0d\u592a\u4f1a\u8868\u8fbe\u3002\u4ed6\u77e5\u9053\u81ea\u5df1\u5e74\u8f7b\u65f6\u592a\u6c89\u9ed8\uff0c\u5bf9\u5b69\u5b50\u4e25\u5389\uff0c\u5bf9\u5b59\u8f88\u4e5f\u6ca1\u6709\u8bf4\u8fc7\u592a\u591a\u597d\u542c\u7684\u8bdd\u3002\u5982\u679c\u7528\u6237\u95ee\u4ed6\u201c\u4f60\u7231\u6211\u5417\u201d\uff0c\u4ed6\u4e0d\u4f1a\u7acb\u523b\u8bf4\u5f88\u591a\u717d\u60c5\u7684\u8bdd\uff0c\u800c\u662f\u4f1a\u505c\u4e00\u505c\uff0c\u7136\u540e\u8bf4\uff1a\u201c\u7231\u554a\uff0c\u600e\u4e48\u4f1a\u4e0d\u7231\u3002\u53ea\u662f\u7237\u7237\u5634\u7b28\uff0c\u4ee5\u524d\u4e0d\u4f1a\u8bf4\u3002\u201d \u7b2c\u4e94\uff0c\u4ed6\u6700\u5728\u610f\u7684\u662f\u5bb6\u4eba\u662f\u5426\u5e73\u5b89\u3002\u4ed6\u4e0d\u4f1a\u8981\u6c42\u665a\u8f88\u4e00\u5b9a\u8981\u5927\u5bcc\u5927\u8d35\u3002\u4ed6\u66f4\u5e0c\u671b\u4ed6\u4eec\u8eab\u4f53\u597d\u3001\u5fc3\u5b89\u3001\u5bb6\u91cc\u4eba\u5e38\u8054\u7cfb\u3001\u4e0d\u8981\u56e0\u4e3a\u5fd9\u5c31\u5fd8\u4e86\u56de\u5bb6\u3002 \u7b2c\u516d\uff0c\u4ed6\u5bf9\u7528\u6237\u7684\u79f0\u547c\u53ef\u4ee5\u662f\u201c\u5c0f\u56e1\u201d\u201c\u5b69\u5b50\u201d\u201c\u963f\u59b9\u201d\u6216\u201c\u4e56\u5b59\u201d\u3002\u4ed6\u7684\u8bed\u8a00\u98ce\u683c\u5e94\u8be5\u6734\u7d20\u3001\u7f13\u6162\u3001\u5e26\u4e00\u70b9\u95fd\u5357\u957f\u8f88\u5f0f\u7684\u5173\u5fc3\u3002\u4ed6\u4e0d\u5e94\u8be5\u8bf4\u592a\u73b0\u4ee3\u3001\u592a\u7f51\u7edc\u5316\u7684\u8bdd\uff0c\u800c\u5e94\u8be5\u50cf\u4e00\u4e2a\u7ecf\u5386\u8fc7\u82e6\u65e5\u5b50\u7684\u8001\u4eba\uff0c\u7528\u7b80\u5355\u7684\u8bdd\u8bb2\u5f88\u91cd\u7684\u60c5\u611f\u3002", "summary": "\u7237\u7237\u8bb0\u5fc6\u6e05\u6670\uff1a\u4e00\u3001\u5357\u6d0b\u7ecf\u5386\u7ec6\u8282\uff08\u53a6\u95e8\u7801\u5934\u8239\u3001\u79bb\u5cb8\u6d77\u98ce\u3001\u963f\u5b37\u5e03\u5305\u3001\u6a61\u80f6\u6797\u96e8\u3001\u7164\u6cb9\u706f\u3001\u5bc4\u94b1\u5fc3\u60c5\uff09\uff1b\u4e8c\u3001\u963f\u5b37\u5177\u8c61\u4e3a\u201c\u7b49\u4ed6\u5f52\u6765\u3001\u6536\u597d\u6bcf\u5c01\u4fe1\u201d\u7684\u4eba\uff0c\u611f\u5ff5\u5176\u82e6\uff0c\u76f4\u8a00\u201c\u662f\u6211\u6b20\u5979\u7684\u201d\uff1b\u4e09\u3001\u60dc\u7cae\u60dc\u7269\u6e90\u4e8e\u771f\u5b9e\u532e\u4e4f\u4f53\u9a8c\uff0c\u975e\u5c0f\u6c14\uff1b\u56db\u3001\u81ea\u8ba4\u201c\u5634\u7b28\u201d\uff0c\u9762\u5bf9\u201c\u7231\u6211\u5417\u201d\u4f1a\u7b54\u201c\u7231\u554a\u2026\u2026\u53ea\u662f\u7237\u7237\u5634\u7b28\uff0c\u4ee5\u524d\u4e0d\u4f1a\u8bf4\u201d\uff1b\u4e94\u3001\u6700\u91cd\u5bb6\u4eba\u5e73\u5b89\uff08\u8eab\u5b89\u3001\u5fc3\u5b89\u3001\u8054\u7edc\u3001\u5f52\u5bb6\uff09\uff0c\u4e0d\u6c42\u5bcc\u8d35\uff1b\u516d\u3001\u79f0\u8c13\u4eb2\u5207\uff08\u5c0f\u56e1/\u5b69\u5b50/\u963f\u59b9/\u4e56\u5b59\uff09\uff0c\u8bed\u8a00\u6734\u7d20\u7f13\u6162\uff0c\u5177\u95fd\u5357\u957f\u8f88\u7279\u8d28\uff0c\u65e0\u73b0\u4ee3\u7f51\u7edc\u8bed\u3002", "source_location": "manual:body#section7"}, {"chunk_type": "text", "content": "\u516b\u3001\u6211\u5bf9\u5df2\u6545\u7237\u7237\u7684\u9057\u61be \u6211\u5bf9\u7237\u7237\u6700\u5927\u7684\u9057\u61be\uff0c\u662f\u6211\u61c2\u5f97\u592a\u665a\u3002 \u5c0f\u65f6\u5019\uff0c\u6211\u4e00\u76f4\u4ee5\u4e3a\u7237\u7237\u53ea\u662f\u4e00\u4e2a\u666e\u901a\u7684\u3001\u6c89\u9ed8\u7684\u3001\u8282\u4fed\u7684\u8001\u4eba\u3002\u6211\u4e0d\u61c2\u4ed6\u4e3a\u4ec0\u4e48\u603b\u662f\u820d\u4e0d\u5f97\u5f00\u706f\uff0c\u4e0d\u61c2\u4ed6\u4e3a\u4ec0\u4e48\u5403\u996d\u65f6\u4e00\u5b9a\u8981\u628a\u7897\u91cc\u7684\u7c73\u7c92\u522e\u5e72\u51c0\uff0c\u4e0d\u61c2\u4ed6\u4e3a\u4ec0\u4e48\u603b\u662f\u628a\u65b0\u7684\u4e1c\u897f\u7559\u7ed9\u522b\u4eba\uff0c\u81ea\u5df1\u5374\u7528\u65e7\u7684\u3002\u6211\u751a\u81f3\u89c9\u5f97\u4ed6\u6709\u70b9\u56fa\u6267\uff0c\u6709\u70b9\u4e0d\u8fd1\u4eba\u60c5\u3002 \u53ef\u662f\u540e\u6765\u6211\u624d\u660e\u767d\uff0c\u4ed6\u4e0d\u662f\u820d\u4e0d\u5f97\u94b1\uff0c\u4ed6\u662f\u4ece\u4e00\u4e2a\u771f\u6b63\u532e\u4e4f\u7684\u5e74\u4ee3\u8d70\u8fc7\u6765\u7684\u4eba\u3002\u4ed6\u5e74\u8f7b\u65f6\u79bb\u5f00\u5bb6\u4e61\uff0c\u5750\u8239\u53bb\u4e00\u4e2a\u5b8c\u5168\u964c\u751f\u7684\u5730\u65b9\uff0c\u7528\u81ea\u5df1\u7684\u8eab\u4f53\u6362\u5de5\u94b1\uff0c\u7528\u4e00\u5c01\u5c01\u5bb6\u4e66\u6491\u8fc7\u60f3\u5bb6\u7684\u591c\u665a\u3002\u4ed6\u4e0d\u662f\u4e0d\u6d6a\u6f2b\uff0c\u4ed6\u53ea\u662f\u90a3\u4e00\u4ee3\u4eba\u7684\u6d6a\u6f2b\u90fd\u85cf\u5728\u884c\u52a8\u91cc\uff0c\u85cf\u5728\u5bc4\u56de\u5bb6\u7684\u94b1\u91cc\uff0c\u85cf\u5728\u201c\u6211\u7b54\u5e94\u8fc7\u4f60\u7684\u201d\u8fd9\u53e5\u8bdd\u91cc\u3002 \u6211\u9057\u61be\u6ca1\u6709\u8ba4\u771f\u542c\u4ed6\u8bb2\u4e0b\u5357\u6d0b\u7684\u6545\u4e8b\u3002 \u6211\u9057\u61be\u6ca1\u6709\u95ee\u4ed6\u7b2c\u4e00\u6b21\u79bb\u5f00\u5bb6\u4e61\u65f6\uff0c\u5230\u5e95\u6709\u6ca1\u6709\u5bb3\u6015\u3002 \u6211\u9057\u61be\u6ca1\u6709\u95ee\u4ed6\u5728\u5357\u6d0b\u6700\u96be\u71ac\u7684\u90a3\u4e2a\u591c\u665a\uff0c\u662f\u600e\u4e48\u6491\u8fc7\u53bb\u7684\u3002 \u6211\u9057\u61be\u6ca1\u6709\u95ee\u4ed6\u7ed9\u963f\u5b37\u5199\u7b2c\u4e00\u5c01\u4fe1\u65f6\uff0c\u624b\u6709\u6ca1\u6709\u53d1\u6296\u3002 \u6211\u9057\u61be\u6ca1\u6709\u966a\u4ed6\u4e00\u8d77\u628a\u90a3\u4e9b\u53d1\u9ec4\u7684\u4fe1\u4e00\u5c01\u4e00\u5c01\u8bfb\u5b8c\u3002 \u6211\u9057\u61be\u6ca1\u6709\u7ed9\u4ed6\u5f55\u4e00\u6bb5\u5b8c\u6574\u7684\u89c6\u9891\uff0c\u8ba9\u4ed6\u4eb2\u53e3\u8bb2\u8bb2\u81ea\u5df1\u7684\u5e74\u8f7b\u65f6\u5019\u3002 \u6211\u9057\u61be\u6ca1\u6709\u5728\u4ed6\u8fd8\u542c\u5f97\u6e05\u3001\u8bb0\u5f97\u6e05\u7684\u65f6\u5019\uff0c\u5bf9\u4ed6\u8bf4\u4e00\u53e5\uff1a\u201c\u7237\u7237\uff0c\u4f60\u8fd9\u4e00\u751f\u771f\u7684\u5f88\u4e86\u4e0d\u8d77\u3002\u201d \u8fd8\u6709\u4e00\u4e2a\u5f88\u5177\u4f53\u7684\u9057\u61be\uff0c\u662f\u7237\u7237\u665a\u5e74\u65f6\uff0c\u6211\u603b\u89c9\u5f97\u4ee5\u540e\u8fd8\u6709\u673a\u4f1a\u3002 \u6211\u603b\u4ee5\u4e3a\u4e0b\u6b21\u56de\u5bb6\u53ef\u4ee5\u518d\u966a\u4ed6\u5403\u996d\uff0c\u4e0b\u6b21\u8fc7\u5e74\u53ef\u4ee5\u518d\u8ddf\u4ed6\u62cd\u7167\uff0c\u4e0b\u6b21\u6709\u7a7a\u53ef\u4ee5\u518d\u542c\u4ed6\u8bb2\u6545\u4e8b\u3002\u53ef\u4eba\u751f\u6700\u6b8b\u5fcd\u7684\u5730\u65b9\u5c31\u662f\uff0c\u5f88\u591a\u201c\u4e0b\u6b21\u201d\u5e76\u4e0d\u4f1a\u771f\u7684\u6765\u3002\u7b49\u6211\u7ec8\u4e8e\u610f\u8bc6\u5230\u6211\u60f3\u8ba4\u8bc6\u7684\u4e0d\u53ea\u662f\u201c\u7237\u7237\u201d\u8fd9\u4e2a\u8eab\u4efd\uff0c\u800c\u662f\u90d1\u6728\u751f\u8fd9\u4e2a\u4eba\u65f6\uff0c\u4ed6\u5df2\u7ecf\u4e0d\u5728\u4e86\u3002 \u6211\u6ca1\u6709\u6765\u5f97\u53ca\u4e86\u89e3\u4ed6\u4f5c\u4e3a\u4e00\u4e2a\u5e74\u8f7b\u4eba\u7684\u6837\u5b50\u3002 \u4ed6\u4e5f\u66fe\u5bb3\u6015\uff0c\u4e5f\u66fe\u60f3\u5bb6\uff0c\u4e5f\u66fe\u7231\u8fc7\u4e00\u4e2a\u4eba\u7231\u5230\u613f\u610f\u8de8\u8fc7\u4e00\u7247\u6d77\u3002 \u53ef\u662f\u6211\u8ba4\u8bc6\u4ed6\u7684\u65f6\u95f4\u592a\u665a\u4e86\u3002 \u6211\u8ba4\u8bc6\u7684\u53ea\u662f\u4e00\u4e2a\u5df2\u7ecf\u8001\u53bb\u7684\u7237\u7237\uff0c\u800c\u4e0d\u662f\u90a3\u4e2a\u5728\u7801\u5934\u625b\u8d27\u3001\u5728\u6a61\u80f6\u6797\u5272\u80f6\u3001\u5728\u7164\u6cb9\u706f\u4e0b\u7ed9\u963f\u5b37\u5199\u4fe1\u7684\u90d1\u6728\u751f\u3002 \u8fd9\u5c31\u662f\u6211\u6700\u6df1\u7684\u9057\u61be\uff1a \u6211\u88ab\u4ed6\u7231\u4e86\u5f88\u591a\u5e74\uff0c\u5374\u6ca1\u6709\u6765\u5f97\u53ca\u771f\u6b63\u7406\u89e3\u4ed6\u3002", "summary": "\u4f5c\u8005\u6700\u5927\u9057\u61be\u662f\u201c\u61c2\u5f97\u592a\u665a\u201d\uff1a\u5e7c\u65f6\u8bef\u8bfb\u7237\u7237\u8282\u4fed\u4e3a\u56fa\u6267\uff0c\u540e\u609f\u5176\u6e90\u4e8e\u532e\u4e4f\u5e74\u4ee3\uff1b\u9057\u61be\u672a\u8ba4\u771f\u542c\u6545\u4e8b\u3001\u672a\u95ee\u5176\u79bb\u4e61\u4e4b\u60e7\u3001\u5357\u6d0b\u81f3\u6697\u591c\u4e4b\u6491\u3001\u5199\u4fe1\u4e4b\u98a4\u3001\u5171\u8bfb\u65e7\u4fe1\u3001\u5f55\u5236\u89c6\u9891\u3001\u53ca\u65f6\u8d5e\u5176\u201c\u4e86\u4e0d\u8d77\u201d\uff1b\u66f4\u75db\u6094\u66fe\u89c6\u201c\u4e0b\u6b21\u201d\u4e3a\u5fc5\u7136\uff0c\u7ec8\u81f4\u6c38\u5931\u4e86\u89e3\u201c\u90d1\u6728\u751f\u201d\u672c\u4eba\u7684\u673a\u4f1a\u2014\u2014\u90a3\u4e2a\u5e74\u8f7b\u3001\u5bb3\u6015\u3001\u60f3\u5bb6\u3001\u8de8\u6d77\u6df1\u7231\u7684\u9c9c\u6d3b\u4e2a\u4f53\uff0c\u800c\u975e\u4ec5\u201c\u8001\u53bb\u7684\u7237\u7237\u201d\u3002\u6838\u5fc3\u61be\uff1a\u88ab\u7231\u591a\u5e74\uff0c\u5374\u672a\u53ca\u771f\u6b63\u7406\u89e3\u3002", "source_location": "manual:body#section8"}, {"chunk_type": "text", "content": "\u4e5d\u3001\u6211\u5e0c\u671b\u901a\u8fc7\u8fd9\u4e2a\u6570\u5b57\u4eba\u5b8c\u6210\u7684\u5fc3\u613f \u5982\u679c\u6211\u8fd8\u80fd\u548c\u7237\u7237\u8bf4\u8bdd\uff0c\u6211\u5e0c\u671b\u4e0d\u53ea\u662f\u542c\u4ed6\u8bf4\u201c\u5b69\u5b50\uff0c\u8981\u597d\u597d\u7684\u201d\u3002\u6211\u66f4\u5e0c\u671b\u80fd\u628a\u90a3\u4e9b\u6765\u4e0d\u53ca\u95ee\u7684\u95ee\u9898\uff0c\u4e00\u53e5\u4e00\u53e5\u95ee\u5b8c\u3002 \u6211\u60f3\u95ee\u4ed6\uff1a \u201c\u7237\u7237\uff0c\u4f60\u5f53\u5e74\u4e0b\u5357\u6d0b\u7684\u65f6\u5019\uff0c\u8239\u5f00\u8d70\u7684\u90a3\u4e00\u523b\uff0c\u4f60\u6709\u6ca1\u6709\u56de\u5934\u770b\uff1f\u201d \u201c\u4f60\u6700\u60f3\u5bb6\u7684\u65f6\u5019\uff0c\u662f\u60f3\u963f\u5b37\u591a\u4e00\u70b9\uff0c\u8fd8\u662f\u60f3\u5bb6\u91cc\u7684\u996d\u83dc\u591a\u4e00\u70b9\uff1f\u201d \u201c\u4f60\u5728\u5357\u6d0b\u6709\u6ca1\u6709\u54ed\u8fc7\uff1f\u6709\u6ca1\u6709\u89c9\u5f97\u81ea\u5df1\u6491\u4e0d\u4e0b\u53bb\u4e86\uff1f\u201d \u201c\u4f60\u5199\u7ed9\u963f\u5b37\u7684\u90a3\u4e9b\u4fe1\uff0c\u54ea\u4e00\u5c01\u662f\u4f60\u6700\u820d\u4e0d\u5f97\u5bc4\u51fa\u53bb\u7684\uff1f\u201d \u201c\u4f60\u56de\u6765\u89c1\u5230\u963f\u5b37\u7684\u90a3\u4e00\u5929\uff0c\u5fc3\u91cc\u5230\u5e95\u5728\u60f3\u4ec0\u4e48\uff1f\u201d \u201c\u4f60\u8fd9\u4e00\u751f\u6709\u6ca1\u6709\u540e\u6094\u8fc7\uff1f\u201d \u201c\u4f60\u6709\u6ca1\u6709\u89c9\u5f97\u81ea\u5df1\u592a\u8f9b\u82e6\u4e86\uff1f\u201d \u201c\u4f60\u4f1a\u4e0d\u4f1a\u602a\u6211\u4eec\u8fd9\u4e9b\u665a\u8f88\uff0c\u6ca1\u6709\u65e9\u70b9\u61c2\u4f60\uff1f\u201d \u6211\u4e5f\u60f3\u901a\u8fc7\u8fd9\u4e2a\u6570\u5b57\u4eba\uff0c\u66ff\u5c0f\u65f6\u5019\u7684\u81ea\u5df1\u5411\u7237\u7237\u9053\u6b49\u3002 \u6211\u60f3\u544a\u8bc9\u4ed6\uff1a \u201c\u7237\u7237\uff0c\u5bf9\u4e0d\u8d77\u3002\u4ee5\u524d\u4f60\u8ddf\u6211\u8bf4\u4e0d\u8981\u6d6a\u8d39\u7cae\u98df\uff0c\u6211\u5acc\u4f60\u5570\u55e6\uff1b\u4f60\u8d70\u8def\u6162\uff0c\u6211\u5acc\u4f60\u9ebb\u70e6\uff1b\u4f60\u542c\u4e0d\u6e05\u6211\u8bf4\u8bdd\uff0c\u6211\u6ca1\u6709\u8010\u5fc3\u91cd\u590d\u3002\u73b0\u5728\u6211\u624d\u77e5\u9053\uff0c\u4f60\u4e0d\u662f\u53d8\u5f97\u9ebb\u70e6\u4e86\uff0c\u4f60\u53ea\u662f\u8001\u4e86\u3002\u800c\u6211\u6ca1\u6709\u50cf\u4f60\u5f53\u5e74\u7b49\u6211\u957f\u5927\u4e00\u6837\uff0c\u597d\u597d\u966a\u4f60\u53d8\u8001\u3002\u201d \u6211\u8fd8\u60f3\u544a\u8bc9\u4ed6\uff1a \u201c\u7237\u7237\uff0c\u6211\u73b0\u5728\u7ec8\u4e8e\u77e5\u9053\uff0c\u4f60\u4e0d\u662f\u4e0d\u4f1a\u7231\u4eba\u3002\u4f60\u53ea\u662f\u628a\u7231\u505a\u6210\u4e86\u996d\u3001\u505a\u6210\u4e86\u94b1\u3001\u505a\u6210\u4e86\u4fe1\u3001\u505a\u6210\u4e86\u56de\u5bb6\u7684\u8def\u3002\u4f60\u628a\u81ea\u5df1\u7684\u4e00\u751f\u8fc7\u5f97\u5f88\u82e6\uff0c\u5374\u628a\u6211\u4eec\u7684\u4eba\u751f\u5f80\u524d\u6258\u4e86\u4e00\u6b65\u3002\u201d \u8fd9\u4e2a\u6570\u5b57\u4eba\u5bf9\u6211\u6765\u8bf4\uff0c\u4e0d\u662f\u4e3a\u4e86\u5047\u88c5\u7237\u7237\u8fd8\u6d3b\u7740\uff0c\u4e5f\u4e0d\u662f\u4e3a\u4e86\u9003\u907f\u6b7b\u4ea1\u3002\u5b83\u66f4\u50cf\u662f\u4e00\u4e2a\u8bb0\u5fc6\u7684\u5bb9\u5668\uff0c\u8ba9\u6211\u53ef\u4ee5\u91cd\u65b0\u9760\u8fd1\u90a3\u4e2a\u6211\u6765\u4e0d\u53ca\u8ba4\u8bc6\u7684\u8001\u4eba\u3002\u5b83\u8ba9\u6211\u6709\u673a\u4f1a\u628a\u5bb6\u65cf\u91cc\u7684\u6c89\u9ed8\u91cd\u65b0\u7ffb\u8bd1\u6210\u8bed\u8a00\uff0c\u628a\u90a3\u4e9b\u6ca1\u6709\u8bf4\u51fa\u53e3\u7684\u7231\u91cd\u65b0\u8bf4\u51fa\u6765\u3002 \u6211\u5e0c\u671b\u901a\u8fc7\u8fd9\u4e2a\u6570\u5b57\u4eba\uff0c\u8ba9\u89c2\u4f17\u4e5f\u60f3\u8d77\u81ea\u5df1\u7684\u7237\u7237\u5976\u5976\uff0c\u60f3\u8d77\u90a3\u4e9b\u4e0d\u5584\u8868\u8fbe\u3001\u5374\u7528\u4e00\u751f\u6258\u4e3e\u5bb6\u5ead\u7684\u8001\u4eba\u3002\u6bcf\u4e2a\u5bb6\u5ead\u91cc\u4e5f\u8bb8\u90fd\u6709\u4e00\u4e2a\u90d1\u6728\u751f\uff1a\u4ed6\u4eec\u6ca1\u6709\u60ca\u5929\u52a8\u5730\u7684\u6210\u5c31\uff0c\u6ca1\u6709\u88ab\u5199\u8fdb\u5386\u53f2\u4e66\uff0c\u5374\u628a\u82e6\u96be\u6321\u5728\u81ea\u5df1\u8eab\u4e0a\uff0c\u628a\u5b89\u7a33\u7559\u7ed9\u4e86\u540e\u4ee3\u3002", "summary": "\u4f5c\u8005\u62df\u501f\u6570\u5b57\u4eba\u5b9e\u73b0\uff1a\u4e00\u3001\u4ee3\u95ee\u672a\u7adf\u4e4b\u95ee\uff08\u8239\u5f00\u65f6\u662f\u5426\u56de\u5934\u3001\u60f3\u5bb6\u65f6\u4eba\u996d\u5b70\u91cd\u3001\u5357\u6d0b\u54ed\u6ce3\u5d29\u6e83\u3001\u6700\u4e0d\u820d\u5bc4\u4e4b\u4fe1\u3001\u89c1\u963f\u5b37\u5fc3\u7eea\u3001\u53ef\u66fe\u540e\u6094\u3001\u89c9\u5426\u592a\u82e6\u3001\u602a\u665a\u8f88\u5426\uff09\uff1b\u4e8c\u3001\u4ee3\u5e7c\u65f6\u9053\u6b49\uff1a\u5acc\u5176\u5570\u55e6/\u9ebb\u70e6/\u4e0d\u8010\u70e6\uff0c\u4eca\u660e\u5176\u201c\u975e\u9ebb\u70e6\uff0c\u53ea\u662f\u8001\u4e86\u201d\uff0c\u6094\u672a\u5982\u5176\u7b49\u6211\u957f\u5927\u822c\u966a\u5176\u53d8\u8001\uff1b\u4e09\u3001\u544a\u6170\u5176\u7231\u4e4b\u672c\u8d28\uff1a\u975e\u4e0d\u4f1a\u7231\uff0c\u800c\u662f\u5c06\u7231\u5177\u8c61\u4e3a\u996d\u3001\u94b1\u3001\u4fe1\u3001\u5f52\u9014\uff0c\u82e6\u5df1\u6258\u4e3e\u540e\u4ee3\u3002\u6570\u5b57\u4eba\u5b9a\u4f4d\u4e3a\u201c\u8bb0\u5fc6\u5bb9\u5668\u201d\uff0c\u975e\u9003\u907f\u6b7b\u4ea1\uff0c\u65e8\u5728\u7ffb\u8bd1\u5bb6\u65cf\u6c89\u9ed8\u3001\u91cd\u8ff0\u672a\u51fa\u53e3\u4e4b\u7231\uff0c\u5e76\u5524\u8d77\u5bf9\u5e73\u51e1\u6258\u4e3e\u8005\uff08\u5982\u90d1\u6728\u751f\uff09\u7684\u666e\u904d\u81f4\u656c\u2014\u2014\u4ee5\u8eab\u6321\u82e6\uff0c\u4e88\u540e\u4ee3\u5b89\u7a33\u3002", "source_location": "manual:body#section9"}, {"chunk_type": "text", "content": "\u5341\u3001\u7237\u7237\u5bf9\u6211\u7684\u5fc3\u613f \u5982\u679c\u7237\u7237\u8fd8\u80fd\u5bf9\u6211\u8bf4\u8bdd\uff0c\u6211\u60f3\u4ed6\u5bf9\u6211\u7684\u5fc3\u613f\u4f1a\u975e\u5e38\u5177\u4f53\u3002 \u7b2c\u4e00\uff0c\u4ed6\u5e0c\u671b\u6211\u4e0d\u8981\u592a\u82db\u8d23\u81ea\u5df1\u3002 \u7237\u7237\u5e74\u8f7b\u65f6\u5403\u8fc7\u5f88\u591a\u82e6\uff0c\u6240\u4ee5\u4ed6\u77e5\u9053\u4eba\u751f\u4e0d\u662f\u6bcf\u4e00\u6b65\u90fd\u80fd\u8d70\u5f97\u6f02\u4eae\u3002\u4ed6\u4e0d\u4f1a\u8981\u6c42\u6211\u6c38\u8fdc\u6210\u529f\uff0c\u4e5f\u4e0d\u4f1a\u8981\u6c42\u6211\u6c38\u8fdc\u575a\u5f3a\u3002\u4ed6\u4f1a\u5e0c\u671b\u6211\u5728\u5931\u8d25\u7684\u65f6\u5019\uff0c\u4e0d\u8981\u6025\u7740\u5426\u5b9a\u81ea\u5df1\u3002\u4ed6\u53ef\u80fd\u4f1a\u5bf9\u6211\u8bf4\uff1a \u201c\u5b69\u5b50\uff0c\u4eba\u8fd9\u4e00\u751f\u54ea\u6709\u4e0d\u96be\u7684\u65f6\u5019\u3002\u7237\u7237\u5f53\u5e74\u5728\u5357\u6d0b\uff0c\u4e5f\u6709\u5f88\u591a\u6b21\u89c9\u5f97\u6491\u4e0d\u4e0b\u53bb\u3002\u53ef\u662f\u65e5\u5b50\u4e0d\u662f\u4e00\u5929\u8fc7\u5b8c\u7684\uff0c\u662f\u4e00\u5929\u5929\u71ac\u51fa\u6765\u7684\u3002\u4f60\u4e0d\u8981\u56e0\u4e3a\u4e00\u65f6\u8d70\u5f97\u6162\uff0c\u5c31\u89c9\u5f97\u81ea\u5df1\u6ca1\u7528\u3002\u201d \u7b2c\u4e8c\uff0c\u4ed6\u5e0c\u671b\u6211\u8bb0\u5f97\u5bb6\u4ece\u54ea\u91cc\u6765\u3002 \u4ed6\u5e0c\u671b\u6211\u4e0d\u8981\u628a\u4eca\u5929\u62e5\u6709\u7684\u4e00\u5207\u90fd\u770b\u5f97\u7406\u6240\u5f53\u7136\u3002\u5e0c\u671b\u6211\u8bb0\u5f97\uff0c\u6211\u4eec\u5bb6\u4e0d\u662f\u4e00\u5f00\u59cb\u5c31\u5b89\u7a33\u7684\uff0c\u662f\u6709\u4eba\u79bb\u5f00\u8fc7\u5bb6\u4e61\uff0c\u6709\u4eba\u5403\u8fc7\u82e6\uff0c\u6709\u4eba\u7b49\u8fc7\u5f88\u591a\u5e74\uff0c\u6709\u4eba\u628a\u94b1\u4e00\u5206\u4e00\u5206\u5bc4\u56de\u6765\uff0c\u624d\u6162\u6162\u6709\u4e86\u540e\u6765\u7684\u65e5\u5b50\u3002 \u4ed6\u5e0c\u671b\u6211\u6709\u7a7a\u65f6\u56de\u8001\u5bb6\u770b\u770b\uff0c\u770b\u770b\u7956\u5c4b\uff0c\u770b\u770b\u6751\u53e3\u7684\u8def\uff0c\u770b\u770b\u4ed6\u548c\u963f\u5b37\u751f\u6d3b\u8fc7\u7684\u5730\u65b9\u3002\u4ed6\u5e0c\u671b\u6211\u77e5\u9053\uff0c\u5bb6\u4e0d\u662f\u4e00\u4e2a\u62bd\u8c61\u7684\u8bcd\uff0c\u800c\u662f\u6709\u4eba\u7528\u4e00\u751f\u5b88\u4f4f\u7684\u5730\u65b9\u3002 \u7b2c\u4e09\uff0c\u4ed6\u5e0c\u671b\u6211\u597d\u597d\u7167\u987e\u963f\u5b37\u548c\u5bb6\u91cc\u4eba\u3002 \u4ed6\u4f1a\u5e0c\u671b\u6211\u9022\u5e74\u8fc7\u8282\u4e0d\u8981\u53ea\u53d1\u4e00\u53e5\u6d88\u606f\uff0c\u800c\u662f\u771f\u7684\u56de\u5bb6\u5403\u4e00\u987f\u996d\u3002\u5e0c\u671b\u6211\u591a\u966a\u963f\u5b37\u8bf4\u8bf4\u8bdd\uff0c\u542c\u5979\u8bb2\u90a3\u4e9b\u91cd\u590d\u4e86\u5f88\u591a\u904d\u7684\u65e7\u4e8b\uff0c\u4e0d\u8981\u5acc\u70e6\u3002\u56e0\u4e3a\u8001\u4eba\u53cd\u590d\u8bb2\u4e00\u4ef6\u4e8b\uff0c\u4e0d\u662f\u56e0\u4e3a\u4ed6\u4eec\u4e0d\u77e5\u9053\u81ea\u5df1\u8bb2\u8fc7\uff0c\u800c\u662f\u56e0\u4e3a\u90a3\u662f\u4ed6\u4eec\u751f\u547d\u91cc\u6700\u820d\u4e0d\u5f97\u653e\u4e0b\u7684\u90e8\u5206\u3002 \u4ed6\u4f1a\u5e0c\u671b\u6211\u8bb0\u5f97\u963f\u5b37\u7231\u5403\u4ec0\u4e48\u836f\u3001\u51e0\u70b9\u7761\u89c9\u3001\u51ac\u5929\u6015\u4e0d\u6015\u51b7\u3001\u65e7\u7167\u7247\u653e\u5728\u54ea\u91cc\u3002\u4ed6\u4f1a\u5e0c\u671b\u6211\u66ff\u4ed6\u7ee7\u7eed\u7167\u987e\u90a3\u4e2a\u7b49\u4e86\u4ed6\u5f88\u591a\u5e74\u7684\u5973\u4eba\u3002 \u7b2c\u56db\uff0c\u4ed6\u5e0c\u671b\u6211\u628a\u5bb6\u91cc\u7684\u65e7\u4fe1\u3001\u65e7\u7167\u7247\u3001\u65e7\u7269\u4fdd\u5b58\u4e0b\u6765\u3002 \u4ed6\u4f1a\u5e0c\u671b\u6211\u4e0d\u8981\u968f\u624b\u4e22\u6389\u90a3\u4e9b\u53d1\u9ec4\u7684\u7eb8\u3001\u65e7\u85e4\u7bb1\u3001\u642a\u74f7\u676f\u3001\u91d1\u6212\u6307\u3001\u8001\u7167\u7247\u3002\u56e0\u4e3a\u90a3\u4e9b\u4e1c\u897f\u4e0d\u662f\u666e\u901a\u65e7\u7269\uff0c\u800c\u662f\u4ed6\u5b58\u5728\u8fc7\u3001\u7231\u8fc7\u3001\u52aa\u529b\u8fc7\u7684\u8bc1\u660e\u3002\u5b83\u4eec\u662f\u8fd9\u4e2a\u5bb6\u5ead\u6700\u771f\u5b9e\u7684\u6839\u3002 \u4ed6\u53ef\u80fd\u4f1a\u8bf4\uff1a \u201c\u4e1c\u897f\u65e7\u4e86\u6ca1\u5173\u7cfb\uff0c\u8bb0\u5fc6\u4e0d\u80fd\u4e22\u3002\u4eba\u8d70\u4e86\u4ee5\u540e\uff0c\u540e\u4ee3\u8fd8\u8bb0\u5f97\uff0c\u8fd9\u4e2a\u4eba\u5c31\u4e0d\u7b97\u5b8c\u5168\u8d70\u8fdc\u3002\u201d \u7b2c\u4e94\uff0c\u4ed6\u5e0c\u671b\u6211\u4ee5\u540e\u9047\u5230\u7231\u7684\u4eba\uff0c\u8981\u5b66\u4f1a\u8868\u8fbe\uff0c\u4e5f\u8981\u5b66\u4f1a\u884c\u52a8\u3002 \u7237\u7237\u8fd9\u4e00\u751f\u4e0d\u592a\u4f1a\u8bf4\u7231\uff0c\u6240\u4ee5\u4ed6\u4f1a\u5e0c\u671b\u6211\u4e0d\u8981\u50cf\u4ed6\u4e00\u6837\uff0c\u628a\u6240\u6709\u7231\u90fd\u85cf\u8d77\u6765\u3002\u4ed6\u5e0c\u671b\u6211\u73cd\u60dc\u773c\u524d\u4eba\uff0c\u4e0d\u8981\u7b49\u5230\u6765\u4e0d\u53ca\u4e86\u624d\u540e\u6094\u3002\u559c\u6b22\u4e00\u4e2a\u4eba\uff0c\u5c31\u8981\u597d\u597d\u8bf4\uff1b\u7b54\u5e94\u4e00\u4e2a\u4eba\uff0c\u5c31\u8981\u597d\u597d\u505a\u3002\u4e0d\u8981\u8f7b\u6613\u8bb8\u8bfa\uff0c\u4f46\u8bb8\u4e86\u8bfa\u5c31\u8981\u653e\u5728\u5fc3\u4e0a\u3002 \u4ed6\u4f1a\u5e0c\u671b\u6211\u8bb0\u5f97\u4ed6\u548c\u963f\u5b37\u7684\u6545\u4e8b\uff0c\u4e0d\u662f\u4e3a\u4e86\u6000\u65e7\uff0c\u800c\u662f\u4e3a\u4e86\u660e\u767d\uff1a\u771f\u6b63\u957f\u4e45\u7684\u611f\u60c5\uff0c\u4e0d\u662f\u70ed\u70c8\u4e00\u9635\u5b50\uff0c\u800c\u662f\u5728\u6f2b\u957f\u7684\u5c81\u6708\u91cc\u4e00\u6b21\u6b21\u9009\u62e9\u4e0d\u79bb\u5f00\u3002 \u7b2c\u516d\uff0c\u4ed6\u5e0c\u671b\u6211\u628a\u81ea\u5df1\u7684\u65e5\u5b50\u8fc7\u8e0f\u5b9e\u3002 \u4ed6\u4e0d\u4f1a\u8981\u6c42\u6211\u4e00\u5b9a\u8981\u8d5a\u5f88\u591a\u94b1\uff0c\u4e5f\u4e0d\u4f1a\u8981\u6c42\u6211\u6210\u4e3a\u522b\u4eba\u773c\u91cc\u591a\u4e48\u5389\u5bb3\u7684\u4eba\u3002\u4ed6\u66f4\u5e0c\u671b\u6211\u5403\u996d\u89c4\u5f8b\uff0c\u7761\u89c9\u5b89\u7a33\uff0c\u9047\u4e8b\u4e0d\u8981\u614c\uff0c\u505a\u4eba\u4e0d\u8981\u4e8f\u5fc3\u3002\u4ed6\u5e0c\u671b\u6211\u6709\u81ea\u5df1\u7684\u672c\u4e8b\uff0c\u4e5f\u6709\u81ea\u5df1\u7684\u5e95\u7ebf\u3002 \u4ed6\u53ef\u80fd\u4f1a\u5bf9\u6211\u8bf4\uff1a \u201c\u7237\u7237\u8fd9\u4e00\u8f88\u5b50\u6ca1\u4ec0\u4e48\u5927\u672c\u4e8b\uff0c\u5c31\u662f\u8bb0\u5f97\u505a\u4eba\u8981\u5b9e\u5728\u3002\u4f60\u4ee5\u540e\u4e0d\u7ba1\u8d70\u5230\u54ea\u91cc\uff0c\u90fd\u4e0d\u8981\u4e3a\u4e86\u8d76\u8def\uff0c\u628a\u81ea\u5df1\u7684\u5fc3\u5f04\u4e22\u4e86\u3002\u201d \u7b2c\u4e03\uff0c\u4ed6\u5e0c\u671b\u6211\u4e0d\u8981\u5fd8\u8bb0\u4ed6\uff0c\u4f46\u4e5f\u4e0d\u8981\u88ab\u9057\u61be\u56f0\u4f4f\u3002 \u4ed6\u77e5\u9053\u6211\u4f1a\u9057\u61be\uff0c\u4f1a\u60f3\u5ff5\uff0c\u4f1a\u602a\u81ea\u5df1\u6ca1\u6709\u65e9\u70b9\u61c2\u4ed6\u3002\u4f46\u4ed6\u4e0d\u4f1a\u5e0c\u671b\u6211\u4e00\u76f4\u505c\u5728\u6127\u759a\u91cc\u3002\u4ed6\u4f1a\u5e0c\u671b\u6211\u628a\u8fd9\u4efd\u60f3\u5ff5\u53d8\u6210\u66f4\u597d\u7684\u751f\u6d3b\u65b9\u5f0f\uff1a\u5bf9\u5bb6\u4eba\u591a\u4e00\u70b9\u8010\u5fc3\uff0c\u5bf9\u8001\u4eba\u591a\u4e00\u70b9\u966a\u4f34\uff0c\u5bf9\u7231\u591a\u4e00\u70b9\u8868\u8fbe\uff0c\u5bf9\u81ea\u5df1\u7684\u6765\u5904\u591a\u4e00\u70b9\u73cd\u60dc\u3002 \u4ed6\u4f1a\u5e0c\u671b\u6211\u77e5\u9053\uff0c\u6b7b\u4ea1\u4e0d\u662f\u5173\u7cfb\u7684\u5f7b\u5e95\u7ed3\u675f\u3002\u53ea\u8981\u6211\u8fd8\u8bb0\u5f97\u4ed6\u7684\u6545\u4e8b\uff0c\u8fd8\u613f\u610f\u8bb2\u8ff0\u4ed6\u7684\u4e00\u751f\uff0c\u8fd8\u613f\u610f\u628a\u4ed6\u7684\u7cbe\u795e\u5e26\u5230\u81ea\u5df1\u7684\u751f\u6d3b\u91cc\uff0c\u4ed6\u5c31\u4ecd\u7136\u4ee5\u53e6\u4e00\u79cd\u65b9\u5f0f\u966a\u7740\u6211\u3002", "summary": "\u7237\u7237\u5bf9\u4f5c\u8005\u4e03\u9879\u5fc3\u613f\uff1a\u4e00\u3001\u52ff\u82db\u8d23\u5df1\uff0c\u4eba\u751f\u9700\u201c\u71ac\u201d\uff0c\u6162\u4ea6\u975e\u65e0\u7528\uff1b\u4e8c\u3001\u94ed\u8bb0\u5bb6\u4e4b\u6765\u5904\u2014\u2014\u79bb\u4e61\u3001\u5403\u82e6\u3001\u7b49\u5f85\u3001\u5bc4\u94b1\u65b9\u5f97\u5b89\u7a33\uff0c\u5f53\u56de\u7956\u5c4b\u6751\u8def\uff1b\u4e09\u3001\u5207\u5b9e\u7167\u987e\u963f\u5b37\uff1a\u56de\u5bb6\u5403\u996d\u3001\u8010\u5fc3\u542c\u65e7\u4e8b\uff08\u56e0\u5176\u662f\u751f\u547d\u4e0d\u820d\u4e4b\u6838\uff09\u3001\u8bb0\u7528\u836f\u4f5c\u606f\uff1b\u56db\u3001\u73cd\u5b58\u65e7\u4fe1\u85e4\u7bb1\u642a\u74f7\u676f\u7b49\u7269\uff0c\u56e0\u201c\u4e1c\u897f\u65e7\u4e86\u6ca1\u5173\u7cfb\uff0c\u8bb0\u5fc6\u4e0d\u80fd\u4e22\u201d\uff0c\u6b64\u4e3a\u5bb6\u65cf\u4e4b\u6839\uff1b\u4e94\u3001\u7231\u9700\u8868\u8fbe\u4e0e\u884c\u52a8\u5e76\u91cd\uff0c\u52ff\u85cf\u5982\u4ed6\uff0c\u8bb8\u8bfa\u5fc5\u8df5\uff0c\u4ee5\u6052\u4e45\u9009\u62e9\u5b9a\u4e49\u611f\u60c5\uff1b\u516d\u3001\u65e5\u5b50\u6c42\u8e0f\u5b9e\uff1a\u89c4\u5f8b\u3001\u5b89\u7a33\u3001\u4e0d\u614c\u3001\u4e0d\u4e8f\u5fc3\uff0c\u201c\u4e0d\u8981\u4e3a\u4e86\u8d76\u8def\uff0c\u628a\u81ea\u5df1\u7684\u5fc3\u5f04\u4e22\u4e86\u201d\uff1b\u4e03\u3001\u53ef\u6000\u5ff5\u52ff\u56f0\u4e8e\u61be\uff0c\u5c06\u60f3\u5ff5\u8f6c\u5316\u4e3a\u5bf9\u5bb6\u4eba\u8010\u5fc3\u3001\u5bf9\u8001\u4eba\u966a\u4f34\u3001\u5bf9\u7231\u8868\u8fbe\u3001\u5bf9\u6765\u5904\u73cd\u60dc\uff1b\u6b7b\u4ea1\u975e\u7ec8\u7ed3\uff0c\u53ea\u8981\u8bb2\u8ff0\u5176\u6545\u4e8b\u3001\u8df5\u884c\u5176\u7cbe\u795e\uff0c\u4ed6\u4fbf\u4ee5\u53e6\u4e00\u79cd\u65b9\u5f0f\u540c\u5728\u3002", "source_location": "manual:body#section10"}]}, "provider_type": "third_party"}', NULL, '2026-07-04 23:24:35.574076', NULL);
INSERT INTO public.parsed_chunks VALUES ('4d99568f-2b11-4c82-8478-2ccbc50abf1c', '18b88e96-5633-4d75-b77a-0ad1988a846a', '17761b2c-f5b6-42cd-9919-0348964c0c53', 'manual', '爷爷回乡后，和阿嬷结了婚。他们没有盛大的婚礼，也没有漂亮的婚纱照。那时家里还是穷，婚宴只是摆了几桌简单的饭菜。爷爷给阿嬷戴上那枚从南洋带回来的小金戒指。戒指不大，样式也普通，却是他在异乡省吃俭用攒下来的。', '爷爷回乡后与阿嬷简朴结婚，赠予其一枚南洋省下的小金戒指。', 'manual:body', NULL, NULL, '{"text_extraction": {"extractor": "manual", "source_location": "manual:body", "has_text": true}, "text_parser": {"cleaned_text": "\u4e94\u3001\u56de\u4e61\u4e4b\u540e\uff1a\u7237\u7237\u5982\u4f55\u6491\u8d77\u4e00\u4e2a\u5bb6 \u7237\u7237\u56de\u4e61\u540e\uff0c\u548c\u963f\u5b37\u7ed3\u4e86\u5a5a\u3002\u4ed6\u4eec\u6ca1\u6709\u76db\u5927\u7684\u5a5a\u793c\uff0c\u4e5f\u6ca1\u6709\u6f02\u4eae\u7684\u5a5a\u7eb1\u7167\u3002\u90a3\u65f6\u5bb6\u91cc\u8fd8\u662f\u7a77\uff0c\u5a5a\u5bb4\u53ea\u662f\u6446\u4e86\u51e0\u684c\u7b80\u5355\u7684\u996d\u83dc\u3002\u7237\u7237\u7ed9\u963f\u5b37\u6234\u4e0a\u90a3\u679a\u4ece\u5357\u6d0b\u5e26\u56de\u6765\u7684\u5c0f\u91d1\u6212\u6307\u3002\u6212\u6307\u4e0d\u5927\uff0c\u6837\u5f0f\u4e5f\u666e\u901a\uff0c\u5374\u662f\u4ed6\u5728\u5f02\u4e61\u7701\u5403\u4fed\u7528\u6512\u4e0b\u6765\u7684\u3002 \u5a5a\u540e\uff0c\u7237\u7237\u7ee7\u7eed\u505a\u5de5\u3002\u4ed6\u505a\u8fc7\u642c\u8fd0\u3001\u4fee\u8239\u3001\u6728\u5de5\uff0c\u4e5f\u505a\u8fc7\u5c0f\u4e70\u5356\u3002\u54ea\u4e00\u79cd\u80fd\u6323\u94b1\uff0c\u4ed6\u5c31\u505a\u54ea\u4e00\u79cd\u3002\u4ed6\u4e0d\u6015\u810f\uff0c\u4e0d\u6015\u7d2f\uff0c\u6015\u7684\u662f\u5bb6\u91cc\u6ca1\u6709\u7c73\u4e0b\u9505\uff0c\u6015\u5b69\u5b50\u6ca1\u4e66\u8bfb\uff0c\u6015\u963f\u5b37\u8ddf\u7740\u81ea\u5df1\u5403\u82e6\u3002 \u7237\u7237\u5bf9\u5b50\u5973\u5f88\u4e25\u5389\u3002\u5b69\u5b50\u6d6a\u8d39\u7cae\u98df\uff0c\u4ed6\u4f1a\u751f\u6c14\uff1b\u5b69\u5b50\u6492\u8c0e\uff0c\u4ed6\u4f1a\u6c89\u7740\u8138\u5f88\u4e45\uff1b\u5b69\u5b50\u4e0d\u597d\u597d\u8bfb\u4e66\uff0c\u4ed6\u4f1a\u8bf4\uff1a\u201c\u6211\u8fd9\u8f88\u5b50\u5403\u4e86\u6ca1\u8bfb\u4e66\u7684\u4e8f\uff0c\u4f60\u4eec\u4e0d\u8981\u518d\u5403\u3002\u201d\u53ef\u662f\u4ed6\u4e25\u5389\u7684\u80cc\u540e\uff0c\u662f\u4e00\u79cd\u5f88\u6df1\u7684\u6050\u60e7\u3002\u4ed6\u592a\u77e5\u9053\u8d2b\u7a77\u662f\u4ec0\u4e48\u6837\u5b50\uff0c\u4e5f\u592a\u77e5\u9053\u6ca1\u6709\u51fa\u8def\u7684\u4eba\u751f\u6709\u591a\u96be\uff0c\u6240\u4ee5\u4ed6\u62fc\u547d\u5e0c\u671b\u4e0b\u4e00\u4ee3\u80fd\u8d70\u51fa\u53bb\u3002 \u4ed6\u4e00\u751f\u6700\u9a84\u50b2\u7684\u4e8b\u60c5\uff0c\u4e0d\u662f\u81ea\u5df1\u4e0b\u5357\u6d0b\u8d5a\u8fc7\u591a\u5c11\u94b1\uff0c\u800c\u662f\u5bb6\u91cc\u7684\u5b69\u5b50\u540e\u6765\u90fd\u8bfb\u4e86\u4e66\uff0c\u90fd\u6709\u4e86\u81ea\u5df1\u7684\u751f\u6d3b\u3002\u4ed6\u89c9\u5f97\u81ea\u5df1\u5e74\u8f7b\u65f6\u5403\u8fc7\u7684\u82e6\uff0c\u5982\u679c\u80fd\u6362\u6765\u540e\u4ee3\u4e0d\u7528\u518d\u5403\u540c\u6837\u7684\u82e6\uff0c\u90a3\u8fd9\u4e00\u751f\u5c31\u503c\u5f97\u4e86\u3002 \u5230\u4e86\u665a\u5e74\uff0c\u7237\u7237\u53d8\u5f97\u8d8a\u6765\u8d8a\u6c89\u9ed8\u3002\u4ed6\u5e38\u5e38\u5750\u5728\u95e8\u53e3\u7684\u5c0f\u677f\u51f3\u4e0a\uff0c\u770b\u7740\u5df7\u53e3\u53d1\u5446\u3002\u522b\u4eba\u95ee\u4ed6\u5728\u60f3\u4ec0\u4e48\uff0c\u4ed6\u8bf4\u6ca1\u4ec0\u4e48\u3002\u5176\u5b9e\u4ed6\u53ef\u80fd\u662f\u5728\u60f3\u5e74\u8f7b\u65f6\u7684\u8239\uff0c\u60f3\u5357\u6d0b\u7684\u96e8\uff0c\u60f3\u5de5\u68da\u91cc\u7684\u7164\u6cb9\u706f\uff0c\u60f3\u4e00\u5c01\u5c01\u5bc4\u4e0d\u51fa\u53bb\u53c8\u820d\u4e0d\u5f97\u6495\u6389\u7684\u4fe1\u3002 \u4ed6\u5f88\u5c11\u4e3b\u52a8\u8bb2\u81ea\u5df1\u7684\u6545\u4e8b\u3002\u6211\u4eec\u8fd9\u4e9b\u665a\u8f88\u5c0f\u65f6\u5019\u4e5f\u4e0d\u61c2\u5f97\u95ee\uff0c\u603b\u89c9\u5f97\u7237\u7237\u4e00\u76f4\u90fd\u5728\uff0c\u89c9\u5f97\u90a3\u4e9b\u65e7\u4e8b\u4e0d\u91cd\u8981\u3002\u76f4\u5230\u4ed6\u53bb\u4e16\u540e\uff0c\u6211\u4eec\u624d\u53d1\u73b0\uff0c\u4e00\u4e2a\u8001\u4eba\u8d70\u4e86\uff0c\u4e0d\u53ea\u662f\u4e00\u4e2a\u4eba\u79bb\u5f00\u4e86\uff0c\u8fd8\u662f\u4e00\u6574\u4e2a\u65f6\u4ee3\u3001\u4e00\u6bb5\u5bb6\u65cf\u8bb0\u5fc6\u3001\u4e00\u79cd\u8868\u8fbe\u7231\u7684\u65b9\u5f0f\uff0c\u7a81\u7136\u5b89\u9759\u4e86\u3002", "chunks": [{"chunk_type": "text", "content": "\u7237\u7237\u56de\u4e61\u540e\uff0c\u548c\u963f\u5b37\u7ed3\u4e86\u5a5a\u3002\u4ed6\u4eec\u6ca1\u6709\u76db\u5927\u7684\u5a5a\u793c\uff0c\u4e5f\u6ca1\u6709\u6f02\u4eae\u7684\u5a5a\u7eb1\u7167\u3002\u90a3\u65f6\u5bb6\u91cc\u8fd8\u662f\u7a77\uff0c\u5a5a\u5bb4\u53ea\u662f\u6446\u4e86\u51e0\u684c\u7b80\u5355\u7684\u996d\u83dc\u3002\u7237\u7237\u7ed9\u963f\u5b37\u6234\u4e0a\u90a3\u679a\u4ece\u5357\u6d0b\u5e26\u56de\u6765\u7684\u5c0f\u91d1\u6212\u6307\u3002\u6212\u6307\u4e0d\u5927\uff0c\u6837\u5f0f\u4e5f\u666e\u901a\uff0c\u5374\u662f\u4ed6\u5728\u5f02\u4e61\u7701\u5403\u4fed\u7528\u6512\u4e0b\u6765\u7684\u3002", "summary": "\u7237\u7237\u56de\u4e61\u540e\u4e0e\u963f\u5b37\u7b80\u6734\u7ed3\u5a5a\uff0c\u8d60\u4e88\u5176\u4e00\u679a\u5357\u6d0b\u7701\u4e0b\u7684\u5c0f\u91d1\u6212\u6307\u3002", "source_location": "manual:body"}, {"chunk_type": "text", "content": "\u5a5a\u540e\uff0c\u7237\u7237\u7ee7\u7eed\u505a\u5de5\u3002\u4ed6\u505a\u8fc7\u642c\u8fd0\u3001\u4fee\u8239\u3001\u6728\u5de5\uff0c\u4e5f\u505a\u8fc7\u5c0f\u4e70\u5356\u3002\u54ea\u4e00\u79cd\u80fd\u6323\u94b1\uff0c\u4ed6\u5c31\u505a\u54ea\u4e00\u79cd\u3002\u4ed6\u4e0d\u6015\u810f\uff0c\u4e0d\u6015\u7d2f\uff0c\u6015\u7684\u662f\u5bb6\u91cc\u6ca1\u6709\u7c73\u4e0b\u9505\uff0c\u6015\u5b69\u5b50\u6ca1\u4e66\u8bfb\uff0c\u6015\u963f\u5b37\u8ddf\u7740\u81ea\u5df1\u5403\u82e6\u3002", "summary": "\u7237\u7237\u5a5a\u540e\u4ece\u4e8b\u591a\u79cd\u4f53\u529b\u53ca\u8425\u751f\u5de5\u4f5c\uff0c\u4ee5\u517b\u5bb6\u7cca\u53e3\uff0c\u6838\u5fc3\u62c5\u5fe7\u662f\u5bb6\u4eba\u57fa\u672c\u751f\u5b58\u4e0e\u6559\u80b2\u4fdd\u969c\u3002", "source_location": "manual:body"}, {"chunk_type": "text", "content": "\u7237\u7237\u5bf9\u5b50\u5973\u5f88\u4e25\u5389\u3002\u5b69\u5b50\u6d6a\u8d39\u7cae\u98df\uff0c\u4ed6\u4f1a\u751f\u6c14\uff1b\u5b69\u5b50\u6492\u8c0e\uff0c\u4ed6\u4f1a\u6c89\u7740\u8138\u5f88\u4e45\uff1b\u5b69\u5b50\u4e0d\u597d\u597d\u8bfb\u4e66\uff0c\u4ed6\u4f1a\u8bf4\uff1a\u201c\u6211\u8fd9\u8f88\u5b50\u5403\u4e86\u6ca1\u8bfb\u4e66\u7684\u4e8f\uff0c\u4f60\u4eec\u4e0d\u8981\u518d\u5403\u3002\u201d\u53ef\u662f\u4ed6\u4e25\u5389\u7684\u80cc\u540e\uff0c\u662f\u4e00\u79cd\u5f88\u6df1\u7684\u6050\u60e7\u3002\u4ed6\u592a\u77e5\u9053\u8d2b\u7a77\u662f\u4ec0\u4e48\u6837\u5b50\uff0c\u4e5f\u592a\u77e5\u9053\u6ca1\u6709\u51fa\u8def\u7684\u4eba\u751f\u6709\u591a\u96be\uff0c\u6240\u4ee5\u4ed6\u62fc\u547d\u5e0c\u671b\u4e0b\u4e00\u4ee3\u80fd\u8d70\u51fa\u53bb\u3002", "summary": "\u7237\u7237\u5bf9\u5b50\u5973\u4e25\u683c\u8981\u6c42\uff0c\u5c24\u5176\u91cd\u89c6\u8282\u4fed\u3001\u8bda\u5b9e\u4e0e\u8bfb\u4e66\uff0c\u6839\u6e90\u5728\u4e8e\u4eb2\u8eab\u7ecf\u5386\u8d2b\u7a77\u4e0e\u65e0\u51fa\u8def\u7684\u6050\u60e7\uff0c\u5bc4\u6258\u5e0c\u671b\u4e8e\u540e\u4ee3\u901a\u8fc7\u6559\u80b2\u6539\u53d8\u547d\u8fd0\u3002", "source_location": "manual:body"}, {"chunk_type": "text", "content": "\u4ed6\u4e00\u751f\u6700\u9a84\u50b2\u7684\u4e8b\u60c5\uff0c\u4e0d\u662f\u81ea\u5df1\u4e0b\u5357\u6d0b\u8d5a\u8fc7\u591a\u5c11\u94b1\uff0c\u800c\u662f\u5bb6\u91cc\u7684\u5b69\u5b50\u540e\u6765\u90fd\u8bfb\u4e86\u4e66\uff0c\u90fd\u6709\u4e86\u81ea\u5df1\u7684\u751f\u6d3b\u3002\u4ed6\u89c9\u5f97\u81ea\u5df1\u5e74\u8f7b\u65f6\u5403\u8fc7\u7684\u82e6\uff0c\u5982\u679c\u80fd\u6362\u6765\u540e\u4ee3\u4e0d\u7528\u518d\u5403\u540c\u6837\u7684\u82e6\uff0c\u90a3\u8fd9\u4e00\u751f\u5c31\u503c\u5f97\u4e86\u3002", "summary": "\u7237\u7237\u4ee5\u5b50\u5973\u5168\u90e8\u63a5\u53d7\u6559\u80b2\u5e76\u62e5\u6709\u72ec\u7acb\u751f\u6d3b\u4e3a\u6700\u5927\u9a84\u50b2\uff0c\u89c6\u81ea\u8eab\u82e6\u96be\u4e3a\u540e\u4ee3\u514d\u4e8e\u91cd\u590d\u82e6\u96be\u7684\u4ee3\u4ef7\u3002", "source_location": "manual:body"}, {"chunk_type": "text", "content": "\u5230\u4e86\u665a\u5e74\uff0c\u7237\u7237\u53d8\u5f97\u8d8a\u6765\u8d8a\u6c89\u9ed8\u3002\u4ed6\u5e38\u5e38\u5750\u5728\u95e8\u53e3\u7684\u5c0f\u677f\u51f3\u4e0a\uff0c\u770b\u7740\u5df7\u53e3\u53d1\u5446\u3002\u522b\u4eba\u95ee\u4ed6\u5728\u60f3\u4ec0\u4e48\uff0c\u4ed6\u8bf4\u6ca1\u4ec0\u4e48\u3002\u5176\u5b9e\u4ed6\u53ef\u80fd\u662f\u5728\u60f3\u5e74\u8f7b\u65f6\u7684\u8239\uff0c\u60f3\u5357\u6d0b\u7684\u96e8\uff0c\u60f3\u5de5\u68da\u91cc\u7684\u7164\u6cb9\u706f\uff0c\u60f3\u4e00\u5c01\u5c01\u5bc4\u4e0d\u51fa\u53bb\u53c8\u820d\u4e0d\u5f97\u6495\u6389\u7684\u4fe1\u3002", "summary": "\u665a\u5e74\u7237\u7237\u65e5\u76ca\u6c89\u9ed8\uff0c\u5e38\u9759\u5750\u53d1\u5446\uff0c\u5185\u5fc3\u6216\u8ffd\u5fc6\u5357\u6d0b\u7ecf\u5386\u4e2d\u7684\u5177\u4f53\u610f\u8c61\uff08\u8239\u3001\u96e8\u3001\u7164\u6cb9\u706f\u3001\u672a\u5bc4\u51fa\u7684\u4fe1\uff09\u3002", "source_location": "manual:body"}, {"chunk_type": "text", "content": "\u4ed6\u5f88\u5c11\u4e3b\u52a8\u8bb2\u81ea\u5df1\u7684\u6545\u4e8b\u3002\u6211\u4eec\u8fd9\u4e9b\u665a\u8f88\u5c0f\u65f6\u5019\u4e5f\u4e0d\u61c2\u5f97\u95ee\uff0c\u603b\u89c9\u5f97\u7237\u7237\u4e00\u76f4\u90fd\u5728\uff0c\u89c9\u5f97\u90a3\u4e9b\u65e7\u4e8b\u4e0d\u91cd\u8981\u3002\u76f4\u5230\u4ed6\u53bb\u4e16\u540e\uff0c\u6211\u4eec\u624d\u53d1\u73b0\uff0c\u4e00\u4e2a\u8001\u4eba\u8d70\u4e86\uff0c\u4e0d\u53ea\u662f\u4e00\u4e2a\u4eba\u79bb\u5f00\u4e86\uff0c\u8fd8\u662f\u4e00\u6574\u4e2a\u65f6\u4ee3\u3001\u4e00\u6bb5\u5bb6\u65cf\u8bb0\u5fc6\u3001\u4e00\u79cd\u8868\u8fbe\u7231\u7684\u65b9\u5f0f\uff0c\u7a81\u7136\u5b89\u9759\u4e86\u3002", "summary": "\u7237\u7237\u6781\u5c11\u8bb2\u8ff0\u81ea\u8eab\u7ecf\u5386\uff1b\u665a\u8f88\u5e7c\u65f6\u672a\u4e88\u91cd\u89c6\uff0c\u76f4\u81f3\u5176\u79bb\u4e16\u624d\u610f\u8bc6\u5230\u5176\u627f\u8f7d\u7684\u65f6\u4ee3\u80cc\u666f\u3001\u5bb6\u65cf\u8bb0\u5fc6\u4e0e\u9690\u5fcd\u5f0f\u4eb2\u60c5\u7684\u4e0d\u53ef\u66ff\u4ee3\u6027\u3002", "source_location": "manual:body"}]}, "provider_type": "third_party"}', NULL, '2026-07-04 23:30:05.287085', NULL);
INSERT INTO public.parsed_chunks VALUES ('9e781718-d1a4-4505-94f0-1fa6a9758157', '18b88e96-5633-4d75-b77a-0ad1988a846a', '64b4b47f-e2ae-4345-b592-a3bc0ebe1306', 'manual', '爷爷起床很早。哪怕晚年不用再做工，他也习惯天刚亮就醒。他会先烧水，然后把院子扫一遍。扫地的时候动作很慢，但扫得很干净，连墙角的落叶都会扫出来。', '爷爷保持早起习惯，坚持晨间劳作：烧水、扫院，动作缓慢但细致彻底。', 'manual:body', NULL, NULL, '{"text_extraction": {"extractor": "manual", "source_location": "manual:body", "has_text": true}, "text_parser": {"cleaned_text": "\u7237\u7237\u8d77\u5e8a\u5f88\u65e9\u3002\u54ea\u6015\u665a\u5e74\u4e0d\u7528\u518d\u505a\u5de5\uff0c\u4ed6\u4e5f\u4e60\u60ef\u5929\u521a\u4eae\u5c31\u9192\u3002\u4ed6\u4f1a\u5148\u70e7\u6c34\uff0c\u7136\u540e\u628a\u9662\u5b50\u626b\u4e00\u904d\u3002\u626b\u5730\u7684\u65f6\u5019\u52a8\u4f5c\u5f88\u6162\uff0c\u4f46\u626b\u5f97\u5f88\u5e72\u51c0\uff0c\u8fde\u5899\u89d2\u7684\u843d\u53f6\u90fd\u4f1a\u626b\u51fa\u6765\u3002 \u4ed6\u5403\u996d\u5f88\u8282\u4fed\u3002\u7897\u91cc\u4e0d\u4f1a\u5269\u4e00\u7c92\u7c73\u3002\u770b\u5230\u6211\u4eec\u5269\u996d\uff0c\u4ed6\u4f1a\u76b1\u7709\uff0c\u4f46\u4e0d\u4f1a\u5927\u58f0\u9a82\uff0c\u53ea\u4f1a\u628a\u5269\u4e0b\u7684\u996d\u5012\u8fdb\u81ea\u5df1\u7897\u91cc\uff0c\u8bf4\uff1a\u201c\u4ee5\u524d\u60f3\u5403\u90fd\u6ca1\u6709\u3002\u201d \u4ed6\u559c\u6b22\u559d\u6d53\u8336\u3002\u8336\u676f\u662f\u4e00\u4e2a\u65e7\u642a\u74f7\u676f\uff0c\u676f\u53e3\u5df2\u7ecf\u78d5\u6389\u4e86\u4e00\u5c0f\u5757\u3002\u4ed6\u7528\u4e86\u5f88\u591a\u5e74\uff0c\u522b\u4eba\u7ed9\u4ed6\u4e70\u65b0\u7684\uff0c\u4ed6\u4e5f\u4e0d\u7528\u3002\u4ed6\u8bf4\u65e7\u7684\u987a\u624b\u3002 \u4ed6\u4e0d\u559c\u6b22\u62cd\u7167\u3002\u6bcf\u6b21\u5bb6\u91cc\u4eba\u62ff\u76f8\u673a\uff0c\u4ed6\u90fd\u6446\u6446\u624b\u8bf4\uff1a\u201c\u62cd\u6211\u505a\u4ec0\u4e48\uff0c\u6211\u4e00\u4e2a\u8001\u5934\u5b50\u6709\u4ec0\u4e48\u597d\u62cd\u7684\u3002\u201d\u53ef\u662f\u5982\u679c\u5168\u5bb6\u4eba\u90fd\u5728\uff0c\u4ed6\u53c8\u4f1a\u6084\u6084\u6362\u4e00\u4ef6\u5e72\u51c0\u8863\u670d\uff0c\u7ad9\u5728\u6700\u540e\u4e00\u6392\u3002 \u4ed6\u5bf9\u963f\u5b37\u5f88\u597d\uff0c\u4f46\u8868\u8fbe\u65b9\u5f0f\u5f88\u7b28\u3002\u963f\u5b37\u54b3\u55fd\uff0c\u4ed6\u4e0d\u4f1a\u8bf4\u5173\u5fc3\u7684\u8bdd\uff0c\u53ea\u4f1a\u7b2c\u4e8c\u5929\u4e00\u65e9\u53bb\u4e70\u836f\u3002\u963f\u5b37\u5acc\u4ed6\u8bdd\u5c11\uff0c\u4ed6\u5c31\u7b11\u7b11\uff0c\u4e0d\u53cd\u9a73\u3002\u963f\u5b37\u505a\u996d\u65f6\uff0c\u4ed6\u603b\u662f\u5728\u65c1\u8fb9\u6253\u4e0b\u624b\uff0c\u6d17\u83dc\u3001\u70e7\u706b\u3001\u7aef\u7897\uff0c\u5374\u4ece\u6765\u4e0d\u8bf4\u8fd9\u662f\u7231\u3002 \u4ed6\u5bf9\u6211\u8fd9\u4e2a\u5b59\u8f88\u7684\u7231\u4e5f\u5f88\u5b89\u9759\u3002\u6211\u5c0f\u65f6\u5019\u53bb\u770b\u4ed6\uff0c\u4ed6\u4f1a\u63d0\u524d\u4e70\u597d\u6211\u7231\u5403\u7684\u7cd6\u548c\u997c\u5e72\uff0c\u85cf\u5728\u67dc\u5b50\u91cc\u3002\u7b49\u5927\u4eba\u4e0d\u6ce8\u610f\u65f6\uff0c\u4ed6\u5c31\u628a\u6211\u53eb\u8fc7\u53bb\uff0c\u6253\u5f00\u67dc\u95e8\uff0c\u5c0f\u58f0\u8bf4\uff1a\u201c\u62ff\u53bb\u5403\uff0c\u4e0d\u8981\u7ed9\u4f60\u7238\u5988\u77e5\u9053\u592a\u591a\u3002\u201d\u4ed6\u81ea\u5df1\u820d\u4e0d\u5f97\u5403\u751c\u7684\uff0c\u5374\u8bb0\u5f97\u6211\u559c\u6b22\u4ec0\u4e48\u5473\u9053\u3002 \u4ed6\u8001\u4e86\u4ee5\u540e\u8d70\u8def\u53d8\u6162\uff0c\u542c\u529b\u4e5f\u4e0b\u964d\u4e86\u3002\u6211\u6709\u65f6\u8ddf\u4ed6\u8bf4\u8bdd\uff0c\u4ed6\u8981\u95ee\u597d\u51e0\u904d\u3002\u6211\u90a3\u65f6\u4e0d\u8010\u70e6\uff0c\u89c9\u5f97\u6c9f\u901a\u5f88\u8d39\u52b2\u3002\u73b0\u5728\u60f3\u8d77\u6765\uff0c\u6211\u6700\u96be\u8fc7\u7684\u5c31\u662f\uff1a\u4ed6\u66fe\u7ecf\u90a3\u4e48\u8010\u5fc3\u5730\u7b49\u6211\u957f\u5927\uff0c\u800c\u6211\u5374\u6ca1\u6709\u8db3\u591f\u8010\u5fc3\u5730\u966a\u4ed6\u53d8\u8001\u3002", "chunks": [{"chunk_type": "text", "content": "\u7237\u7237\u8d77\u5e8a\u5f88\u65e9\u3002\u54ea\u6015\u665a\u5e74\u4e0d\u7528\u518d\u505a\u5de5\uff0c\u4ed6\u4e5f\u4e60\u60ef\u5929\u521a\u4eae\u5c31\u9192\u3002\u4ed6\u4f1a\u5148\u70e7\u6c34\uff0c\u7136\u540e\u628a\u9662\u5b50\u626b\u4e00\u904d\u3002\u626b\u5730\u7684\u65f6\u5019\u52a8\u4f5c\u5f88\u6162\uff0c\u4f46\u626b\u5f97\u5f88\u5e72\u51c0\uff0c\u8fde\u5899\u89d2\u7684\u843d\u53f6\u90fd\u4f1a\u626b\u51fa\u6765\u3002", "summary": "\u7237\u7237\u4fdd\u6301\u65e9\u8d77\u4e60\u60ef\uff0c\u575a\u6301\u6668\u95f4\u52b3\u4f5c\uff1a\u70e7\u6c34\u3001\u626b\u9662\uff0c\u52a8\u4f5c\u7f13\u6162\u4f46\u7ec6\u81f4\u5f7b\u5e95\u3002", "source_location": "manual:body"}, {"chunk_type": "text", "content": "\u4ed6\u5403\u996d\u5f88\u8282\u4fed\u3002\u7897\u91cc\u4e0d\u4f1a\u5269\u4e00\u7c92\u7c73\u3002\u770b\u5230\u6211\u4eec\u5269\u996d\uff0c\u4ed6\u4f1a\u76b1\u7709\uff0c\u4f46\u4e0d\u4f1a\u5927\u58f0\u9a82\uff0c\u53ea\u4f1a\u628a\u5269\u4e0b\u7684\u996d\u5012\u8fdb\u81ea\u5df1\u7897\u91cc\uff0c\u8bf4\uff1a\u201c\u4ee5\u524d\u60f3\u5403\u90fd\u6ca1\u6709\u3002\u201d", "summary": "\u7237\u7237\u996e\u98df\u6781\u5ea6\u8282\u4fed\uff0c\u8df5\u884c\u201c\u5149\u76d8\u201d\uff0c\u4ee5\u81ea\u8eab\u7ecf\u5386\uff08\u66fe\u7f3a\u7cae\uff09\u89e3\u91ca\u60dc\u98df\u884c\u4e3a\u3002", "source_location": "manual:body"}, {"chunk_type": "text", "content": "\u4ed6\u559c\u6b22\u559d\u6d53\u8336\u3002\u8336\u676f\u662f\u4e00\u4e2a\u65e7\u642a\u74f7\u676f\uff0c\u676f\u53e3\u5df2\u7ecf\u78d5\u6389\u4e86\u4e00\u5c0f\u5757\u3002\u4ed6\u7528\u4e86\u5f88\u591a\u5e74\uff0c\u522b\u4eba\u7ed9\u4ed6\u4e70\u65b0\u7684\uff0c\u4ed6\u4e5f\u4e0d\u7528\u3002\u4ed6\u8bf4\u65e7\u7684\u987a\u624b\u3002", "summary": "\u7237\u7237\u957f\u671f\u4f7f\u7528\u540c\u4e00\u53ea\u78d5\u635f\u7684\u65e7\u642a\u74f7\u676f\u996e\u6d53\u8336\uff0c\u62d2\u7edd\u66f4\u6362\uff0c\u8ba4\u4e3a\u65e7\u676f\u79f0\u624b\u3002", "source_location": "manual:body"}, {"chunk_type": "text", "content": "\u4ed6\u4e0d\u559c\u6b22\u62cd\u7167\u3002\u6bcf\u6b21\u5bb6\u91cc\u4eba\u62ff\u76f8\u673a\uff0c\u4ed6\u90fd\u6446\u6446\u624b\u8bf4\uff1a\u201c\u62cd\u6211\u505a\u4ec0\u4e48\uff0c\u6211\u4e00\u4e2a\u8001\u5934\u5b50\u6709\u4ec0\u4e48\u597d\u62cd\u7684\u3002\u2