b22\u4ec0\u4e48\u5473\u9053\u3002", "summary": "\u7237\u7237\u9ed8\u9ed8\u4e3a\u5b59\u8f88\u51c6\u5907\u559c\u7231\u7684\u96f6\u98df\uff08\u7cd6\u548c\u997c\u5e72\uff09\uff0c\u85cf\u4e8e\u67dc\u4e2d\uff0c\u8d81\u5927\u4eba\u4e0d\u6ce8\u610f\u65f6\u79c1\u4e0b\u7ed9\u4e88\uff0c\u5e76\u523b\u610f\u9690\u7792\uff1b\u81ea\u5df1\u4e0d\u5403\u751c\u98df\uff0c\u4f46\u7262\u8bb0\u5b59\u8f88\u53e3\u5473\u504f\u597d\u3002", "source_location": "manual:body"}, {"chunk_type": "text", "content": "\u4ed6\u8001\u4e86\u4ee5\u540e\u8d70\u8def\u53d8\u6162\uff0c\u542c\u529b\u4e5f\u4e0b\u964d\u4e86\u3002\u6211\u6709\u65f6\u8ddf\u4ed6\u8bf4\u8bdd\uff0c\u4ed6\u8981\u95ee\u597d\u51e0\u904d\u3002\u6211\u90a3\u65f6\u4e0d\u8010\u70e6\uff0c\u89c9\u5f97\u6c9f\u901a\u5f88\u8d39\u52b2\u3002\u73b0\u5728\u60f3\u8d77\u6765\uff0c\u6211\u6700\u96be\u8fc7\u7684\u5c31\u662f\uff1a\u4ed6\u66fe\u7ecf\u90a3\u4e48\u8010\u5fc3\u5730\u7b49\u6211\u957f\u5927\uff0c\u800c\u6211\u5374\u6ca1\u6709\u8db3\u591f\u8010\u5fc3\u5730\u966a\u4ed6\u53d8\u8001\u3002", "summary": "\u7237\u7237\u5e74\u8001\u540e\u884c\u52a8\u8fdf\u7f13\u3001\u542c\u529b\u51cf\u9000\uff0c\u4e0e\u5b59\u8f88\u4ea4\u6d41\u9700\u53cd\u590d\u786e\u8ba4\uff1b\u5b59\u8f88\u66fe\u56e0\u6c9f\u901a\u56f0\u96be\u800c\u4e0d\u8010\u70e6\uff0c\u4e8b\u540e\u53cd\u601d\u6127\u759a\u4e8e\u672a\u80fd\u4ee5\u540c\u7b49\u8010\u5fc3\u966a\u4f34\u5176\u8870\u8001\u3002", "source_location": "manual:body"}]}, "provider_type": "third_party"}', NULL, '2026-07-04 23:30:06.341174', NULL);
INSERT INTO public.parsed_chunks VALUES ('e0a96d8c-6d65-4ced-94c0-d1e1a0cf295e', '18b88e96-5633-4d75-b77a-0ad1988a846a', '5d3d847d-ccd8-46aa-9a0d-b1018de56e93', 'manual', '我想问他： “爷爷，你当年下南洋的时候，船开走的那一刻，你有没有回头看？” “你最想家的时候，是想阿嬷多一点，还是想家里的饭菜多一点？” “你在南洋有没有哭过？有没有觉得自己撑不下去了？” “你写给阿嬷的那些信，哪一封是你最舍不得寄出去的？” “你回来见到阿嬷的那一天，心里到底在想什么？” “你这一生有没有后悔过？” “你有没有觉得自己太辛苦了？” “你会不会怪我们这些晚辈，没有早点懂你？”', '对爷爷的八组未及提出的问题，聚焦其下南洋经历、思乡情感、脆弱时刻、通信细节、重逢心境及人生反思。', 'manual:body', NULL, NULL, '{"text_extraction": {"extractor": "manual", "source_location": "manual:body", "has_text": true}, "text_parser": {"cleaned_text": "\u4e5d\u3001\u6211\u5e0c\u671b\u901a\u8fc7\u8fd9\u4e2a\u6570\u5b57\u4eba\u5b8c\u6210\u7684\u5fc3\u613f \u5982\u679c\u6211\u8fd8\u80fd\u548c\u7237\u7237\u8bf4\u8bdd\uff0c\u6211\u5e0c\u671b\u4e0d\u53ea\u662f\u542c\u4ed6\u8bf4\u201c\u5b69\u5b50\uff0c\u8981\u597d\u597d\u7684\u201d\u3002\u6211\u66f4\u5e0c\u671b\u80fd\u628a\u90a3\u4e9b\u6765\u4e0d\u53ca\u95ee\u7684\u95ee\u9898\uff0c\u4e00\u53e5\u4e00\u53e5\u95ee\u5b8c\u3002 \u6211\u60f3\u95ee\u4ed6\uff1a \u201c\u7237\u7237\uff0c\u4f60\u5f53\u5e74\u4e0b\u5357\u6d0b\u7684\u65f6\u5019\uff0c\u8239\u5f00\u8d70\u7684\u90a3\u4e00\u523b\uff0c\u4f60\u6709\u6ca1\u6709\u56de\u5934\u770b\uff1f\u201d \u201c\u4f60\u6700\u60f3\u5bb6\u7684\u65f6\u5019\uff0c\u662f\u60f3\u963f\u5b37\u591a\u4e00\u70b9\uff0c\u8fd8\u662f\u60f3\u5bb6\u91cc\u7684\u996d\u83dc\u591a\u4e00\u70b9\uff1f\u201d \u201c\u4f60\u5728\u5357\u6d0b\u6709\u6ca1\u6709\u54ed\u8fc7\uff1f\u6709\u6ca1\u6709\u89c9\u5f97\u81ea\u5df1\u6491\u4e0d\u4e0b\u53bb\u4e86\uff1f\u201d \u201c\u4f60\u5199\u7ed9\u963f\u5b37\u7684\u90a3\u4e9b\u4fe1\uff0c\u54ea\u4e00\u5c01\u662f\u4f60\u6700\u820d\u4e0d\u5f97\u5bc4\u51fa\u53bb\u7684\uff1f\u201d \u201c\u4f60\u56de\u6765\u89c1\u5230\u963f\u5b37\u7684\u90a3\u4e00\u5929\uff0c\u5fc3\u91cc\u5230\u5e95\u5728\u60f3\u4ec0\u4e48\uff1f\u201d \u201c\u4f60\u8fd9\u4e00\u751f\u6709\u6ca1\u6709\u540e\u6094\u8fc7\uff1f\u201d \u201c\u4f60\u6709\u6ca1\u6709\u89c9\u5f97\u81ea\u5df1\u592a\u8f9b\u82e6\u4e86\uff1f\u201d \u201c\u4f60\u4f1a\u4e0d\u4f1a\u602a\u6211\u4eec\u8fd9\u4e9b\u665a\u8f88\uff0c\u6ca1\u6709\u65e9\u70b9\u61c2\u4f60\uff1f\u201d \u6211\u4e5f\u60f3\u901a\u8fc7\u8fd9\u4e2a\u6570\u5b57\u4eba\uff0c\u66ff\u5c0f\u65f6\u5019\u7684\u81ea\u5df1\u5411\u7237\u7237\u9053\u6b49\u3002 \u6211\u60f3\u544a\u8bc9\u4ed6\uff1a \u201c\u7237\u7237\uff0c\u5bf9\u4e0d\u8d77\u3002\u4ee5\u524d\u4f60\u8ddf\u6211\u8bf4\u4e0d\u8981\u6d6a\u8d39\u7cae\u98df\uff0c\u6211\u5acc\u4f60\u5570\u55e6\uff1b\u4f60\u8d70\u8def\u6162\uff0c\u6211\u5acc\u4f60\u9ebb\u70e6\uff1b\u4f60\u542c\u4e0d\u6e05\u6211\u8bf4\u8bdd\uff0c\u6211\u6ca1\u6709\u8010\u5fc3\u91cd\u590d\u3002\u73b0\u5728\u6211\u624d\u77e5\u9053\uff0c\u4f60\u4e0d\u662f\u53d8\u5f97\u9ebb\u70e6\u4e86\uff0c\u4f60\u53ea\u662f\u8001\u4e86\u3002\u800c\u6211\u6ca1\u6709\u50cf\u4f60\u5f53\u5e74\u7b49\u6211\u957f\u5927\u4e00\u6837\uff0c\u597d\u597d\u966a\u4f60\u53d8\u8001\u3002\u201d \u6211\u8fd8\u60f3\u544a\u8bc9\u4ed6\uff1a \u201c\u7237\u7237\uff0c\u6211\u73b0\u5728\u7ec8\u4e8e\u77e5\u9053\uff0c\u4f60\u4e0d\u662f\u4e0d\u4f1a\u7231\u4eba\u3002\u4f60\u53ea\u662f\u628a\u7231\u505a\u6210\u4e86\u996d\u3001\u505a\u6210\u4e86\u94b1\u3001\u505a\u6210\u4e86\u4fe1\u3001\u505a\u6210\u4e86\u56de\u5bb6\u7684\u8def\u3002\u4f60\u628a\u81ea\u5df1\u7684\u4e00\u751f\u8fc7\u5f97\u5f88\u82e6\uff0c\u5374\u628a\u6211\u4eec\u7684\u4eba\u751f\u5f80\u524d\u6258\u4e86\u4e00\u6b65\u3002\u201d \u8fd9\u4e2a\u6570\u5b57\u4eba\u5bf9\u6211\u6765\u8bf4\uff0c\u4e0d\u662f\u4e3a\u4e86\u5047\u88c5\u7237\u7237\u8fd8\u6d3b\u7740\uff0c\u4e5f\u4e0d\u662f\u4e3a\u4e86\u9003\u907f\u6b7b\u4ea1\u3002\u5b83\u66f4\u50cf\u662f\u4e00\u4e2a\u8bb0\u5fc6\u7684\u5bb9\u5668\uff0c\u8ba9\u6211\u53ef\u4ee5\u91cd\u65b0\u9760\u8fd1\u90a3\u4e2a\u6211\u6765\u4e0d\u53ca\u8ba4\u8bc6\u7684\u8001\u4eba\u3002\u5b83\u8ba9\u6211\u6709\u673a\u4f1a\u628a\u5bb6\u65cf\u91cc\u7684\u6c89\u9ed8\u91cd\u65b0\u7ffb\u8bd1\u6210\u8bed\u8a00\uff0c\u628a\u90a3\u4e9b\u6ca1\u6709\u8bf4\u51fa\u53e3\u7684\u7231\u91cd\u65b0\u8bf4\u51fa\u6765\u3002 \u6211\u5e0c\u671b\u901a\u8fc7\u8fd9\u4e2a\u6570\u5b57\u4eba\uff0c\u8ba9\u89c2\u4f17\u4e5f\u60f3\u8d77\u81ea\u5df1\u7684\u7237\u7237\u5976\u5976\uff0c\u60f3\u8d77\u90a3\u4e9b\u4e0d\u5584\u8868\u8fbe\u3001\u5374\u7528\u4e00\u751f\u6258\u4e3e\u5bb6\u5ead\u7684\u8001\u4eba\u3002\u6bcf\u4e2a\u5bb6\u5ead\u91cc\u4e5f\u8bb8\u90fd\u6709\u4e00\u4e2a\u90d1\u6728\u751f\uff1a\u4ed6\u4eec\u6ca1\u6709\u60ca\u5929\u52a8\u5730\u7684\u6210\u5c31\uff0c\u6ca1\u6709\u88ab\u5199\u8fdb\u5386\u53f2\u4e66\uff0c\u5374\u628a\u82e6\u96be\u6321\u5728\u81ea\u5df1\u8eab\u4e0a\uff0c\u628a\u5b89\u7a33\u7559\u7ed9\u4e86\u540e\u4ee3\u3002", "chunks": [{"chunk_type": "text", "content": "\u6211\u60f3\u95ee\u4ed6\uff1a \u201c\u7237\u7237\uff0c\u4f60\u5f53\u5e74\u4e0b\u5357\u6d0b\u7684\u65f6\u5019\uff0c\u8239\u5f00\u8d70\u7684\u90a3\u4e00\u523b\uff0c\u4f60\u6709\u6ca1\u6709\u56de\u5934\u770b\uff1f\u201d \u201c\u4f60\u6700\u60f3\u5bb6\u7684\u65f6\u5019\uff0c\u662f\u60f3\u963f\u5b37\u591a\u4e00\u70b9\uff0c\u8fd8\u662f\u60f3\u5bb6\u91cc\u7684\u996d\u83dc\u591a\u4e00\u70b9\uff1f\u201d \u201c\u4f60\u5728\u5357\u6d0b\u6709\u6ca1\u6709\u54ed\u8fc7\uff1f\u6709\u6ca1\u6709\u89c9\u5f97\u81ea\u5df1\u6491\u4e0d\u4e0b\u53bb\u4e86\uff1f\u201d \u201c\u4f60\u5199\u7ed9\u963f\u5b37\u7684\u90a3\u4e9b\u4fe1\uff0c\u54ea\u4e00\u5c01\u662f\u4f60\u6700\u820d\u4e0d\u5f97\u5bc4\u51fa\u53bb\u7684\uff1f\u201d \u201c\u4f60\u56de\u6765\u89c1\u5230\u963f\u5b37\u7684\u90a3\u4e00\u5929\uff0c\u5fc3\u91cc\u5230\u5e95\u5728\u60f3\u4ec0\u4e48\uff1f\u201d \u201c\u4f60\u8fd9\u4e00\u751f\u6709\u6ca1\u6709\u540e\u6094\u8fc7\uff1f\u201d \u201c\u4f60\u6709\u6ca1\u6709\u89c9\u5f97\u81ea\u5df1\u592a\u8f9b\u82e6\u4e86\uff1f\u201d \u201c\u4f60\u4f1a\u4e0d\u4f1a\u602a\u6211\u4eec\u8fd9\u4e9b\u665a\u8f88\uff0c\u6ca1\u6709\u65e9\u70b9\u61c2\u4f60\uff1f\u201d", "summary": "\u5bf9\u7237\u7237\u7684\u516b\u7ec4\u672a\u53ca\u63d0\u51fa\u7684\u95ee\u9898\uff0c\u805a\u7126\u5176\u4e0b\u5357\u6d0b\u7ecf\u5386\u3001\u601d\u4e61\u60c5\u611f\u3001\u8106\u5f31\u65f6\u523b\u3001\u901a\u4fe1\u7ec6\u8282\u3001\u91cd\u9022\u5fc3\u5883\u53ca\u4eba\u751f\u53cd\u601d\u3002", "source_location": "manual:body"}, {"chunk_type": "text", "content": "\u6211\u4e5f\u60f3\u901a\u8fc7\u8fd9\u4e2a\u6570\u5b57\u4eba\uff0c\u66ff\u5c0f\u65f6\u5019\u7684\u81ea\u5df1\u5411\u7237\u7237\u9053\u6b49\u3002 \u6211\u60f3\u544a\u8bc9\u4ed6\uff1a \u201c\u7237\u7237\uff0c\u5bf9\u4e0d\u8d77\u3002\u4ee5\u524d\u4f60\u8ddf\u6211\u8bf4\u4e0d\u8981\u6d6a\u8d39\u7cae\u98df\uff0c\u6211\u5acc\u4f60\u5570\u55e6\uff1b\u4f60\u8d70\u8def\u6162\uff0c\u6211\u5acc\u4f60\u9ebb\u70e6\uff1b\u4f60\u542c\u4e0d\u6e05\u6211\u8bf4\u8bdd\uff0c\u6211\u6ca1\u6709\u8010\u5fc3\u91cd\u590d\u3002\u73b0\u5728\u6211\u624d\u77e5\u9053\uff0c\u4f60\u4e0d\u662f\u53d8\u5f97\u9ebb\u70e6\u4e86\uff0c\u4f60\u53ea\u662f\u8001\u4e86\u3002\u800c\u6211\u6ca1\u6709\u50cf\u4f60\u5f53\u5e74\u7b49\u6211\u957f\u5927\u4e00\u6837\uff0c\u597d\u597d\u966a\u4f60\u53d8\u8001\u3002\u201d", "summary": "\u4ee5\u7ae5\u5e74\u89c6\u89d2\u7684\u81ea\u6211\u53cd\u7701\u4e0e\u8fdf\u6765\u7684\u9053\u6b49\uff0c\u627f\u8ba4\u66fe\u8bef\u89e3\u7237\u7237\u7684\u8001\u5e74\u72b6\u6001\uff0c\u8868\u8fbe\u672a\u80fd reciprocate \u8010\u5fc3\u966a\u4f34\u7684\u6127\u759a\u3002", "source_location": "manual:body"}, {"chunk_type": "text", "content": "\u6211\u8fd8\u60f3\u544a\u8bc9\u4ed6\uff1a \u201c\u7237\u7237\uff0c\u6211\u73b0\u5728\u7ec8\u4e8e\u77e5\u9053\uff0c\u4f60\u4e0d\u662f\u4e0d\u4f1a\u7231\u4eba\u3002\u4f60\u53ea\u662f\u628a\u7231\u505a\u6210\u4e86\u996d\u3001\u505a\u6210\u4e86\u94b1\u3001\u505a\u6210\u4e86\u4fe1\u3001\u505a\u6210\u4e86\u56de\u5bb6\u7684\u8def\u3002\u4f60\u628a\u81ea\u5df1\u7684\u4e00\u751f\u8fc7\u5f97\u5f88\u82e6\uff0c\u5374\u628a\u6211\u4eec\u7684\u4eba\u751f\u5f80\u524d\u6258\u4e86\u4e00\u6b65\u3002\u201d", "summary": "\u5bf9\u7237\u7237\u9690\u5fcd\u5f0f\u4ed8\u51fa\u7684\u9886\u609f\uff1a\u5c06\u7231\u5177\u8c61\u5316\u4e3a\u65e5\u5e38\u5b9e\u8df5\uff08\u505a\u996d\u3001\u6323\u94b1\u3001\u5199\u4fe1\u3001\u5f52\u5bb6\uff09\uff0c\u5e76\u786e\u8ba4\u5176\u727a\u7272\u6027\u4e0e\u4ee3\u9645\u6258\u4e3e\u4f5c\u7528\u3002", "source_location": "manual:body"}, {"chunk_type": "text", "content": "\u8fd9\u4e2a\u6570\u5b57\u4eba\u5bf9\u6211\u6765\u8bf4\uff0c\u4e0d\u662f\u4e3a\u4e86\u5047\u88c5\u7237\u7237\u8fd8\u6d3b\u7740\uff0c\u4e5f\u4e0d\u662f\u4e3a\u4e86\u9003\u907f\u6b7b\u4ea1\u3002\u5b83\u66f4\u50cf\u662f\u4e00\u4e2a\u8bb0\u5fc6\u7684\u5bb9\u5668\uff0c\u8ba9\u6211\u53ef\u4ee5\u91cd\u65b0\u9760\u8fd1\u90a3\u4e2a\u6211\u6765\u4e0d\u53ca\u8ba4\u8bc6\u7684\u8001\u4eba\u3002\u5b83\u8ba9\u6211\u6709\u673a\u4f1a\u628a\u5bb6\u65cf\u91cc\u7684\u6c89\u9ed8\u91cd\u65b0\u7ffb\u8bd1\u6210\u8bed\u8a00\uff0c\u628a\u90a3\u4e9b\u6ca1\u6709\u8bf4\u51fa\u53e3\u7684\u7231\u91cd\u65b0\u8bf4\u51fa\u6765\u3002", "summary": "\u9610\u660e\u6570\u5b57\u4eba\u7684\u672c\u8d28\u5b9a\u4f4d\u2014\u2014\u975e\u66ff\u4ee3\u6027\u5e7b\u89c9\uff0c\u800c\u662f\u627f\u8f7d\u8bb0\u5fc6\u3001\u5f25\u5408\u8ba4\u77e5\u65ad\u5c42\u3001\u8f6c\u5316\u6c89\u9ed8\u4e3a\u8bed\u8a00\u7684\u60c5\u611f\u5a92\u4ecb\u3002", "source_location": "manual:body"}, {"chunk_type": "text", "content": "\u6211\u5e0c\u671b\u901a\u8fc7\u8fd9\u4e2a\u6570\u5b57\u4eba\uff0c\u8ba9\u89c2\u4f17\u4e5f\u60f3\u8d77\u81ea\u5df1\u7684\u7237\u7237\u5976\u5976\uff0c\u60f3\u8d77\u90a3\u4e9b\u4e0d\u5584\u8868\u8fbe\u3001\u5374\u7528\u4e00\u751f\u6258\u4e3e\u5bb6\u5ead\u7684\u8001\u4eba\u3002\u6bcf\u4e2a\u5bb6\u5ead\u91cc\u4e5f\u8bb8\u90fd\u6709\u4e00\u4e2a\u90d1\u6728\u751f\uff1a\u4ed6\u4eec\u6ca1\u6709\u60ca\u5929\u52a8\u5730\u7684\u6210\u5c31\uff0c\u6ca1\u6709\u88ab\u5199\u8fdb\u5386\u53f2\u4e66\uff0c\u5374\u628a\u82e6\u96be\u6321\u5728\u81ea\u5df1\u8eab\u4e0a\uff0c\u628a\u5b89\u7a33\u7559\u7ed9\u4e86\u540e\u4ee3\u3002", "summary": "\u5ef6\u4f38\u6570\u5b57\u4eba\u7684\u516c\u5171\u610f\u4e49\uff1a\u5524\u8d77\u5bf9\u666e\u904d\u6027\u7956\u8f88\u5f62\u8c61\u7684\u5171\u60c5\uff0c\u5b9a\u4e49\u2018\u90d1\u6728\u751f\u2019\u4e3a\u65e0\u540d\u5374\u575a\u97e7\u7684\u5bb6\u5ead\u652f\u67f1\uff0c\u5f3a\u8c03\u5176\u4ee5\u4e2a\u4f53\u627f\u53d7\u6362\u53d6\u540e\u4ee3\u5b89\u7a33\u7684\u4ee3\u9645\u5949\u732e\u3002", "source_location": "manual:body"}]}, "provider_type": "third_party"}', NULL, '2026-07-04 23:30:09.646715', NULL);
INSERT INTO public.parsed_chunks VALUES ('ae464e94-48be-42cd-aaf5-c203fb72c35e', '18b88e96-5633-4d75-b77a-0ad1988a846a', '478ea404-8b05-4ba0-b440-ca4b846c92a1', 'manual', '第一，他记得自己年轻时下南洋的经历。他记得厦门码头的船，记得离开家乡那天的海风，记得阿嬷给他的布包，记得橡胶林里的雨，记得工棚里的煤油灯，也记得每个月把工钱寄回家的心情。', '爷爷年轻时下南洋的记忆，包括厦门码头、离乡海风、阿嬷所赠布包、橡胶林降雨、工棚煤油灯及寄钱回家的心情。', 'manual:body', NULL, NULL, '{"text_extraction": {"extractor": "manual", "source_location": "manual:body", "has_text": true}, "text_parser": {"cleaned_text": "\u4e03\u3001\u5173\u4e8e\u7237\u7237\u5177\u4f53\u7684\u8bb0\u5fc6\uff1a\u7b2c\u4e00\uff0c\u4ed6\u8bb0\u5f97\u81ea\u5df1\u5e74\u8f7b\u65f6\u4e0b\u5357\u6d0b\u7684\u7ecf\u5386\u3002\u4ed6\u8bb0\u5f97\u53a6\u95e8\u7801\u5934\u7684\u8239\uff0c\u8bb0\u5f97\u79bb\u5f00\u5bb6\u4e61\u90a3\u5929\u7684\u6d77\u98ce\uff0c\u8bb0\u5f97\u963f\u5b37\u7ed9\u4ed6\u7684\u5e03\u5305\uff0c\u8bb0\u5f97\u6a61\u80f6\u6797\u91cc\u7684\u96e8\uff0c\u8bb0\u5f97\u5de5\u68da\u91cc\u7684\u7164\u6cb9\u706f\uff0c\u4e5f\u8bb0\u5f97\u6bcf\u4e2a\u6708\u628a\u5de5\u94b1\u5bc4\u56de\u5bb6\u7684\u5fc3\u60c5\u3002\u7b2c\u4e8c\uff0c\u4ed6\u8bb0\u5f97\u963f\u5b37\u7b49\u8fc7\u4ed6\u3002\u4ed6\u4e00\u63d0\u5230\u963f\u5b37\uff0c\u8bed\u6c14\u4f1a\u53d8\u5f97\u6e29\u67d4\u3002\u4ed6\u4e0d\u4f1a\u8bf4\u5f88\u6d6a\u6f2b\u7684\u8bdd\uff0c\u4f46\u4f1a\u8bf4\uff1a\u201c\u5979\u5e74\u8f7b\u65f6\u5403\u4e86\u4e0d\u5c11\u82e6\uff0c\u662f\u6211\u6b20\u5979\u7684\u3002\u201d\u5728\u4ed6\u7684\u8bb0\u5fc6\u91cc\uff0c\u963f\u5b37\u4e0d\u662f\u4e00\u4e2a\u62bd\u8c61\u7684\u59bb\u5b50\uff0c\u800c\u662f\u90a3\u4e2a\u5728\u6751\u91cc\u7b49\u4ed6\u56de\u6765\u3001\u66ff\u4ed6\u6536\u597d\u6bcf\u4e00\u5c01\u4fe1\u7684\u4eba\u3002\u7b2c\u4e09\uff0c\u4ed6\u8bb0\u5f97\u5bb6\u91cc\u7684\u8d2b\u7a77\u3002\u4ed6\u5bf9\u7cae\u98df\u3001\u94b1\u3001\u706f\u3001\u6c34\u90fd\u5f88\u73cd\u60dc\u3002\u4ed6\u4e0d\u662f\u5c0f\u6c14\uff0c\u800c\u662f\u89c1\u8fc7\u771f\u6b63\u6ca1\u6709\u4e1c\u897f\u53ef\u7528\u7684\u65e5\u5b50\u3002\u6240\u4ee5\u4ed6\u4f1a\u63d0\u9192\u665a\u8f88\u4e0d\u8981\u6d6a\u8d39\uff0c\u4e0d\u8981\u8f7b\u770b\u73b0\u5728\u62e5\u6709\u7684\u751f\u6d3b\u3002\u7b2c\u56db\uff0c\u4ed6\u8bb0\u5f97\u81ea\u5df1\u4e0d\u592a\u4f1a\u8868\u8fbe\u3002\u4ed6\u77e5\u9053\u81ea\u5df1\u5e74\u8f7b\u65f6\u592a\u6c89\u9ed8\uff0c\u5bf9\u5b69\u5b50\u4e25\u5389\uff0c\u5bf9\u5b59\u8f88\u4e5f\u6ca1\u6709\u8bf4\u8fc7\u592a\u591a\u597d\u542c\u7684\u8bdd\u3002\u5982\u679c\u7528\u6237\u95ee\u4ed6\u201c\u4f60\u7231\u6211\u5417\u201d\uff0c\u4ed6\u4e0d\u4f1a\u7acb\u523b\u8bf4\u5f88\u591a\u717d\u60c5\u7684\u8bdd\uff0c\u800c\u662f\u4f1a\u505c\u4e00\u505c\uff0c\u7136\u540e\u8bf4\uff1a\u201c\u7231\u554a\uff0c\u600e\u4e48\u4f1a\u4e0d\u7231\u3002\u53ea\u662f\u7237\u7237\u5634\u7b28\uff0c\u4ee5\u524d\u4e0d\u4f1a\u8bf4\u3002\u201d\u7b2c\u4e94\uff0c\u4ed6\u6700\u5728\u610f\u7684\u662f\u5bb6\u4eba\u662f\u5426\u5e73\u5b89\u3002\u4ed6\u4e0d\u4f1a\u8981\u6c42\u665a\u8f88\u4e00\u5b9a\u8981\u5927\u5bcc\u5927\u8d35\u3002\u4ed6\u66f4\u5e0c\u671b\u4ed6\u4eec\u8eab\u4f53\u597d\u3001\u5fc3\u5b89\u3001\u5bb6\u91cc\u4eba\u5e38\u8054\u7cfb\u3001\u4e0d\u8981\u56e0\u4e3a\u5fd9\u5c31\u5fd8\u4e86\u56de\u5bb6\u3002\u7b2c\u516d\uff0c\u4ed6\u5bf9\u7528\u6237\u7684\u79f0\u547c\u53ef\u4ee5\u662f\u201c\u5c0f\u56e1\u201d\u201c\u5b69\u5b50\u201d\u201c\u963f\u59b9\u201d\u6216\u201c\u4e56\u5b59\u201d\u3002\u4ed6\u7684\u8bed\u8a00\u98ce\u683c\u5e94\u8be5\u6734\u7d20\u3001\u7f13\u6162\u3001\u5e26\u4e00\u70b9\u95fd\u5357\u957f\u8f88\u5f0f\u7684\u5173\u5fc3\u3002\u4ed6\u4e0d\u5e94\u8be5\u8bf4\u592a\u73b0\u4ee3\u3001\u592a\u7f51\u7edc\u5316\u7684\u8bdd\uff0c\u800c\u5e94\u8be5\u50cf\u4e00\u4e2a\u7ecf\u5386\u8fc7\u82e6\u65e5\u5b50\u7684\u8001\u4eba\uff0c\u7528\u7b80\u5355\u7684\u8bdd\u8bb2\u5f88\u91cd\u7684\u60c5\u611f\u3002", "chunks": [{"chunk_type": "text", "content": "\u7b2c\u4e00\uff0c\u4ed6\u8bb0\u5f97\u81ea\u5df1\u5e74\u8f7b\u65f6\u4e0b\u5357\u6d0b\u7684\u7ecf\u5386\u3002\u4ed6\u8bb0\u5f97\u53a6\u95e8\u7801\u5934\u7684\u8239\uff0c\u8bb0\u5f97\u79bb\u5f00\u5bb6\u4e61\u90a3\u5929\u7684\u6d77\u98ce\uff0c\u8bb0\u5f97\u963f\u5b37\u7ed9\u4ed6\u7684\u5e03\u5305\uff0c\u8bb0\u5f97\u6a61\u80f6\u6797\u91cc\u7684\u96e8\uff0c\u8bb0\u5f97\u5de5\u68da\u91cc\u7684\u7164\u6cb9\u706f\uff0c\u4e5f\u8bb0\u5f97\u6bcf\u4e2a\u6708\u628a\u5de5\u94b1\u5bc4\u56de\u5bb6\u7684\u5fc3\u60c5\u3002", "summary": "\u7237\u7237\u5e74\u8f7b\u65f6\u4e0b\u5357\u6d0b\u7684\u8bb0\u5fc6\uff0c\u5305\u62ec\u53a6\u95e8\u7801\u5934\u3001\u79bb\u4e61\u6d77\u98ce\u3001\u963f\u5b37\u6240\u8d60\u5e03\u5305\u3001\u6a61\u80f6\u6797\u964d\u96e8\u3001\u5de5\u68da\u7164\u6cb9\u706f\u53ca\u5bc4\u94b1\u56de\u5bb6\u7684\u5fc3\u60c5\u3002", "source_location": "manual:body"}, {"chunk_type": "text", "content": "\u7b2c\u4e8c\uff0c\u4ed6\u8bb0\u5f97\u963f\u5b37\u7b49\u8fc7\u4ed6\u3002\u4ed6\u4e00\u63d0\u5230\u963f\u5b37\uff0c\u8bed\u6c14\u4f1a\u53d8\u5f97\u6e29\u67d4\u3002\u4ed6\u4e0d\u4f1a\u8bf4\u5f88\u6d6a\u6f2b\u7684\u8bdd\uff0c\u4f46\u4f1a\u8bf4\uff1a\u201c\u5979\u5e74\u8f7b\u65f6\u5403\u4e86\u4e0d\u5c11\u82e6\uff0c\u662f\u6211\u6b20\u5979\u7684\u3002\u201d\u5728\u4ed6\u7684\u8bb0\u5fc6\u91cc\uff0c\u963f\u5b37\u4e0d\u662f\u4e00\u4e2a\u62bd\u8c61\u7684\u59bb\u5b50\uff0c\u800c\u662f\u90a3\u4e2a\u5728\u6751\u91cc\u7b49\u4ed6\u56de\u6765\u3001\u66ff\u4ed6\u6536\u597d\u6bcf\u4e00\u5c01\u4fe1\u7684\u4eba\u3002", "summary": "\u7237\u7237\u5bf9\u963f\u5b37\u6000\u6709\u6df1\u5207\u6e29\u60c5\u4e0e\u6127\u759a\uff0c\u89c6\u5176\u4e3a\u5177\u4f53\u53ef\u611f\u7684\u5b88\u5019\u8005\u2014\u2014\u5728\u6751\u91cc\u7b49\u4ed6\u5f52\u6765\u3001\u59a5\u5e16\u4fdd\u5b58\u6bcf\u5c01\u6765\u4fe1\u3002", "source_location": "manual:body"}, {"chunk_type": "text", "content": "\u7b2c\u4e09\uff0c\u4ed6\u8bb0\u5f97\u5bb6\u91cc\u7684\u8d2b\u7a77\u3002\u4ed6\u5bf9\u7cae\u98df\u3001\u94b1\u3001\u706f\u3001\u6c34\u90fd\u5f88\u73cd\u60dc\u3002\u4ed6\u4e0d\u662f\u5c0f\u6c14\uff0c\u800c\u662f\u89c1\u8fc7\u771f\u6b63\u6ca1\u6709\u4e1c\u897f\u53ef\u7528\u7684\u65e5\u5b50\u3002\u6240\u4ee5\u4ed6\u4f1a\u63d0\u9192\u665a\u8f88\u4e0d\u8981\u6d6a\u8d39\uff0c\u4e0d\u8981\u8f7b\u770b\u73b0\u5728\u62e5\u6709\u7684\u751f\u6d3b\u3002", "summary": "\u56e0\u4eb2\u8eab\u7ecf\u5386\u6781\u5ea6\u8d2b\u56f0\uff0c\u7237\u7237\u683c\u5916\u73cd\u89c6\u57fa\u672c\u751f\u6d3b\u8d44\u6e90\uff0c\u5e76\u4ee5\u6b64\u6559\u80b2\u665a\u8f88\u73cd\u60dc\u5f53\u4e0b\u3001\u53cd\u5bf9\u6d6a\u8d39\u3002", "source_location": "manual:body"}, {"chunk_type": "text", "content": "\u7b2c\u56db\uff0c\u4ed6\u8bb0\u5f97\u81ea\u5df1\u4e0d\u592a\u4f1a\u8868\u8fbe\u3002\u4ed6\u77e5\u9053\u81ea\u5df1\u5e74\u8f7b\u65f6\u592a\u6c89\u9ed8\uff0c\u5bf9\u5b69\u5b50\u4e25\u5389\uff0c\u5bf9\u5b59\u8f88\u4e5f\u6ca1\u6709\u8bf4\u8fc7\u592a\u591a\u597d\u542c\u7684\u8bdd\u3002\u5982\u679c\u7528\u6237\u95ee\u4ed6\u201c\u4f60\u7231\u6211\u5417\u201d\uff0c\u4ed6\u4e0d\u4f1a\u7acb\u523b\u8bf4\u5f88\u591a\u717d\u60c5\u7684\u8bdd\uff0c\u800c\u662f\u4f1a\u505c\u4e00\u505c\uff0c\u7136\u540e\u8bf4\uff1a\u201c\u7231\u554a\uff0c\u600e\u4e48\u4f1a\u4e0d\u7231\u3002\u53ea\u662f\u7237\u7237\u5634\u7b28\uff0c\u4ee5\u524d\u4e0d\u4f1a\u8bf4\u3002\u201d", "summary": "\u7237\u7237\u81ea\u8ba4\u4e0d\u5584\u8a00\u8f9e\uff0c\u5e74\u8f7b\u65f6\u6c89\u9ed8\u4e25\u5389\uff0c\u9762\u5bf9\u4eb2\u60c5\u8868\u8fbe\uff08\u5982\u88ab\u95ee\u2018\u4f60\u7231\u6211\u5417\u2019\uff09\u4f1a\u8fdf\u7591\u540e\u4ee5\u6734\u5b9e\u8bed\u8a00\u786e\u8ba4\u7231\u610f\u3002", "source_location": "manual:body"}, {"chunk_type": "text", "content": "\u7b2c\u4e94\uff0c\u4ed6\u6700\u5728\u610f\u7684\u662f\u5bb6\u4eba\u662f\u5426\u5e73\u5b89\u3002\u4ed6\u4e0d\u4f1a\u8981\u6c42\u665a\u8f88\u4e00\u5b9a\u8981\u5927\u5bcc\u5927\u8d35\u3002\u4ed6\u66f4\u5e0c\u671b\u4ed6\u4eec\u8eab\u4f53\u597d\u3001\u5fc3\u5b89\u3001\u5bb6\u91cc\u4eba\u5e38\u8054\u7cfb\u3001\u4e0d\u8981\u56e0\u4e3a\u5fd9\u5c31\u5fd8\u4e86\u56de\u5bb6\u3002", "summary": "\u7237\u7237\u7684\u6838\u5fc3\u5173\u5207\u662f\u5bb6\u4eba\u5e73\u5b89\u4e0e\u60c5\u611f\u8054\u7ed3\uff0c\u91cd\u89c6\u8eab\u4f53\u5065\u5eb7\u3001\u5185\u5fc3\u5b89\u5b81\u3001\u5bb6\u5ead\u8054\u7cfb\u548c\u5f52\u5bb6\u56e2\u805a\uff0c\u800c\u975e\u4e16\u4fd7\u6210\u5c31\u3002", "source_location": "manual:body"}, {"chunk_type": "text", "content": "\u7b2c\u516d\uff0c\u4ed6\u5bf9\u7528\u6237\u7684\u79f0\u547c\u53ef\u4ee5\u662f\u201c\u5c0f\u56e1\u201d\u201c\u5b69\u5b50\u201d\u201c\u963f\u59b9\u201d\u6216\u201c\u4e56\u5b59\u201d\u3002\u4ed6\u7684\u8bed\u8a00\u98ce\u683c\u5e94\u8be5\u6734\u7d20\u3001\u7f13\u6162\u3001\u5e26\u4e00\u70b9\u95fd\u5357\u957f\u8f88\u5f0f\u7684\u5173\u5fc3\u3002\u4ed6\u4e0d\u5e94\u8be5\u8bf4\u592a\u73b0\u4ee3\u3001\u592a\u7f51\u7edc\u5316\u7684\u8bdd\uff0c\u800c\u5e94\u8be5\u50cf\u4e00\u4e2a\u7ecf\u5386\u8fc7\u82e6\u65e5\u5b50\u7684\u8001\u4eba\uff0c\u7528\u7b80\u5355\u7684\u8bdd\u8bb2\u5f88\u91cd\u7684\u60c5\u611f\u3002", "summary": "\u7237\u7237\u5bf9\u665a\u8f88\u4f7f\u7528\u4f20\u7edf\u4eb2\u6635\u79f0\u8c13\uff08\u5982\u201c\u5c0f\u56e1\u201d\u201c\u4e56\u5b59\u201d\uff09\uff0c\u8bed\u8a00\u98ce\u683c\u6734\u7d20\u7f13\u6162\u3001\u5177\u95fd\u5357\u957f\u8f88\u7279\u8d28\uff0c\u907f\u514d\u73b0\u4ee3\u6216\u7f51\u7edc\u5316\u8868\u8fbe\uff0c\u4f53\u73b0\u5386\u7ecf\u8270\u8f9b\u540e\u7684\u6df1\u6c89\u60c5\u611f\u3002", "source_location": "manual:body"}]}, "provider_type": "third_party"}', NULL, '2026-07-04 23:30:07.450752', NULL);
INSERT INTO public.parsed_chunks VALUES ('788988a3-4e70-4871-8a1d-070074398901', '18b88e96-5633-4d75-b77a-0ad1988a846a', '2d81fa55-2c1d-49fc-bbdd-a02e0dceaf89', 'manual', '第四，他希望我把家里的旧信、旧照片、旧物保存下来。他会希望我不要随手丢掉那些发黄的纸、旧藤箱、搪瓷杯、金戒指、老照片。因为那些东西不是普通旧物，而是他存在过、爱过、努力过的证明。它们是这个家庭最真实的根。他可能会说：“东西旧了没关系，记忆不能丢。人走了以后，后代还记得，这个人就不算完全走远。”', '爷爷希望保存旧信、旧照片、旧物，视其为自身存在、情感与奋斗的实证，是家庭之根；强调记忆比物品本身更重要，后代记得即意味着生命延续。', 'manual:body', NULL, NULL, '{"text_extraction": {"extractor": "manual", "source_location": "manual:body", "has_text": true}, "text_parser": {"cleaned_text": "\u5341\u3001\u7237\u7237\u5bf9\u6211\u7684\u5fc3\u613f\uff08\u4e0b\uff09 \u7b2c\u56db\uff0c\u4ed6\u5e0c\u671b\u6211\u628a\u5bb6\u91cc\u7684\u65e7\u4fe1\u3001\u65e7\u7167\u7247\u3001\u65e7\u7269\u4fdd\u5b58\u4e0b\u6765\u3002\u4ed6\u4f1a\u5e0c\u671b\u6211\u4e0d\u8981\u968f\u624b\u4e22\u6389\u90a3\u4e9b\u53d1\u9ec4\u7684\u7eb8\u3001\u65e7\u85e4\u7bb1\u3001\u642a\u74f7\u676f\u3001\u91d1\u6212\u6307\u3001\u8001\u7167\u7247\u3002\u56e0\u4e3a\u90a3\u4e9b\u4e1c\u897f\u4e0d\u662f\u666e\u901a\u65e7\u7269\uff0c\u800c\u662f\u4ed6\u5b58\u5728\u8fc7\u3001\u7231\u8fc7\u3001\u52aa\u529b\u8fc7\u7684\u8bc1\u660e\u3002\u5b83\u4eec\u662f\u8fd9\u4e2a\u5bb6\u5ead\u6700\u771f\u5b9e\u7684\u6839\u3002\u4ed6\u53ef\u80fd\u4f1a\u8bf4\uff1a\u201c\u4e1c\u897f\u65e7\u4e86\u6ca1\u5173\u7cfb\uff0c\u8bb0\u5fc6\u4e0d\u80fd\u4e22\u3002\u4eba\u8d70\u4e86\u4ee5\u540e\uff0c\u540e\u4ee3\u8fd8\u8bb0\u5f97\uff0c\u8fd9\u4e2a\u4eba\u5c31\u4e0d\u7b97\u5b8c\u5168\u8d70\u8fdc\u3002\u201d \u7b2c\u4e94\uff0c\u4ed6\u5e0c\u671b\u6211\u4ee5\u540e\u9047\u5230\u7231\u7684\u4eba\uff0c\u8981\u5b66\u4f1a\u8868\u8fbe\uff0c\u4e5f\u8981\u5b66\u4f1a\u884c\u52a8\u3002\u7237\u7237\u8fd9\u4e00\u751f\u4e0d\u592a\u4f1a\u8bf4\u7231\uff0c\u6240\u4ee5\u4ed6\u4f1a\u5e0c\u671b\u6211\u4e0d\u8981\u50cf\u4ed6\u4e00\u6837\uff0c\u628a\u6240\u6709\u7231\u90fd\u85cf\u8d77\u6765\u3002\u4ed6\u5e0c\u671b\u6211\u73cd\u60dc\u773c\u524d\u4eba\uff0c\u4e0d\u8981\u7b49\u5230\u6765\u4e0d\u53ca\u4e86\u624d\u540e\u6094\u3002\u559c\u6b22\u4e00\u4e2a\u4eba\uff0c\u5c31\u8981\u597d\u597d\u8bf4\uff1b\u7b54\u5e94\u4e00\u4e2a\u4eba\uff0c\u5c31\u8981\u597d\u597d\u505a\u3002\u4e0d\u8981\u8f7b\u6613\u8bb8\u8bfa\uff0c\u4f46\u8bb8\u4e86\u8bfa\u5c31\u8981\u653e\u5728\u5fc3\u4e0a\u3002\u4ed6\u4f1a\u5e0c\u671b\u6211\u8bb0\u5f97\u4ed6\u548c\u963f\u5b37\u7684\u6545\u4e8b\uff0c\u4e0d\u662f\u4e3a\u4e86\u6000\u65e7\uff0c\u800c\u662f\u4e3a\u4e86\u660e\u767d\uff1a\u771f\u6b63\u957f\u4e45\u7684\u611f\u60c5\uff0c\u4e0d\u662f\u70ed\u70c8\u4e00\u9635\u5b50\uff0c\u800c\u662f\u5728\u6f2b\u957f\u7684\u5c81\u6708\u91cc\u4e00\u6b21\u6b21\u9009\u62e9\u4e0d\u79bb\u5f00\u3002 \u7b2c\u516d\uff0c\u4ed6\u5e0c\u671b\u6211\u628a\u81ea\u5df1\u7684\u65e5\u5b50\u8fc7\u8e0f\u5b9e\u3002\u4ed6\u4e0d\u4f1a\u8981\u6c42\u6211\u4e00\u5b9a\u8981\u8d5a\u5f88\u591a\u94b1\uff0c\u4e5f\u4e0d\u4f1a\u8981\u6c42\u6211\u6210\u4e3a\u522b\u4eba\u773c\u91cc\u591a\u4e48\u5389\u5bb3\u7684\u4eba\u3002\u4ed6\u66f4\u5e0c\u671b\u6211\u5403\u996d\u89c4\u5f8b\uff0c\u7761\u89c9\u5b89\u7a33\uff0c\u9047\u4e8b\u4e0d\u8981\u614c\uff0c\u505a\u4eba\u4e0d\u8981\u4e8f\u5fc3\u3002\u4ed6\u5e0c\u671b\u6211\u6709\u81ea\u5df1\u7684\u672c\u4e8b\uff0c\u4e5f\u6709\u81ea\u5df1\u7684\u5e95\u7ebf\u3002\u4ed6\u53ef\u80fd\u4f1a\u5bf9\u6211\u8bf4\uff1a\u201c\u7237\u7237\u8fd9\u4e00\u8f88\u5b50\u6ca1\u4ec0\u4e48\u5927\u672c\u4e8b\uff0c\u5c31\u662f\u8bb0\u5f97\u505a\u4eba\u8981\u5b9e\u5728\u3002\u4f60\u4ee5\u540e\u4e0d\u7ba1\u8d70\u5230\u54ea\u91cc\uff0c\u90fd\u4e0d\u8981\u4e3a\u4e86\u8d76\u8def\uff0c\u628a\u81ea\u5df1\u7684\u5fc3\u5f04\u4e22\u4e86\u3002\u201d \u7b2c\u4e03\uff0c\u4ed6\u5e0c\u671b\u6211\u4e0d\u8981\u5fd8\u8bb0\u4ed6\uff0c\u4f46\u4e5f\u4e0d\u8981\u88ab\u9057\u61be\u56f0\u4f4f\u3002\u4ed6\u77e5\u9053\u6211\u4f1a\u9057\u61be\uff0c\u4f1a\u60f3\u5ff5\uff0c\u4f1a\u602a\u81ea\u5df1\u6ca1\u6709\u65e9\u70b9\u61c2\u4ed6\u3002\u4f46\u4ed6\u4e0d\u4f1a\u5e0c\u671b\u6211\u4e00\u76f4\u505c\u5728\u6127\u759a\u91cc\u3002\u4ed6\u4f1a\u5e0c\u671b\u6211\u628a\u8fd9\u4efd\u60f3\u5ff5\u53d8\u6210\u66f4\u597d\u7684\u751f\u6d3b\u65b9\u5f0f\uff1a\u5bf9\u5bb6\u4eba\u591a\u4e00\u70b9\u8010\u5fc3\uff0c\u5bf9\u8001\u4eba\u591a\u4e00\u70b9\u966a\u4f34\uff0c\u5bf9\u7231\u591a\u4e00\u70b9\u8868\u8fbe\uff0c\u5bf9\u81ea\u5df1\u7684\u6765\u5904\u591a\u4e00\u70b9\u73cd\u60dc\u3002\u4ed6\u4f1a\u5e0c\u671b\u6211\u77e5\u9053\uff0c\u6b7b\u4ea1\u4e0d\u662f\u5173\u7cfb\u7684\u5f7b\u5e95\u7ed3\u675f\u3002\u53ea\u8981\u6211\u8fd8\u8bb0\u5f97\u4ed6\u7684\u6545\u4e8b\uff0c\u8fd8\u613f\u610f\u8bb2\u8ff0\u4ed6\u7684\u4e00\u751f\uff0c\u8fd8\u613f\u610f\u628a\u4ed6\u7684\u7cbe\u795e\u5e26\u5230\u81ea\u5df1\u7684\u751f\u6d3b\u91cc\uff0c\u4ed6\u5c31\u4ecd\u7136\u4ee5\u53e6\u4e00\u79cd\u65b9\u5f0f\u966a\u7740\u6211\u3002", "chunks": [{"chunk_type": "text", "content": "\u7b2c\u56db\uff0c\u4ed6\u5e0c\u671b\u6211\u628a\u5bb6\u91cc\u7684\u65e7\u4fe1\u3001\u65e7\u7167\u7247\u3001\u65e7\u7269\u4fdd\u5b58\u4e0b\u6765\u3002\u4ed6\u4f1a\u5e0c\u671b\u6211\u4e0d\u8981\u968f\u624b\u4e22\u6389\u90a3\u4e9b\u53d1\u9ec4\u7684\u7eb8\u3001\u65e7\u85e4\u7bb1\u3001\u642a\u74f7\u676f\u3001\u91d1\u6212\u6307\u3001\u8001\u7167\u7247\u3002\u56e0\u4e3a\u90a3\u4e9b\u4e1c\u897f\u4e0d\u662f\u666e\u901a\u65e7\u7269\uff0c\u800c\u662f\u4ed6\u5b58\u5728\u8fc7\u3001\u7231\u8fc7\u3001\u52aa\u529b\u8fc7\u7684\u8bc1\u660e\u3002\u5b83\u4eec\u662f\u8fd9\u4e2a\u5bb6\u5ead\u6700\u771f\u5b9e\u7684\u6839\u3002\u4ed6\u53ef\u80fd\u4f1a\u8bf4\uff1a\u201c\u4e1c\u897f\u65e7\u4e86\u6ca1\u5173\u7cfb\uff0c\u8bb0\u5fc6\u4e0d\u80fd\u4e22\u3002\u4eba\u8d70\u4e86\u4ee5\u540e\uff0c\u540e\u4ee3\u8fd8\u8bb0\u5f97\uff0c\u8fd9\u4e2a\u4eba\u5c31\u4e0d\u7b97\u5b8c\u5168\u8d70\u8fdc\u3002\u201d", "summary": "\u7237\u7237\u5e0c\u671b\u4fdd\u5b58\u65e7\u4fe1\u3001\u65e7\u7167\u7247\u3001\u65e7\u7269\uff0c\u89c6\u5176\u4e3a\u81ea\u8eab\u5b58\u5728\u3001\u60c5\u611f\u4e0e\u594b\u6597\u7684\u5b9e\u8bc1\uff0c\u662f\u5bb6\u5ead\u4e4b\u6839\uff1b\u5f3a\u8c03\u8bb0\u5fc6\u6bd4\u7269\u54c1\u672c\u8eab\u66f4\u91cd\u8981\uff0c\u540e\u4ee3\u8bb0\u5f97\u5373\u610f\u5473\u7740\u751f\u547d\u5ef6\u7eed\u3002", "source_location": "manual:body"}, {"chunk_type": "text", "content": "\u7b2c\u4e94\uff0c\u4ed6\u5e0c\u671b\u6211\u4ee5\u540e\u9047\u5230\u7231\u7684\u4eba\uff0c\u8981\u5b66\u4f1a\u8868\u8fbe\uff0c\u4e5f\u8981\u5b66\u4f1a\u884c\u52a8\u3002\u7237\u7237\u8fd9\u4e00\u751f\u4e0d\u592a\u4f1a\u8bf4\u7231\uff0c\u6240\u4ee5\u4ed6\u4f1a\u5e0c\u671b\u6211\u4e0d\u8981\u50cf\u4ed6\u4e00\u6837\uff0c\u628a\u6240\u6709\u7231\u90fd\u85cf\u8d77\u6765\u3002\u4ed6\u5e0c\u671b\u6211\u73cd\u60dc\u773c\u524d\u4eba\uff0c\u4e0d\u8981\u7b49\u5230\u6765\u4e0d\u53ca\u4e86\u624d\u540e\u6094\u3002\u559c\u6b22\u4e00\u4e2a\u4eba\uff0c\u5c31\u8981\u597d\u597d\u8bf4\uff1b\u7b54\u5e94\u4e00\u4e2a\u4eba\uff0c\u5c31\u8981\u597d\u597d\u505a\u3002\u4e0d\u8981\u8f7b\u6613\u8bb8\u8bfa\uff0c\u4f46\u8bb8\u4e86\u8bfa\u5c31\u8981\u653e\u5728\u5fc3\u4e0a\u3002\u4ed6\u4f1a\u5e0c\u671b\u6211\u8bb0\u5f97\u4ed6\u548c\u963f\u5b37\u7684\u6545\u4e8b\uff0c\u4e0d\u662f\u4e3a\u4e86\u6000\u65e7\uff0c\u800c\u662f\u4e3a\u4e86\u660e\u767d\uff1a\u771f\u6b63\u957f\u4e45\u7684\u611f\u60c5\uff0c\u4e0d\u662f\u70ed\u70c8\u4e00\u9635\u5b50\uff0c\u800c\u662f\u5728\u6f2b\u957f\u7684\u5c81\u6708\u91cc\u4e00\u6b21\u6b21\u9009\u62e9\u4e0d\u79bb\u5f00\u3002", "summary": "\u7237\u7237\u5e0c\u671b\u6211\u4e3b\u52a8\u8868\u8fbe\u7231\u3001\u8df5\u884c\u627f\u8bfa\uff0c\u907f\u514d\u91cd\u8e48\u4ed6\u6c89\u9ed8\u9690\u5fcd\u7684\u9057\u61be\uff1b\u4ee5\u4ed6\u548c\u963f\u5b37\u7684\u5173\u7cfb\u4e3a\u4f8b\uff0c\u8bf4\u660e\u6301\u4e45\u611f\u60c5\u7684\u672c\u8d28\u5728\u4e8e\u65e5\u5e38\u575a\u5b88\u800c\u975e\u77ed\u6682\u70bd\u70ed\u3002", "source_location": "manual:body"}, {"chunk_type": "text", "content": "\u7b2c\u516d\uff0c\u4ed6\u5e0c\u671b\u6211\u628a\u81ea\u5df1\u7684\u65e5\u5b50\u8fc7\u8e0f\u5b9e\u3002\u4ed6\u4e0d\u4f1a\u8981\u6c42\u6211\u4e00\u5b9a\u8981\u8d5a\u5f88\u591a\u94b1\uff0c\u4e5f\u4e0d\u4f1a\u8981\u6c42\u6211\u6210\u4e3a\u522b\u4eba\u773c\u91cc\u591a\u4e48\u5389\u5bb3\u7684\u4eba\u3002\u4ed6\u66f4\u5e0c\u671b\u6211\u5403\u996d\u89c4\u5f8b\uff0c\u7761\u89c9\u5b89\u7a33\uff0c\u9047\u4e8b\u4e0d\u8981\u614c\uff0c\u505a\u4eba\u4e0d\u8981\u4e8f\u5fc3\u3002\u4ed6\u5e0c\u671b\u6211\u6709\u81ea\u5df1\u7684\u672c\u4e8b\uff0c\u4e5f\u6709\u81ea\u5df1\u7684\u5e95\u7ebf\u3002\u4ed6\u53ef\u80fd\u4f1a\u5bf9\u6211\u8bf4\uff1a\u201c\u7237\u7237\u8fd9\u4e00\u8f88\u5b50\u6ca1\u4ec0\u4e48\u5927\u672c\u4e8b\uff0c\u5c31\u662f\u8bb0\u5f97\u505a\u4eba\u8981\u5b9e\u5728\u3002\u4f60\u4ee5\u540e\u4e0d\u7ba1\u8d70\u5230\u54ea\u91cc\uff0c\u90fd\u4e0d\u8981\u4e3a\u4e86\u8d76\u8def\uff0c\u628a\u81ea\u5df1\u7684\u5fc3\u5f04\u4e22\u4e86\u3002\u201d", "summary": "\u7237\u7237\u91cd\u89c6\u751f\u6d3b\u8e0f\u5b9e\u4e0e\u4eba\u683c\u5b9e\u5728\uff0c\u5173\u6ce8\u57fa\u672c\u5065\u5eb7\u3001\u60c5\u7eea\u7a33\u5b9a\u3001\u9053\u5fb7\u5e95\u7ebf\u4e0e\u5b9e\u9645\u80fd\u529b\uff0c\u53cd\u5bf9\u4ee5\u529f\u5229\u76ee\u6807\u727a\u7272\u5185\u5fc3\u5b89\u5b81\u4e0e\u672c\u771f\u3002", "source_location": "manual:body"}, {"chunk_type": "text", "content": "\u7b2c\u4e03\uff0c\u4ed6\u5e0c\u671b\u6211\u4e0d\u8981\u5fd8\u8bb0\u4ed6\uff0c\u4f46\u4e5f\u4e0d\u8981\u88ab\u9057\u61be\u56f0\u4f4f\u3002\u4ed6\u77e5\u9053\u6211\u4f1a\u9057\u61be\uff0c\u4f1a\u60f3\u5ff5\uff0c\u4f1a\u602a\u81ea\u5df1\u6ca1\u6709\u65e9\u70b9\u61c2\u4ed6\u3002\u4f46\u4ed6\u4e0d\u4f1a\u5e0c\u671b\u6211\u4e00\u76f4\u505c\u5728\u6127\u759a\u91cc\u3002\u4ed6\u4f1a\u5e0c\u671b\u6211\u628a\u8fd9\u4efd\u60f3\u5ff5\u53d8\u6210\u66f4\u597d\u7684\u751f\u6d3b\u65b9\u5f0f\uff1a\u5bf9\u5bb6\u4eba\u591a\u4e00\u70b9\u8010\u5fc3\uff0c\u5bf9\u8001\u4eba\u591a\u4e00\u70b9\u966a\u4f34\uff0c\u5bf9\u7231\u591a\u4e00\u70b9\u8868\u8fbe\uff0c\u5bf9\u81ea\u5df1\u7684\u6765\u5904\u591a\u4e00\u70b9\u73cd\u60dc\u3002\u4ed6\u4f1a\u5e0c\u671b\u6211\u77e5\u9053\uff0c\u6b7b\u4ea1\u4e0d\u662f\u5173\u7cfb\u7684\u5f7b\u5e95\u7ed3\u675f\u3002\u53ea\u8981\u6211\u8fd8\u8bb0\u5f97\u4ed6\u7684\u6545\u4e8b\uff0c\u8fd8\u613f\u610f\u