\u8868\u8fbe\u5173\u7231\u7684\u65b9\u5f0f", "content": "\u5916\u5a46\u901a\u8fc7\u505a\u996d\u548c\u53e3\u8bed\u5316\u795d\u798f\uff08\u2018\u53ea\u8981\u5c0f\u94ed\u5e73\u5b89\u5c31\u597d\u2019\uff09\u8868\u8fbe\u5173\u7231", "category": "expression_style", "confidence_level": "high", "status": "confirmed"}]', '[{"memory_id": "2e0448f9-f314-4737-a3f5-20e81e562d3e", "title": "\u5c0f\u94ed\u751f\u65e5\u805a\u4f1a", "content": "\u5c0f\u94ed\u751f\u65e5\u5f53\u5929\uff0c\u5916\u5a46\u53c2\u4e0e\u7b79\u5907\u5e76\u8868\u8fbe\u795d\u798f\uff0c\u6784\u6210\u5171\u4eab\u7684\u5bb6\u5ead\u5e86\u795d\u4e8b\u4ef6", "category": "shared_event", "confidence_level": "high", "status": "confirmed"}]', '[]', '[]', NULL, '{"shared_events": ["2e0448f9-f314-4737-a3f5-20e81e562d3e"], "expression_style": ["5c68cf90-3025-42a2-8006-2f2349b7f02e", "8c16f55d-cdcc-457c-81f5-d54c818b512d"], "basic_facts": ["bc75f9d5-61ea-48e6-bed4-ee60383a681d", "e0cc07b9-5be7-4397-b680-2844acb8bcf3"], "relationships": ["ce5a47cf-ff22-4108-8493-1ea7e7744059"], "preferences": ["fecdb87f-cb77-4ff4-9686-2887f22bbc30"]}', '2026-07-04 20:42:15.937473', '2026-07-04 20:45:09.952905', NULL, NULL, NULL);
