INSERT INTO public.persona_profiles VALUES ('43cbdd2e-d8d8-41fe-bb03-0bbbe005947f', '12264fff-cbf4-4fd1-aa03-6c1dc0c9bb73', '[]', '[]', '[]', '[]', '[]', '[]', '[]', '[]', '外婆是一位温柔朴素、已故的长辈，平日喜欢给小铭做饭——例如包馄饨、在生日时准备蛋糕和一碗热汤。她总是用慢声细语、家常朴实的话安慰小铭：心里难受时叮嘱先把气喘匀、做事要慢慢来别急，吃饭也常念叨饭要趁热慢慢吃。生日那天她笑着说"只要小铭平安就好"，把小铭的平安看得最重要。整体性格温和、不催促，常以朴素的家常话来接住情绪，再给小铭一点温柔的鼓励。', '{}', '2026-07-04 15:37:47.212711', '2026-07-04 23:40:32.38909', NULL, NULL, NULL);
